fn encode_nonnegative_integer_reply(value: u64, out: &mut Vec<u8>) {
    out.push(b':');
    let mut buf = [0_u8; 20];
    let start = fr_protocol::write_u64_digits(&mut buf, 20, value);
    out.extend_from_slice(&buf[start..]);
    out.extend_from_slice(b"\r\n");
}

