fn set_command_arity_ok(argv: &[Vec<u8>]) -> Option<bool> {
    argv.first()
        .is_some_and(|command| eq_ascii_token(command, b"SET"))
        .then_some(argv.len() >= 3)
}

fn set_command_keys(argv: &[Vec<u8>]) -> Option<Vec<Vec<u8>>> {
    (argv.len() >= 2
        && argv
            .first()
            .is_some_and(|command| eq_ascii_token(command, b"SET")))
    .then(|| vec![argv[1].clone()])
}

fn plain_set_owned_argv(key: &[u8], value: &[u8], trailing: Option<&[u8]>) -> Vec<Vec<u8>> {
    let mut argv = vec![b"SET".to_vec(), key.to_vec(), value.to_vec()];
    if let Some(t) = trailing {
        argv.push(t.to_vec());
    }
    argv
}

fn slowlog_arg_from_prefix(prefix: &[u8], full_len: usize) -> Vec<u8> {
    if full_len > SLOWLOG_ENTRY_MAX_STRING {
        let mut arg = prefix[..prefix.len().min(SLOWLOG_ENTRY_MAX_STRING)].to_vec();
        arg.extend_from_slice(
            format!("... ({} more bytes)", full_len - SLOWLOG_ENTRY_MAX_STRING).as_bytes(),
        );
        arg
    } else {
        prefix.to_vec()
    }
}

fn plain_set_slowlog_argv_from_prefix(
    key: &[u8],
    value_prefix: &[u8],
    value_len: usize,
) -> Vec<Vec<u8>> {
    vec![
        b"SET".to_vec(),
        slowlog_arg_from_prefix(key, key.len()),
        slowlog_arg_from_prefix(value_prefix, value_len),
    ]
}

/// (frankenredis-5gisf) Reconstruct the owned `MSET k v [k v ...]` argv for the
/// rare slowlog/latency/threat paths of the borrowed MSET fast path.
fn plain_mset_owned_argv(pairs: &[(&[u8], &[u8])]) -> Vec<Vec<u8>> {
    let mut argv = Vec::with_capacity(1 + pairs.len() * 2);
    argv.push(b"MSET".to_vec());
    for (k, v) in pairs {
        argv.push(k.to_vec());
        argv.push(v.to_vec());
    }
    argv
}

