/// The fixed-single-key, variadic-value WRITE commands that share one borrowed
/// runtime fast path (`CMD key value [value ...]` -> Integer): SADD, LPUSH,
/// RPUSH. (frankenredis-ev067)
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum PlainKeyedValuesCmd {
    Sadd,
    Lpush,
    Rpush,
    Pfadd,
    // (frankenredis-n8ct0) Variadic DELETE siblings — `CMD key member [member ...]`
    // -> Integer(count removed). Same wire shape + reply as SADD, so they share
    // this borrowed fast path; routed to store.hdel/store.srem which own all
    // accounting + empty-key autodelete (the fast path is gated off whenever
    // notifications/replication/AOF/tracking are active, so no extra side effects).
    Hdel,
    Srem,
    // (frankenredis-zremfast) Variadic zset DELETE sibling — `ZREM key member
    // [member ...]` -> Integer(count removed). Identical wire shape + reply +
    // accounting to SREM (store.zrem mirrors store.srem: type-check, keyspace
    // hit/miss, dirty, empty-key autodelete), so it shares this borrowed fast path;
    // gated off whenever notifications/replication/AOF/tracking are active.
    Zrem,
    // (frankenredis-pushxfast) Conditional variadic push siblings — `CMD key member
    // [member ...]` -> Integer(new length, 0 when the key is absent so it is NOT
    // created). Same wire shape + reply as LPUSH/RPUSH; routed to store.lpushx/rpushx
    // which own the exists-check + all accounting (gated off whenever
    // notifications/replication/AOF/tracking are active, so no extra side effects).
    Lpushx,
    Rpushx,
}

impl PlainKeyedValuesCmd {
    /// Upstream-casing token used for slowlog/threat argv reconstruction and the
    /// `last_argv_len_sum` accounting (which counts the wire bytes of the verb).
    fn name_upper(self) -> &'static str {
        match self {
            PlainKeyedValuesCmd::Sadd => "SADD",
            PlainKeyedValuesCmd::Lpush => "LPUSH",
            PlainKeyedValuesCmd::Rpush => "RPUSH",
            PlainKeyedValuesCmd::Pfadd => "PFADD",
            PlainKeyedValuesCmd::Hdel => "HDEL",
            PlainKeyedValuesCmd::Srem => "SREM",
            PlainKeyedValuesCmd::Zrem => "ZREM",
            PlainKeyedValuesCmd::Lpushx => "LPUSHX",
            PlainKeyedValuesCmd::Rpushx => "RPUSHX",
        }
    }

    /// Lowercase name used for `last_command_name` and the per-command latency
    /// histogram bucket — matching what the generic dispatch records.
    fn name_lower(self) -> &'static str {
        match self {
            PlainKeyedValuesCmd::Sadd => "sadd",
            PlainKeyedValuesCmd::Lpush => "lpush",
            PlainKeyedValuesCmd::Rpush => "rpush",
            PlainKeyedValuesCmd::Pfadd => "pfadd",
            PlainKeyedValuesCmd::Hdel => "hdel",
            PlainKeyedValuesCmd::Srem => "srem",
            PlainKeyedValuesCmd::Zrem => "zrem",
            PlainKeyedValuesCmd::Lpushx => "lpushx",
            PlainKeyedValuesCmd::Rpushx => "rpushx",
        }
    }
}

fn plain_keyed_values_owned_argv(
    cmd: PlainKeyedValuesCmd,
    key: &[u8],
    values: &[&[u8]],
) -> Vec<Vec<u8>> {
    let mut argv = Vec::with_capacity(values.len() + 2);
    argv.push(cmd.name_upper().as_bytes().to_vec());
    argv.push(key.to_vec());
    argv.extend(values.iter().map(|v| v.to_vec()));
    argv
}

/// The single-key, no-count WRITE-pop commands that share one borrowed runtime
/// fast path (`CMD key` -> popped element as a bulk string, nil when the
/// collection is absent/empty): LPOP, RPOP, SPOP. (frankenredis-ev067)
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum PlainKeyedPopCmd {
    Lpop,
    Rpop,
    Spop,
    Zpopmin,
    Zpopmax,
}

impl PlainKeyedPopCmd {
    fn name_upper(self) -> &'static str {
        match self {
            PlainKeyedPopCmd::Lpop => "LPOP",
            PlainKeyedPopCmd::Rpop => "RPOP",
            PlainKeyedPopCmd::Spop => "SPOP",
            PlainKeyedPopCmd::Zpopmin => "ZPOPMIN",
            PlainKeyedPopCmd::Zpopmax => "ZPOPMAX",
        }
    }

    fn name_lower(self) -> &'static str {
        match self {
            PlainKeyedPopCmd::Lpop => "lpop",
            PlainKeyedPopCmd::Rpop => "rpop",
            PlainKeyedPopCmd::Spop => "spop",
            PlainKeyedPopCmd::Zpopmin => "zpopmin",
            PlainKeyedPopCmd::Zpopmax => "zpopmax",
        }
    }

    /// LPOP/RPOP/SPOP reply with a single bulk string (the popped element);
    /// ZPOPMIN/ZPOPMAX reply with a `[member, score]` flat array. The borrowed
    /// fast path uses this to pick the reply shape. (frankenredis-zpopfast)
    // (wc0i6) Reply-shape helper kept for the borrowed ZPOP fast-path wiring; not
    // yet called, so allow until the caller lands (vs deleting in-flight groundwork).
    #[allow(dead_code)]
    fn is_zpop(self) -> bool {
        matches!(self, PlainKeyedPopCmd::Zpopmin | PlainKeyedPopCmd::Zpopmax)
    }
}

