/// Saturating i128 -> i64 clamp (mirrors fr-command's clamp_i128_to_i64).
fn clamp_i128_to_i64_runtime(value: i128) -> i64 {
    if value < i128::from(i64::MIN) {
        i64::MIN
    } else if value > i128::from(i64::MAX) {
        i64::MAX
    } else {
        value as i64
    }
}

