/// Append `bytes` to `out`, ASCII-lowercased, with the same result as
/// `out.push_str(&String::from_utf8_lossy(bytes).to_ascii_lowercase())` but
/// without an intermediate allocation for the common valid-UTF-8 case (char-wise
/// `to_ascii_lowercase` equals byte-wise for ASCII; multi-byte chars unchanged).
/// (frankenredis-hackk)
fn push_ascii_lowercase_lossy(out: &mut String, bytes: &[u8]) {
    // (frankenredis-loweasc) Command names are ASCII in the overwhelming common
    // case, and this runs on EVERY command (write_client_info_command_name sets
    // last_command_name for CLIENT INFO/LIST). For all-ASCII input, lowercase
    // with a direct byte loop — skipping the UTF-8 validation + char-iteration
    // (from_utf8 + Utf8Chunks) the general path pays. Byte-identical: every byte
    // is <= 0x7F so ascii-lowercasing keeps it valid 1-byte UTF-8, exactly what
    // `ch.to_ascii_lowercase()` produces for ASCII chars. Non-ASCII input (only a
    // malformed command name) keeps the char-correct slow path below.
    if bytes.is_ascii() {
        out.reserve(bytes.len());
        for &b in bytes {
            out.push(b.to_ascii_lowercase() as char);
        }
        return;
    }
    match std::str::from_utf8(bytes) {
        Ok(s) => {
            for ch in s.chars() {
                out.push(ch.to_ascii_lowercase());
            }
        }
        Err(_) => out.push_str(&String::from_utf8_lossy(bytes).to_ascii_lowercase()),
    }
}

/// Write the canonical lowercase command name (with `parent|sub` for container
/// commands) into `out`, reusing its buffer instead of allocating a fresh String
/// each command — this runs on every command via `execute_dispatch`. Byte-
/// identical to the prior `client_info_command_name` return value.
/// (frankenredis-hackk)
fn write_client_info_command_name(out: &mut String, argv: &[Vec<u8>]) {
    out.clear();
    let Some(command) = argv.first() else {
        out.push_str("NULL");
        return;
    };
    push_ascii_lowercase_lossy(out, command);
    let Some(sub) = argv.get(1) else {
        return;
    };
    // `out` currently holds exactly the lowercased command name.
    let uses_subcommand = matches!(
        out.as_str(),
        "acl"
            | "client"
            | "cluster"
            | "command"
            | "config"
            | "debug"
            | "function"
            | "latency"
            | "memory"
            | "module"
            | "object"
            | "pubsub"
            | "script"
            | "sentinel"
            | "slowlog"
            | "xgroup"
            | "xinfo"
    );
    if !uses_subcommand {
        return;
    }
    out.push('|');
    push_ascii_lowercase_lossy(out, sub);
}

fn acl_log_age_seconds(now_ms: u64, timestamp_ms: u64) -> String {
    let age_ms = now_ms.saturating_sub(timestamp_ms);
    let age_seconds = age_ms as f64 / 1000.0;
    let rendered = format!("{age_seconds:.3}");
    rendered
        .trim_end_matches('0')
        .trim_end_matches('.')
        .to_string()
}

