/// Commands that vendored Redis propagates to replicas only (PROPAGATE_REPL)
/// and never to the AOF (no PROPAGATE_AOF): PUBLISH and SPUBLISH. They flow
/// down the replication stream so subscribers attached to a replica receive
/// messages published on the master, but pub/sub traffic is transient and is
/// never persisted to the append-only file. The AOF disk flush filters these
/// records back out by name so the on-disk AOF matches upstream.
fn command_is_replication_only(argv: &[Vec<u8>]) -> bool {
    argv.first().is_some_and(|cmd| {
        eq_ascii_token(cmd, b"PUBLISH")
            || eq_ascii_token(cmd, b"SPUBLISH")
            // REPLCONF (e.g. GETACK, injected by WAIT to solicit an immediate replica
            // ack) rides the replication backlog to feed replicas but is a
            // replication-control command that must NEVER be persisted to the AOF —
            // upstream never writes REPLCONF to the AOF, and replaying it on load would
            // be a bogus command. (frankenredis-97shd)
            || eq_ascii_token(cmd, b"REPLCONF")
    })
}

/// Single-key PFCOUNT is a "may-replicate" read: when the cached HLL
/// cardinality is invalid it recomputes the estimate and rewrites the cache
/// into the HLL header (HLL_VALID_CACHE), bumping `dirty`. Upstream
/// pfcountCommand then propagates the PFCOUNT verbatim under the default flags
/// (PROPAGATE_AOF | PROPAGATE_REPL) so replicas and the AOF recompute the same
/// cache and the HLL string stays byte-identical. It is NOT a write command —
/// it is never denyoom — so it must flow through the replication/AOF capture
/// gate WITHOUT being treated as a write by the maxmemory/OOM gate (which keys
/// on `command_advances_replication_offset`). The dispatch dirty-gate ensures
/// capture happens only on the turn it actually recomputed: a cache hit and
/// multi-key PFCOUNT never dirty, so they never propagate, matching upstream.
fn command_is_may_replicate_read(argv: &[Vec<u8>]) -> bool {
    argv.first()
        .is_some_and(|cmd| eq_ascii_token(cmd, b"PFCOUNT"))
}

/// The exact CMD_MAY_REPLICATE set from vendored redis 7.2.4 commands.def:
/// commands that are not necessarily plain writes but can still produce
/// replication traffic. Upstream treats them like writes for CLIENT PAUSE WRITE
/// (and a few other gates), so they must be deferred under a write-pause.
/// (frankenredis)
fn command_is_may_replicate(cmd: &[u8]) -> bool {
    eq_ascii_token(cmd, b"EVAL")
        || eq_ascii_token(cmd, b"EVALSHA")
        || eq_ascii_token(cmd, b"FCALL")
        || eq_ascii_token(cmd, b"PFCOUNT")
        || eq_ascii_token(cmd, b"PUBLISH")
        || eq_ascii_token(cmd, b"SPUBLISH")
}

/// Mirror upstream networking.c::addReplySubcommandSyntaxError for
/// ACL subcommands whose handlers fall through (commands.def arity
/// is variadic: -2). Uses the user-typed subcommand casing and an
/// uppercased parent command, capped at 128 bytes per upstream's
/// `%.128s` format. (br-frankenredis-aclsyntax)
fn acl_subcommand_syntax_error(argv: &[Vec<u8>]) -> RespFrame {
    let sub_raw: &[u8] = argv.get(1).map(Vec::as_slice).unwrap_or(b"");
    let mut sub_bytes = sub_raw.to_vec();
    if sub_bytes.len() > 128 {
        sub_bytes.truncate(128);
    }
    let sub_display = String::from_utf8_lossy(&sub_bytes).into_owned();
    RespFrame::Error(format!(
        "ERR unknown subcommand or wrong number of arguments for '{sub_display}'. Try ACL HELP."
    ))
}

#[allow(dead_code)]
fn increment_run_id_hex(current: &str) -> String {
    let parsed = u128::from_str_radix(current, 16).unwrap_or(0);
    format!("{:040x}", parsed.saturating_add(1))
}

fn replicaof_command_name(argv: &[Vec<u8>]) -> &'static str {
    if argv
        .first()
        .is_some_and(|command| command.eq_ignore_ascii_case(b"SLAVEOF"))
    {
        "SLAVEOF"
    } else {
        "REPLICAOF"
    }
}

#[inline]
/// (frankenredis-wal9t) Upstream parses DB index args via
/// getIntFromObjectOrReply, narrowing to `int` (i32) before the
/// dbnum range check. Values outside i32 surface a generic
/// "value is out of range, value must between -2147483648 and
/// 2147483647" message; values inside i32 but outside [0, dbnum)
/// get the per-command DB-index-out-of-range message. SWAPDB
/// uses a custom "invalid first/second DB index" wording that
/// covers BOTH non-numeric and i32-overflow inputs — pass that
/// same message for both `i32_overflow_message` and via the
/// caller's parse-failure branch.
fn parse_db_index_arg(
    arg: &[u8],
    out_of_range_message: &'static str,
    database_count: usize,
) -> Result<usize, RespFrame> {
    parse_db_index_arg_with_overflow(
        arg,
        "ERR value is out of range, value must between -2147483648 and 2147483647",
        out_of_range_message,
        database_count,
    )
}

fn parse_db_index_arg_with_overflow(
    arg: &[u8],
    i32_overflow_message: &str,
    out_of_range_message: &str,
    database_count: usize,
) -> Result<usize, RespFrame> {
    let parsed = parse_i64_arg(arg)
        .map_err(|_| RespFrame::Error("ERR value is not an integer or out of range".to_string()))?;
    if i32::try_from(parsed).is_err() {
        return Err(RespFrame::Error(i32_overflow_message.to_string()));
    }
    if (0..database_count as i64).contains(&parsed) {
        Ok(parsed as usize)
    } else {
        Err(RespFrame::Error(out_of_range_message.to_string()))
    }
}

