    /// Load and replay AOF records from the configured path, restoring store state.
    ///
    /// Each AOF record is dispatched through the command router as if it were
    /// a client command. Returns the number of records replayed, or an error.
    pub fn load_aof(&mut self, now_ms: u64) -> Result<usize, PersistError> {
        let path = match &self.server.aof_path {
            Some(path) => path.clone(),
            None => return Ok(0),
        };
        // redis 7 multi-part AOF: the path may be (or contain) a manifest with a
        // base file (RDB or AOF) plus incrementals. Otherwise it's a single AOF
        // file. (frankenredis-nvcby)
        let (base_rdb, records) = match resolve_aof_manifest(&path) {
            Some(manifest_path) => {
                // Continue the loaded sequence so post-load rewrites bump it
                // and incremental flushes append to the loaded incr file rather
                // than starting a fresh manifest. (frankenredis-oe6qt)
                if let Ok(manifest) = fr_persist::read_aof_manifest_file(&manifest_path) {
                    self.server.aof_current_seq =
                        manifest.curr_base_file_seq.max(manifest.curr_incr_file_seq);
                }
                let loaded = fr_persist::read_aof_manifest_dir(&manifest_path)?;
                let base =
                    if loaded.base_rdb_entries.is_empty() && loaded.base_rdb_functions.is_empty() {
                        None
                    } else {
                        Some((loaded.base_rdb_entries, loaded.base_rdb_functions))
                    };
                (base, loaded.records)
            }
            None => {
                // Legacy single-file AOF: the next rewrite/flush migrates it to
                // the manifest layout starting at seq 1. (frankenredis-oe6qt)
                self.server.aof_current_seq = 0;
                (None, fr_persist::read_aof_file(&path)?)
            }
        };
        // Count both the base-RDB keys (multi-part AOF where the just-rewritten
        // base holds the dataset and the incr is empty) and the replayed incr
        // records, so a freshly rewritten appendonlydir still reports a non-zero
        // load. (frankenredis-oe6qt)
        let count = records.len()
            + base_rdb
                .as_ref()
                .map_or(0, |(entries, _functions)| entries.len());
        let mut original_store = std::mem::replace(&mut self.server.store, Store::new());
        let original_records = std::mem::take(&mut self.server.aof_records);
        let original_aof_db = self.server.aof_selected_db;
        let original_db = self.session.selected_db;

        self.server.aof_selected_db = 0;
        self.session.selected_db = 0;
        // Seed the fresh store with the base RDB snapshot (multi-part AOF) before
        // replaying the incremental command records. (frankenredis-nvcby)
        if let Some((entries, functions)) = &base_rdb {
            if apply_rdb_entries_to_store(&mut self.server.store, entries.clone(), now_ms).is_err()
            {
                self.server.store = original_store;
                self.server.aof_records = original_records;
                self.server.aof_selected_db = original_aof_db;
                self.session.selected_db = original_db;
                return Err(PersistError::InvalidFrame);
            }
            for code in functions {
                let _ = self.server.store.function_load(code, true);
            }
        }
        for (index, record) in records.iter().enumerate() {
            let replay_now_ms = now_ms.saturating_add(index as u64);
            let reply = self.with_execution_source(ExecutionSource::AofLoad, |runtime| {
                runtime.execute_frame(record.to_resp_frame(), replay_now_ms)
            });
            if matches!(reply, RespFrame::Error(_)) {
                original_store.stat_total_error_replies = original_store
                    .stat_total_error_replies
                    .saturating_add(self.server.store.stat_total_error_replies);
                original_store.stat_unexpected_error_replies = original_store
                    .stat_unexpected_error_replies
                    .saturating_add(self.server.store.stat_unexpected_error_replies);
                self.server.store = original_store;
                self.server.aof_records = original_records;
                self.server.aof_selected_db = original_aof_db;
                self.session.selected_db = original_db;
                return Err(PersistError::InvalidFrame);
            }
        }

        self.server.aof_records = records;
        // (frankenredis-ol9tz) The replayed records are exactly the on-disk
        // file contents, so the incremental flush starts from the tail.
        self.server.aof_disk_flushed_records = self.server.aof_records.len();
        self.server.aof_selected_db = self.session.selected_db;
        self.session.selected_db = original_db;
        // Preserve server context that the boot path established on
        // `original_store` before AOF replay swapped in a fresh
        // `Store::new()` (e.g. `aof_enabled = true` from `set_aof_path`
        // plus INFO/CLUSTER identity fields such as run_id and tcp_port).
        // The error path restores `original_store` wholesale; the success
        // path mirrors the non-dataset context onto the replayed store.
        // (br-frankenredis-7epx)
        preserve_store_load_context(&mut self.server.store, &original_store);
        Ok(count)
    }

    /// Load an RDB snapshot from the configured path, replacing store state.
    /// Returns the number of entries loaded, or an error.
    pub fn load_rdb(&mut self, now_ms: u64) -> Result<usize, PersistError> {
        let path = match &self.server.rdb_path {
            Some(path) => path.clone(),
            None => return Ok(0),
        };
        let (entries, _aux, functions) = fr_persist::read_rdb_file_with_functions(&path)?;
        let mut store = Store::new();
        // (frankenredis-63p1s) Apply the live encoding thresholds BEFORE the
        // rebuild so replayed collections pick their encoding under the current
        // config, not the fresh store's compiled defaults.
        copy_encoding_thresholds(&mut store, &self.server.store);
        let counts = apply_rdb_entries_to_store(&mut store, entries, now_ms)?;
        // Re-register FUNCTION libraries carried in the dump so FUNCTION LIST /
        // FCALL survive a restart, matching redis. (frankenredis-tm139)
        for code in &functions {
            let _ = store.function_load(code, true);
        }
        store.stat_rdb_last_load_keys_expired = u64::try_from(counts.expired).unwrap_or(u64::MAX);
        store.stat_rdb_last_load_keys_loaded = u64::try_from(counts.loaded).unwrap_or(u64::MAX);
        preserve_store_load_context(&mut store, &self.server.store);
        self.server.store = store;
        Ok(counts.loaded)
    }

    fn handle_debug_reload_requested(&mut self, now_ms: u64) -> RespFrame {
        if let Err(reply) = self.persist_snapshot_to_disk(now_ms, false, true) {
            return reply;
        }

        if self.server.aof_path.is_some() {
            return match self.load_aof(now_ms.saturating_add(1)) {
                Ok(_) => RespFrame::SimpleString("OK".to_string()),
                Err(_) => RespFrame::Error("ERR failed to reload dataset from AOF".to_string()),
            };
        }

        if let Some(path) = self.server.rdb_path.clone() {
            return match read_rdb_file(&path) {
                Ok((entries, _aux)) => {
                    let mut store = Store::new();
                    // (frankenredis-63p1s) live encoding thresholds before rebuild.
                    copy_encoding_thresholds(&mut store, &self.server.store);
                    let counts = match apply_rdb_entries_to_store(
                        &mut store,
                        entries,
                        now_ms.saturating_add(1),
                    ) {
                        Ok(counts) => counts,
                        Err(_) => {
                            return RespFrame::Error(
                                "ERR failed to reload dataset from RDB".to_string(),
                            );
                        }
                    };
                    store.stat_rdb_last_load_keys_expired =
                        u64::try_from(counts.expired).unwrap_or(u64::MAX);
                    store.stat_rdb_last_load_keys_loaded =
                        u64::try_from(counts.loaded).unwrap_or(u64::MAX);
                    // (frankenredis-hpfey) Carry CONFIG SET state (encoding
                    // thresholds, eviction policy, keyspace notifications) and
                    // server identity across the reload — the RDB holds only data.
                    preserve_store_load_context(&mut store, &self.server.store);
                    self.server.store = store;
                    self.session.selected_db = 0;
                    RespFrame::SimpleString("OK".to_string())
                }
                Err(_) => RespFrame::Error("ERR failed to reload dataset from RDB".to_string()),
            };
        }

        // (frankenredis-8hzzv) Vendored debug.c::DEBUG RELOAD does not
        // require persistence to be configured at startup — it always
        // round-trips through an RDB tempfile (server.rdb_filename
        // defaults to 'dump.rdb'). The semantic intent is to validate
        // the rdbSave/rdbLoad encoder pair, not to reload from a
        // configured path. fr previously short-circuited with
        // 'requires configured appendonly or RDB persistence' when no
        // --rdb / --aof was supplied.
        //
        // For parity, perform the round-trip entirely in memory:
        // serialize the live store via encode_rdb, decode the bytes
        // back, then replace the store. This validates the
        // encoder/decoder pair without touching disk.
        let fn_codes = self.rdb_function_codes();
        let fn_refs: Vec<&[u8]> = fn_codes.iter().map(Vec::as_slice).collect();
        let bytes = if let Some(bytes) =
            try_encode_string_only_rdb_snapshot(&mut self.server.store, now_ms, &[], &fn_refs)
        {
            bytes
        } else {
            let entries = store_to_rdb_entries(&mut self.server.store, now_ms);
            fr_persist::encode_rdb_with_functions_and_thresholds(
                &entries,
                &[],
                &fn_refs,
                live_compact_thresholds(&self.server.store),
            )
        };
        let decoded = match fr_persist::decode_rdb_prefix(&bytes) {
            Ok(out) if out.consumed == bytes.len() => out,
            _ => {
                return RespFrame::Error(
                    "ERR failed to reload dataset from in-memory RDB round-trip".to_string(),
                );
            }
        };
        let mut store = Store::new();
        // (frankenredis-63p1s) live encoding thresholds before rebuild.
        copy_encoding_thresholds(&mut store, &self.server.store);
        let counts =
            match apply_rdb_entries_to_store(&mut store, decoded.entries, now_ms.saturating_add(1))
            {
                Ok(counts) => counts,
                Err(_) => {
                    return RespFrame::Error(
                        "ERR failed to reload dataset from in-memory RDB round-trip".to_string(),
                    );
                }
            };
        // Restore FUNCTION libraries through the round-trip too. (frankenredis-c0u9q)
        for code in &decoded.functions {
            let _ = store.function_load(code, true);
        }
        store.stat_rdb_last_load_keys_expired = u64::try_from(counts.expired).unwrap_or(u64::MAX);
        store.stat_rdb_last_load_keys_loaded = u64::try_from(counts.loaded).unwrap_or(u64::MAX);
        // (frankenredis-hpfey) Carry CONFIG SET state + server identity across the
        // in-memory reload — the RDB round-trip holds only data.
        preserve_store_load_context(&mut store, &self.server.store);
        self.server.store = store;
        self.session.selected_db = 0;
        RespFrame::SimpleString("OK".to_string())
    }

    #[must_use]
    pub fn default_strict() -> Self {
        Self::new(RuntimePolicy::default())
    }

