    #[must_use]
    pub fn evidence(&self) -> &EvidenceLedger {
        &self.server.evidence
    }

    #[must_use]
    pub fn aof_records(&self) -> &[AofRecord] {
        &self.server.aof_records
    }

    #[must_use]
    pub fn encoded_aof_stream(&self) -> Vec<u8> {
        encode_aof_stream(&self.server.aof_records)
    }

    #[must_use]
    pub fn encoded_aof_stream_from_offset(&self, offset: u64) -> Vec<u8> {
        // The encoded backlog spans [aof_base_offset, primary_offset] and offsets
        // advance by whole-record encoded lengths, so the suffix from `offset` is
        // exactly the last (primary_offset - offset) bytes. Encode only that tail
        // (O(records in the tail)) instead of re-encoding the whole backlog and
        // slicing — byte-identical to the prior `encoded_aof_stream()[start..]`.
        // (frankenredis-cc aoftail)
        let primary = self.server.replication_ack_state.primary_offset.0;
        let tail_bytes = usize::try_from(primary.saturating_sub(offset)).unwrap_or(usize::MAX);
        encode_aof_stream_tail_bytes(&self.server.aof_records, tail_bytes)
    }

    /// Library source for every registered FUNCTION, name-sorted, for embedding
    /// FUNCTION2 records into an RDB snapshot so they survive a save/load cycle.
    /// (frankenredis-c0u9q)
    fn rdb_function_codes(&self) -> Vec<Vec<u8>> {
        self.server
            .store
            .function_list(None)
            .iter()
            .map(|lib| lib.code.clone())
            .collect()
    }

    #[must_use]
    pub fn encoded_rdb_snapshot(&mut self, now_ms: u64) -> Vec<u8> {
        let fn_codes = self.rdb_function_codes();
        let fn_refs: Vec<&[u8]> = fn_codes.iter().map(Vec::as_slice).collect();
        let aux = [
            ("redis-ver", fr_store::REDIS_COMPAT_VERSION),
            ("frankenredis", "true"),
        ];
        if let Some(bytes) =
            try_encode_string_only_rdb_snapshot(&mut self.server.store, now_ms, &aux, &fn_refs)
        {
            bytes
        } else {
            let entries = store_to_rdb_entries(&mut self.server.store, now_ms);
            fr_persist::encode_rdb_with_functions_and_thresholds(
                &entries,
                &aux,
                &fn_refs,
                live_compact_thresholds(&self.server.store),
            )
        }
    }

    pub fn replay_aof_stream(
        &mut self,
        input: &[u8],
        now_ms: u64,
    ) -> Result<Vec<RespFrame>, PersistError> {
        let records = decode_aof_stream(input)?;
        Ok(self.replay_aof_records(&records, now_ms))
    }

    #[must_use]
    pub fn replay_aof_records(&mut self, records: &[AofRecord], now_ms: u64) -> Vec<RespFrame> {
        self.replay_records_with_source(records, now_ms, ExecutionSource::AofLoad)
    }

    fn replay_records_with_source(
        &mut self,
        records: &[AofRecord],
        now_ms: u64,
        source: ExecutionSource,
    ) -> Vec<RespFrame> {
        let mut replies = Vec::with_capacity(records.len());
        for (index, record) in records.iter().enumerate() {
            let replay_now_ms = now_ms.saturating_add(index as u64);
            let reply = self.with_execution_source(source, |runtime| {
                runtime.execute_frame(record.to_resp_frame(), replay_now_ms)
            });
            replies.push(reply);
        }
        replies
    }

    pub fn apply_replication_sync_payload(
        &mut self,
        reply_line: &str,
        payload: &[u8],
        now_ms: u64,
    ) -> Result<(), PersistError> {
        match parse_psync_reply(reply_line).map_err(|_| PersistError::InvalidFrame)? {
            PsyncReply::Continue { replid } => {
                if let Some(replid) = replid {
                    self.server.replication_runtime_state.backlog.replid = replid;
                }
                let records = decode_aof_stream(payload)?;
                self.replay_records_with_source(
                    &records,
                    now_ms,
                    ExecutionSource::ReplicationReplay,
                );
            }
            PsyncReply::FullResync { replid, offset } => {
                let decoded = fr_persist::decode_rdb_prefix(payload)?;
                if decoded.consumed != payload.len() {
                    return Err(PersistError::InvalidFrame);
                }
                let mut store = Store::new();
                // (frankenredis-63p1s) live encoding thresholds before rebuild.
                copy_encoding_thresholds(&mut store, &self.server.store);
                let counts = apply_rdb_entries_to_store(&mut store, decoded.entries, now_ms)?;
                // (frankenredis-t1yxa) Re-register FUNCTION libraries carried in
                // the full-sync snapshot so FCALL / FUNCTION LIST work on the
                // replica too, matching the master.
                for code in &decoded.functions {
                    let _ = store.function_load(code, true);
                }
                store.stat_rdb_last_load_keys_expired =
                    u64::try_from(counts.expired).unwrap_or(u64::MAX);
                store.stat_rdb_last_load_keys_loaded =
                    u64::try_from(counts.loaded).unwrap_or(u64::MAX);
                // (frankenredis-replport) A full-resync replaces the store with
                // one loaded from the primary's RDB; carry over this instance's
                // identity (server_port, run_id, pid, cluster, AOF/sentinel mode)
                // exactly like the AOF/RDB local-load paths, so the replica keeps
                // its own --port. Otherwise server_port reverted to the 6379
                // default, corrupting INFO tcp_port and the REPLCONF
                // listening-port advertised on reconnect (master's slave0 port).
                preserve_store_load_context(&mut store, &self.server.store);
                self.server.store = store;
                self.server.aof_records.clear();
                // (frankenredis-ol9tz) Buffer reset to empty; AOF flush cursor
                // must follow so it doesn't index past the cleared buffer.
                self.server.aof_disk_flushed_records = 0;
                // Track the base offset where the local AOF buffer starts.
                // New records will be indexed from 0, but they correspond to
                // absolute offset starting at this value.
                self.server.aof_base_offset = offset.0;
                self.server.aof_selected_db = 0;
                self.session.selected_db = 0;
                self.server
                    .replication_runtime_state
                    .backlog
                    .rotate(replid, offset, offset);
                self.server.replication_ack_state.primary_offset = offset;
                self.server.replication_ack_state.local_fsync_offset = offset;
            }
        }
        if let ReplicationRoleState::Replica { ref mut state, .. } =
            self.server.replication_runtime_state.role
        {
            *state = "connected";
        }
        self.server.refresh_replica_ack_snapshots();
        Ok(())
    }

    #[must_use]
    pub fn replica_sync_target(&self) -> Option<(String, u16)> {
        match &self.server.replication_runtime_state.role {
            ReplicationRoleState::Replica { host, port, state } if *state != "connected" => {
                Some((host.clone(), *port))
            }
            _ => None,
        }
    }

    #[must_use]
    pub fn replica_psync_request(&self) -> Option<(String, i64)> {
        let ReplicationRoleState::Replica { state, .. } =
            &self.server.replication_runtime_state.role
        else {
            return None;
        };
        if *state == "reconnect" {
            return Some((
                self.server.replication_runtime_state.backlog.replid.clone(),
                i64::try_from(self.server.replication_ack_state.primary_offset.0)
                    .unwrap_or(i64::MAX),
            ));
        }
        Some(("?".to_string(), -1))
    }

    #[must_use]
    pub fn replica_primary_auth(&self) -> Option<(Option<Vec<u8>>, Vec<u8>)> {
        self.server
            .masterauth
            .as_ref()
            .map(|password| (self.server.masteruser.clone(), password.clone()))
    }

    #[must_use]
    pub fn take_replica_reconfigure_request(&mut self) -> bool {
        let requested = self.server.replica_reconfigure_requested;
        self.server.replica_reconfigure_requested = false;
        requested
    }

    pub fn set_replica_connection_state(&mut self, state: &'static str) {
        if let ReplicationRoleState::Replica {
            state: role_state, ..
        } = &mut self.server.replication_runtime_state.role
        {
            *role_state = state;
        }
    }

    #[must_use]
    pub fn replication_primary_offset(&self) -> ReplOffset {
        self.server.replication_ack_state.primary_offset
    }

    /// Returns the start offset of the replication backlog.
    /// This is the earliest offset still available in the AOF stream.
    #[must_use]
    pub fn replication_backlog_start_offset(&self) -> ReplOffset {
        self.server.replication_runtime_state.backlog.start_offset
    }

    /// Returns the base offset of the local AOF buffer.
    /// For a primary, this is 0. For a replica after FULLRESYNC, this is
    /// the primary's offset at sync time.
    #[must_use]
    pub fn aof_base_offset(&self) -> u64 {
        self.server.aof_base_offset
    }

    #[must_use]
    pub fn is_replica(&self, client_id: u64) -> bool {
        self.server
            .replication_runtime_state
            .replicas
            .contains_key(&client_id)
    }

    /// True if any replica is currently attached to this primary. The replica
    /// registry is the authoritative set: a connection's
    /// `replication_sent_offset` is set only when `is_replica` is true (set
    /// together at PSYNC), and a replica leaves the registry only by
    /// disconnecting, so registry-empty ⟺ no connection needs replication
    /// propagation. Lets the event loop skip the O(connected-clients)
    /// propagate sweep when there are no replicas (the common case).
    #[must_use]
    pub fn has_connected_replicas(&self) -> bool {
        !self.server.replication_runtime_state.replicas.is_empty()
    }

    /// (frankenredis-97shd) Solicit an immediate ack from every connected replica by
    /// injecting `REPLCONF GETACK *` into the replication stream. Called once when a
    /// WAIT/WAITAOF(numreplicas>0) blocks: without it, replica ack offsets advance
    /// only on the replica's ~1Hz periodic ACK, so a short-timeout WAIT undercounts
    /// (`WAIT 1 200` -> :0 where redis returns :1) and successful WAITs are up to ~1s
    /// slow. The GETACK record rides the offset-tracked backlog to the replicas
    /// (advancing master_repl_offset like upstream) but `command_is_replication_only`
    /// keeps it out of the AOF. No-op when no replica is attached.
    pub fn solicit_replica_ack(&mut self) {
        if !self.has_connected_replicas() {
            return;
        }
        self.capture_aof_record(&[b"REPLCONF".to_vec(), b"GETACK".to_vec(), b"*".to_vec()]);
    }

    /// The client-output-buffer-limit HARD limit (in bytes) that applies to the
    /// connection `client_id`, by its redis client class (slave / pubsub /
    /// normal). A hard limit of 0 means "unlimited" in redis, returned here as
    /// `usize::MAX` so the fr-server write-buffer guard never disconnects such a
    /// client. (frankenredis-8sb0l)
    #[must_use]
    pub fn effective_output_hard_limit(&self, client_id: u64) -> usize {
        let limits = &self.server.client_output_buffer_limits;
        let class = if self.is_replica(client_id) {
            limits.slave
        } else if self.is_pubsub_client(client_id) {
            limits.pubsub
        } else {
            limits.normal
        };
        if class.hard == 0 {
            usize::MAX
        } else {
            usize::try_from(class.hard).unwrap_or(usize::MAX)
        }
    }

    /// The slave-class HARD limit (bytes; 0 → `usize::MAX`). Used for the
    /// replica→primary link write buffer. (frankenredis-8sb0l)
    #[must_use]
    pub fn replica_link_output_hard_limit(&self) -> usize {
        let hard = self.server.client_output_buffer_limits.slave.hard;
        if hard == 0 {
            usize::MAX
        } else {
            usize::try_from(hard).unwrap_or(usize::MAX)
        }
    }

    #[must_use]
    pub fn replica_ack_frame(&self) -> Option<RespFrame> {
        let ReplicationRoleState::Replica { .. } = &self.server.replication_runtime_state.role
        else {
            return None;
        };
        Some(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"REPLCONF".to_vec())),
            RespFrame::BulkString(Some(b"ACK".to_vec())),
            RespFrame::BulkString(Some(
                self.server
                    .replication_ack_state
                    .primary_offset
                    .0
                    .to_string()
                    .into_bytes(),
            )),
        ])))
    }

    #[must_use]
    pub fn tls_runtime_state(&self) -> &TlsRuntimeState {
        self.server.tls_runtime_state()
    }

    #[must_use]
    pub fn server_state(&self) -> &ServerState {
        &self.server
    }

    #[must_use]
    pub fn server_state_mut(&mut self) -> &mut ServerState {
        &mut self.server
    }

    #[must_use]
    pub fn client_session(&self) -> &ClientSession {
        &self.session
    }

    /// Create a new `ClientSession` for this runtime's server state.
    /// Used by multi-client servers to create per-connection sessions.
    #[must_use]
    pub fn new_session(&self) -> ClientSession {
        ClientSession::new_for_server(&self.server)
    }

    /// Swap the active client session, returning the previous one.
    /// Used by multi-client servers to switch between per-connection sessions
    /// before executing commands.
    pub fn swap_session(&mut self, mut session: ClientSession) -> ClientSession {
        // Ensure the new session is correctly associated with this server's state.
        session.refresh_authentication_for_server(&self.server.auth_state, true);
        std::mem::replace(&mut self.session, session)
    }

    /// Retrieve the current client session ID.
    pub fn client_id(&self) -> u64 {
        self.session.client_id
    }

    #[must_use]
    pub fn suppress_current_network_reply(&self) -> bool {
        self.session.client_reply.suppress_current_response
    }

    /// Resolve the current tail ID for a stream key, used by blocking XREAD
    /// callers that must freeze `$` cursors at block time.
    pub fn xread_block_resume_id(&mut self, key: &[u8], now_ms: u64) -> Option<(u64, u64)> {
        self.server.store.xlast_id(key, now_ms).ok().flatten()
    }

    /// Update or insert a session snapshot used by multi-client CLIENT LIST.
    pub fn record_client_session(&mut self, session: &ClientSession) {
        self.refresh_client_tracking_bcast_membership(session.client_id, &session.client_tracking);
        self.server
            .client_sessions
            .insert(session.client_id, session.clone());
        // (frankenredis-zfu61 perf) The clients.normal / clients.slaves memory
        // aggregates were re-summed over EVERY live session here — once per
        // pipelined batch, O(live-clients) plus a HashSet allocation, on the hot
        // path — purely to feed the rarely-queried MEMORY STATS / MEMORY USAGE /
        // INFO memory fields. Upstream samples client memory lazily (clientsCron
        // / on the MEMORY command), so refresh is now deferred to those read
        // sites (`refresh_client_memory_aggregates` is called from
        // handle_info_command and the MEMORY dispatch). The per-command snapshot
        // insert above is kept (CLIENT LIST/INFO still need it).
    }

    /// (frankenredis-zfu61) Recompute `stat_clients_normal_mem_bytes` and
    /// `stat_clients_replica_mem_bytes` on Store by iterating every
    /// currently-live client session. Drives MEMORY STATS' clients.normal
    /// and clients.slaves fields. Per-client cost mirrors upstream
    /// clientMemUsage(c) = querybuf_alloc + reply_buffer_size + per-client
    /// struct overhead; fr's per-session contribution is 432 (struct
    /// overhead, same baseline tepuj uses for tot-mem) + qbuf + qbuf-free
    /// + output_buffer. The replica/normal bucket follows `Runtime::is_replica`.
    fn refresh_client_memory_aggregates(&mut self) {
        const PER_CLIENT_STRUCT_BYTES: usize = 432;
        let mut normal_total: usize = 0;
        let mut replica_total: usize = 0;
        let replica_client_ids: HashSet<u64> = self
            .server
            .replication_runtime_state
            .replicas
            .keys()
            .copied()
            .collect();
        for (id, session) in &self.server.client_sessions {
            let mem = PER_CLIENT_STRUCT_BYTES
                .saturating_add(session.qbuf_bytes)
                .saturating_add(session.qbuf_free_bytes)
                .saturating_add(session.output_buffer_bytes);
            if replica_client_ids.contains(id) {
                replica_total = replica_total.saturating_add(mem);
            } else {
                normal_total = normal_total.saturating_add(mem);
            }
        }
        self.server.store.stat_clients_normal_mem_bytes = normal_total;
        self.server.store.stat_clients_replica_mem_bytes = replica_total;
    }

    /// (frankenredis-jrqgd) Feed a pre-dispatch sample of a client's
    /// read/write buffer sizes into the server-wide recent-max
    /// accumulators so INFO clients emits real
    /// `client_recent_max_input_buffer` / `client_recent_max_output_buffer`
    /// values instead of hardcoded zeros. fr-server invokes this from
    /// handle_readable *before* swapping the session into the runtime,
    /// while read_buf still holds the inbound bytes that are about to
    /// be consumed by the dispatch.
    pub fn observe_client_buffer_sizes(
        &mut self,
        input_buffer_bytes: usize,
        output_buffer_bytes: usize,
    ) {
        self.server
            .store
            .observe_client_buffer_sizes(input_buffer_bytes, output_buffer_bytes);
    }

    /// Remove a disconnected session from the CLIENT LIST registry.
    pub fn remove_client_session(&mut self, client_id: u64) {
        self.server.client_sessions.remove(&client_id);
        self.server.client_tracking_bcast_clients.remove(&client_id);
        self.remove_client_tracking_observer(client_id);
        // (frankenredis-zfu61 perf) The dropped client's contribution is picked
        // up by the lazy refresh at the next MEMORY STATS / INFO memory read
        // (see record_client_session); no eager O(live-clients) re-sum here.
    }

    /// Track a new client connection for INFO stats.
    pub fn track_connection_opened(&mut self) {
        self.server.store.stat_total_connections_received += 1;
        self.server.store.stat_connected_clients += 1;
    }

    /// Track network input bytes for INFO stats.
    pub fn track_net_input_bytes(&mut self, bytes: u64) {
        self.server.store.stat_total_net_input_bytes += bytes;
    }

    /// Track network output bytes for INFO stats.
    pub fn track_net_output_bytes(&mut self, bytes: u64) {
        self.server.store.stat_total_net_output_bytes += bytes;
    }

    /// (frankenredis-k96mc) Record one event-loop READ event. Upstream
    /// server.c::readQueryFromClient bumps server.stat_total_reads_processed once
    /// per readable handler invocation that read data — NOT once per command — so
    /// a pipelined batch counts as a single read. The event loop calls this once
    /// per `handle_readable` that drained ≥1 byte, before dispatching the batch.
    pub fn note_read_event(&mut self) {
        self.server.store.stat_total_reads_processed += 1;
    }

    /// (frankenredis-k96mc) Record one event-loop WRITE event. Upstream
    /// server.c::writeToClient bumps server.stat_total_writes_processed once per
    /// flush of a client's pending output — NOT once per reply — so the event loop
    /// calls this once per successful `try_flush` of a non-empty write buffer.
    pub fn note_write_event(&mut self) {
        self.server.store.stat_total_writes_processed += 1;
    }

    /// Record an instantaneous ops/sec sample. Call once per server-hz tick.
    pub fn record_ops_sec_sample(&mut self, elapsed_ms: u64) {
        self.server.store.record_ops_sec_sample(elapsed_ms);
    }

    /// Track one completed server event loop cycle for INFO stats.
    pub fn record_eventloop_cycle(&mut self, duration_usec: u64) {
        self.server.store.record_eventloop_cycle(duration_usec);
    }

    /// Track a rejected connection (maxclients exceeded).
    pub fn track_rejected_connection(&mut self) {
        self.server.store.stat_rejected_connections += 1;
    }

    /// Track a full resync event (PSYNC FULLRESYNC).
    pub fn track_sync_full(&mut self) {
        self.server.store.stat_sync_full += 1;
    }

    /// Track a successful partial resync (PSYNC CONTINUE).
    pub fn track_sync_partial_ok(&mut self) {
        self.server.store.stat_sync_partial_ok += 1;
    }

    /// Track a failed partial resync attempt (fell back to full resync).
    pub fn track_sync_partial_err(&mut self) {
        self.server.store.stat_sync_partial_err += 1;
    }

    /// Track a client disconnection for INFO stats.
    pub fn track_connection_closed(&mut self) {
        self.server.store.stat_connected_clients =
            self.server.store.stat_connected_clients.saturating_sub(1);
    }

    /// Clean up replication/monitor state for a disconnected client.
    pub fn cleanup_disconnected_client(&mut self, client_id: u64) {
        self.disable_monitor(client_id);
        self.server.client_tracking_bcast_clients.remove(&client_id);
        self.remove_client_tracking_observer(client_id);
        if self
            .server
            .replication_runtime_state
            .replicas
            .remove(&client_id)
            .is_some()
        {
            self.server.refresh_replica_ack_snapshots();
        }
    }

    /// Drain pending pub/sub messages for the current session's client.
    pub fn drain_pending_pubsub(&mut self) -> Vec<fr_store::PubSubMessage> {
        // First drain any messages from the per-client Store (legacy path for
        // single-session tests), then drain from the global outbox.
        let mut msgs = self.server.store.drain_pending_pubsub();
        // (frankenredis-pubsubdrain) drain_pending_pubsub runs after EVERY
        // command for EVERY client, but the global pub/sub outbox is empty for
        // any workload without active subscribers (the overwhelmingly common
        // case). Guard the per-client `pubsub_outbox.remove` — a hash + bucket
        // probe that showed up at ~0.7% self in a pipelined LPUSH profile —
        // behind an O(1) `is_empty()` check on the whole map. Byte-identical:
        // when the outbox is empty, `remove(&client_id)` returns `None` and
        // contributes nothing, so skipping it cannot change the result.
        if !self.server.pubsub_outbox.is_empty() {
            let client_id = self.session.client_id;
            if let Some(outbox) = self.server.pubsub_outbox.remove(&client_id) {
                msgs.extend(outbox);
            }
        }
        msgs
    }

    /// Drain pending pub/sub messages for a specific client by ID.
    /// Used by the server event loop to deliver messages to non-active clients.
    pub fn drain_pubsub_for_client(&mut self, client_id: u64) -> Vec<fr_store::PubSubMessage> {
        self.server
            .pubsub_outbox
            .remove(&client_id)
            .unwrap_or_default()
    }

    /// Drain every nonempty per-client pub/sub outbox in one map traversal.
    ///
    /// `HashMap::drain` retains the map's allocation for the next publish while avoiding the
    /// client-ID snapshot followed by one keyed removal per subscriber.
    #[cfg_attr(any(test, feature = "bench-reference"), inline(never))]
    pub fn drain_pubsub_outboxes(&mut self) -> Vec<(u64, Vec<fr_store::PubSubMessage>)> {
        let mut outboxes = Vec::with_capacity(self.server.pubsub_outbox.len());
        outboxes.extend(
            self.server
                .pubsub_outbox
                .drain()
                .filter(|(_, messages)| !messages.is_empty()),
        );
        outboxes
    }

    /// Return all client IDs that have pending pub/sub messages.
    #[cfg_attr(any(test, feature = "bench-reference"), inline(never))]
    pub fn pubsub_clients_with_pending(&self) -> Vec<u64> {
        let mut client_ids = Vec::with_capacity(self.server.pubsub_outbox.len());
        client_ids.extend(
            self.server
                .pubsub_outbox
                .iter()
                .filter(|(_, messages)| !messages.is_empty())
                .map(|(&client_id, _)| client_id),
        );
        client_ids
    }

    /// Frozen pre-optimization pending-client snapshot for same-binary benchmarks.
    #[cfg(any(test, feature = "bench-reference"))]
    #[doc(hidden)]
    #[inline(never)]
    pub fn pubsub_clients_with_pending_hashset_reference(&self) -> HashSet<u64> {
        self.server
            .pubsub_outbox
            .iter()
            .filter(|(_, messages)| !messages.is_empty())
            .map(|(&client_id, _)| client_id)
            .collect()
    }

    fn session_has_pubsub_permissions_revoked(&self, session: &ClientSession) -> bool {
        let has_pubsub_state = self
            .server
            .pubsub_client_channels
            .get(&session.client_id)
            .is_some_and(|channels| !channels.is_empty())
            || self
                .server
                .pubsub_client_patterns
                .get(&session.client_id)
                .is_some_and(|patterns| !patterns.is_empty())
            || self
                .server
                .pubsub_client_shard_channels
                .get(&session.client_id)
                .is_some_and(|channels| !channels.is_empty());
        if !has_pubsub_state {
            return false;
        }

        let Some(username) = session.authenticated_user.as_ref() else {
            return false;
        };
        let Some(user) = self.server.auth_state.get_user(username) else {
            return true;
        };

        self.server
            .pubsub_client_channels
            .get(&session.client_id)
            .is_some_and(|channels| {
                channels
                    .iter()
                    .any(|channel| !user.is_channel_allowed(channel))
            })
            || self
                .server
                .pubsub_client_patterns
                .get(&session.client_id)
                .is_some_and(|patterns| {
                    patterns
                        .iter()
                        .any(|pattern| !user.is_channel_pattern_allowed(pattern))
                })
            || self
                .server
                .pubsub_client_shard_channels
                .get(&session.client_id)
                .is_some_and(|channels| {
                    channels
                        .iter()
                        .any(|channel| !user.is_channel_allowed(channel))
                })
    }

    fn queue_acl_pubsub_revocations_for_user(&mut self, username: &[u8]) {
        let sessions = self.client_list_sessions();
        for session in sessions.values() {
            if session.authenticated_user.as_deref() != Some(username) {
                continue;
            }
            if self.session_has_pubsub_permissions_revoked(session)
                && !self
                    .server
                    .pending_client_kills
                    .contains(&session.client_id)
            {
                self.server.pending_client_kills.push(session.client_id);
            }
        }
    }

    fn queue_acl_deleted_user_disconnects(&mut self, username: &[u8]) {
        let sessions = self.client_list_sessions();
        for session in sessions.values() {
            if session.authenticated_user.as_deref() == Some(username)
                && !self
                    .server
                    .pending_client_kills
                    .contains(&session.client_id)
            {
                self.server.pending_client_kills.push(session.client_id);
            }
        }
    }

    fn queue_acl_pubsub_revocations_for_all_users(&mut self) {
        let sessions = self.client_list_sessions();
        for session in sessions.values() {
            if self.session_has_pubsub_permissions_revoked(session)
                && !self
                    .server
                    .pending_client_kills
                    .contains(&session.client_id)
            {
                self.server.pending_client_kills.push(session.client_id);
            }
        }
    }

    // ── Pub/Sub global registry operations ──────────────────────────

    /// Subscribe the current client to a channel. Returns total subscription count.
    pub fn pubsub_subscribe(&mut self, channel: Vec<u8>) -> usize {
        let client_id = self.session.client_id;
        self.server.store.subscribe(channel.clone());
        self.server
            .pubsub_channel_subs
            .entry(channel.clone())
            .or_default()
            .insert(client_id);
        self.server
            .pubsub_client_channels
            .entry(client_id)
            .or_default()
            .insert(channel);
        self.pubsub_sub_count(client_id)
    }

    /// Unsubscribe the current client from a channel. Returns total subscription count.
    pub fn pubsub_unsubscribe(&mut self, channel: &[u8]) -> usize {
        let client_id = self.session.client_id;
        if let Some(subs) = self.server.pubsub_channel_subs.get_mut(channel) {
            subs.remove(&client_id);
            if subs.is_empty() {
                self.server.pubsub_channel_subs.remove(channel);
            }
        }
        if let Some(channels) = self.server.pubsub_client_channels.get_mut(&client_id) {
            channels.remove(channel);
            if channels.is_empty() {
                self.server.pubsub_client_channels.remove(&client_id);
            }
        }
        if !self.server.pubsub_channel_subs.contains_key(channel) {
            self.server.store.unsubscribe(channel);
        }
        self.pubsub_sub_count(client_id)
    }

    /// Subscribe the current client to a pattern. Returns total subscription count.
    pub fn pubsub_psubscribe(&mut self, pattern: Vec<u8>) -> usize {
        let client_id = self.session.client_id;
        self.server.store.psubscribe(pattern.clone());
        self.server
            .pubsub_pattern_subs
            .entry(pattern.clone())
            .or_default()
            .insert(client_id);
        self.server
            .pubsub_client_patterns
            .entry(client_id)
            .or_default()
            .insert(pattern);
        self.pubsub_sub_count(client_id)
    }

    /// Unsubscribe the current client from a pattern. Returns total subscription count.
    pub fn pubsub_punsubscribe(&mut self, pattern: &[u8]) -> usize {
        let client_id = self.session.client_id;
        if let Some(subs) = self.server.pubsub_pattern_subs.get_mut(pattern) {
            subs.remove(&client_id);
            if subs.is_empty() {
                self.server.pubsub_pattern_subs.remove(pattern);
            }
        }
        if let Some(patterns) = self.server.pubsub_client_patterns.get_mut(&client_id) {
            patterns.remove(pattern);
            if patterns.is_empty() {
                self.server.pubsub_client_patterns.remove(&client_id);
            }
        }
        if !self.server.pubsub_pattern_subs.contains_key(pattern) {
            self.server.store.punsubscribe(pattern);
        }
        self.pubsub_sub_count(client_id)
    }

    /// Subscribe the current client to a shard channel. Returns shard sub count.
    pub fn pubsub_ssubscribe(&mut self, channel: Vec<u8>) -> usize {
        let client_id = self.session.client_id;
        self.server.store.ssubscribe(channel.clone());
        self.server
            .pubsub_shard_subs
            .entry(channel.clone())
            .or_default()
            .insert(client_id);
        self.server
            .pubsub_client_shard_channels
            .entry(client_id)
            .or_default()
            .insert(channel);
        self.pubsub_shard_sub_count(client_id)
    }

    /// Unsubscribe the current client from a shard channel. Returns shard sub count.
    pub fn pubsub_sunsubscribe(&mut self, channel: &[u8]) -> usize {
        let client_id = self.session.client_id;
        if let Some(subs) = self.server.pubsub_shard_subs.get_mut(channel) {
            subs.remove(&client_id);
            if subs.is_empty() {
                self.server.pubsub_shard_subs.remove(channel);
            }
        }
        if let Some(channels) = self.server.pubsub_client_shard_channels.get_mut(&client_id) {
            channels.remove(channel);
            if channels.is_empty() {
                self.server.pubsub_client_shard_channels.remove(&client_id);
            }
        }
        if !self.server.pubsub_shard_subs.contains_key(channel) {
            self.server.store.sunsubscribe(channel);
        }
        self.pubsub_shard_sub_count(client_id)
    }

    /// Publish a message to a channel. Queues messages in each subscriber's
    /// outbox. Returns the number of clients that received the message.
    pub fn pubsub_publish(&mut self, channel: &[u8], message: &[u8]) -> usize {
        let mut receivers = 0;

        // Direct channel subscribers
        if let Some(client_ids) = self.server.pubsub_channel_subs.get(channel) {
            for &client_id in client_ids {
                self.server
                    .pubsub_outbox
                    .entry(client_id)
                    .or_default()
                    .push(fr_store::PubSubMessage::Message {
                        channel: channel.to_vec(),
                        data: message.to_vec(),
                    });
                receivers += 1;
            }
        }

        // Pattern subscribers — each matching pattern produces a pmessage
        // OPTIMIZATION: Avoid intermediate allocations and excessive cloning.
        for (pattern, client_ids) in &self.server.pubsub_pattern_subs {
            if fr_store::glob_match(pattern, channel) {
                for &client_id in client_ids {
                    self.server
                        .pubsub_outbox
                        .entry(client_id)
                        .or_default()
                        .push(fr_store::PubSubMessage::PMessage {
                            pattern: pattern.clone(),
                            channel: channel.to_vec(),
                            data: message.to_vec(),
                        });
                    receivers += 1;
                }
            }
        }

        receivers
    }

    /// Publish a message to a shard channel. Returns receiver count.
    pub fn pubsub_spublish(&mut self, channel: &[u8], message: &[u8]) -> usize {
        let mut receivers = 0;
        if let Some(client_ids) = self.server.pubsub_shard_subs.get(channel) {
            for &client_id in client_ids {
                self.server
                    .pubsub_outbox
                    .entry(client_id)
                    .or_default()
                    .push(fr_store::PubSubMessage::SMessage {
                        channel: channel.to_vec(),
                        data: message.to_vec(),
                    });
                receivers += 1;
            }
        }
        receivers
    }

    /// Remove all subscriptions for a client (called on disconnect).
    pub fn pubsub_cleanup_client(&mut self, client_id: u64) {
        if let Some(channels) = self.server.pubsub_client_channels.remove(&client_id) {
            for ch in channels {
                if let Some(subs) = self.server.pubsub_channel_subs.get_mut(&ch) {
                    subs.remove(&client_id);
                    if subs.is_empty() {
                        self.server.pubsub_channel_subs.remove(&ch);
                        self.server.store.unsubscribe(&ch);
                    }
                }
            }
        }
        if let Some(patterns) = self.server.pubsub_client_patterns.remove(&client_id) {
            for pat in patterns {
                if let Some(subs) = self.server.pubsub_pattern_subs.get_mut(&pat) {
                    subs.remove(&client_id);
                    if subs.is_empty() {
                        self.server.pubsub_pattern_subs.remove(&pat);
                        self.server.store.punsubscribe(&pat);
                    }
                }
            }
        }
        if let Some(shard_channels) = self.server.pubsub_client_shard_channels.remove(&client_id) {
            for ch in shard_channels {
                if let Some(subs) = self.server.pubsub_shard_subs.get_mut(&ch) {
                    subs.remove(&client_id);
                    if subs.is_empty() {
                        self.server.pubsub_shard_subs.remove(&ch);
                        self.server.store.sunsubscribe(&ch);
                    }
                }
            }
        }
        self.server.pubsub_outbox.remove(&client_id);
    }

    pub fn pubsub_sub_count(&self, client_id: u64) -> usize {
        // (frankenredis-pubsub-empty-fast) Skip both per-client hash probes when
        // no client holds any channel/pattern subscription (O(1) is_empty).
        if self.server.pubsub_client_channels.is_empty()
            && self.server.pubsub_client_patterns.is_empty()
        {
            return 0;
        }
        self.server
            .pubsub_client_channels
            .get(&client_id)
            .map_or(0, std::collections::HashSet::len)
            + self
                .server
                .pubsub_client_patterns
                .get(&client_id)
                .map_or(0, std::collections::HashSet::len)
    }

    pub fn pubsub_shard_sub_count(&self, client_id: u64) -> usize {
        // (frankenredis-pubsub-empty-fast) Skip the per-client hash probe when no
        // client holds any shard subscription (O(1) is_empty).
        if self.server.pubsub_client_shard_channels.is_empty() {
            return 0;
        }
        self.server
            .pubsub_client_shard_channels
            .get(&client_id)
            .map_or(0, std::collections::HashSet::len)
    }

    /// Returns true if a given client ID has any active pub/sub subscriptions.
    pub fn is_pubsub_client(&self, client_id: u64) -> bool {
        // (frankenredis-pubsub-empty-fast) O(1) global short-circuit: when no
        // client anywhere holds a channel/pattern/shard subscription, this
        // client cannot be a pub/sub client. Skips up to three per-client
        // HashMap hash+probes on the per-command hot path (profiled ~4-7% of
        // GET/SET CPU via effective_output_hard_limit) for the overwhelmingly
        // common no-subscriber workload. Byte-identical: every empty map yields
        // the same `false` through the slow path below.
        if self.server.pubsub_client_channels.is_empty()
            && self.server.pubsub_client_patterns.is_empty()
            && self.server.pubsub_client_shard_channels.is_empty()
        {
            return false;
        }
        self.pubsub_sub_count(client_id) > 0
            || self
                .server
                .pubsub_client_patterns
                .get(&client_id)
                .is_some_and(|patterns| !patterns.is_empty())
            || self.pubsub_shard_sub_count(client_id) > 0
    }

    /// Returns true if the current client has any active pub/sub subscriptions.
    pub fn is_in_subscription_mode(&self) -> bool {
        if self.server.pubsub_client_channels.is_empty()
            && self.server.pubsub_client_patterns.is_empty()
            && self.server.pubsub_client_shard_channels.is_empty()
        {
            return false;
        }
        self.is_pubsub_client(self.session.client_id)
    }

    fn pubsub_frame_for_protocol(resp_protocol_version: i64, items: Vec<RespFrame>) -> RespFrame {
        if resp_protocol_version == 3 {
            RespFrame::Push(items)
        } else {
            RespFrame::Array(Some(items))
        }
    }

    fn current_pubsub_frame(&self, items: Vec<RespFrame>) -> RespFrame {
        Self::pubsub_frame_for_protocol(self.session.resp_protocol_version, items)
    }

    fn current_pubsub_sequence(&self, mut replies: Vec<RespFrame>) -> RespFrame {
        if replies.len() == 1 {
            replies.pop().unwrap_or(RespFrame::BulkString(None))
        } else {
            RespFrame::Sequence(replies)
        }
    }

    fn current_pubsub_reply(
        &self,
        kind: &'static [u8],
        channel: Option<Vec<u8>>,
        count: usize,
    ) -> RespFrame {
        self.current_pubsub_frame(vec![
            RespFrame::BulkString(Some(kind.to_vec())),
            RespFrame::BulkString(channel),
            RespFrame::Integer(count as i64),
        ])
    }

    fn tracking_key_matches_prefixes(key: &[u8], tracking: &ClientTrackingState) -> bool {
        tracking.prefixes.is_empty()
            || tracking
                .prefixes
                .iter()
                .any(|prefix| key.starts_with(prefix))
    }

    fn add_tracking_invalidation(
        invalidations: &mut BTreeMap<u64, Vec<Vec<u8>>>,
        target_id: u64,
        key: &[u8],
    ) {
        // (frankenredis-b8z6y) Push unconditionally; the caller dedups once
        // (O(K)) at flush time. The old per-add `iter().any(== key)` rescan made
        // building a K-key invalidation list O(K^2).
        invalidations
            .entry(target_id)
            .or_default()
            .push(key.to_vec());
    }

    fn refresh_client_tracking_bcast_membership(
        &mut self,
        client_id: u64,
        tracking: &ClientTrackingState,
    ) {
        if tracking.enabled && tracking.bcast {
            self.server.client_tracking_bcast_clients.insert(client_id);
        } else {
            self.server.client_tracking_bcast_clients.remove(&client_id);
        }
    }

    fn queue_client_tracking_invalidations(&mut self, keys: &[Vec<u8>]) {
        if keys.is_empty() {
            return;
        }
        if self.server.client_tracking_observed_keys.is_empty()
            && self.server.client_tracking_bcast_clients.is_empty()
        {
            return;
        }

        let observed_keys: Vec<(Vec<u8>, HashSet<u64, foldhash::quality::RandomState>)> = keys
            .iter()
            .filter_map(|key| {
                self.server
                    .client_tracking_observed_keys
                    .remove(key)
                    .map(|owners| (key.clone(), owners))
            })
            .collect();
        // BCAST clients: upstream batches every matching key modified by the
        // command into a SINGLE invalidate message per target (one flush per
        // command via trackingHandlePendingKeyInvalidations).
        let mut bcast_invalidations: BTreeMap<u64, Vec<Vec<u8>>> = BTreeMap::new();
        if !self.server.client_tracking_bcast_clients.is_empty() {
            let bcast_owner_ids: Vec<u64> = self
                .server
                .client_tracking_bcast_clients
                .iter()
                .copied()
                .collect();
            for owner_id in bcast_owner_ids {
                let Some(session) = self.client_session_including_current(owner_id) else {
                    self.server.client_tracking_bcast_clients.remove(&owner_id);
                    continue;
                };
                let tracking = &session.client_tracking;
                if !tracking.enabled || !tracking.bcast {
                    self.server.client_tracking_bcast_clients.remove(&owner_id);
                    continue;
                }
                if tracking.noloop && owner_id == self.session.client_id {
                    continue;
                }

                let target_id = tracking.redirect.unwrap_or(owner_id);
                if !self.client_session_exists_including_current(target_id) {
                    continue;
                }

                for key in keys {
                    if Self::tracking_key_matches_prefixes(key, tracking) {
                        Self::add_tracking_invalidation(&mut bcast_invalidations, target_id, key);
                    }
                }
            }
        }
        for (target_id, keys) in bcast_invalidations {
            let keys = dedup_keys_preserve_order(keys);
            if !keys.is_empty() {
                self.server
                    .pubsub_outbox
                    .entry(target_id)
                    .or_default()
                    .push(fr_store::PubSubMessage::Invalidate { keys });
            }
        }

        // Non-BCAST (default / OPTIN / OPTOUT) clients: upstream
        // trackingInvalidateKey fires PER KEY as each key is modified, so every
        // invalidated key produces its OWN invalidate push (a single-key
        // message), in key-modification order — NOT one batched message.
        // (frankenredis-8ypwc)
        for (key, owner_ids) in observed_keys {
            let mut targets: Vec<u64> = Vec::new();
            for owner_id in owner_ids {
                let Some(session) = self.client_session_including_current(owner_id) else {
                    continue;
                };
                let tracking = &session.client_tracking;
                if !tracking.enabled || tracking.bcast {
                    continue;
                }
                if tracking.noloop && owner_id == self.session.client_id {
                    continue;
                }
                let target_id = tracking.redirect.unwrap_or(owner_id);
                if self.client_session_exists_including_current(target_id) {
                    targets.push(target_id);
                }
            }
            // The owner set's iteration order is unspecified; sort so multi-
            // observer output is deterministic. One message per caching client,
            // matching upstream's per-client send.
            targets.sort_unstable();
            for target_id in targets {
                self.server
                    .pubsub_outbox
                    .entry(target_id)
                    .or_default()
                    .push(fr_store::PubSubMessage::Invalidate {
                        keys: vec![key.clone()],
                    });
            }
        }
    }

    /// Send a flush-all client-tracking invalidation. Upstream
    /// db.c::signalFlushedDb → trackingInvalidateKeysOnFlush emits a single
    /// `invalidate` push carrying a NULL payload to every tracking client when
    /// the keyspace is flushed (FLUSHALL/FLUSHDB), telling each one to evict
    /// its entire client-side cache. fr previously emitted nothing, leaving a
    /// tracking client with stale cached entries after a flush.
    /// (frankenredis-o90ga)
    ///
    /// The NULL payload is carried as an `Invalidate` with an EMPTY key vector
    /// — a value the per-key path never produces (it guards `!keys.is_empty()`)
    /// — which the frame encoder renders as `invalidate` + RESP3 null.
    fn queue_client_tracking_flush_invalidation(&mut self) {
        let mut targets: std::collections::BTreeSet<u64> = std::collections::BTreeSet::new();
        for (owner_id, session) in self
            .server
            .client_sessions
            .iter()
            .filter(|(owner_id, _)| **owner_id != self.session.client_id)
            .chain(std::iter::once((&self.session.client_id, &self.session)))
        {
            let tracking = &session.client_tracking;
            if !tracking.enabled {
                continue;
            }
            // A NOLOOP client that issued the flush does not get its own
            // invalidation (mirrors trackingInvalidateKey's current_client skip).
            if tracking.noloop && *owner_id == self.session.client_id {
                continue;
            }
            let target_id = tracking.redirect.unwrap_or(*owner_id);
            if self.client_session_exists_including_current(target_id) {
                targets.insert(target_id);
            }
        }
        for target_id in targets {
            self.server
                .pubsub_outbox
                .entry(target_id)
                .or_default()
                .push(fr_store::PubSubMessage::Invalidate { keys: Vec::new() });
        }
        // Every key is gone; drop the observed-keys table so no stale per-key
        // invalidation can later fire for a key that no longer exists.
        self.server.client_tracking_observed_keys.clear();
    }

    fn client_session_exists_including_current(&self, client_id: u64) -> bool {
        client_id == self.session.client_id || self.server.client_sessions.contains_key(&client_id)
    }

    fn client_session_including_current(&self, client_id: u64) -> Option<&ClientSession> {
        if client_id == self.session.client_id {
            Some(&self.session)
        } else {
            self.server.client_sessions.get(&client_id)
        }
    }

    fn should_record_client_tracking_keys(&self) -> bool {
        let tracking = &self.session.client_tracking;
        tracking.enabled
            && !tracking.bcast
            && if tracking.optin {
                tracking.caching == Some(true)
            } else if tracking.optout {
                tracking.caching != Some(false)
            } else {
                true
            }
    }

    fn record_client_tracking_keys(&mut self, keys: &[Vec<u8>]) {
        if keys.is_empty() || !self.should_record_client_tracking_keys() {
            return;
        }
        let client_id = self.session.client_id;
        for key in keys {
            self.server
                .client_tracking_observed_keys
                .entry(key.clone())
                .or_default()
                .insert(client_id);
        }
    }

    fn remove_client_tracking_observer(&mut self, client_id: u64) {
        self.server
            .client_tracking_observed_keys
            .retain(|_, observers| {
                observers.remove(&client_id);
                !observers.is_empty()
            });
    }

    fn pubsub_context_error(command_name: &str) -> RespFrame {
        RespFrame::Error(format!(
            "ERR Can't execute '{}': only (P|S)SUBSCRIBE / (P|S)UNSUBSCRIBE / PING / QUIT / RESET are allowed in this context",
            command_name
        ))
    }

    fn pubsub_blocked_command_name(argv: &[Vec<u8>]) -> String {
        // (frankenredis-gcll9) Mirror upstream server.c: the
        // subscribe-context error wording uses c->cmd->fullname,
        // which for any container subcommand is "parent|sub". fr
        // previously namespaced only PUBSUB; CLIENT/CONFIG/etc.
        // surfaced just the bare parent name and broke parity for
        // common monitoring tools that grep the error wording.
        canonical_command_fullname(argv)
    }

    fn pubsub_command_allowed_in_subscription_mode(
        special_command: Option<RuntimeSpecialCommand>,
        argv: &[Vec<u8>],
    ) -> bool {
        // Mirrors upstream server.c::processCommand:4067-4082 allow list:
        // pingCommand, (s|p)subscribeCommand, (s|p)unsubscribeCommand,
        // quitCommand, resetCommand. Note PUBSUB-the-command is NOT in
        // upstream's allow list — RESP2 subscribers cannot query pubsub
        // state without opening a separate connection. The RESP3 bypass
        // (any command allowed) is enforced one level up in execute_frame
        // by checking resp_protocol_version. (frankenredis-dddxp)
        matches!(
            special_command,
            Some(RuntimeSpecialCommand::Subscribe)
                | Some(RuntimeSpecialCommand::Unsubscribe)
                | Some(RuntimeSpecialCommand::Psubscribe)
                | Some(RuntimeSpecialCommand::Punsubscribe)
                | Some(RuntimeSpecialCommand::Ssubscribe)
                | Some(RuntimeSpecialCommand::Sunsubscribe)
                | Some(RuntimeSpecialCommand::Quit)
                | Some(RuntimeSpecialCommand::Reset)
        ) || argv
            .first()
            .is_some_and(|command| eq_ascii_token(command, b"PING"))
    }

    pub fn configure_maxmemory_enforcement(
        &mut self,
        maxmemory_bytes: usize,
        not_counted_bytes: usize,
        sample_limit: usize,
        max_cycles: usize,
    ) {
        self.server.configure_maxmemory_enforcement(
            maxmemory_bytes,
            not_counted_bytes,
            sample_limit,
            max_cycles,
        );
    }

    pub fn set_eviction_safety_gate(&mut self, safety_gate: EvictionSafetyGateState) {
        self.server.set_eviction_safety_gate(safety_gate);
    }

    #[must_use]
    pub fn maxmemory_pressure_state(&self) -> fr_store::MaxmemoryPressureState {
        self.server.maxmemory_pressure_state()
    }

    #[must_use]
    pub fn last_eviction_loop_result(&self) -> Option<EvictionLoopResult> {
        self.server.last_eviction_loop_result()
    }

    pub fn set_requirepass(&mut self, requirepass: Option<Vec<u8>>) {
        self.apply_requirepass_update(requirepass, false);
    }

    /// Per-command refresh of the O(1) runtime→store scalar mirrors that INFO
    /// (and a couple of tests) expect to be live immediately after the mutating
    /// command (e.g. `maxmemory_bytes_live` right after CONFIG SET maxmemory).
    /// The EXPENSIVE O(n) INFO aggregates moved to `refresh_store_info_aggregates`
    /// (lazy, INFO-only) — see (frankenredis-infolazy).
    fn refresh_store_runtime_info_context(&mut self) {
        self.server.store.maxmemory_bytes_live = self.server.maxmemory_bytes;
        self.server.store.rdb_bgsave_in_progress = self.server.rdb_bgsave_pid.is_some();
        self.server.store.rdb_bgsave_start_time_sec = self.server.rdb_bgsave_start_time_sec;
        self.server.store.aof_rewrite_in_progress = self.server.aof_rewrite_pid.is_some();
        self.server.store.aof_rewrite_start_time_sec = self.server.aof_rewrite_start_time_sec;
        self.server.store.aof_rewrite_scheduled = self.server.aof_rewrite_scheduled;
    }

    /// (frankenredis-infolazy) The O(n) INFO-only store aggregates: client-
    /// tracking stats (a scan over EVERY client session + the observed-key map)
    /// and the replication-backlog memory estimate (a scan over EVERY buffered
    /// AOF record, summing argv byte lengths). These fields are consumed ONLY by
    /// the INFO `stats` / `memory` section builders, so computing them on every
    /// command — O(clients + tracked_keys + backlog_bytes) per command — was pure
    /// per-command waste (the borrowed fast paths already skip it). Refresh them
    /// lazily, only when INFO actually needs the relevant section. Mirrors the
    /// `refresh_client_memory_aggregates` laziness shipped in zfu61.
    fn refresh_store_info_aggregates(&mut self) {
        // Count every OTHER client from the registry, then the current session
        // authoritatively. At this lazy (INFO-time) call the active session has
        // already been synced into `client_sessions`, so it must be excluded from
        // the registry scan to avoid double-counting (the previous per-command
        // call ran before that sync). (frankenredis-infolazy)
        let current_id = self.session.client_id;
        let mut tracking_clients: u64 = 0;
        let mut total_prefixes: usize = 0;
        for (id, session) in &self.server.client_sessions {
            if *id == current_id {
                continue;
            }
            if session.client_tracking.enabled {
                tracking_clients += 1;
                total_prefixes += session.client_tracking.prefixes.len();
            }
        }
        if self.session.client_tracking.enabled {
            tracking_clients += 1;
            total_prefixes += self.session.client_tracking.prefixes.len();
        }
        self.server.store.stat_tracking_clients = tracking_clients;
        self.server.store.stat_tracking_total_keys =
            self.server.client_tracking_observed_keys.len();
        self.server.store.stat_tracking_total_items = self
            .server
            .client_tracking_observed_keys
            .values()
            .map(|observers| observers.len())
            .sum();
        self.server.store.stat_tracking_total_prefixes = total_prefixes;
        // Replication backlog memory usage from the aof_records buffer. Each
        // AofRecord holds a Vec<Vec<u8>> for the command argv.
        self.server.store.mem_replication_backlog = self
            .server
            .aof_records
            .iter()
            .map(|record| {
                std::mem::size_of::<fr_persist::AofRecord>()
                    + record
                        .argv
                        .iter()
                        .map(|arg| arg.len() + std::mem::size_of::<Vec<u8>>())
                        .sum::<usize>()
            })
            .sum();
    }

    pub fn add_user(&mut self, username: Vec<u8>, password: Vec<u8>) {
        self.server.auth_state.add_user(username, password);
        self.session
            .refresh_authentication_for_server(&self.server.auth_state, false);
    }

    #[must_use]
    pub fn is_authenticated(&self) -> bool {
        self.session.is_authenticated()
    }

    fn acl_permission_error(&self, argv: &[Vec<u8>]) -> Option<AclCommandPermissionError> {
        let username = self.session.current_user_name();
        let Some(user) = self.server.auth_state.get_user(username) else {
            // User was deleted while session is still active. In Redis, the
            // connection would be killed asynchronously. For compatibility
            // in single-session mode, allow continued access.
            return None;
        };

        user.acl_permission_error_for_argv(argv)
    }

    #[must_use]
    pub fn is_cluster_read_only(&self) -> bool {
        self.session.cluster_state.mode == ClusterClientMode::ReadOnly
    }

    #[must_use]
    pub fn parser_config(&self) -> fr_protocol::ParserConfig {
        fr_protocol::ParserConfig {
            max_bulk_len: self
                .policy
                .gate
                .max_bulk_len
                .min(self.server.proto_max_bulk_len),
            max_array_len: self.policy.gate.max_array_len,
            max_recursion_depth: 128,
            // Server-side parsing of CLIENT → SERVER command frames
            // stays RESP2-only; the RESP3 downgrade helpers are
            // reserved for trusted client-side replies (live-oracle
            // harness). (br-frankenredis-ozcx)
            ..fr_protocol::ParserConfig::default()
        }
    }

    #[must_use]
    pub fn is_cluster_asking(&self) -> bool {
        self.session.cluster_state.asking
    }

