    fn apply_requirepass_update(
        &mut self,
        requirepass: Option<Vec<u8>>,
        preserve_authenticated_user: bool,
    ) {
        self.server.auth_state.set_requirepass(requirepass);
        self.session.refresh_authentication_for_server(
            &self.server.auth_state,
            preserve_authenticated_user,
        );
    }

    fn apply_masteruser_update(&mut self, masteruser: Option<Vec<u8>>) {
        let changed = self.server.masteruser != masteruser;
        self.server.masteruser = masteruser;
        if changed
            && let ReplicationRoleState::Replica { state, .. } =
                &mut self.server.replication_runtime_state.role
        {
            *state = "connecting";
            self.server.replica_reconfigure_requested = true;
        }
    }

    fn apply_masterauth_update(&mut self, masterauth: Option<Vec<u8>>) {
        let changed = self.server.masterauth != masterauth;
        self.server.masterauth = masterauth;
        if changed
            && let ReplicationRoleState::Replica { state, .. } =
                &mut self.server.replication_runtime_state.role
        {
            *state = "connecting";
            self.server.replica_reconfigure_requested = true;
        }
    }

    pub fn set_masteruser(&mut self, masteruser: Option<Vec<u8>>) {
        self.apply_masteruser_update(masteruser);
    }

    pub fn set_masterauth(&mut self, masterauth: Option<Vec<u8>>) {
        self.apply_masterauth_update(masterauth);
    }

    pub fn apply_tls_config(
        &mut self,
        candidate: TlsConfig,
        now_ms: u64,
    ) -> Result<(), TlsCfgError> {
        let packet_id = next_packet_id();
        // Render candidate to debug bytes only once; passed into the threat
        // recorder lazily so the success path stays free of digest cost.
        let candidate_debug = format!("{candidate:?}").into_bytes();

        let plan = match plan_tls_runtime_apply(&self.server.tls_state, candidate) {
            Ok(plan) => plan,
            Err(error) => {
                let preferred_deviation = preferred_tls_deviation_for_error(&error);
                let gated_error = self.gate_tls_error_for_mode(error, preferred_deviation);
                self.record_tls_config_event(
                    now_ms,
                    packet_id,
                    candidate_debug,
                    &gated_error,
                    preferred_deviation,
                );
                return Err(gated_error);
            }
        };

        let mut next_state = self.server.tls_state.clone();
        match plan.listener_transition {
            TlsListenerTransition::Enable => next_state.tls_listener_enabled = true,
            TlsListenerTransition::Disable => next_state.tls_listener_enabled = false,
            TlsListenerTransition::Keep => {}
        }
        if plan.requires_context_swap {
            next_state.active_config = if plan.candidate_config.tls_enabled() {
                Some(plan.candidate_config.clone())
            } else {
                None
            };
        }
        if plan.requires_connection_type_configure {
            next_state.connection_type_configured = true;
        }
        self.server.tls_state = next_state;
        Ok(())
    }

    /// Check and reap any completed background child processes.
    #[allow(unsafe_code)]
    pub fn check_child_processes(&mut self, now_ms: u64) {
        #[cfg(unix)]
        unsafe {
            if let Some(pid) = self.server.rdb_bgsave_pid {
                let mut status = 0;
                let res = libc::waitpid(pid, &mut status, libc::WNOHANG);
                // res == pid: child exited (success = exited cleanly with code 0;
                // a signal-killed child is WIFEXITED-false → failure). res == 0:
                // still running, leave state. res < 0 with ECHILD: the child is
                // gone/unwaitable — e.g. auto-reaped because SIGCHLD was inherited
                // as SIG_IGN — so clear the pid (treating it as a failed save) to
                // avoid a permanently stuck "Background save already in progress".
                // (frankenredis-bgreap) EINTR/other -1 is left to retry next tick.
                let child_gone =
                    res < 0 && std::io::Error::last_os_error().raw_os_error() == Some(libc::ECHILD);
                if res == pid || child_gone {
                    self.server.rdb_bgsave_pid = None;
                    self.server.rdb_bgsave_start_time_sec = None;
                    let success =
                        res == pid && libc::WIFEXITED(status) && libc::WEXITSTATUS(status) == 0;
                    self.server.store.record_bgsave_status(success);
                }
            }
            if let Some(pid) = self.server.aof_rewrite_pid {
                let mut status = 0;
                let res = libc::waitpid(pid, &mut status, libc::WNOHANG);
                // (frankenredis-bgreap) Same ECHILD-clears-stuck-state handling as
                // the bgsave branch above.
                let child_gone =
                    res < 0 && std::io::Error::last_os_error().raw_os_error() == Some(libc::ECHILD);
                if res == pid || child_gone {
                    self.server.aof_rewrite_pid = None;
                    self.server.aof_rewrite_start_time_sec = None;
                    let success =
                        res == pid && libc::WIFEXITED(status) && libc::WEXITSTATUS(status) == 0;
                    self.server.store.record_aof_bgrewrite_status(success);
                }
            }
        }
        self.maybe_run_scheduled_aof_rewrite(now_ms);
    }

    /// Wait for child processes to finish (useful for tests).
    #[allow(unsafe_code)]
    pub fn wait_for_child_processes(&mut self) {
        #[cfg(unix)]
        unsafe {
            if let Some(pid) = self.server.rdb_bgsave_pid {
                let mut status = 0;
                libc::waitpid(pid, &mut status, 0); // Blocking wait
                self.server.rdb_bgsave_pid = None;
                self.server.rdb_bgsave_start_time_sec = None;
                let success = libc::WIFEXITED(status) && libc::WEXITSTATUS(status) == 0;
                self.server.store.record_bgsave_status(success);
            }
            if let Some(pid) = self.server.aof_rewrite_pid {
                let mut status = 0;
                libc::waitpid(pid, &mut status, 0); // Blocking wait
                self.server.aof_rewrite_pid = None;
                self.server.aof_rewrite_start_time_sec = None;
                let success = libc::WIFEXITED(status) && libc::WEXITSTATUS(status) == 0;
                self.server.store.record_aof_bgrewrite_status(success);
            }
        }
        self.maybe_run_scheduled_aof_rewrite(0);
    }

    fn maybe_run_scheduled_aof_rewrite(&mut self, now_ms: u64) {
        if !self.server.aof_rewrite_scheduled
            || self.server.rdb_bgsave_pid.is_some()
            || self.server.aof_rewrite_pid.is_some()
        {
            return;
        }
        let _ = self.handle_bgrewriteaof_requested(now_ms);
    }

    /// Run `f` with `self.session` temporarily swapped for a fresh
    /// one, then restore the prior session regardless of the result.
    /// Used by the differential conformance harness to emulate a
    /// fresh TCP connection for connection-mode commands (AUTH,
    /// HELLO, SELECT, RESET, …) while keeping the shared ACL
    /// subsystem and keyspace intact — matching the behaviour of a
    /// new connection against the persistent vendored oracle.
    /// (br-frankenredis-faqe)
    pub fn with_isolated_session<F, R>(&mut self, f: F) -> R
    where
        F: FnOnce(&mut Runtime) -> R,
    {
        // Allocate a unique client_id for the isolated session so any
        // server-shared per-client state mutated by the wrapped command
        // (replication_runtime_state.replicas, client_sessions, pubsub
        // tables, ...) doesn't collide with the saved session's id when
        // both happen to default to 0. (frankenredis-isosessionid)
        static ISOLATED_CLIENT_ID_COUNTER: std::sync::atomic::AtomicU64 =
            std::sync::atomic::AtomicU64::new(0);
        let isolated_id = u64::MAX
            - ISOLATED_CLIENT_ID_COUNTER.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
        let saved = std::mem::take(&mut self.session);
        self.session.client_id = isolated_id;
        let result = f(self);
        // Drop any per-client residue the isolated session left behind,
        // mirroring TCP-side cleanup_disconnected_client semantics so
        // state doesn't leak between cases.
        self.cleanup_disconnected_client(isolated_id);
        self.session = saved;
        result
    }

    pub fn execute_frame(&mut self, frame: RespFrame, now_ms: u64) -> RespFrame {
        // Owned-frame callers (conformance, internal) keep passing the frame so
        // its exact wire structure feeds the threat-evidence digests verbatim.
        self.execute_frame_ref(&frame, now_ms)
    }

    /// Execute a retained frame without cloning its nested RESP payload.
    ///
    /// Online replica replay keeps the parsed frame for diagnostics and `REPLCONF GETACK`
    /// classification after dispatch, so borrowing avoids an otherwise redundant deep clone.
    #[cfg_attr(feature = "bench-reference", inline(never))]
    pub fn execute_frame_ref(&mut self, frame: &RespFrame, now_ms: u64) -> RespFrame {
        let argv_result = frame_to_argv(frame);
        self.execute_dispatch(
            Some(frame),
            argv_result
                .as_deref()
                .map_err(|_| CommandError::InvalidCommandFrame),
            now_ms,
            None,
        )
    }

    pub fn execute_frame_with_unix_time_us(
        &mut self,
        frame: &RespFrame,
        now_ms: u64,
        unix_time_us: u64,
    ) -> RespFrame {
        let argv_result = frame_to_argv(frame);
        self.execute_dispatch(
            Some(frame),
            argv_result
                .as_deref()
                .map_err(|_| CommandError::InvalidCommandFrame),
            now_ms,
            Some(unix_time_us),
        )
    }

    /// Hot-path entry for the network server. `argv` has already been MOVED out
    /// of the parsed command frame (one allocation per argument total, vs the
    /// frame-based path which clones every argument a second time). The original
    /// frame is not retained; the cold preflight/threat-evidence paths
    /// reconstruct a byte-identical `RespFrame::Array(BulkString)` from argv on
    /// demand, so digests stay exact while the hot success path never
    /// materializes a frame. Wire commands are always multibulk-of-bulkstrings,
    /// so the reconstruction is the exact inverse of the parse.
    /// (frankenredis-8yfmt)
    pub fn execute_argv_with_unix_time_us(
        &mut self,
        argv: &[Vec<u8>],
        now_ms: u64,
        unix_time_us: u64,
    ) -> RespFrame {
        self.execute_dispatch(None, Ok(argv), now_ms, Some(unix_time_us))
    }

    pub fn execute_plain_set_borrowed(
        &mut self,
        key: &[u8],
        value: &[u8],
        now_ms: u64,
    ) -> Option<RespFrame> {
        self.execute_plain_set_borrowed_ok(key, value, now_ms)
            .map(|()| RespFrame::SimpleString("OK".to_string()))
    }

    /// (BlackThrush) Non-allocating twin of [`Self::execute_plain_set_borrowed`]:
    /// runs the identical borrowed plain-SET write but reports success as `Some(())`
    /// so the dispatcher can emit the constant `+OK\r\n` straight into the connection
    /// buffer (via `BorrowedMultibulkAction::FastOkReply`) instead of heap-allocating
    /// a `SimpleString("OK")` reply frame on every SET. `None` means the borrowed fast
    /// path declined and the caller must fall back to the generic argv path, exactly
    /// as before.
    pub fn execute_plain_set_borrowed_ok(
        &mut self,
        key: &[u8],
        value: &[u8],
        now_ms: u64,
    ) -> Option<()> {
        let default_write_allowed = self.plain_borrowed_default_key_write_allows(now_ms);
        self.execute_plain_set_borrowed_with_default_write_gate(
            key,
            value,
            now_ms,
            default_write_allowed,
        )
    }

    pub fn execute_plain_set_borrowed_with_default_write_gate(
        &mut self,
        key: &[u8],
        value: &[u8],
        now_ms: u64,
        default_write_allowed: bool,
    ) -> Option<()> {
        if !self.can_execute_plain_set_borrowed_with_default_write_gate(
            key,
            value,
            default_write_allowed,
        ) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("set");
        self.session.last_argv_len_sum = b"SET".len() + key.len() + value.len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        self.server.store.set_plain_borrowed(key, value, now_ms);
        let elapsed_us = self.finish_chained_command(start);

        self.record_plain_set_borrowed_metrics(
            key, value, None, false, elapsed_us, now_ms, packet_id,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        Some(())
    }

    /// (BlackThrush) Borrowed WRITE fast path for `SET key value KEEPTTL` — the one
    /// difference from plain SET is that any existing TTL is preserved instead of
    /// cleared. Mirrors fr_command's `ExpiryMode::KeepTtl` arm exactly through the
    /// fused borrowed store specialization. The parser only
    /// matches *4 with a literal KEEPTTL token; KEEPTTL GET / NX KEEPTTL / any other
    /// shape is *5+ and falls through to the generic. Gated identically to plain SET.
    pub fn execute_plain_set_keepttl_borrowed(
        &mut self,
        key: &[u8],
        value: &[u8],
        now_ms: u64,
        default_write_allowed: bool,
    ) -> Option<RespFrame> {
        self.execute_plain_set_keepttl_borrowed_ok(key, value, now_ms, default_write_allowed)
            .map(|()| RespFrame::SimpleString("OK".to_string()))
    }

    /// (BlackThrush) Non-allocating twin of [`Self::execute_plain_set_keepttl_borrowed`]:
    /// runs the identical borrowed `SET key value KEEPTTL` write but reports success as
    /// `Some(())` so the dispatcher can emit the constant `+OK\r\n` straight into the connection
    /// buffer (via `BorrowedMultibulkAction::FastOkReply`) instead of heap-allocating a
    /// `SimpleString("OK")` reply frame. `None` means the borrowed fast path declined.
    pub fn execute_plain_set_keepttl_borrowed_ok(
        &mut self,
        key: &[u8],
        value: &[u8],
        now_ms: u64,
        default_write_allowed: bool,
    ) -> Option<()> {
        if !self.can_execute_plain_set_borrowed_with_default_write_gate(
            key,
            value,
            default_write_allowed,
        ) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("set");
        self.session.last_argv_len_sum = b"SET".len() + key.len() + value.len() + b"KEEPTTL".len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        self.server.store.set_keep_ttl_borrowed(key, value, now_ms);
        let elapsed_us = self.finish_chained_command(start);

        self.record_plain_set_borrowed_metrics(
            key,
            value,
            Some(b"KEEPTTL"),
            false,
            elapsed_us,
            now_ms,
            packet_id,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        Some(())
    }

    /// (BlackThrush) Borrowed WRITE fast path for `SET key value GET` (no NX/XX/
    /// expiry). Mirrors the generic set's COMMAND_GET arm: read the old value FIRST
    /// via store.get (which records the keyspace hit/miss exactly like the generic's
    /// `old_value = store.get(..)?`, and surfaces WRONGTYPE on a non-string key
    /// WITHOUT writing), then — only when the read succeeded — store the new value
    /// with plain-SET semantics (TTL cleared) and reply the old value (nil if it was
    /// absent). SET..GET with NX/XX/KEEPTTL/expiry is *5+ and falls through.
    pub fn execute_plain_set_get_borrowed(
        &mut self,
        key: &[u8],
        value: &[u8],
        now_ms: u64,
        default_write_allowed: bool,
    ) -> Option<RespFrame> {
        if !self.can_execute_plain_set_borrowed_with_default_write_gate(
            key,
            value,
            default_write_allowed,
        ) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("set");
        self.session.last_argv_len_sum = b"SET".len() + key.len() + value.len() + b"GET".len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        // Read old value first (records the hit/miss + WRONGTYPE) exactly like the
        // generic; only write when the key holds a string (or is absent).
        let reply = match self.server.store.get(key, now_ms) {
            Ok(old) => {
                self.server.store.set_plain_borrowed(key, value, now_ms);
                RespFrame::BulkString(old)
            }
            Err(err) => CommandError::Store(err).to_resp(),
        };
        let elapsed_us = self.finish_chained_command(start);
        let failed = matches!(reply, RespFrame::Error(_));

        self.record_plain_set_borrowed_metrics(
            key,
            value,
            Some(b"GET"),
            failed,
            elapsed_us,
            now_ms,
            packet_id,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        self.account_plain_borrowed_error_reply(&reply);
        Some(reply)
    }

    /// (frankenredis-setoptget) Borrowed WRITE fast path for `SET key value OPT GET`
    /// where OPT ∈ {NX, XX, KEEPTTL} (*5). Plain SET-GET is fast, but GET combined
    /// with one option fell to the generic argv path (measured NX+GET 0.50x, XX+GET
    /// 0.62x, KEEPTTL+GET 0.71x). Like the generic setGenericCommand with OBJ_SET_GET:
    /// read the old value FIRST (records the hit/miss, surfaces WRONGTYPE on a
    /// non-string key WITHOUT writing), then apply the option's set/abort:
    ///   NX      -> set only when the key is absent (old.is_none())
    ///   XX      -> set only when the key already exists (old.is_some())
    ///   KEEPTTL -> always set, preserving the existing absolute expiry
    /// and reply the old value (nil if absent). Reuses store.get / set_plain_borrowed
    /// / get_expires_at_ms / set_with_abs_expiry (NO new store code). `opt` is the
    /// exact NX/XX/KEEPTTL token (already validated by the parser).
    pub fn execute_plain_set_opt_get_borrowed(
        &mut self,
        key: &[u8],
        value: &[u8],
        opt: &[u8],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if self.policy.gate.max_array_len < 5
            || self.policy.gate.max_bulk_len < b"SET".len()
            || key.len() > self.policy.gate.max_bulk_len
            || value.len() > self.policy.gate.max_bulk_len
        {
            return None;
        }
        let is_nx = opt.eq_ignore_ascii_case(b"NX");
        let is_xx = opt.eq_ignore_ascii_case(b"XX");
        let is_keepttl = opt.eq_ignore_ascii_case(b"KEEPTTL");
        if !(is_nx || is_xx || is_keepttl) {
            return None;
        }
        if !self.plain_borrowed_default_key_write_allows(now_ms) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("set");
        self.session.last_argv_len_sum =
            b"SET".len() + key.len() + value.len() + opt.len() + b"GET".len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        // KEEPTTL+GET can share the read and TTL-preserving overwrite lookup, moving the old
        // value directly into the reply. NX/XX keep their conditional read-then-maybe-write path.
        let reply = if is_keepttl {
            match self
                .server
                .store
                .set_keep_ttl_get_borrowed(key, value, now_ms)
            {
                Ok(old) => RespFrame::BulkString(old),
                Err(err) => CommandError::Store(err).to_resp(),
            }
        } else {
            match self.server.store.get(key, now_ms) {
                Ok(old) => {
                    if (is_nx && old.is_none()) || (is_xx && old.is_some()) {
                        self.server.store.set_plain_borrowed(key, value, now_ms);
                    }
                    RespFrame::BulkString(old)
                }
                Err(err) => CommandError::Store(err).to_resp(),
            }
        };
        let elapsed_us = self.finish_chained_command(start);
        let failed = matches!(reply, RespFrame::Error(_));

        self.record_plain_set_opt_get_borrowed_metrics(
            opt, key, value, failed, elapsed_us, now_ms, packet_id,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        self.account_plain_borrowed_error_reply(&reply);
        Some(reply)
    }

    #[allow(clippy::too_many_arguments)]
    fn record_plain_set_opt_get_borrowed_metrics(
        &mut self,
        opt: &[u8],
        key: &[u8],
        value: &[u8],
        failed: bool,
        elapsed_us: u64,
        now_ms: u64,
        packet_id: u64,
    ) {
        let mut argv: Option<Vec<Vec<u8>>> = None;
        let build = || {
            vec![
                b"SET".to_vec(),
                key.to_vec(),
                value.to_vec(),
                opt.to_vec(),
                b"GET".to_vec(),
            ]
        };
        if self.server.store.slowlog_log_slower_than_us >= 0
            && (elapsed_us as i64) >= self.server.store.slowlog_log_slower_than_us
        {
            let argv_ref = argv.get_or_insert_with(build);
            self.record_slowlog(argv_ref, elapsed_us, now_ms);
        }

        let threshold_ms = self.server.store.latency_tracker.threshold_ms;
        let duration_ms = elapsed_us.div_ceil(1000);
        if threshold_ms != 0 && duration_ms > threshold_ms {
            let argv_ref = argv.get_or_insert_with(build);
            self.server
                .record_latency_sample(argv_ref, elapsed_us, now_ms);
        }

        if self.server.latency_tracking {
            let kind = if failed {
                CommandRecordKind::Failed
            } else {
                CommandRecordKind::Success
            };
            self.server
                .store
                .record_command_histogram_canonical_with_kind("set", elapsed_us, kind);
        }

        if elapsed_us > (self.server.command_time_budget_ms * 1000) {
            let argv_ref = argv.get_or_insert_with(build);
            self.record_threat_event(ThreatEventInput {
                now_ms,
                packet_id,
                threat_class: ThreatClass::ResourceExhaustion,
                preferred_deviation: Some(HardenedDeviationCategory::ResourceClamp),
                subsystem: "router",
                action: "slow_command_detected",
                reason_code: "command_time_budget_exceeded",
                reason: format!(
                    "command 'SET' took {elapsed_us}us, exceeding budget {}ms",
                    self.server.command_time_budget_ms
                ),
                input_source: ThreatInputDigestSource::Argv(argv_ref),
                output: &RespFrame::BulkString(None),
            });
        }
    }

    /// (frankenredis-setexfast) Conservative borrowed WRITE fast path for the
    /// no-flag `SET key value EX seconds` form (the dominant set-with-TTL). Mirrors
    /// the generic set() for that exact option set: validate `seconds` as the
    /// generic does (getExpireMillisecondsOrReply — strictly positive, `seconds*1000`
    /// not overflowing, `now + px` fitting i64), then store.set with the derived px
    /// and reply `+OK`. The parser only matches *5 with a literal EX token, so NX/
    /// XX/GET/KEEPTTL/PX/EXAT/PXAT and every other shape fall through to the generic
    /// path; a malformed/<=0/overflowing seconds value returns None so the generic
    /// emits the exact "value is not an integer" / "invalid expire time in 'set'
    /// command". SET never type-checks (it overwrites), so there is no WRONGTYPE.
    /// Recorded as `set` (it IS the SET command). Gated by the WRITE predicate.
    /// (frankenredis-setnxfast) Conservative borrowed WRITE fast path for the
    /// no-other-option `SET key value NX` form (idempotent set / lock-acquire).
    /// Mirrors the generic set() for that exact option set: `store.setnx` sets the
    /// value only when the key is absent (no TTL), returning whether it set. The
    /// reply is `+OK` when set, nil (`BulkString(None)`) when the key already
    /// existed — exactly the generic's NX-without-GET behaviour. The parser only
    /// matches *4 with a literal NX token, so XX/GET/KEEPTTL/EX/PX and every other
    /// shape fall through to the generic. SET never type-checks (NX only checks
    /// existence), so there is no WRONGTYPE. Recorded as `set`. Gated by WRITE.
    /// (frankenredis-setxxfast) Conservative borrowed WRITE fast path for the
    /// no-other-option `SET key value XX` form (set only if the key already exists —
    /// update-only). Mirrors the generic set() for that exact option set: the NX/XX
    /// existence check uses the NON-counting peek (redis SET uses lookupKeyWrite, no
    /// keyspace stat); when the key exists, store.set overwrites the value and (no
    /// KEEPTTL) clears any TTL → `+OK`, otherwise nil (BulkString None). The parser
    /// only matches *4 with a literal XX token; NX/GET/KEEPTTL/EX/PX and every other
    /// shape fall through to the generic. SET never type-checks. Recorded as `set`.
    pub fn execute_plain_set_xx_borrowed(
        &mut self,
        key: &[u8],
        value: &[u8],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if self.policy.gate.max_array_len < 4
            || self.policy.gate.max_bulk_len < b"SET".len()
            || key.len() > self.policy.gate.max_bulk_len
            || value.len() > self.policy.gate.max_bulk_len
        {
            return None;
        }
        if !self.plain_borrowed_default_key_write_allows(now_ms) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("set");
        self.session.last_argv_len_sum = b"SET".len() + key.len() + value.len() + b"XX".len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        // XX: set only when the key exists (non-counting peek, matching redis 0/0).
        let reply = if self.server.store.peek_value_type(key, now_ms).is_some() {
            self.server
                .store
                .set(key.to_vec(), value.to_vec(), None, now_ms);
            RespFrame::SimpleString("OK".to_string())
        } else {
            RespFrame::BulkString(None)
        };
        let elapsed_us = self.finish_chained_command(start);

        self.record_plain_set_cond_borrowed_metrics(
            b"XX", key, value, elapsed_us, now_ms, packet_id,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        Some(reply)
    }

