    /// (frankenredis-setnxexfast) Conservative borrowed WRITE fast path for the
    /// `SET key value NX EX|PX time` distributed-lock pattern (both option orders).
    /// Mirrors the generic set() for exactly {NX, EX|PX}: validate the expiry value
    /// FIRST (as the generic does, after its option scan — defer on malformed/<=0/
    /// overflow so it emits "value is not an integer" / "invalid expire time in 'set'
    /// command"), then the NX check via the non-counting exists_no_touch — nil
    /// (BulkString None) when the key already exists, else store.set with the px TTL
    /// → `+OK`. The parser only matches *6 with exactly one NX and one EX/PX, so
    /// XX/GET/KEEPTTL/EXAT/PXAT/conflicts fall through to the generic. Recorded as
    /// `set`. Gated by the WRITE predicate.
    #[allow(clippy::too_many_arguments)]
    pub fn execute_plain_set_cond_relexpire_borrowed(
        &mut self,
        is_xx: bool,
        is_seconds: bool,
        key: &[u8],
        value: &[u8],
        time_arg: &[u8],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if self.policy.gate.max_array_len < 6
            || self.policy.gate.max_bulk_len < b"SET".len()
            || key.len() > self.policy.gate.max_bulk_len
            || value.len() > self.policy.gate.max_bulk_len
        {
            return None;
        }
        if !self.plain_borrowed_default_key_write_allows(now_ms) {
            return None;
        }
        let raw = parse_i64_arg(time_arg).ok()?;
        if raw <= 0 {
            return None;
        }
        let raw = raw as u64;
        let px = if is_seconds {
            if raw > i64::MAX as u64 / 1000 {
                return None;
            }
            raw.saturating_mul(1000)
        } else {
            raw
        };
        let now_i = i64::try_from(now_ms).unwrap_or(i64::MAX);
        i64::try_from(px).ok()?.checked_add(now_i)?; // basetime overflow -> defer
        let unit_upper: &[u8] = if is_seconds { b"EX" } else { b"PX" };
        let cond_upper: &[u8] = if is_xx { b"XX" } else { b"NX" };

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("set");
        self.session.last_argv_len_sum = b"SET".len()
            + key.len()
            + value.len()
            + cond_upper.len()
            + unit_upper.len()
            + time_arg.len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        // NX/XX existence check via the NON-counting peek (redis SET uses lookupKeyWrite,
        // which does NOT bump keyspace_hits/misses); exists_no_touch would over-count.
        // XX sets only when present, NX only when absent: set iff (exists == is_xx).
        let exists = self.server.store.peek_value_type(key, now_ms).is_some();
        let reply = if exists == is_xx {
            self.server
                .store
                .set(key.to_vec(), value.to_vec(), Some(px), now_ms);
            RespFrame::SimpleString("OK".to_string())
        } else {
            RespFrame::BulkString(None)
        };
        let elapsed_us = self.finish_chained_command(start);

        self.record_plain_set_nx_relexpire_borrowed_metrics(
            cond_upper, unit_upper, key, value, time_arg, elapsed_us, now_ms, packet_id,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        Some(reply)
    }

