    /// Conservative borrowed runtime fast path for fixed-single-key variadic
    /// WRITE commands SADD / LPUSH / RPUSH / HDEL / SREM
    /// (`CMD key value [value ...]`). Mirrors the generic handlers exactly —
    /// the store method's Integer reply, WRONGTYPE on a key holding the wrong
    /// type — while skipping argv materialization, the generic command dispatch
    /// (classify + command_table_index + dispatch_with_client_context), and the
    /// post-`Ok` keyspace/tracking/AOF bookkeeping block, all of which
    /// `plain_borrowed_default_key_write_allows` guarantees is no-op in plain
    /// mode (db0 master, no aof/replica/notify/tracking/monitor/blocked-client/
    /// transaction/script). These commands are classified as writes, so each
    /// counts one write regardless of outcome.
    /// Returns None (fall back to generic) on any disabling state.
    /// (frankenredis-ev067 — the SADD/LPUSH/RPUSH analog of
    /// [`Self::execute_plain_append_borrowed`].) KEEP IN SYNC with the q0qym
    /// borrowed-write gate.
    pub fn execute_plain_keyed_values_write_borrowed(
        &mut self,
        cmd: PlainKeyedValuesCmd,
        key: &[u8],
        values: &[&[u8]],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if self.policy.gate.max_array_len < 3
            || self.policy.gate.max_bulk_len < cmd.name_upper().len()
            || key.len() > self.policy.gate.max_bulk_len
            || values
                .iter()
                .any(|v| v.len() > self.policy.gate.max_bulk_len)
        {
            return None;
        }
        if !self.plain_borrowed_default_key_write_allows(now_ms) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str(cmd.name_lower());
        self.session.last_argv_len_sum =
            cmd.name_upper().len() + key.len() + values.iter().map(|v| v.len()).sum::<usize>();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        // Pass borrowed values straight through so the store copies each member
        // once directly into its container. The old code first collected an
        // intermediate Vec<Vec<u8>> here, then had the store clone out of it.
        let start = self.chained_command_start();
        let store_result = match cmd {
            PlainKeyedValuesCmd::Sadd => self
                .server
                .store
                .sadd(key, values, now_ms)
                .map(|n| i64::try_from(n).unwrap_or(i64::MAX)),
            PlainKeyedValuesCmd::Lpush => self
                .server
                .store
                .lpush(key, values, now_ms)
                .map(|n| i64::try_from(n).unwrap_or(i64::MAX)),
            PlainKeyedValuesCmd::Rpush => self
                .server
                .store
                .rpush(key, values, now_ms)
                .map(|n| i64::try_from(n).unwrap_or(i64::MAX)),
            PlainKeyedValuesCmd::Pfadd => self
                .server
                .store
                .pfadd_borrowed(key, values, now_ms)
                .map(i64::from),
            // (frankenredis-n8ct0) store.hdel/srem own type-check, keyspace
            // hit/miss accounting, dirty tracking, and empty-key autodelete —
            // identical to the generic path which calls the same methods.
            PlainKeyedValuesCmd::Hdel => self
                .server
                .store
                .hdel(key, values, now_ms)
                .map(|n| i64::try_from(n).unwrap_or(i64::MAX)),
            PlainKeyedValuesCmd::Srem => self
                .server
                .store
                .srem(key, values, now_ms)
                .map(|n| i64::try_from(n).unwrap_or(i64::MAX)),
            PlainKeyedValuesCmd::Zrem => self
                .server
                .store
                .zrem(key, values, now_ms)
                .map(|n| i64::try_from(n).unwrap_or(i64::MAX)),
            // (frankenredis-pushxfast) store.lpushx/rpushx take owned values + own
            // the exists-check, keyspace/dirty accounting, and (no) autocreate —
            // identical to the generic path. The to_vec mirrors the generic's
            // argv[2..].to_vec(), so this matches generic alloc behaviour and the
            // win is purely the skipped dispatch.
            PlainKeyedValuesCmd::Lpushx => {
                let owned: Vec<Vec<u8>> = values.iter().map(|v| v.to_vec()).collect();
                self.server
                    .store
                    .lpushx(key, &owned, now_ms)
                    .map(|n| i64::try_from(n).unwrap_or(i64::MAX))
            }
            PlainKeyedValuesCmd::Rpushx => {
                let owned: Vec<Vec<u8>> = values.iter().map(|v| v.to_vec()).collect();
                self.server
                    .store
                    .rpushx(key, &owned, now_ms)
                    .map(|n| i64::try_from(n).unwrap_or(i64::MAX))
            }
        };
        let elapsed_us = self.finish_chained_command(start);
        let reply = match store_result {
            Ok(n) => RespFrame::Integer(n),
            Err(err) => CommandError::Store(err).to_resp(),
        };
        let failed = matches!(reply, RespFrame::Error(_));

        self.record_plain_keyed_values_borrowed_metrics(
            cmd, key, values, elapsed_us, now_ms, packet_id, failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let RespFrame::Error(msg) = &reply {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(reply)
    }

