    /// Conservative borrowed runtime fast path for `HSET key field value [field
    /// value ...]`. Mirrors the generic handler exactly — one `store.hset` per
    /// field/value pair, the reply is the count of NEWLY created fields, and a
    /// key holding the wrong type errors on the first pair (no mutation, since
    /// the type is rechecked each call) just like the generic `?`-propagation.
    /// `pairs` must be a non-empty even-length slice (the caller guarantees this;
    /// odd/empty falls back to the generic WrongArity path). Skips argv
    /// materialization + generic dispatch + the post-Ok bookkeeping block, all
    /// no-op in plain mode. HSET is a write, counted once. (frankenredis-ev067)
    pub fn execute_plain_hset_borrowed(
        &mut self,
        key: &[u8],
        pairs: &[&[u8]],
        now_ms: u64,
    ) -> Option<RespFrame> {
        let default_write_allowed = self.plain_borrowed_default_key_write_allows(now_ms);
        self.execute_plain_hset_borrowed_with_default_write_gate(
            key,
            pairs,
            now_ms,
            default_write_allowed,
        )
    }

    pub fn execute_plain_hset_borrowed_with_default_write_gate(
        &mut self,
        key: &[u8],
        pairs: &[&[u8]],
        now_ms: u64,
        default_write_allowed: bool,
    ) -> Option<RespFrame> {
        if self.policy.gate.max_array_len < 4
            || self.policy.gate.max_bulk_len < b"HSET".len()
            || key.len() > self.policy.gate.max_bulk_len
            || pairs
                .iter()
                .any(|p| p.len() > self.policy.gate.max_bulk_len)
        {
            return None;
        }
        if !default_write_allowed {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("hset");
        self.session.last_argv_len_sum =
            b"HSET".len() + key.len() + pairs.iter().map(|p| p.len()).sum::<usize>();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        let mut added = 0_usize;
        let mut error: Option<RespFrame> = None;
        // (frankenredis-hsetcmdbulk) For a multi-field HSET, do ONE keyspace
        // setup + (fresh+unique) pre-sized bulk build instead of re-paying the
        // per-field keyspace probes and incremental rehashes. Small HSETs keep
        // the direct per-field path (the bulk path's fixed overhead would not
        // pay off). Byte-identical result + reply.
        if pairs.len() >= 8 {
            match self.server.store.hset_borrowed_many(key, pairs, now_ms) {
                Ok(n) => added = n,
                Err(err) => error = Some(CommandError::Store(err).to_resp()),
            }
        } else {
            for pair in pairs.as_chunks::<2>().0 {
                match self
                    .server
                    .store
                    .hset_borrowed(key, pair[0], pair[1].to_vec(), now_ms)
                {
                    Ok(true) => added += 1,
                    Ok(false) => {}
                    Err(err) => {
                        error = Some(CommandError::Store(err).to_resp());
                        break;
                    }
                }
            }
        }
        let elapsed_us = self.finish_chained_command(start);
        let reply =
            error.unwrap_or_else(|| RespFrame::Integer(i64::try_from(added).unwrap_or(i64::MAX)));
        let failed = matches!(reply, RespFrame::Error(_));

        self.record_plain_hset_borrowed_metrics(key, pairs, elapsed_us, now_ms, packet_id, failed);

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let RespFrame::Error(msg) = &reply {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(reply)
    }

    fn record_plain_hset_borrowed_metrics(
        &mut self,
        key: &[u8],
        pairs: &[&[u8]],
        elapsed_us: u64,
        now_ms: u64,
        packet_id: u64,
        failed: bool,
    ) {
        let mut argv: Option<Vec<Vec<u8>>> = None;
        let build = |key: &[u8], pairs: &[&[u8]]| -> Vec<Vec<u8>> {
            let mut a = Vec::with_capacity(pairs.len() + 2);
            a.push(b"HSET".to_vec());
            a.push(key.to_vec());
            a.extend(pairs.iter().map(|p| p.to_vec()));
            a
        };
        if self.server.store.slowlog_log_slower_than_us >= 0
            && (elapsed_us as i64) >= self.server.store.slowlog_log_slower_than_us
        {
            let argv_ref = argv.get_or_insert_with(|| build(key, pairs));
            self.record_slowlog(argv_ref, elapsed_us, now_ms);
        }

        let threshold_ms = self.server.store.latency_tracker.threshold_ms;
        let duration_ms = elapsed_us.div_ceil(1000);
        if threshold_ms != 0 && duration_ms > threshold_ms {
            let argv_ref = argv.get_or_insert_with(|| build(key, pairs));
            self.server
                .record_latency_sample(argv_ref, elapsed_us, now_ms);
        }

        if self.server.latency_tracking {
            let kind = if failed {
                CommandRecordKind::Failed
            } else {
                CommandRecordKind::Success
            };
            self.server
                .store
                .record_command_histogram_canonical_with_kind("hset", elapsed_us, kind);
        }

        if elapsed_us > (self.server.command_time_budget_ms * 1000) {
            let argv_ref = argv.get_or_insert_with(|| build(key, pairs));
            self.record_threat_event(ThreatEventInput {
                now_ms,
                packet_id,
                threat_class: ThreatClass::ResourceExhaustion,
                preferred_deviation: Some(HardenedDeviationCategory::ResourceClamp),
                subsystem: "router",
                action: "slow_command_detected",
                reason_code: "command_time_budget_exceeded",
                reason: format!(
                    "command 'HSET' took {}us, exceeding budget {}ms",
                    elapsed_us, self.server.command_time_budget_ms
                ),
                input_source: ThreatInputDigestSource::Argv(argv_ref),
                output: &RespFrame::Integer(0),
            });
        }
    }

    pub fn execute_plain_hmset_borrowed(
        &mut self,
        key: &[u8],
        pairs: &[&[u8]],
        now_ms: u64,
    ) -> Option<RespFrame> {
        self.execute_plain_hmset_borrowed_ok(key, pairs, now_ms)
            .map(|outcome| outcome.unwrap_or_else(|| RespFrame::SimpleString("OK".to_string())))
    }

    /// (BlackThrush) Non-allocating twin of [`Self::execute_plain_hmset_borrowed`]: runs the
    /// identical borrowed HMSET write but factors the reply so the dispatcher can skip the
    /// per-HMSET `SimpleString("OK")` allocation on the (dominant) success path. Returns
    /// `Some(None)` on success — the caller emits the constant `+OK\r\n` straight into the
    /// connection buffer via `BorrowedMultibulkAction::FastOkReply`; `Some(Some(err))` when the
    /// write produced an error frame (e.g. WRONGTYPE), routed through the ordinary `FastReply`
    /// path exactly as before; and `None` when the borrowed fast path declined.
    pub fn execute_plain_hmset_borrowed_ok(
        &mut self,
        key: &[u8],
        pairs: &[&[u8]],
        now_ms: u64,
    ) -> Option<Option<RespFrame>> {
        let default_write_allowed = self.plain_borrowed_default_key_write_allows(now_ms);
        self.execute_plain_hmset_borrowed_with_default_write_gate(
            key,
            pairs,
            now_ms,
            default_write_allowed,
        )
    }

    pub fn execute_plain_hmset_borrowed_with_default_write_gate(
        &mut self,
        key: &[u8],
        pairs: &[&[u8]],
        now_ms: u64,
        default_write_allowed: bool,
    ) -> Option<Option<RespFrame>> {
        if self.policy.gate.max_array_len < 4
            || self.policy.gate.max_bulk_len < b"HMSET".len()
            || key.len() > self.policy.gate.max_bulk_len
            || pairs
                .iter()
                .any(|p| p.len() > self.policy.gate.max_bulk_len)
        {
            return None;
        }
        if !default_write_allowed {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("hmset");
        self.session.last_argv_len_sum =
            b"HMSET".len() + key.len() + pairs.iter().map(|p| p.len()).sum::<usize>();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        let mut error: Option<RespFrame> = None;
        // (frankenredis-hsetcmdbulk) Same O(n^2)-per-field-refresh fix as HSET:
        // route multi-field HMSET through the one-setup bulk build.
        if pairs.len() >= 8 {
            if let Err(err) = self.server.store.hset_borrowed_many(key, pairs, now_ms) {
                error = Some(CommandError::Store(err).to_resp());
            }
        } else {
            for pair in pairs.as_chunks::<2>().0 {
                match self
                    .server
                    .store
                    .hset_borrowed(key, pair[0], pair[1].to_vec(), now_ms)
                {
                    Ok(_) => {}
                    Err(err) => {
                        error = Some(CommandError::Store(err).to_resp());
                        break;
                    }
                }
            }
        }
        let elapsed_us = self.finish_chained_command(start);
        // `error` is `Some(Error(..))` only on failure; the success reply is a constant +OK that
        // the caller emits directly (FastOkReply) without allocating a `SimpleString` frame.
        let failed = error.is_some();

        self.record_plain_hmset_borrowed_metrics(key, pairs, elapsed_us, now_ms, packet_id, failed);

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let Some(RespFrame::Error(msg)) = &error {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(error)
    }

