    /// (CrimsonHawk) Borrowed fast path for the bare single-triple
    /// `GEOADD key lon lat member` (no NX/XX/CH, exactly one triple). Upstream
    /// geo.c::geoaddCommand builds a `ZADD key score member` argv and dispatches
    /// zaddGenericCommand, where score = the 52-bit geohash interleave as an f64
    /// (exactly representable, 52 < 53 mantissa bits). This mirrors that without
    /// the generic-argv dispatch tax (profiled as ~entirely dispatch-bound: the
    /// geo encode is <1%). Parses BOTH coordinates BEFORE any state change and
    /// DEFERS (returns None → generic path, which emits the exact error) on a
    /// non-numeric coordinate ("value is not a valid float") or an out-of-WGS84
    /// coordinate ("invalid longitude,latitude pair"). Multi-triple / option
    /// shapes never reach here (the parser only matches the 5-element form).
    /// Records cmdstat as `geoadd`; the keyspace "zadd" event / ZADD propagation
    /// are gated off (default-write-gate defers when notify/repl/AOF/etc active).
    pub fn execute_plain_geoadd_borrowed(
        &mut self,
        key: &[u8],
        lon: &[u8],
        lat: &[u8],
        member: &[u8],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if self.policy.gate.max_array_len < 4
            || self.policy.gate.max_bulk_len < b"GEOADD".len()
            || key.len() > self.policy.gate.max_bulk_len
            || lon.len() > self.policy.gate.max_bulk_len
            || lat.len() > self.policy.gate.max_bulk_len
            || member.len() > self.policy.gate.max_bulk_len
        {
            return None;
        }
        // Parse + range-check BOTH coordinates before any state change; bail to
        // the generic path (exact error) on the first bad one.
        let longitude = fr_command::parse_f64_arg(lon).ok()?;
        let latitude = fr_command::parse_f64_arg(lat).ok()?;
        let bits = fr_command::geo_encode_wgs84(longitude, latitude)?;
        let score = bits as f64;
        if !self.plain_borrowed_default_key_write_allows(now_ms) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("geoadd");
        self.session.last_argv_len_sum =
            b"GEOADD".len() + key.len() + lon.len() + lat.len() + member.len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        let reply =
            match self
                .server
                .store
                .zadd_plain_owned(key, vec![(score, member.to_vec())], now_ms)
            {
                Ok(count) => RespFrame::Integer(i64::try_from(count).unwrap_or(i64::MAX)),
                Err(err) => CommandError::Store(err).to_resp(),
            };
        let elapsed_us = self.finish_chained_command(start);
        let failed = matches!(reply, RespFrame::Error(_));

        self.record_plain_geoadd_borrowed_metrics(
            key, lon, lat, member, elapsed_us, now_ms, packet_id, failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let RespFrame::Error(msg) = &reply {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(reply)
    }

