    /// Borrowed fast path for bare `ZADD key INCR score member` (*5, no NX/XX/GT/LT).
    /// redis implements ZINCRBY via the ZADD-INCR path, so this is byte-identical to
    /// ZINCRBY (same store.zincrby, same NaN wording, same RESP2-bulk/RESP3-Double score
    /// reply) EXCEPT cmdstat/argv are "zadd". Conditional INCR (with NX/XX/GT/LT) is *6+
    /// and falls to the generic path.
    pub fn execute_plain_zadd_incr_borrowed(
        &mut self,
        key: &[u8],
        delta_arg: &[u8],
        member: &[u8],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if self.policy.gate.max_array_len < 5
            || self.policy.gate.max_bulk_len < b"ZADD".len()
            || key.len() > self.policy.gate.max_bulk_len
            || delta_arg.len() > self.policy.gate.max_bulk_len
            || member.len() > self.policy.gate.max_bulk_len
        {
            return None;
        }
        let delta = fr_command::parse_score_f64_arg(delta_arg).ok()?;
        if !self.plain_borrowed_default_key_write_allows(now_ms) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("zadd");
        self.session.last_argv_len_sum =
            b"ZADD".len() + key.len() + b"INCR".len() + delta_arg.len() + member.len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let resp3 = self.session.resp_protocol_version == 3;
        let start = self.chained_command_start();
        let reply = match self
            .server
            .store
            .zincrby(key, member.to_vec(), delta, now_ms)
        {
            Ok(score) => {
                if resp3 {
                    RespFrame::double_from_f64(score)
                } else {
                    RespFrame::BulkString(Some(fr_store::redis_score_to_string(score).into_bytes()))
                }
            }
            Err(fr_store::StoreError::IncrFloatNaN) => {
                CommandError::Custom("ERR resulting score is not a number (NaN)".to_string())
                    .to_resp()
            }
            Err(err) => CommandError::Store(err).to_resp(),
        };
        let elapsed_us = self.finish_chained_command(start);
        let failed = matches!(reply, RespFrame::Error(_));

        self.record_plain_zadd_incr_borrowed_metrics(
            key, delta_arg, member, elapsed_us, now_ms, packet_id, failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let RespFrame::Error(msg) = &reply {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(reply)
    }

