    /// (frankenredis-zaddflagmulti) ZADD with 1-2 flags (NX/XX/GT/LT/CH) and
    /// MULTIPLE score/member pairs — `ZADD key FLAG [FLAG2] s1 m1 s2 m2 ...`.
    /// The flagless multipair path (execute_plain_zadd_borrowed) and the
    /// single-pair flag paths (zadd_flag/zadd_flag2) were already fast; the
    /// flag+multipair combination still fell to the generic argv path (measured
    /// 0.58-0.63x vs redis). Combines the flag-parsing/validation of
    /// execute_plain_zadd_flag2_borrowed with the pairs handling of
    /// execute_plain_zadd_borrowed, reusing store.zadd_with_options (NO new store
    /// code). Any invalid flag combination, INCR, or bad score returns None so the
    /// generic path produces the exact error reply. `flags` is 1-2 elements,
    /// `pairs` is 2*N interleaved score/member bulks (N >= 2).
    pub fn execute_plain_zadd_flag_multi_borrowed(
        &mut self,
        key: &[u8],
        flags: &[&[u8]],
        pairs: &[&[u8]],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if self.policy.gate.max_bulk_len < b"ZADD".len()
            || key.len() > self.policy.gate.max_bulk_len
            || flags
                .iter()
                .any(|f| f.len() > self.policy.gate.max_bulk_len)
            || pairs
                .iter()
                .any(|p| p.len() > self.policy.gate.max_bulk_len)
        {
            return None;
        }
        let mut opts = fr_store::ZaddOptions {
            nx: false,
            xx: false,
            gt: false,
            lt: false,
            ch: false,
        };
        for f in flags {
            if f.eq_ignore_ascii_case(b"NX") {
                opts.nx = true;
            } else if f.eq_ignore_ascii_case(b"XX") {
                opts.xx = true;
            } else if f.eq_ignore_ascii_case(b"GT") {
                opts.gt = true;
            } else if f.eq_ignore_ascii_case(b"LT") {
                opts.lt = true;
            } else if f.eq_ignore_ascii_case(b"CH") {
                opts.ch = true;
            } else {
                return None;
            }
        }
        // Invalid combos defer to the generic path (which emits the exact error).
        if (opts.nx && (opts.xx || opts.gt || opts.lt)) || (opts.gt && opts.lt) {
            return None;
        }
        if flags.len() == 2 && flags[0].eq_ignore_ascii_case(flags[1]) {
            return None;
        }
        // Parse every score BEFORE any state change; bail to the generic path on
        // the first invalid score (it produces the exact error reply).
        let mut members: Vec<(f64, Vec<u8>)> = Vec::with_capacity(pairs.len() / 2);
        for pair in pairs.as_chunks::<2>().0 {
            let score = fr_command::parse_score_f64_arg(pair[0]).ok()?;
            members.push((score, pair[1].to_vec()));
        }
        if !self.plain_borrowed_default_key_write_allows(now_ms) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("zadd");
        self.session.last_argv_len_sum = b"ZADD".len()
            + key.len()
            + flags.iter().map(|f| f.len()).sum::<usize>()
            + pairs.iter().map(|p| p.len()).sum::<usize>();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        let reply = match self
            .server
            .store
            .zadd_with_options(key, members, opts, now_ms)
        {
            Ok((count, _changed)) => RespFrame::Integer(count as i64),
            Err(err) => CommandError::Store(err).to_resp(),
        };
        let elapsed_us = self.finish_chained_command(start);
        let failed = matches!(reply, RespFrame::Error(_));

        self.record_plain_zadd_flag_multi_borrowed_metrics(
            key, flags, pairs, elapsed_us, now_ms, packet_id, failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let RespFrame::Error(msg) = &reply {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(reply)
    }

    #[allow(clippy::too_many_arguments)]
    fn record_plain_zadd_flag_multi_borrowed_metrics(
        &mut self,
        key: &[u8],
        flags: &[&[u8]],
        pairs: &[&[u8]],
        elapsed_us: u64,
        now_ms: u64,
        packet_id: u64,
        failed: bool,
    ) {
        let mut argv: Option<Vec<Vec<u8>>> = None;
        let build = |key: &[u8], flags: &[&[u8]], pairs: &[&[u8]]| -> Vec<Vec<u8>> {
            let mut a = Vec::with_capacity(pairs.len() + flags.len() + 2);
            a.push(b"ZADD".to_vec());
            a.push(key.to_vec());
            a.extend(flags.iter().map(|f| f.to_vec()));
            a.extend(pairs.iter().map(|p| p.to_vec()));
            a
        };
        if self.server.store.slowlog_log_slower_than_us >= 0
            && (elapsed_us as i64) >= self.server.store.slowlog_log_slower_than_us
        {
            let argv_ref = argv.get_or_insert_with(|| build(key, flags, pairs));
            self.record_slowlog(argv_ref, elapsed_us, now_ms);
        }

        let threshold_ms = self.server.store.latency_tracker.threshold_ms;
        let duration_ms = elapsed_us.div_ceil(1000);
        if threshold_ms != 0 && duration_ms > threshold_ms {
            let argv_ref = argv.get_or_insert_with(|| build(key, flags, pairs));
            self.server
                .record_latency_sample(argv_ref, elapsed_us, now_ms);
        }

        if self.server.latency_tracking {
            let kind = if failed {
                CommandRecordKind::Failed
            } else {
                CommandRecordKind::Success
            };
            self.server
                .store
                .record_command_histogram_canonical_with_kind("zadd", elapsed_us, kind);
        }

        if elapsed_us > (self.server.command_time_budget_ms * 1000) {
            let argv_ref = argv.get_or_insert_with(|| build(key, flags, pairs));
            self.record_threat_event(ThreatEventInput {
                now_ms,
                packet_id,
                threat_class: ThreatClass::ResourceExhaustion,
                preferred_deviation: Some(HardenedDeviationCategory::ResourceClamp),
                subsystem: "router",
                action: "slow_command_detected",
                reason_code: "command_time_budget_exceeded",
                reason: format!(
                    "command 'ZADD' took {}us, exceeding budget {}ms",
                    elapsed_us, self.server.command_time_budget_ms
                ),
                input_source: ThreatInputDigestSource::Argv(argv_ref),
                output: &RespFrame::Integer(0),
            });
        }
    }

    /// Conservative borrowed runtime fast path for the no-count WRITE-pop
    /// commands LPOP / RPOP / SPOP (`CMD key`). Mirrors the generic no-count
    /// handlers exactly — the store pop method's bulk-string reply (nil when the
    /// collection is absent or empty), WRONGTYPE on a mismatched key, and the
    /// store method's own emptied-key deletion — while skipping argv
    /// materialization + generic dispatch + the post-Ok bookkeeping block, all
    /// no-op in plain mode. These are write commands, counted once. The COUNT
    /// form (argc > 2) is handled by the caller falling back to the generic path.
    /// (frankenredis-ev067 — the pop analog of the keyed-values fast path.)
    pub fn execute_plain_keyed_pop_borrowed(
        &mut self,
        cmd: PlainKeyedPopCmd,
        key: &[u8],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if self.policy.gate.max_array_len < 2
            || self.policy.gate.max_bulk_len < cmd.name_upper().len()
            || key.len() > self.policy.gate.max_bulk_len
        {
            return None;
        }
        if !self.plain_borrowed_default_key_write_allows(now_ms) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str(cmd.name_lower());
        self.session.last_argv_len_sum = cmd.name_upper().len() + key.len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let resp3 = self.session.resp_protocol_version == 3;
        let start = self.chained_command_start();
        let reply = match cmd {
            PlainKeyedPopCmd::Lpop => match self.server.store.lpop(key, now_ms) {
                Ok(value) => RespFrame::BulkString(value),
                Err(err) => CommandError::Store(err).to_resp(),
            },
            PlainKeyedPopCmd::Rpop => match self.server.store.rpop(key, now_ms) {
                Ok(value) => RespFrame::BulkString(value),
                Err(err) => CommandError::Store(err).to_resp(),
            },
            PlainKeyedPopCmd::Spop => match self.server.store.spop(key, now_ms) {
                Ok(value) => RespFrame::BulkString(value),
                Err(err) => CommandError::Store(err).to_resp(),
            },
            // (frankenredis-zpopfast) ZPOPMIN/ZPOPMAX (no count) reply with a
            // flat `[member, score]` array, or an empty array on a miss — exactly
            // what the generic `zpopmin`/`zpopmax` command handlers produce. The
            // score frame is RESP3 Double / RESP2 bulk-string, matching
            // `zpop_score_frame`.
            PlainKeyedPopCmd::Zpopmin => {
                plain_zpop_reply(self.server.store.zpopmin(key, now_ms), resp3)
            }
            PlainKeyedPopCmd::Zpopmax => {
                plain_zpop_reply(self.server.store.zpopmax(key, now_ms), resp3)
            }
        };
        let elapsed_us = self.finish_chained_command(start);
        let failed = matches!(reply, RespFrame::Error(_));

        self.record_plain_keyed_pop_borrowed_metrics(
            cmd, key, elapsed_us, now_ms, packet_id, failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let RespFrame::Error(msg) = &reply {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(reply)
    }

    fn record_plain_keyed_pop_borrowed_metrics(
        &mut self,
        cmd: PlainKeyedPopCmd,
        key: &[u8],
        elapsed_us: u64,
        now_ms: u64,
        packet_id: u64,
        failed: bool,
    ) {
        let mut argv: Option<Vec<Vec<u8>>> = None;
        if self.server.store.slowlog_log_slower_than_us >= 0
            && (elapsed_us as i64) >= self.server.store.slowlog_log_slower_than_us
        {
            let argv_ref = argv.get_or_insert_with(|| plain_keyed_pop_owned_argv(cmd, key));
            self.record_slowlog(argv_ref, elapsed_us, now_ms);
        }

        let threshold_ms = self.server.store.latency_tracker.threshold_ms;
        let duration_ms = elapsed_us.div_ceil(1000);
        if threshold_ms != 0 && duration_ms > threshold_ms {
            let argv_ref = argv.get_or_insert_with(|| plain_keyed_pop_owned_argv(cmd, key));
            self.server
                .record_latency_sample(argv_ref, elapsed_us, now_ms);
        }

        if self.server.latency_tracking {
            let kind = if failed {
                CommandRecordKind::Failed
            } else {
                CommandRecordKind::Success
            };
            // (frankenredis-par0e) cmd.name_lower() is a static lowercase canonical
            // name — record directly, skipping the per-command re-lowercase +
            // UTF-8 validation, and hitting the lpush/rpush/sadd direct fields.
            self.server
                .store
                .record_command_histogram_canonical_with_kind(cmd.name_lower(), elapsed_us, kind);
        }

        if elapsed_us > (self.server.command_time_budget_ms * 1000) {
            let argv_ref = argv.get_or_insert_with(|| plain_keyed_pop_owned_argv(cmd, key));
            self.record_threat_event(ThreatEventInput {
                now_ms,
                packet_id,
                threat_class: ThreatClass::ResourceExhaustion,
                preferred_deviation: Some(HardenedDeviationCategory::ResourceClamp),
                subsystem: "router",
                action: "slow_command_detected",
                reason_code: "command_time_budget_exceeded",
                reason: format!(
                    "command '{}' took {}us, exceeding budget {}ms",
                    cmd.name_upper(),
                    elapsed_us,
                    self.server.command_time_budget_ms
                ),
                input_source: ThreatInputDigestSource::Argv(argv_ref),
                output: &RespFrame::BulkString(None),
            });
        }
    }

    pub fn execute_plain_get_borrowed_into(
        &mut self,
        key: &[u8],
        now_ms: u64,
        resp3: bool,
        out: &mut Vec<u8>,
    ) -> Option<()> {
        let default_read_allowed = self.plain_borrowed_default_key_read_allows(now_ms);
        self.execute_plain_get_borrowed_into_with_default_read_gate(
            key,
            now_ms,
            resp3,
            out,
            default_read_allowed,
        )
    }

    pub fn execute_plain_get_borrowed_into_with_default_read_gate(
        &mut self,
        key: &[u8],
        now_ms: u64,
        resp3: bool,
        out: &mut Vec<u8>,
        default_read_allowed: bool,
    ) -> Option<()> {
        if !self.can_execute_plain_get_borrowed_with_default_read_gate(key, default_read_allowed) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("get");
        self.session.last_argv_len_sum = b"GET".len() + key.len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        let suppress_reply = self.suppress_current_network_reply();
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        let result = self.server.store.get_string_bytes(key, now_ms);
        let end = Instant::now();
        let mut error_reply = None;
        match result {
            Ok(value) => {
                if !suppress_reply {
                    encode_bulk_string_slice(value.as_deref(), resp3, out);
                }
            }
            Err(err) => {
                let reply = CommandError::Store(err).to_resp();
                if !suppress_reply {
                    if resp3 {
                        reply.encode_into_resp3(out);
                    } else {
                        reply.encode_into(out);
                    }
                }
                error_reply = Some(reply);
            }
        }
        let elapsed_us = self.finish_chained_command_at(start, end);
        let failed = error_reply.is_some();

        self.record_plain_get_borrowed_metrics(key, elapsed_us, now_ms, packet_id, failed);

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let Some(RespFrame::Error(msg)) = &error_reply {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(())
    }

    /// Borrow-encoded PING fast path: writes `+PONG\r\n` (no arg) or the bulk
    /// echo of the message straight into `out`, with ZERO allocations — no owned
    /// argv (`Vec<Vec<u8>>`), no `RespFrame`, no `"PONG"` String. Deep-pipeline
    /// PING was ~3.4x slower than redis purely from the generic path's per-command
    /// argv + reply allocations (redis answers PING from a shared static object);
    /// PING is the cleanest proxy for that per-command overhead. Falls back
    /// (returns `None`) via the SAME gate the GET read fast path uses, so every
    /// non-plain case — unauthenticated (NOAUTH), MULTI (queue), subscriber mode
    /// (multibulk pong), monitored, non-default reply mode, etc. — defers to the
    /// generic path that handles it. (frankenredis-ping-fastpath)
    pub fn execute_plain_ping_borrowed_into(
        &mut self,
        msg: Option<&[u8]>,
        now_ms: u64,
        resp3: bool,
        out: &mut Vec<u8>,
    ) -> Option<()> {
        if !self.plain_borrowed_default_key_read_allows(now_ms) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("ping");
        self.session.last_argv_len_sum = b"PING".len() + msg.map_or(0, <[u8]>::len);
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        let suppress_reply = self.suppress_current_network_reply();

        let start = self.chained_command_start();
        if !suppress_reply {
            match msg {
                // `PING` -> simple string `+PONG` (protocol-invariant RESP2/RESP3).
                None => out.extend_from_slice(b"+PONG\r\n"),
                // `PING <msg>` -> bulk echo of the message.
                Some(m) => encode_bulk_string_slice(Some(m), resp3, out),
            }
        }
        let elapsed_us = self.finish_chained_command(start);

        self.record_plain_ping_borrowed_metrics(msg, elapsed_us, now_ms, packet_id);

        Some(())
    }

    /// PING sibling of `record_plain_get_borrowed_metrics` (slowlog, latency
