    /// (frankenredis-randomkeyfast) Borrowed READ fast path for the no-arg `RANDOMKEY`.
    /// The default-read gate already requires selected_db == 0, so this scopes to db 0
    /// exactly like the generic randomkey (store.randomkey_in_db + decode_db_key for the
    /// logical name); reply is the chosen key bulk string, or nil on an empty db. Same
    /// store primitive + RNG advancement as the generic handler.
    pub fn execute_plain_randomkey_borrowed(&mut self, now_ms: u64) -> Option<RespFrame> {
        if self.policy.gate.max_array_len < 1 || self.policy.gate.max_bulk_len < b"RANDOMKEY".len()
        {
            return None;
        }
        if !self.plain_borrowed_default_key_read_allows(now_ms) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("randomkey");
        self.session.last_argv_len_sum = b"RANDOMKEY".len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        // Gate guarantees selected_db == 0; mirror the generic randomkey exactly.
        let reply = match self.server.store.randomkey_in_db(0, now_ms) {
            Some(physical) => {
                let logical = fr_store::decode_db_key(&physical)
                    .map(|(_, logical)| logical.to_vec())
                    .unwrap_or(physical);
                RespFrame::BulkString(Some(logical))
            }
            None => RespFrame::BulkString(None),
        };
        let elapsed_us = self.finish_chained_command(start);

        self.record_plain_randomkey_borrowed_metrics(elapsed_us, now_ms, packet_id);

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        Some(reply)
    }

    /// (BlueFalcon) Borrowed WRITE fast path for `MOVE key db`. Mirrors the
    /// generic runtime handler exactly under the plain write gate: cluster mode is
    /// rejected before DB parsing, DB-index errors keep Redis' i32/range wording,
    /// same-DB errors happen before key lookup, source/destination probes are
    /// no-stat, and successful transfer increments `dirty` exactly once.
    pub fn execute_plain_move_borrowed(
        &mut self,
        key: &[u8],
        db_arg: &[u8],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if self.policy.gate.max_array_len < 3
            || self.policy.gate.max_bulk_len < b"MOVE".len()
            || key.len() > self.policy.gate.max_bulk_len
            || db_arg.len() > self.policy.gate.max_bulk_len
            || !self.plain_borrowed_default_key_write_allows(now_ms)
        {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("move");
        self.session.last_argv_len_sum = b"MOVE".len() + key.len() + db_arg.len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        let reply = if self.server.store.cluster_enabled {
            RespFrame::Error("ERR MOVE is not allowed in cluster mode".to_string())
        } else {
            match parse_db_index_arg(
                db_arg,
                "ERR DB index is out of range",
                self.server.store.database_count,
            ) {
                Ok(target_db) if target_db == self.session.selected_db => {
                    RespFrame::Error("ERR source and destination objects are the same".to_string())
                }
                Ok(target_db) => {
                    let source = if self.session.selected_db == 0 {
                        std::borrow::Cow::Borrowed(key)
                    } else {
                        std::borrow::Cow::Owned(encode_db_key(self.session.selected_db, key))
                    };
                    if !self.server.store.exists_no_stat(source.as_ref(), now_ms) {
                        RespFrame::Integer(0)
                    } else {
                        let destination = encode_db_key(target_db, key);
                        if self.server.store.exists_no_stat(&destination, now_ms) {
                            RespFrame::Integer(0)
                        } else {
                            match self.server.store.move_existing_no_stat(
                                source.as_ref(),
                                &destination,
                                now_ms,
                            ) {
                                Ok(moved) => RespFrame::Integer(i64::from(moved)),
                                Err(err) => CommandError::Store(err).to_resp(),
                            }
                        }
                    }
                }
                Err(RespFrame::Error(message)) => RespFrame::Error(message),
                Err(_) => CommandError::InvalidInteger.to_resp(),
            }
        };
        let elapsed_us = self.finish_chained_command(start);
        let failed = matches!(reply, RespFrame::Error(_));
        let key_owned = key.to_vec();
        let db_owned = db_arg.to_vec();

        self.record_plain_zremrange_borrowed_metrics(
            "move",
            "MOVE",
            || vec![b"MOVE".to_vec(), key_owned.clone(), db_owned.clone()],
            elapsed_us,
            now_ms,
            packet_id,
            failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);
        self.account_plain_borrowed_error_reply(&reply);

        Some(reply)
    }

