    fn can_execute_plain_zmscore_borrowed(
        &mut self,
        key: &[u8],
        members: &[&[u8]],
        now_ms: u64,
    ) -> bool {
        if members.is_empty()
            || members.len().saturating_add(2) > MAX_COMMAND_ARITY
            || self.policy.gate.max_array_len < members.len().saturating_add(2)
            || self.policy.gate.max_bulk_len < b"ZMSCORE".len()
            || key.len() > self.policy.gate.max_bulk_len
            || members
                .iter()
                .any(|m| m.len() > self.policy.gate.max_bulk_len)
        {
            return false;
        }
        self.plain_borrowed_default_key_read_allows(now_ms)
    }

    /// Borrowed fast path for `ZMSCORE key member [member ...]`: mirrors the
    /// generic handler — exists_no_touch(key) records the single keyspace
    /// hit/miss (record_source_key_lookups) then the no-stat store.zmscore reads
    /// each member's score. Reply is an array of RESP3 Double / RESP2 bulk-string
    /// score (canonical redis_score_to_string) or nil per missing member, or
    /// WRONGTYPE for a non-zset key. (cold-cmd audit)
    pub fn execute_plain_zmscore_borrowed(
        &mut self,
        key: &[u8],
        members: &[&[u8]],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if !self.can_execute_plain_zmscore_borrowed(key, members, now_ms) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("zmscore");
        self.session.last_argv_len_sum =
            b"ZMSCORE".len() + key.len() + members.iter().map(|m| m.len()).sum::<usize>();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let resp3 = self.session.resp_protocol_version == 3;
        let start = self.chained_command_start();
        // Mirror record_source_key_lookups(store, &[key]) then store.zmscore.
        let _ = self.server.store.exists_no_touch(key, now_ms);
        let result = self.server.store.zmscore(key, members, now_ms);
        let elapsed_us = self.finish_chained_command(start);
        let reply = match result {
            Ok(scores) => RespFrame::Array(Some(
                scores
                    .into_iter()
                    .map(|s| match s {
                        Some(score) => {
                            if resp3 {
                                RespFrame::double_from_f64(score)
                            } else {
                                RespFrame::BulkString(Some(
                                    fr_store::redis_score_to_string(score).into_bytes(),
                                ))
                            }
                        }
                        None => RespFrame::BulkString(None),
                    })
                    .collect(),
            )),
            Err(err) => CommandError::Store(err).to_resp(),
        };
        let failed = matches!(reply, RespFrame::Error(_));

        self.record_plain_zmscore_borrowed_metrics(
            key, members, elapsed_us, now_ms, packet_id, failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let RespFrame::Error(msg) = &reply {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(reply)
    }

    /// Direct-encoding twin of [`Self::execute_plain_zmscore_borrowed`]. It
    /// preserves the same store calls and metrics while skipping one owned
    /// score string / `RespFrame` per returned score on the network fast path.
    pub fn execute_plain_zmscore_borrowed_into(
        &mut self,
        key: &[u8],
        members: &[&[u8]],
        now_ms: u64,
        resp3: bool,
        out: &mut Vec<u8>,
    ) -> Option<()> {
        if !self.can_execute_plain_zmscore_borrowed(key, members, now_ms) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("zmscore");
        self.session.last_argv_len_sum =
            b"ZMSCORE".len() + key.len() + members.iter().map(|m| m.len()).sum::<usize>();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        let suppress_reply = self.suppress_current_network_reply();
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        let _ = self.server.store.exists_no_touch(key, now_ms);
        let result = self.server.store.zmscore(key, members, now_ms);
        let elapsed_us = self.finish_chained_command(start);

        let mut error_msg = None;
        match result {
            Ok(scores) => {
                if !suppress_reply {
                    fr_protocol::encode_aggregate_header(scores.len(), false, out);
                    for score in scores {
                        match score {
                            Some(score) => fr_protocol::encode_redis_double(score, resp3, out),
                            None => encode_bulk_string_slice(None, resp3, out),
                        }
                    }
                }
            }
            Err(err) => {
                let reply = CommandError::Store(err).to_resp();
                if !suppress_reply {
                    if resp3 {
                        reply.encode_into_resp3(out);
                    } else {
                        reply.encode_into(out);
                    }
                }
                if let RespFrame::Error(msg) = reply {
                    error_msg = Some(msg);
                }
            }
        }
        let failed = error_msg.is_some();

        self.record_plain_zmscore_borrowed_metrics(
            key, members, elapsed_us, now_ms, packet_id, failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let Some(msg) = error_msg {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(())
    }

