    /// Shared core for the four no-flag `*3 key time` expiry-set commands. Mirrors
    /// the generic expire_like(kind) + no-option apply_expiry_with_options EXACTLY:
    /// the same per-kind overflow validation, the same i128 deadline
    /// (deadline_from_expire_kind), then pttl_no_stats (missing yields 0) followed
    /// by store.expire_at_milliseconds, which handles delete-on-past, dirty, and
    /// the "del" keyspace event. Returns None (defers to the generic, no side
    /// effects) on a malformed / out-of-range time so the canonical "value is not
    /// an integer" / "invalid expire time in '<cmd>' command" error is emitted
    /// there, and on any flagged form (the recognizer matches only argc 3). Gated
    /// by the WRITE predicate, so propagation, AOF, keyspace events, and tracking
    /// are provably inactive.
    fn execute_plain_expire_kind_borrowed(
        &mut self,
        kind: PlainExpireKind,
        key: &[u8],
        time_arg: &[u8],
        cond_token: Option<&[u8]>,
        now_ms: u64,
    ) -> Option<RespFrame> {
        let name_upper = kind.name_upper();
        if self.policy.gate.max_array_len < 3
            || self.policy.gate.max_bulk_len < name_upper.len()
            || key.len() > self.policy.gate.max_bulk_len
        {
            return None;
        }
        if !self.plain_borrowed_default_key_write_allows(now_ms) {
            return None;
        }
        // A single NX|XX|GT|LT condition token (matching parse_expire_options for one
        // option). Any unknown/other token defers to the generic path for the exact
        // "Unsupported option" error; multi-option and conflict cases are *5+ packets
        // the recognizer never matches, so they fall through too.
        let (nx, xx, gt, lt) = match cond_token {
            None => (false, false, false, false),
            Some(t) if t.eq_ignore_ascii_case(b"NX") => (true, false, false, false),
            Some(t) if t.eq_ignore_ascii_case(b"XX") => (false, true, false, false),
            Some(t) if t.eq_ignore_ascii_case(b"GT") => (false, false, true, false),
            Some(t) if t.eq_ignore_ascii_case(b"LT") => (false, false, false, true),
            Some(_) => return None,
        };
        // Same validation as expire_like(kind); defer on any failure for exact errors.
        let raw_time = parse_i64_arg(time_arg).ok()?;
        kind.validated_when_ms(raw_time, now_ms)?; // overflow -> defer ("invalid expire time")
        let when_ms_i128 = kind.deadline_ms_i128(raw_time, now_ms);

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str(kind.name_lower());
        self.session.last_argv_len_sum =
            name_upper.len() + key.len() + time_arg.len() + cond_token.map_or(0, <[u8]>::len);
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        // Mirror fr_command::apply_expiry_with_options exactly (NX/XX/GT/LT use the
        // non-counting PTTL so the comparison read does not bump keyspace_hits).
        let applied = {
            let current_remaining_ms = match self.server.store.pttl_no_stats(key, now_ms) {
                fr_store::PttlValue::KeyMissing => None,
                fr_store::PttlValue::NoExpiry => Some(None),
                fr_store::PttlValue::Remaining(ms) => Some(Some(ms)),
            };
            match current_remaining_ms {
                None => false, // key missing
                Some(remaining) => 'apply: {
                    if nx && remaining.is_some() {
                        break 'apply false;
                    }
                    if xx && remaining.is_none() {
                        break 'apply false;
                    }
                    if gt {
                        let Some(rem) = remaining else {
                            break 'apply false;
                        };
                        let cur = i128::from(now_ms).saturating_add(i128::from(rem));
                        if when_ms_i128 <= cur {
                            break 'apply false;
                        }
                    }
                    if lt && let Some(rem) = remaining {
                        let cur = i128::from(now_ms).saturating_add(i128::from(rem));
                        if when_ms_i128 >= cur {
                            break 'apply false;
                        }
                    }
                    self.server.store.expire_at_milliseconds(
                        key,
                        clamp_i128_to_i64_runtime(when_ms_i128),
                        now_ms,
                    )
                }
            }
        };
        let elapsed_us = self.finish_chained_command(start);
        let reply = RespFrame::Integer(i64::from(applied));

        self.record_plain_expire_borrowed_metrics(
            kind, key, time_arg, cond_token, elapsed_us, now_ms, packet_id,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        Some(reply)
    }

    #[allow(clippy::too_many_arguments)]
    fn record_plain_expire_borrowed_metrics(
        &mut self,
        kind: PlainExpireKind,
        key: &[u8],
        time_arg: &[u8],
        cond_token: Option<&[u8]>,
        elapsed_us: u64,
        now_ms: u64,
        packet_id: u64,
    ) {
        let name_upper = kind.name_upper();
        let mut argv: Option<Vec<Vec<u8>>> = None;
        if self.server.store.slowlog_log_slower_than_us >= 0
            && (elapsed_us as i64) >= self.server.store.slowlog_log_slower_than_us
        {
            let argv_ref = argv.get_or_insert_with(|| {
                plain_expire_owned_argv(name_upper, key, time_arg, cond_token)
            });
            self.record_slowlog(argv_ref, elapsed_us, now_ms);
        }

        let threshold_ms = self.server.store.latency_tracker.threshold_ms;
        let duration_ms = elapsed_us.div_ceil(1000);
        if threshold_ms != 0 && duration_ms > threshold_ms {
            let argv_ref = argv.get_or_insert_with(|| {
                plain_expire_owned_argv(name_upper, key, time_arg, cond_token)
            });
            self.server
                .record_latency_sample(argv_ref, elapsed_us, now_ms);
        }

        if self.server.latency_tracking {
            self.server
                .store
                .record_command_histogram_canonical_with_kind(
                    kind.name_lower(),
                    elapsed_us,
                    CommandRecordKind::Success,
                );
        }

        if elapsed_us > (self.server.command_time_budget_ms * 1000) {
            let argv_ref = argv.get_or_insert_with(|| {
                plain_expire_owned_argv(name_upper, key, time_arg, cond_token)
            });
            self.record_threat_event(ThreatEventInput {
                now_ms,
                packet_id,
                threat_class: ThreatClass::ResourceExhaustion,
                preferred_deviation: Some(HardenedDeviationCategory::ResourceClamp),
                subsystem: "router",
                action: "slow_command_detected",
                reason_code: "command_time_budget_exceeded",
                reason: format!(
                    "command '{}' took {elapsed_us}us, exceeding budget {}ms",
                    String::from_utf8_lossy(name_upper),
                    self.server.command_time_budget_ms
                ),
                input_source: ThreatInputDigestSource::Argv(argv_ref),
                output: &RespFrame::Integer(0),
            });
        }
    }

