        let offset = parse_i64_arg(offset_arg).ok()?;
        if !(0..4_294_967_296).contains(&offset) {
            return None;
        }
        let bit = parse_i64_arg(value_arg).ok()?;
        if bit != 0 && bit != 1 {
            return None;
        }

