    /// (frankenredis-hincrbyfloatfast) Conservative borrowed WRITE fast path for
    /// `HINCRBYFLOAT key field increment`. Mirrors the generic hincrbyfloat EXACTLY:
    /// parse the increment via the shared `parse_f64_arg` (f80 long-double fallback),
    /// defer on a non-float so the canonical "value is not a valid float" is emitted
    /// there; defer on a NaN/Inf increment so the generic's pre-lookup "value is NaN
    /// or Infinity" is emitted; then `store.hincrbyfloat_text` (f80 text path) →
    /// BulkString(new), with the HINCRBYFLOAT-SPECIFIC error mapping (IncrFloatNaN →
    /// "value is NaN or Infinity", ValueNotFloat → "hash value is not a float", else
    /// CommandError::Store). Gated by the WRITE predicate.
    pub fn execute_plain_hincrbyfloat_borrowed(
        &mut self,
        key: &[u8],
        field: &[u8],
        increment_arg: &[u8],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if !self.can_execute_plain_hincrbyfloat_borrowed(key, field, now_ms) {
            return None;
        }
        let delta = match parse_f64_arg(increment_arg) {
            Ok(v) => v,
            Err(_) if fr_store::long_double_text_is_valid(increment_arg) => 0.0,
            Err(_) => return None,
        };
        if delta.is_nan() || delta.is_infinite() {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("hincrbyfloat");
        self.session.last_argv_len_sum =
            b"HINCRBYFLOAT".len() + key.len() + field.len() + increment_arg.len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        let result = self
            .server
            .store
            .hincrbyfloat_text(key, field, increment_arg, delta, now_ms);
        let elapsed_us = self.finish_chained_command(start);
        let reply = match result {
            Ok(text) => RespFrame::BulkString(Some(text)),
            Err(fr_store::StoreError::IncrFloatNaN) => {
                RespFrame::Error("ERR value is NaN or Infinity".to_string())
            }
            Err(fr_store::StoreError::ValueNotFloat) => {
                RespFrame::Error("ERR hash value is not a float".to_string())
            }
            Err(err) => CommandError::Store(err).to_resp(),
        };
        let failed = matches!(reply, RespFrame::Error(_));

        self.record_plain_hincrbyfloat_borrowed_metrics(
            key,
            field,
            increment_arg,
            elapsed_us,
            now_ms,
            packet_id,
            failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let RespFrame::Error(msg) = &reply {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(reply)
    }

