    fn can_execute_plain_geopos_borrowed(
        &mut self,
        key: &[u8],
        members: &[&[u8]],
        now_ms: u64,
    ) -> bool {
        if members.is_empty()
            || self.policy.gate.max_array_len < members.len().saturating_add(2)
            || self.policy.gate.max_bulk_len < b"GEOPOS".len()
            || key.len() > self.policy.gate.max_bulk_len
            || members
                .iter()
                .any(|m| m.len() > self.policy.gate.max_bulk_len)
        {
            return false;
        }
        self.plain_borrowed_default_key_read_allows(now_ms)
    }

    /// Borrowed runtime fast path for `GEOPOS key member [member ...]` — mirrors
    /// the GEODIST fast path. Calls the SAME helpers the generic `geopos` uses
    /// (one `record_source_key_lookups` for the key, then no-stat `zmscore` for all
    /// members, then `geo_decode_score` / `geo_coord_frame`), so keyspace/LFU/LRU
    /// accounting and the reply bytes — including the RESP3 Double vs RESP2 bulk
    /// coordinate encoding via the connection's negotiated protocol — are identical
    /// to generic `geopos`. WRONGTYPE surfaces via the same `zmscore` error; a
    /// missing key/member yields the same nil array. Read-only: no
    /// dirty/propagation. Returns None (fall back) on any disabling state. (cc)
    /// (BlackThrush) Borrowed READ fast path for `GEOHASH key member [member ...]`.
    /// Mirrors execute_plain_geopos_borrowed (one keyspace lookup + no-stat zmscore
    /// for all members) but emits each member's 11-char base32 geohash via
    /// fr_command::geo_hash_string_from_score (nil for a missing member). This also
    /// records exactly ONE keyspace hit like redis (the generic GEOHASH path uses a
    /// per-member zscore that over-counts for multi-member — fixed here).
    /// (BlackThrush) Borrowed READ fast path for `XRANGE key start end [COUNT n]`.
    /// Streams were an entirely uncovered class. Parses the start/end range bounds
    /// and optional positive COUNT, then store.xrange + the same record emit as the
    /// generic (array of [id, [field, value ...]]). Defers to the generic on a
    /// malformed range bound (canonical error) and on COUNT <= 0 (the key-type-
    /// dependent null/empty/wrongtype reply), so only the clean common shape is
    /// fast-pathed.
    /// (BlackThrush) Borrowed fast path for `PUBLISH channel message`. PUBLISH is
    /// a RuntimeSpecialCommand normally; this intercepts the *3 form before the
    /// generic special-command routing. Under the plain write gate (no replicas EVER
    /// connected, no monitors/AOF/etc.) the replica-only propagation
    /// (capture_replication_only_record) is a provable no-op, so the fast path just
    /// delivers to local subscribers via pubsub_publish and returns the receiver
    /// count. Identical local delivery + count as handle_publish_command.
    /// (BlackThrush) Borrowed fast path for `SPUBLISH channel message` — the shard
    /// sibling of execute_plain_publish_borrowed. Same plain-write-gate no-op-repl
    /// basis; delivers to shard subscribers via pubsub_spublish and returns the count.
    /// (BlackThrush) Borrowed fast path for `WAIT numreplicas timeout`. WAIT is a
    /// non-blocking RuntimeSpecialCommand (handle_wait_command refreshes ack
    /// snapshots, evaluates, returns the acked-replica count — it does not block).
    /// Under the plain write gate (role = Primary, any_replica_ever_connected =
    /// false) there are no replica ack offsets, so evaluate_wait is deterministically
    /// 0. Validates both integer args, deferring malformed numreplicas (InvalidInteger)
    /// and malformed/negative timeout (the canonical timeout errors) to the generic
    /// path so the exact error + ordering is preserved; otherwise returns Integer(0).
    pub fn execute_plain_wait_borrowed(
        &mut self,
        numreplicas_arg: &[u8],
        timeout_arg: &[u8],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if self.policy.gate.max_bulk_len < b"WAIT".len()
            || numreplicas_arg.len() > self.policy.gate.max_bulk_len
            || timeout_arg.len() > self.policy.gate.max_bulk_len
        {
            return None;
        }
        if !self.plain_borrowed_default_key_write_allows(now_ms) {
            return None;
        }
        // Defer malformed numreplicas (InvalidInteger). CRITICAL: WAIT with
        // numreplicas > 0 BLOCKS until the timeout elapses or that many replicas ack —
        // only numreplicas <= 0 (0 required; handle_wait clamps negatives to 0) returns
        // immediately. Fast-path ONLY the immediate case; defer the blocking case to
        // the generic so its wait semantics are preserved.
        let num = parse_i64_arg(numreplicas_arg).ok()?;
        if num > 0 {
            return None;
        }
        // Defer malformed timeout (not-an-integer) and negative timeout (timeout is
        // negative) so the generic surfaces the exact error.
        let timeout = parse_i64_arg(timeout_arg).ok()?;
        if timeout < 0 {
            return None;
        }
        let argv_len_sum = b"WAIT".len() + numreplicas_arg.len() + timeout_arg.len();
        let packet_id = self.plain_zremrange_write_preamble("wait", argv_len_sum, now_ms);
        let st = self.chained_command_start();
        let elapsed_us = self.finish_chained_command(st);
        let reply = RespFrame::Integer(0);
        self.record_plain_zremrange_borrowed_metrics(
            "wait",
            "WAIT",
            || {
                vec![
                    b"WAIT".to_vec(),
                    numreplicas_arg.to_vec(),
                    timeout_arg.to_vec(),
                ]
            },
            elapsed_us,
            now_ms,
            packet_id,
            false,
        );
        Some(reply)
    }

