    /// (CrimsonHawk) Zero-copy `_into` fast path for single-key non-blocking `XREAD [COUNT n] STREAMS
    /// key id` — streams the entries' fields BORROWED into `out` via `xread_borrow_scan` (12.14x store
    /// A/B). RESP2 ONLY (declines RESP3 → generic emits the `%N` map form). Replicates the generic's
    /// TWO-phase keyspace accounting (`xlast_id` then `xread` = 2 hits per key, per frankenredis-lnglj)
    /// and its reply shape: no records ⇒ nil `*-1`; records ⇒ `*1 *2 <key> <entries>`. The id is
    /// resolved exactly as the generic (`$` → last id via `xlast_id`; `-`/`+`/`(`/bad → decline to
    /// generic; else `parse_stream_range_bound`).
    pub fn execute_plain_xread_single_borrowed_into(
        &mut self,
        key: &[u8],
        id_arg: &[u8],
        count_arg: Option<&[u8]>,
        now_ms: u64,
        resp3: bool,
        out: &mut Vec<u8>,
    ) -> Option<()> {
        if self.policy.gate.max_bulk_len < b"XREAD".len()
            || key.len() > self.policy.gate.max_bulk_len
            || id_arg.len() > self.policy.gate.max_bulk_len
            || count_arg.is_some_and(|c| c.len() > self.policy.gate.max_bulk_len)
        {
            return None;
        }
        if !self.plain_borrowed_default_key_read_allows(now_ms) {
            return None;
        }
        // Pre-validate the id (no side effects) so every declined form falls to generic byte-exact.
        let is_dollar = id_arg == b"$";
        if !is_dollar
            && (id_arg == b"-"
                || id_arg == b"+"
                || id_arg.first() == Some(&b'(')
                || fr_command::parse_stream_range_bound(id_arg, true).is_err())
        {
            return None;
        }
        let count = match count_arg {
            None => None,
            Some(c) => {
                let n = parse_i64_arg(c).ok()?;
                if n > 0 {
                    Some(usize::try_from(n).unwrap_or(usize::MAX))
                } else {
                    None
                }
            }
        };
        let argv_len_sum = b"XREAD".len()
            + count_arg.map_or(0, |c| b"COUNT".len() + c.len())
            + b"STREAMS".len()
            + key.len()
            + id_arg.len();
        let packet_id = self.plain_read_borrowed_preamble("xread", argv_len_sum, now_ms);
        let suppress_reply = self.suppress_current_network_reply();
        let st = self.chained_command_start();
        // Two-phase lookup (matches the generic: xlast_id then xread = 2 keyspace hits per key).
        let mut error_reply = None;
        match self.server.store.xlast_id(key, now_ms) {
            Ok(resolved_last) => {
                let cursor = if is_dollar {
                    resolved_last.unwrap_or((u64::MAX, u64::MAX))
                } else {
                    // Validated above; parse cannot fail here.
                    fr_command::parse_stream_range_bound(id_arg, true).unwrap_or((0, 0))
                };
                let result =
                    self.server
                        .store
                        .xread_borrow_scan(key, cursor, count, now_ms, |ev| {
                            if suppress_reply {
                                return;
                            }
                            match ev {
                                fr_store::XrangeReplyEvent::RecordCount(n) => {
                                    if n == 0 {
                                        // Empty XREAD ⇒ nil (`Array(None)`): `*-1` in RESP2, `_` in RESP3.
                                        out.extend_from_slice(if resp3 {
                                            b"_\r\n"
                                        } else {
                                            b"*-1\r\n"
                                        });
                                    } else if resp3 {
                                        // RESP3 map: `%1` + key + entries (no `*2` pair wrapper).
                                        fr_protocol::encode_map_header(1, true, out);
                                        fr_protocol::encode_bulk_string_slice(
                                            Some(key),
                                            false,
                                            out,
                                        );
                                        fr_protocol::encode_aggregate_header(n, false, out);
                                    } else {
                                        // RESP2 array-of-pairs: `*1` + `*2` + key + entries.
                                        out.extend_from_slice(b"*1\r\n*2\r\n");
                                        fr_protocol::encode_bulk_string_slice(
                                            Some(key),
                                            false,
                                            out,
                                        );
                                        fr_protocol::encode_aggregate_header(n, false, out);
                                    }
                                }
                                fr_store::XrangeReplyEvent::RecordStart(id, pairs) => {
                                    fr_protocol::encode_aggregate_header(2, false, out);
                                    let id_bytes = fr_command::format_stream_id(id);
                                    fr_protocol::encode_bulk_string_slice(
                                        Some(&id_bytes),
                                        false,
                                        out,
                                    );
                                    fr_protocol::encode_aggregate_header(pairs * 2, false, out);
                                }
                                fr_store::XrangeReplyEvent::Field(f) => {
                                    fr_protocol::encode_bulk_string_slice(Some(f), false, out);
                                }
                            }
                        });
                if let Err(err) = result {
                    let reply = CommandError::Store(err).to_resp();
                    if !suppress_reply {
                        reply.encode_into(out);
                    }
                    error_reply = Some(reply);
                }
            }
            Err(err) => {
                let reply = CommandError::Store(err).to_resp();
                if !suppress_reply {
                    reply.encode_into(out);
                }
                error_reply = Some(reply);
            }
        }
        let elapsed_us = self.finish_chained_command(st);
        let failed = error_reply.is_some();
        self.record_plain_zremrange_borrowed_metrics(
            "xread",
            "XREAD",
            || {
                let mut argv = vec![b"XREAD".to_vec()];
                if let Some(c) = count_arg {
                    argv.push(b"COUNT".to_vec());
                    argv.push(c.to_vec());
                }
                argv.push(b"STREAMS".to_vec());
                argv.push(key.to_vec());
                argv.push(id_arg.to_vec());
                argv
            },
            elapsed_us,
            now_ms,
            packet_id,
            failed,
        );
        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);
        if let Some(reply) = &error_reply {
            self.account_plain_borrowed_error_reply(reply);
        }
        Some(())
    }

    /// (CrimsonHawk) Zero-copy `_into` fast path for MULTI-key (2..=8) non-blocking `XREAD [COUNT n]
    /// STREAMS k1..km i1..im` — RESP2 only. Streams each key's entries' fields BORROWED into a per-key
    /// temp chunk, then assembles `[[key, entries], …]` (only keys WITH results; none ⇒ nil `*-1`),
    /// eliminating the per-field `to_pairs()` clone. Replicates the generic's TWO-PHASE lookup
    /// exactly: a RESOLUTION pass (`xlast_id` for every key, in order, resolving `$` and surfacing
    /// WRONGTYPE BEFORE any key is served — matching upstream's error-before-serve + hit ordering)
    /// then a SERVE pass (`xread_borrow_scan` per key) = 2 keyspace hits per key.
    pub fn execute_plain_xread_multi_borrowed_into(
        &mut self,
        keys: &[&[u8]],
        ids: &[&[u8]],
        count_arg: Option<&[u8]>,
        now_ms: u64,
        resp3: bool,
        out: &mut Vec<u8>,
    ) -> Option<()> {
        if self.policy.gate.max_bulk_len < b"XREAD".len()
            || keys.iter().any(|k| k.len() > self.policy.gate.max_bulk_len)
            || ids.iter().any(|i| i.len() > self.policy.gate.max_bulk_len)
            || count_arg.is_some_and(|c| c.len() > self.policy.gate.max_bulk_len)
        {
            return None;
        }
        if !self.plain_borrowed_default_key_read_allows(now_ms) {
            return None;
        }
        // Pre-validate EVERY id (no side effects) so any declined form defers the whole command.
        for &id_arg in ids {
            if id_arg != b"$"
                && (id_arg == b"-"
                    || id_arg == b"+"
                    || id_arg.first() == Some(&b'(')
                    || fr_command::parse_stream_range_bound(id_arg, true).is_err())
            {
                return None;
            }
        }
        let count = match count_arg {
            None => None,
            Some(c) => {
                let n = parse_i64_arg(c).ok()?;
                if n > 0 {
                    Some(usize::try_from(n).unwrap_or(usize::MAX))
                } else {
                    None
                }
            }
        };
        let mut argv_len_sum = b"XREAD".len() + b"STREAMS".len();
        if let Some(c) = count_arg {
            argv_len_sum += b"COUNT".len() + c.len();
        }
        for &k in keys {
            argv_len_sum += k.len();
        }
        for &i in ids {
            argv_len_sum += i.len();
        }
        let packet_id = self.plain_read_borrowed_preamble("xread", argv_len_sum, now_ms);
        let suppress_reply = self.suppress_current_network_reply();
        let st = self.chained_command_start();

        let mut error_reply: Option<RespFrame> = None;

        // Phase 1 — resolution: xlast_id for every key (hit 1 each), resolve `$`, surface WRONGTYPE
        // before serving any key (matching upstream's error-before-serve + hit ordering).
        let mut cursors: Vec<fr_store::StreamId> = Vec::with_capacity(keys.len());
        for (i, &key) in keys.iter().enumerate() {
            match self.server.store.xlast_id(key, now_ms) {
                Ok(resolved_last) => {
                    let cursor = if ids[i] == b"$" {
                        resolved_last.unwrap_or((u64::MAX, u64::MAX))
                    } else {
                        fr_command::parse_stream_range_bound(ids[i], true).unwrap_or((0, 0))
                    };
                    cursors.push(cursor);
                }
                Err(err) => {
                    error_reply = Some(CommandError::Store(err).to_resp());
                    break;
                }
            }
        }

        // Phase 2 — serve: xread_borrow_scan per key (hit 2 each) into a per-key temp chunk; keep only
        // keys WITH results.
        let mut chunks: Vec<Vec<u8>> = Vec::new();
        if error_reply.is_none() {
            for (i, &key) in keys.iter().enumerate() {
                let mut chunk: Vec<u8> = Vec::new();
                let mut has_records = false;
                let result =
                    self.server
                        .store
                        .xread_borrow_scan(key, cursors[i], count, now_ms, |ev| match ev {
                            fr_store::XrangeReplyEvent::RecordCount(n) => {
                                if n > 0 {
                                    has_records = true;
                                    // RESP2 wraps each stream as an `[key, entries]` *2 pair; the RESP3
                                    // map emits key then entries directly (no pair wrapper).
                                    if !resp3 {
                                        chunk.extend_from_slice(b"*2\r\n");
                                    }
                                    fr_protocol::encode_bulk_string_slice(
                                        Some(key),
                                        false,
                                        &mut chunk,
                                    );
                                    fr_protocol::encode_aggregate_header(n, false, &mut chunk);
                                }
                            }
                            fr_store::XrangeReplyEvent::RecordStart(id, pairs) => {
                                fr_protocol::encode_aggregate_header(2, false, &mut chunk);
                                let id_bytes = fr_command::format_stream_id(id);
                                fr_protocol::encode_bulk_string_slice(
                                    Some(&id_bytes),
                                    false,
                                    &mut chunk,
                                );
                                fr_protocol::encode_aggregate_header(pairs * 2, false, &mut chunk);
                            }
                            fr_store::XrangeReplyEvent::Field(f) => {
                                fr_protocol::encode_bulk_string_slice(Some(f), false, &mut chunk);
                            }
                        });
                match result {
                    Ok(()) => {
                        if has_records {
                            chunks.push(chunk);
                        }
                    }
                    Err(err) => {
                        // xlast_id already validated each key as stream/missing, so this is
                        // unreachable in practice; handle defensively to keep WRONGTYPE semantics.
                        error_reply = Some(CommandError::Store(err).to_resp());
                        break;
                    }
                }
            }
        }

        if !suppress_reply {
            if let Some(reply) = &error_reply {
                reply.encode_into(out);
            } else if chunks.is_empty() {
                // All requested streams empty ⇒ nil: `*-1` in RESP2, `_` in RESP3.
                out.extend_from_slice(if resp3 { b"_\r\n" } else { b"*-1\r\n" });
            } else {
                // RESP2 array of `[key, entries]` pairs; RESP3 map (`%N`) of key→entries.
                if resp3 {
                    fr_protocol::encode_map_header(chunks.len(), true, out);
                } else {
                    fr_protocol::encode_aggregate_header(chunks.len(), false, out);
                }
                for chunk in &chunks {
                    out.extend_from_slice(chunk);
                }
            }
        }
        let elapsed_us = self.finish_chained_command(st);
        let failed = error_reply.is_some();
        self.record_plain_zremrange_borrowed_metrics(
            "xread",
            "XREAD",
            || Self::xread_multi_argv(count_arg, keys, ids),
            elapsed_us,
            now_ms,
            packet_id,
            failed,
        );
        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);
        if let Some(reply) = &error_reply {
            self.account_plain_borrowed_error_reply(reply);
        }
        Some(())
    }

    fn xread_multi_argv(count_arg: Option<&[u8]>, keys: &[&[u8]], ids: &[&[u8]]) -> Vec<Vec<u8>> {
        let mut argv = vec![b"XREAD".to_vec()];
        if let Some(c) = count_arg {
            argv.push(b"COUNT".to_vec());
            argv.push(c.to_vec());
        }
        argv.push(b"STREAMS".to_vec());
        for &k in keys {
            argv.push(k.to_vec());
        }
        for &i in ids {
            argv.push(i.to_vec());
        }
        argv
    }

    /// (CrimsonHawk) Zero-copy `_into` fast path for single-key `XREADGROUP GROUP g c [COUNT n]
    /// STREAMS key <explicit-id>` — the HISTORY (re-read pending) read. Streams the consumer's PEL
    /// entries' fields BORROWED into `out` (3.17x store A/B). A no-stat eligibility gate
    /// (`xreadgroup_history_eligible`: stream + group + consumer + NO TTL) DECLINES every error / `>` /
    /// NOACK / missing case to the generic path byte+stats-exact; only the clean happy path is served.
    /// 2-hit accounting: `exists_no_touch` (resolution) + `xreadgroup_history_borrow_scan`
    /// (`record_keyspace_lookup`). History ALWAYS includes the stream (`[key, entries]`, entries maybe
    /// empty); tombstones (XDEL'd pending) render `[id, nil]`. RESP2 array-of-pairs / RESP3 `%1` map.
    #[allow(clippy::too_many_arguments)]
    pub fn execute_plain_xreadgroup_history_borrowed_into(
        &mut self,
        group: &[u8],
        consumer: &[u8],
        key: &[u8],
        id_arg: &[u8],
        count_arg: Option<&[u8]>,
        now_ms: u64,
        resp3: bool,
        out: &mut Vec<u8>,
    ) -> Option<()> {
        if self.policy.gate.max_bulk_len < b"XREADGROUP".len()
            || key.len() > self.policy.gate.max_bulk_len
            || group.len() > self.policy.gate.max_bulk_len
            || consumer.len() > self.policy.gate.max_bulk_len
            || id_arg.len() > self.policy.gate.max_bulk_len
            || count_arg.is_some_and(|c| c.len() > self.policy.gate.max_bulk_len)
        {
            return None;
        }
        if !self.plain_borrowed_default_key_read_allows(now_ms) {
            return None;
        }
        // Only the explicit-id HISTORY read; `>` (new-entries write path) + specials defer to generic.
        if id_arg == b">"
            || id_arg == b"-"
            || id_arg == b"+"
            || id_arg == b"$"
            || id_arg.first() == Some(&b'(')
        {
            return None;
        }
        let start_id = fr_command::parse_stream_range_bound(id_arg, true).ok()?;
        let count = match count_arg {
            None => None,
            Some(c) => {
                let n = parse_i64_arg(c).ok()?;
                if n > 0 {
                    Some(usize::try_from(n).unwrap_or(usize::MAX))
                } else {
                    None
                }
            }
        };
        // No-stat eligibility: decline everything but the clean happy path (→ generic byte+stats-exact).
        if !self
            .server
            .store
            .xreadgroup_history_eligible(key, group, consumer)
        {
            return None;
        }
        let argv_len_sum = b"XREADGROUP".len()
            + b"GROUP".len()
            + group.len()
            + consumer.len()
            + count_arg.map_or(0, |c| b"COUNT".len() + c.len())
            + b"STREAMS".len()
            + key.len()
            + id_arg.len();
        let packet_id = self.plain_read_borrowed_preamble("xreadgroup", argv_len_sum, now_ms);
        let suppress_reply = self.suppress_current_network_reply();
        let st = self.chained_command_start();
        // Resolution-loop lookup (hit 1); the borrow-scan's record_keyspace_lookup is hit 2.
        let _ = self.server.store.exists_no_touch(key, now_ms);
        self.server.store.xreadgroup_history_borrow_scan(
            key,
            group,
            consumer,
            start_id,
            count,
            now_ms,
            |ev| {
                if suppress_reply {
                    return;
                }
                match ev {
                    fr_store::XreadgroupHistEvent::RecordCount(n) => {
                        // History ALWAYS includes the stream (even empty ⇒ `[key, []]`).
                        if resp3 {
                            fr_protocol::encode_map_header(1, true, out);
                        } else {
                            out.extend_from_slice(b"*1\r\n*2\r\n");
                        }
                        fr_protocol::encode_bulk_string_slice(Some(key), false, out);
                        fr_protocol::encode_aggregate_header(n, false, out);
                    }
                    fr_store::XreadgroupHistEvent::RecordStart(id, pairs) => {
                        fr_protocol::encode_aggregate_header(2, false, out);
                        let id_bytes = fr_command::format_stream_id(id);
                        fr_protocol::encode_bulk_string_slice(Some(&id_bytes), false, out);
                        fr_protocol::encode_aggregate_header(pairs * 2, false, out);
                    }
                    fr_store::XreadgroupHistEvent::RecordStartNil(id) => {
                        fr_protocol::encode_aggregate_header(2, false, out);
                        let id_bytes = fr_command::format_stream_id(id);
                        fr_protocol::encode_bulk_string_slice(Some(&id_bytes), false, out);
                        // Tombstone value = nil array: `*-1` (RESP2) / `_` (RESP3).
                        out.extend_from_slice(if resp3 { b"_\r\n" } else { b"*-1\r\n" });
                    }
                    fr_store::XreadgroupHistEvent::Field(f) => {
                        fr_protocol::encode_bulk_string_slice(Some(f), false, out);
                    }
                }
            },
        );
        let elapsed_us = self.finish_chained_command(st);
        self.record_plain_zremrange_borrowed_metrics(
            "xreadgroup",
            "XREADGROUP",
            || {
                let mut argv = vec![
                    b"XREADGROUP".to_vec(),
                    b"GROUP".to_vec(),
                    group.to_vec(),
                    consumer.to_vec(),
                ];
                if let Some(c) = count_arg {
                    argv.push(b"COUNT".to_vec());
                    argv.push(c.to_vec());
                }
                argv.push(b"STREAMS".to_vec());
                argv.push(key.to_vec());
                argv.push(id_arg.to_vec());
                argv
            },
            elapsed_us,
            now_ms,
            packet_id,
            false,
        );
        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);
        Some(())
    }

    pub fn execute_plain_geohash_borrowed(
        &mut self,
        key: &[u8],
        members: &[&[u8]],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if !self.can_execute_plain_geopos_borrowed(key, members, now_ms) {
            return None;
        }
        let packet_id = self.plain_read_borrowed_preamble(
            "geohash",
            b"GEOHASH".len() + key.len() + members.iter().map(|m| m.len()).sum::<usize>(),
            now_ms,
        );
        let st = self.chained_command_start();
        fr_command::record_source_key_lookups(&mut self.server.store, &[key], now_ms);
        let reply = match self.server.store.zmscore(key, members, now_ms) {
            Ok(scores) => {
                let frames = scores
                    .into_iter()
                    .map(|score| match score {
                        Some(s) => RespFrame::BulkString(fr_command::geo_hash_string_from_score(s)),
                        None => RespFrame::BulkString(None),
                    })
                    .collect();
                RespFrame::Array(Some(frames))
            }
            Err(err) => CommandError::Store(err).to_resp(),
        };
        let elapsed_us = self.finish_chained_command(st);
        let failed = matches!(reply, RespFrame::Error(_));
        self.record_plain_zremrange_borrowed_metrics(
            "geohash",
            "GEOHASH",
            || {
                let mut argv = Vec::with_capacity(members.len() + 2);
                argv.push(b"GEOHASH".to_vec());
                argv.push(key.to_vec());
                argv.extend(members.iter().map(|m| m.to_vec()));
                argv
            },
            elapsed_us,
            now_ms,
            packet_id,
            failed,
        );
        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);
        self.account_plain_borrowed_error_reply(&reply);
        Some(reply)
    }

    pub fn execute_plain_geohash_single_borrowed_into(
        &mut self,
        key: &[u8],
        member: &[u8],
        now_ms: u64,
        resp3: bool,
        out: &mut Vec<u8>,
    ) -> Option<()> {
        if self.policy.gate.max_array_len < 3
            || self.policy.gate.max_bulk_len < b"GEOHASH".len()
            || key.len() > self.policy.gate.max_bulk_len
            || member.len() > self.policy.gate.max_bulk_len
            || !self.plain_borrowed_default_key_read_allows(now_ms)
        {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("geohash");
        self.session.last_argv_len_sum = b"GEOHASH".len() + key.len() + member.len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        let suppress_reply = self.suppress_current_network_reply();
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        let result = self.server.store.zscore(key, member, now_ms);
        let elapsed_us = self.finish_chained_command(start);
        let mut error_reply = None;
        match result {
            Ok(score) => {
                if !suppress_reply {
                    fr_protocol::encode_aggregate_header(1, false, out);
                    match score.and_then(fr_command::geo_hash_bytes_from_score) {
                        Some(hash) => encode_bulk_string_slice(Some(&hash), resp3, out),
                        None => encode_bulk_string_slice(None, resp3, out),
                    }
                }
            }
            Err(err) => {
                let reply = CommandError::Store(err).to_resp();
                if !suppress_reply {
                    if resp3 {
                        reply.encode_into_resp3(out);
                    } else {
                        reply.encode_into(out);
                    }
                }
                error_reply = Some(reply);
            }
        }
        let failed = error_reply.is_some();
        self.record_plain_zremrange_borrowed_metrics(
            "geohash",
            "GEOHASH",
            || vec![b"GEOHASH".to_vec(), key.to_vec(), member.to_vec()],
            elapsed_us,
            now_ms,
            packet_id,
            failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let Some(reply) = &error_reply {
            self.account_plain_borrowed_error_reply(reply);
        }

        Some(())
    }

    pub fn execute_plain_geopos_borrowed(
        &mut self,
        key: &[u8],
        members: &[&[u8]],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if !self.can_execute_plain_geopos_borrowed(key, members, now_ms) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("geopos");
        self.session.last_argv_len_sum =
            b"GEOPOS".len() + key.len() + members.iter().map(|m| m.len()).sum::<usize>();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let resp3 = self.session.resp_protocol_version == 3;
        let start = self.chained_command_start();
        // Mirror generic geopos: one keyspace lookup for the key, then no-stat
        // zmscore for all members.
        fr_command::record_source_key_lookups(&mut self.server.store, &[key], now_ms);
        let reply = match self.server.store.zmscore(key, members, now_ms) {
            Ok(scores) => {
                let frames = scores
                    .into_iter()
                    .map(|score| match score {
                        Some(s) => match fr_command::geo_decode_score(s) {
                            Some((lon, lat)) => RespFrame::Array(Some(vec![
                                fr_command::geo_coord_frame(lon, resp3),
                                fr_command::geo_coord_frame(lat, resp3),
                            ])),
                            None => RespFrame::Array(None),
                        },
                        None => RespFrame::Array(None),
                    })
                    .collect();
                RespFrame::Array(Some(frames))
            }
            Err(err) => CommandError::Store(err).to_resp(),
        };
        let elapsed_us = self.finish_chained_command(start);
        let failed = matches!(reply, RespFrame::Error(_));

        self.record_plain_geopos_borrowed_metrics(
            key, members, elapsed_us, now_ms, packet_id, failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let RespFrame::Error(msg) = &reply {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(reply)
    }

