    /// Parse a BITFIELD integer encoding `i<bits>`/`u<bits>` — copied byte-for-byte
    /// from the generic `bitfield_parse_encoding` so the fast path accepts EXACTLY
    /// the same encodings (any divergence returns None -> generic fallback).
    fn bitfield_fast_parse_encoding(arg: &[u8]) -> Option<(bool, u8)> {
        let s = std::str::from_utf8(arg).ok()?;
        if s.is_empty() {
            return None;
        }
        let (signed, rest) = if s.starts_with('i') || s.starts_with('I') {
            (true, &s[1..])
        } else if s.starts_with('u') || s.starts_with('U') {
            (false, &s[1..])
        } else {
            return None;
        };
        let bits: u8 = rest.parse().ok()?;
        if bits == 0 || (signed && bits > 64) || (!signed && bits > 63) {
            return None;
        }
        Some((signed, bits))
    }

    /// Parse a BITFIELD offset (`100` or `#5`) — copied from generic
    /// `bitfield_parse_offset` (same 512 MiB cap) for byte-identical acceptance.
    fn bitfield_fast_parse_offset(arg: &[u8], bits: u8) -> Option<u64> {
        const MAX_BIT_OFFSET_EXCLUSIVE: u64 = 512 * 1024 * 1024 * 8;
        let s = std::str::from_utf8(arg).ok()?;
        let offset = if let Some(rest) = s.strip_prefix('#') {
            let n: u64 = rest.parse().ok()?;
            n.checked_mul(u64::from(bits))?
        } else {
            s.parse::<u64>().ok()?
        };
        if offset >= MAX_BIT_OFFSET_EXCLUSIVE {
            return None;
        }
        Some(offset)
    }

    fn can_execute_plain_bitfield_get_borrowed(
        &mut self,
        cmd: PlainBitfieldGetCmd,
        key: &[u8],
        now_ms: u64,
    ) -> bool {
        if self.policy.gate.max_array_len < 5
            || self.policy.gate.max_bulk_len < cmd.name_upper().len()
            || key.len() > self.policy.gate.max_bulk_len
        {
            return false;
        }
        self.plain_borrowed_default_key_read_allows(now_ms)
    }

    fn can_execute_plain_bitfield_set_borrowed(&mut self, key: &[u8], now_ms: u64) -> bool {
        if self.policy.gate.max_array_len < 6
            || self.policy.gate.max_bulk_len < b"BITFIELD".len()
            || key.len() > self.policy.gate.max_bulk_len
        {
            return false;
        }
        self.plain_borrowed_default_key_write_allows(now_ms)
    }

    /// Borrowed runtime fast path for the hot single-op write form
    /// `BITFIELD key SET uN <offset> <value>` when the unsigned value is already
    /// in range for the field. Overflow modes, signed fields, INCRBY, OVERFLOW,
    /// multi-op commands, and invalid forms deliberately fall back to the generic
    /// BITFIELD handler, which owns those Redis edge semantics.
    pub fn execute_plain_bitfield_set_borrowed(
        &mut self,
        key: &[u8],
        set_arg: &[u8],
        enc_arg: &[u8],
        offset_arg: &[u8],
        value_arg: &[u8],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if !set_arg.eq_ignore_ascii_case(b"SET") {
            return None;
        }
        let (signed, bits) = Self::bitfield_fast_parse_encoding(enc_arg)?;
        if signed {
            return None;
        }
        let bit_offset = Self::bitfield_fast_parse_offset(offset_arg, bits)?;
        let value = parse_i64_arg(value_arg).ok()?;
        let max_value = if bits == 63 {
            i64::MAX
        } else {
            (1i64 << u32::from(bits)) - 1
        };
        if !(0..=max_value).contains(&value) {
            return None;
        }
        if !self.can_execute_plain_bitfield_set_borrowed(key, now_ms) {
            return None;
        }

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("bitfield");
        self.session.last_argv_len_sum = b"BITFIELD".len()
            + key.len()
            + set_arg.len()
            + enc_arg.len()
            + offset_arg.len()
            + value_arg.len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        let result = self
            .server
            .store
            .bitfield_set(key, bit_offset, bits, value, now_ms);
        let elapsed_us = self.finish_chained_command(start);
        let reply = match result {
            Ok(old) => RespFrame::Array(Some(vec![RespFrame::Integer(old)])),
            Err(err) => CommandError::Store(err).to_resp(),
        };
        let failed = matches!(reply, RespFrame::Error(_));

        self.record_plain_bitfield_set_borrowed_metrics(
            key, set_arg, enc_arg, offset_arg, value_arg, elapsed_us, now_ms, packet_id, failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let RespFrame::Error(msg) = &reply {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(reply)
    }

