    /// Borrowed fast path for the plain rank form `ZRANGE key start stop`.
    /// Most option-bearing shapes stay on generic dispatch so REV,
    /// BYSCORE/BYLEX, LIMIT, and their exact validation order remain canonical.
    /// The single hot rank `WITHSCORES` shape has its own direct encoder below.
    pub fn execute_plain_zrange_borrowed(
        &mut self,
        key: &[u8],
        start_arg: &[u8],
        stop_arg: &[u8],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if !self.can_execute_plain_zrange_borrowed(key, start_arg, stop_arg, now_ms) {
            return None;
        }
        let start_idx = fr_command::parse_i64_arg(start_arg).ok()?;
        let stop_idx = fr_command::parse_i64_arg(stop_arg).ok()?;

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("zrange");
        self.session.last_argv_len_sum =
            b"ZRANGE".len() + key.len() + start_arg.len() + stop_arg.len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let started = Instant::now();
        let result = self.server.store.zrange(key, start_idx, stop_idx, now_ms);
        let elapsed_us = started.elapsed().as_micros() as u64;
        let reply = match result {
            Ok(members) => RespFrame::Array(Some(
                members
                    .into_iter()
                    .map(|member| RespFrame::BulkString(Some(member)))
                    .collect(),
            )),
            Err(err) => CommandError::Store(err).to_resp(),
        };
        let failed = matches!(reply, RespFrame::Error(_));

        self.record_plain_zrange_borrowed_metrics(
            key, start_arg, stop_arg, elapsed_us, now_ms, packet_id, failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let RespFrame::Error(msg) = &reply {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(reply)
    }

    /// (frankenredis-zrange-into) `_into` form of [`Self::execute_plain_zrange_borrowed`]
    /// for the hot plain `ZRANGE key start stop` (no WITHSCORES): streams the `*N`
    /// member-only array straight into `out` via [`Store::zrange_borrow_scan`]
    /// instead of building an owned `RespFrame::Array` from `Store::zrange` (which
    /// clones every member into a `Vec<u8>` and allocates N `RespFrame`s). The
    /// member clone is the dominant cost — a store-level probe measured 2.6-4.6x on
    /// the member-copy work, with no large-offset regression (the borrow walk's
    /// linear skip beats the adaptive treap-seek + clone even at start=N/2). A
    /// plain member array is byte-identical in RESP2/RESP3, so no `resp3` param is
    /// needed (as with the LRANGE `_into`). Same gate / metrics / wrong-type
    /// handling as `execute_plain_zrange_borrowed`; the old owned form stays for the
    /// cold generic-args caller. Returns `None` (fall back) on any disabling state.
    pub fn execute_plain_zrange_borrowed_into(
        &mut self,
        key: &[u8],
        start_arg: &[u8],
        stop_arg: &[u8],
        now_ms: u64,
        out: &mut Vec<u8>,
    ) -> Option<()> {
        if !self.can_execute_plain_zrange_borrowed(key, start_arg, stop_arg, now_ms) {
            return None;
        }
        let start_idx = fr_command::parse_i64_arg(start_arg).ok()?;
        let stop_idx = fr_command::parse_i64_arg(stop_arg).ok()?;

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("zrange");
        self.session.last_argv_len_sum =
            b"ZRANGE".len() + key.len() + start_arg.len() + stop_arg.len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        let suppress_reply = self.suppress_current_network_reply();
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let started = Instant::now();
        let result = self
            .server
            .store
            .zrange_borrow_scan(key, start_idx, stop_idx, now_ms, |ev| {
                if suppress_reply {
                    return;
                }
                match ev {
                    fr_store::SmembersScanEvent::Len(n) => {
                        fr_protocol::encode_aggregate_header(n, false, out);
                    }
                    fr_store::SmembersScanEvent::Member(m) => {
                        fr_protocol::encode_bulk_string_slice(Some(m), false, out);
                    }
                }
            });
        let elapsed_us = started.elapsed().as_micros() as u64;
        let mut error_reply = None;
        if let Err(err) = result {
            let reply = CommandError::Store(err).to_resp();
            if !suppress_reply {
                reply.encode_into(out);
            }
            error_reply = Some(reply);
        }
        let failed = error_reply.is_some();

        self.record_plain_zrange_borrowed_metrics(
            key, start_arg, stop_arg, elapsed_us, now_ms, packet_id, failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let Some(RespFrame::Error(msg)) = &error_reply {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(())
    }

    /// Direct-encoding twin for the hot rank form
    /// `ZRANGE key start stop WITHSCORES`. It preserves rank-only validation and
    /// store semantics while avoiding one score `String` / score `RespFrame` per
    /// returned member-score pair on the network fast path.
    pub fn execute_plain_zrange_withscores_borrowed_into(
        &mut self,
        key: &[u8],
        start_arg: &[u8],
        stop_arg: &[u8],
        now_ms: u64,
        resp3: bool,
        out: &mut Vec<u8>,
    ) -> Option<()> {
        if !self.can_execute_plain_zrange_borrowed(key, start_arg, stop_arg, now_ms)
            || self.policy.gate.max_array_len < 5
            || self.policy.gate.max_bulk_len < b"WITHSCORES".len()
        {
            return None;
        }
        let start_idx = fr_command::parse_i64_arg(start_arg).ok()?;
        let stop_idx = fr_command::parse_i64_arg(stop_arg).ok()?;

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("zrange");
        self.session.last_argv_len_sum =
            b"ZRANGE".len() + key.len() + start_arg.len() + stop_arg.len() + b"WITHSCORES".len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        let suppress_reply = self.suppress_current_network_reply();
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let started = Instant::now();
        // (frankenredis-zrange-into) Stream borrowed (member, score) pairs directly
        // into `out` — the `zrange_withscores` owned form cloned every member into
        // `Vec<(Vec<u8>, f64)>`. Byte-identical framing: RESP3 emits an `*N` array
        // of `[member,double]` pairs (Len(N) header + a 2-header per pair); RESP2
        // emits a flat `*(N*2)` array (Len·2 header, member then double per pair).
        let result = self.server.store.zrange_withscores_borrow_scan(
            key,
            start_idx,
            stop_idx,
            now_ms,
            |ev| {
                if suppress_reply {
                    return;
                }
                match ev {
                    fr_store::ZRangeWithScoresScanEvent::Len(n) => {
                        let entries = if resp3 { n } else { n * 2 };
                        fr_protocol::encode_aggregate_header(entries, false, out);
                    }
                    fr_store::ZRangeWithScoresScanEvent::Pair(member, score) => {
                        if resp3 {
                            fr_protocol::encode_aggregate_header(2, false, out);
                        }
                        encode_bulk_string_slice(Some(member), resp3, out);
                        fr_protocol::encode_redis_double(score, resp3, out);
                    }
                }
            },
        );
        let elapsed_us = started.elapsed().as_micros() as u64;

        let mut error_msg = None;
        if let Err(err) = result {
            let reply = CommandError::Store(err).to_resp();
            if !suppress_reply {
                if resp3 {
                    reply.encode_into_resp3(out);
                } else {
                    reply.encode_into(out);
                }
            }
            if let RespFrame::Error(msg) = reply {
                error_msg = Some(msg);
            }
        }
        let failed = error_msg.is_some();

        self.record_plain_zrange_withscores_borrowed_metrics(
            key, start_arg, stop_arg, elapsed_us, now_ms, packet_id, failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let Some(msg) = error_msg {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(())
    }

    /// (frankenredis-zrange-into) Borrowed READ fast path for the canonical
