    fn can_execute_plain_incrby_borrowed(
        &mut self,
        key: &[u8],
        delta_arg: &[u8],
        now_ms: u64,
    ) -> bool {
        if self.policy.gate.max_array_len < 3
            || self.policy.gate.max_bulk_len < b"INCRBY".len()
            || key.len() > self.policy.gate.max_bulk_len
            || delta_arg.len() > self.policy.gate.max_bulk_len
        {
            return false;
        }
        self.plain_borrowed_default_key_write_allows(now_ms)
    }

    /// Conservative borrowed runtime fast path for `INCRBY key delta`: mirrors
    /// `execute_plain_incr_borrowed` (write path) with a parsed delta. Engages
    /// ONLY for a well-formed integer delta; a non-integer delta returns None so
    /// the generic path emits the identical "not an integer" error (and stats).
    /// Returns the new value, or WRONGTYPE / not-an-integer / overflow error,
    /// exactly like the generic handler. Returns None on any disabling state.
    /// (frankenredis-q0qym)
    pub fn execute_plain_incrby_borrowed(
        &mut self,
        key: &[u8],
        delta_arg: &[u8],
        now_ms: u64,
    ) -> Option<RespFrame> {
        if !self.can_execute_plain_incrby_borrowed(key, delta_arg, now_ms) {
            return None;
        }
        // Only fast-path a well-formed integer delta; defer the not-an-integer
        // error (and its stats) to the generic path.
        let delta = parse_i64_arg(delta_arg).ok()?;

        self.server.store.stat_total_commands_processed += 1;
        if self.session.connected_at_ms == 0 {
            self.session.connected_at_ms = now_ms;
        }
        self.session.last_interaction_ms = self.session.last_interaction_ms.max(now_ms);
        self.session.last_command_name.clear();
        self.session.last_command_name.push_str("incrby");
        self.session.last_argv_len_sum = b"INCRBY".len() + key.len() + delta_arg.len();
        let packet_id = next_packet_id();

        self.apply_existing_client_reply_suppression_to_undispatched_reply();
        self.server.last_eviction_loop = None;
        let _ = self.run_active_expire_cycle(now_ms, ActiveExpireCycleKind::Fast);

        let start = self.chained_command_start();
        let result = self.server.store.incrby(key, delta, now_ms);
        let elapsed_us = self.finish_chained_command(start);
        let reply = match result {
            Ok(value) => RespFrame::Integer(value),
            Err(err) => CommandError::Store(err).to_resp(),
        };
        let failed = matches!(reply, RespFrame::Error(_));

        self.record_plain_incrby_borrowed_metrics(
            key, delta_arg, elapsed_us, now_ms, packet_id, failed,
        );

        let lazy_evicted = self.server.store.take_lazy_expired_propagation();
        self.server.propagate_expired_key_deletions(&lazy_evicted);

        if let RespFrame::Error(msg) = &reply {
            self.server.store.stat_total_error_replies += 1;
            if self.execution_source.counts_as_unexpected_error_reply() {
                self.server.store.stat_unexpected_error_replies += 1;
            }
            if let Some(code) = msg.split(|c: char| c.is_ascii_whitespace()).next()
                && !code.is_empty()
            {
                *self
                    .server
                    .store
                    .errorstats_per_type
                    .entry(code.to_string())
                    .or_insert(0) += 1;
            }
        }

        Some(reply)
    }

