    use std::time::Instant;

    #[test]
    fn replconf_option_classifier_matches_owned_reference() {
        use super::{Runtime, classify_replconf_option, classify_replconf_option_owned_reference};

        for option in [
            b"ACK".as_slice(),
            b"ack",
            b"FaCk",
            b"GETACK",
            b"getack",
            b"LISTENING-PORT",
            b"listening-port",
            b"IP-ADDRESS",
            b"ip-address",
            b"CAPA",
            b"capa",
            b"unknown",
            b"",
            b"\xffACK",
        ] {
            assert_eq!(
                classify_replconf_option(option),
                classify_replconf_option_owned_reference(option),
                "option={option:?}",
            );
        }
        for byte in 0_u8..=u8::MAX {
            let option = [byte];
            assert_eq!(
                classify_replconf_option(&option),
                classify_replconf_option_owned_reference(&option),
                "single byte={byte:#04x}",
            );
        }

        let mut state = 0x9e37_79b9_7f4a_7c15_u64;
        for len in 0..=20 {
            for _ in 0..2_000 {
                let mut option = vec![0_u8; len];
                for byte in &mut option {
                    state ^= state << 13;
                    state ^= state >> 7;
                    state ^= state << 17;
                    *byte = state as u8;
                }
                assert_eq!(
                    classify_replconf_option(&option),
                    classify_replconf_option_owned_reference(&option),
                    "generated option={option:?}",
                );
            }
        }

        let mut runtime = Runtime::default_strict();
        let invalid_utf8 = [0xff];
        let argv: [&[u8]; 3] = [b"REPLCONF", &invalid_utf8, b"value"];
        assert_eq!(
            runtime.execute_frame(command(&argv), 0),
            fr_protocol::RespFrame::Error("ERR Unrecognized REPLCONF option: �".to_string()),
        );
    }

    #[test]
    fn replica_ack_snapshot_capacity_reuse_matches_owned_reference() {
        use super::{ReplOffset, ServerState};

        fn seed_replicas(server: &mut ServerState, count: usize) {
            server.replication_runtime_state.replicas.clear();
            for index in 0..count {
                let replica = server
                    .replication_runtime_state
                    .ensure_replica(index as u64);
                replica.ack_offset = ReplOffset((index as u64).wrapping_mul(17).wrapping_add(3));
                replica.fsync_offset = ReplOffset((index as u64).wrapping_mul(29).wrapping_add(5));
            }
        }

        let mut server = ServerState::default();
        for count in [0, 1, 8, 64] {
            seed_replicas(&mut server, count);
            server.replication_ack_state.replica_ack_offsets = vec![ReplOffset(u64::MAX); 5];
            server.replication_ack_state.replica_fsync_offsets = vec![ReplOffset(u64::MAX); 7];
            server.refresh_replica_ack_snapshots_owned_reference();
            let expected = server.replication_ack_state.clone();

            server.replication_ack_state.replica_ack_offsets = vec![ReplOffset(u64::MAX); 3];
            server.replication_ack_state.replica_fsync_offsets = vec![ReplOffset(u64::MAX); 4];
            server.refresh_replica_ack_snapshots_reusing_capacity();
            assert_eq!(
                server.replication_ack_state, expected,
                "replica_count={count}"
            );
        }

        seed_replicas(&mut server, 64);
        server.refresh_replica_ack_snapshots_reusing_capacity();
        let ack_pointer = server.replication_ack_state.replica_ack_offsets.as_ptr();
        let fsync_pointer = server.replication_ack_state.replica_fsync_offsets.as_ptr();
        let ack_capacity = server.replication_ack_state.replica_ack_offsets.capacity();
        let fsync_capacity = server
            .replication_ack_state
            .replica_fsync_offsets
            .capacity();

        for count in [8, 0, 64] {
            seed_replicas(&mut server, count);
            let expected_ack = server.replication_runtime_state.replica_ack_offsets();
            let expected_fsync = server.replication_runtime_state.replica_fsync_offsets();
            server.refresh_replica_ack_snapshots_reusing_capacity();
            assert_eq!(
                server.replication_ack_state.replica_ack_offsets,
                expected_ack
            );
            assert_eq!(
                server.replication_ack_state.replica_fsync_offsets,
                expected_fsync
            );
            assert_eq!(
                server.replication_ack_state.replica_ack_offsets.as_ptr(),
                ack_pointer
            );
            assert_eq!(
                server.replication_ack_state.replica_fsync_offsets.as_ptr(),
                fsync_pointer
            );
            assert_eq!(
                server.replication_ack_state.replica_ack_offsets.capacity(),
                ack_capacity
            );
            assert_eq!(
                server
                    .replication_ack_state
                    .replica_fsync_offsets
                    .capacity(),
                fsync_capacity
            );
        }
    }

    // (CrimsonHawk) The SSCAN/HSCAN borrow `_into` extend-past-cursor-0 strict cursor parse accepts
    // ONLY clean canonical base-10 u64s and declines everything the generic `parse_scan_cursor`
    // would treat differently (leading zeros, sign, non-digits, overflow) so declined forms fall to
    // the generic path byte-identically.
    #[test]
    fn parse_canonical_scan_cursor_accepts_only_clean_u64() {
        use super::Runtime;
        assert_eq!(Runtime::parse_canonical_scan_cursor(b"0"), Some(0));
        assert_eq!(Runtime::parse_canonical_scan_cursor(b"10"), Some(10));
        assert_eq!(Runtime::parse_canonical_scan_cursor(b"255"), Some(255));
        assert_eq!(
            Runtime::parse_canonical_scan_cursor(b"18446744073709551615"),
            Some(u64::MAX)
        );
        // Declined → generic handles these (byte-identical routing).
        for bad in [
            b"".as_slice(),
            b"007",
            b"00",
            b"+5",
            b"-1",
            b"1a",
            b" 5",
            b"5 ",
            b"0x10",
            b"18446744073709551616", // u64::MAX + 1 (overflow)
        ] {
            assert_eq!(
                Runtime::parse_canonical_scan_cursor(bad),
                None,
                "expected decline for {bad:?}"
            );
        }
    }

    // (frankenredis-b8z6y) Client-tracking invalidation dedup: the new
    // push-all-then-dedup-once (O(K)) helper must produce a byte-identical list to
    // the old per-add O(K) linear-rescan dedup (each distinct key once, in
    // first-seen order), across randomized inputs with duplicates; pinned by a
    // golden fingerprint. Plus a Score microbench (old O(K^2) vs new O(K)) on a
    // large all-distinct list (the worst case the quadratic hit).
    #[test]
    fn dedup_keys_preserve_order_isomorphic_and_faster_b8z6y() {
        use super::dedup_keys_preserve_order;

        // The old behavior: O(K) linear `iter().any(== key)` rescan per push.
        fn old_inline_dedup(keys: &[Vec<u8>]) -> Vec<Vec<u8>> {
            let mut out: Vec<Vec<u8>> = Vec::new();
            for k in keys {
                if !out.iter().any(|existing| existing == k) {
                    out.push(k.clone());
                }
            }
            out
        }

        let mut st: u64 = 0x0CAFE1234BEEF567;
        let mut next = || {
            st ^= st << 13;
            st ^= st >> 7;
            st ^= st << 17;
            st
        };
        let mut golden: u64 = 0xcbf2_9ce4_8422_2325;
        let fnv = |g: &mut u64, b: &[u8]| {
            for &byte in b {
                *g ^= u64::from(byte);
                *g = g.wrapping_mul(0x0000_0100_0000_01b3);
            }
        };
        for _ in 0..3000 {
            // Small alphabet of keys forces frequent duplicates.
            let n = (next() % 40) as usize;
            let keys: Vec<Vec<u8>> = (0..n)
                .map(|_| format!("k{}", next() % 12).into_bytes())
                .collect();
            let got = dedup_keys_preserve_order(keys.clone());
            assert_eq!(got, old_inline_dedup(&keys), "dedup mismatch keys={keys:?}");
            for k in &got {
                fnv(&mut golden, k);
            }
            fnv(&mut golden, &[0xFF]);
        }
        // Edge cases.
        assert_eq!(dedup_keys_preserve_order(vec![]), Vec::<Vec<u8>>::new());
        assert_eq!(
            dedup_keys_preserve_order(vec![b"a".to_vec()]),
            vec![b"a".to_vec()]
        );
        assert_eq!(
            dedup_keys_preserve_order(vec![
                b"a".to_vec(),
                b"a".to_vec(),
                b"b".to_vec(),
                b"a".to_vec()
            ]),
            vec![b"a".to_vec(), b"b".to_vec()]
        );
        assert_eq!(
            golden, 0x11f7_6ac9_0a1f_4b31,
            "dedup output fingerprint changed: {golden:#018x}"
        );

        if cfg!(debug_assertions) {
            return;
        }
        // Score: all-distinct K-key list — old O(K^2) linear dedup vs new O(K).
        let big: Vec<Vec<u8>> = (0..20_000u32)
            .map(|i| format!("key:{i:06}").into_bytes())
            .collect();
        let reps = 20;
        let t0 = Instant::now();
        let mut acc = 0usize;
        for _ in 0..reps {
            acc = acc.wrapping_add(old_inline_dedup(&big).len());
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(acc);
        let t1 = Instant::now();
        let mut acc2 = 0usize;
        for _ in 0..reps {
            acc2 = acc2.wrapping_add(dedup_keys_preserve_order(big.clone()).len());
        }
        let new_ns = t1.elapsed().as_nanos().max(1);
        std::hint::black_box(acc2);
        assert_eq!(acc, acc2, "old/new disagree on deduped count");
        let score = old_ns as f64 / new_ns as f64;
        eprintln!("B8Z6Y dedup 20k distinct keys: old={old_ns}ns new={new_ns}ns score={score:.2}x");
        assert!(
            score >= 2.0,
            "O(K) dedup must be >=2.0x vs O(K^2); got {score:.2}x"
        );
    }

