    fn command(parts: &[&[u8]]) -> RespFrame {
        RespFrame::Array(Some(
            parts
                .iter()
                .map(|part| RespFrame::BulkString(Some((*part).to_vec())))
                .collect(),
        ))
    }

    fn command_owned(parts: Vec<Vec<u8>>) -> RespFrame {
        RespFrame::Array(Some(
            parts
                .into_iter()
                .map(|part| RespFrame::BulkString(Some(part)))
                .collect(),
        ))
    }

    fn frame_wire_bytes(frame: &RespFrame, resp3: bool) -> Vec<u8> {
        let mut bytes = Vec::new();
        if resp3 {
            frame.encode_into_resp3(&mut bytes);
        } else {
            frame.encode_into(&mut bytes);
        }
        bytes
    }

    /// Remove every appendonlydir artifact for `basename` in `dir` (the single
    /// file, the manifest, and all `<basename>.<seq>.base.rdb`/`.incr.aof`), so a
    /// fixed-dir AOF test never inherits a prior run's files. The appendonlydir
    /// layout (frankenredis-oe6qt) writes multiple files into a reused temp dir,
    /// so cleaning only the legacy single file is no longer enough.
    /// (frankenredis-5jpn9)
    fn clean_aof_artifacts(dir: &std::path::Path, basename: &str) {
        if let Ok(entries) = std::fs::read_dir(dir) {
            for entry in entries.flatten() {
                if let Some(name) = entry.file_name().to_str()
                    && name.starts_with(basename)
                {
                    let _ = std::fs::remove_file(entry.path());
                }
            }
        }
    }

    fn parse_all_resp_frames(bytes: &[u8]) -> Vec<RespFrame> {
        let mut frames = Vec::new();
        let mut offset = 0;
        while offset < bytes.len() {
            let parsed = parse_frame(&bytes[offset..]).expect("runtime output must be valid RESP");
            assert!(
                parsed.consumed > 0,
                "runtime output parser must make progress"
            );
            offset += parsed.consumed;
            frames.push(parsed.frame);
        }
        frames
    }

    fn argv(parts: &[&[u8]]) -> Vec<Vec<u8>> {
        parts.iter().map(|part| (*part).to_vec()).collect()
    }

    #[test]
    fn plain_set_borrowed_fast_path_is_disabled_when_aof_is_configured() {
        let mut rt = Runtime::default_strict();
        rt.set_aof_path(std::path::PathBuf::from("appendonly.aof"));

        assert_eq!(rt.execute_plain_set_borrowed(b"aof-key", b"value", 1), None);
        assert!(rt.aof_records().is_empty());
        assert_eq!(
            rt.execute_frame(command(&[b"GET", b"aof-key"]), 2),
            RespFrame::BulkString(None)
        );

        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"aof-key", b"value"]), 3),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.aof_records()
                .last()
                .expect("generic SET captures AOF")
                .argv,
            argv(&[b"SET", b"aof-key", b"value"])
        );
    }

    #[test]
    fn plain_set_keepttl_borrowed_fast_path_matches_generic_ttl_and_missing() {
        let mut fast = Runtime::default_strict();
        let mut generic = Runtime::default_strict();

        for rt in [&mut fast, &mut generic] {
            assert_eq!(
                rt.execute_frame(command(&[b"SET", b"hot", b"old", b"PX", b"5000"]), 10),
                RespFrame::SimpleString("OK".to_string())
            );
        }

        let gate = fast.plain_borrowed_default_key_write_gate(20);
        let fast_reply = fast
            .execute_plain_set_keepttl_borrowed(b"hot", b"new", 20, gate)
            .expect("borrowed SET KEEPTTL should engage");
        let generic_reply =
            generic.execute_frame(command(&[b"SET", b"hot", b"new", b"KEEPTTL"]), 20);
        assert_eq!(fast_reply, generic_reply);
        assert_eq!(fast_reply, RespFrame::SimpleString("OK".to_string()));
        assert_eq!(
            fast.execute_frame(command(&[b"GET", b"hot"]), 21),
            generic.execute_frame(command(&[b"GET", b"hot"]), 21)
        );
        assert_eq!(
            fast.server.store.get_expires_at_ms(b"hot", 21),
            generic.server.store.get_expires_at_ms(b"hot", 21)
        );
        assert_eq!(fast.server.store.dirty, generic.server.store.dirty);
        assert_eq!(
            fast.server.store.state_digest(),
            generic.server.store.state_digest()
        );

        let gate = fast.plain_borrowed_default_key_write_gate(30);
        let fast_reply = fast
            .execute_plain_set_keepttl_borrowed(b"missing", b"value", 30, gate)
            .expect("borrowed SET KEEPTTL miss should engage");
        let generic_reply =
            generic.execute_frame(command(&[b"SET", b"missing", b"value", b"KEEPTTL"]), 30);
        assert_eq!(fast_reply, generic_reply);
        assert_eq!(
            fast.server.store.get_expires_at_ms(b"missing", 31),
            generic.server.store.get_expires_at_ms(b"missing", 31)
        );
        assert_eq!(
            fast.execute_frame(command(&[b"GET", b"missing"]), 31),
            generic.execute_frame(command(&[b"GET", b"missing"]), 31)
        );
        assert_eq!(fast.server.store.dirty, generic.server.store.dirty);
        assert_eq!(
            fast.server.store.state_digest(),
            generic.server.store.state_digest()
        );
    }

    #[test]
    fn plain_set_keepttl_get_borrowed_matches_generic_hit_miss_and_wrongtype() {
        let mut fast = Runtime::default_strict();
        let mut generic = Runtime::default_strict();

        for rt in [&mut fast, &mut generic] {
            assert_eq!(
                rt.execute_frame(
                    command(&[b"SET", b"hot", b"old heap payload", b"PX", b"5000"]),
                    10,
                ),
                RespFrame::SimpleString("OK".to_string())
            );
        }

        let fast_reply = fast
            .execute_plain_set_opt_get_borrowed(
                b"hot",
                b"new heap payload",
                b"KEEPTTL",
                20,
            )
            .expect("borrowed SET KEEPTTL GET should engage");
        let generic_reply = generic.execute_frame(
            command(&[
                b"SET",
                b"hot",
                b"new heap payload",
                b"KEEPTTL",
                b"GET",
            ]),
            20,
        );
        assert_eq!(fast_reply, generic_reply);
        assert_eq!(
            fast_reply,
            RespFrame::BulkString(Some(b"old heap payload".to_vec()))
        );
        assert_eq!(
            fast.server.store.get_expires_at_ms(b"hot", 21),
            generic.server.store.get_expires_at_ms(b"hot", 21)
        );

        let fast_reply = fast
            .execute_plain_set_opt_get_borrowed(b"missing", b"value", b"KEEPTTL", 30)
            .expect("borrowed SET KEEPTTL GET miss should engage");
        let generic_reply = generic.execute_frame(
            command(&[b"SET", b"missing", b"value", b"KEEPTTL", b"GET"]),
            30,
        );
        assert_eq!(fast_reply, generic_reply);
        assert_eq!(fast_reply, RespFrame::BulkString(None));

        for rt in [&mut fast, &mut generic] {
            assert_eq!(
                rt.execute_frame(command(&[b"LPUSH", b"list", b"old"]), 40),
                RespFrame::Integer(1)
            );
        }
        let fast_reply = fast
            .execute_plain_set_opt_get_borrowed(b"list", b"new", b"KEEPTTL", 50)
            .expect("borrowed SET KEEPTTL GET wrongtype should engage");
        let generic_reply = generic.execute_frame(
            command(&[b"SET", b"list", b"new", b"KEEPTTL", b"GET"]),
            50,
        );
        assert_eq!(fast_reply, generic_reply);
        assert!(matches!(
            fast_reply,
            RespFrame::Error(ref message) if message.starts_with("WRONGTYPE")
        ));
        assert_eq!(
            fast.server.store.stat_keyspace_hits,
            generic.server.store.stat_keyspace_hits
        );
        assert_eq!(
            fast.server.store.stat_keyspace_misses,
            generic.server.store.stat_keyspace_misses
        );
        assert_eq!(fast.server.store.dirty, generic.server.store.dirty);
        assert_eq!(
            fast.server.store.state_digest(),
            generic.server.store.state_digest()
        );
    }

