    #[test]
    fn plain_bitcount_ranged_borrowed_matches_generic() {
        // (frankenredis-bitcountrange) BITCOUNT key start end [BYTE|BIT] borrow ==
        // generic dispatch across every shape: argc 4 (BYTE-default) and argc 5
        // (explicit BYTE/BIT), positive/negative/reversed indices, missing key,
        // wrong-type, empty string, and the deferral cases (bad integer, bad unit,
        // upstream's fully-negative reversed-range early-return-0). The fast path
        // and generic path are driven on twin runtimes and compared reply + the
        // keyspace/error stat trio after every op.
        let mut direct = Runtime::default_strict();
        let mut generic = Runtime::default_strict();
        for rt in [&mut direct, &mut generic] {
            rt.execute_frame(command(&[b"SET", b"s", b"foobar"]), 1);
            rt.execute_frame(command(&[b"SET", b"empty", b""]), 1);
            rt.execute_frame(command(&[b"RPUSH", b"l", b"x"]), 1);
        }
        // (key, range-as-trailing-args) tuples that exercise the recognized argc
        // 4/5 forms; each engages and must equal generic byte-for-byte.
        let engage: &[(&[u8], &[&[u8]])] = &[
            (b"s", &[b"0", b"0"]),
            (b"s", &[b"1", b"1"]),
            (b"s", &[b"0", b"-1"]),
            (b"s", &[b"0", b"0", b"BYTE"]),
            (b"s", &[b"5", b"30", b"BIT"]),
            (b"s", &[b"0", b"-1", b"BIT"]),
            (b"s", &[b"-100", b"-1", b"byte"]),
            (b"empty", &[b"0", b"-1"]),
            (b"empty", &[b"0", b"0", b"BIT"]),
            (b"missing", &[b"0", b"-1", b"BYTE"]),
            (b"l", &[b"0", b"-1"]),
            (b"l", &[b"0", b"0", b"BIT"]),
            // fully-negative reversed range: upstream early-returns 0 (argc 5)
            (b"s", &[b"-1", b"-2", b"BYTE"]),
            (b"s", &[b"-1", b"-2", b"BIT"]),
        ];
        let mut ts = 2u64;
        for (key, tail) in engage {
            let range = match tail {
                [s, e] => Some((*s, *e, None)),
                [s, e, u] => Some((*s, *e, Some(*u))),
                _ => unreachable!(),
            };
            let f = direct
                .execute_plain_bitcount_borrowed(key, range, ts)
                .expect("ranged bitcount fast path should engage");
            let mut argv = vec![b"BITCOUNT".to_vec(), key.to_vec()];
            argv.extend(tail.iter().map(|a| a.to_vec()));
            let g = generic.execute_frame(command_owned(argv), ts);
            assert_eq!(f, g, "engage key={key:?} tail={tail:?}");
            ts += 1;
        }
        // Deferral cases: the fast path must return None (no side effects) so the
        // generic path produces the canonical error / early-return reply. Drive
        // BOTH paths' deferral through generic on each runtime to keep stats in
        // lockstep, then assert the recognizer declines.
        let defer: &[(&[u8], &[&[u8]])] = &[
            (b"s", &[b"nan", b"0", b"BYTE"]),  // bad start integer
            (b"s", &[b"0", b"nan", b"BIT"]),   // bad end integer
            (b"s", &[b"0", b"0", b"NEITHER"]), // bad unit -> SyntaxError
            (b"missing", &[b"nan", b"0"]),     // missing key short-circuits to 0
        ];
        for (key, tail) in defer {
            let range = match tail {
                [s, e] => Some((*s, *e, None)),
                [s, e, u] => Some((*s, *e, Some(*u))),
                _ => unreachable!(),
            };
            assert!(
                direct
                    .execute_plain_bitcount_borrowed(key, range, ts)
                    .is_none(),
                "ranged bitcount fast path must defer key={key:?} tail={tail:?}"
            );
            let mut argv = vec![b"BITCOUNT".to_vec(), key.to_vec()];
            argv.extend(tail.iter().map(|a| a.to_vec()));
            let f = direct.execute_frame(command_owned(argv.clone()), ts);
            let g = generic.execute_frame(command_owned(argv), ts);
            assert_eq!(f, g, "defer key={key:?} tail={tail:?}");
            ts += 1;
        }
        assert_eq!(
            direct.server.store.stat_keyspace_hits,
            generic.server.store.stat_keyspace_hits
        );
        assert_eq!(
            direct.server.store.stat_keyspace_misses,
            generic.server.store.stat_keyspace_misses
        );
        assert_eq!(
            direct.server.store.stat_total_error_replies,
            generic.server.store.stat_total_error_replies
        );
    }

    #[test]
    fn plain_expire_borrowed_matches_generic() {
        // (cold-cmd audit) EXPIRE key seconds (no-flag) borrow == generic: set on
        // existing key (1) with matching TTL, missing key (0), past deadline
        // deletes the key (1, then gone), and defers on malformed/overflow values.
        // Run the SAME ops on two runtimes and compare reply + resulting state.
        let mut direct = Runtime::default_strict();
        let mut generic = Runtime::default_strict();
        for rt in [&mut direct, &mut generic] {
            rt.execute_frame(command(&[b"SET", b"a", b"v"]), 1000);
            rt.execute_frame(command(&[b"SET", b"b", b"v"]), 1000);
            rt.execute_frame(command(&[b"SET", b"gone", b"v"]), 1000);
        }
        // existing key, positive TTL
        assert_eq!(
            direct.execute_plain_expire_borrowed(b"a", b"100", 1000),
            Some(RespFrame::Integer(1))
        );
        assert_eq!(
            generic.execute_frame(command(&[b"EXPIRE", b"b", b"100"]), 1000),
            RespFrame::Integer(1)
        );
        // resulting TTL identical (a via fast path, b via generic, same input)
        assert_eq!(
            direct.execute_frame(command(&[b"PTTL", b"a"]), 1000),
            generic.execute_frame(command(&[b"PTTL", b"b"]), 1000)
        );
        // missing key -> 0
        assert_eq!(
            direct.execute_plain_expire_borrowed(b"missing", b"100", 1000),
            Some(RespFrame::Integer(0))
        );
        // past deadline (negative seconds) deletes the key and returns 1
        assert_eq!(
            direct.execute_plain_expire_borrowed(b"gone", b"-1", 1000),
            Some(RespFrame::Integer(1))
        );
        assert_eq!(
            direct.execute_frame(command(&[b"EXISTS", b"gone"]), 1000),
            RespFrame::Integer(0)
        );
        // defer: malformed seconds, and overflow
        assert!(
            direct
                .execute_plain_expire_borrowed(b"a", b"notnum", 1000)
                .is_none()
        );
        assert!(
            direct
                .execute_plain_expire_borrowed(b"a", b"9999999999999999999", 1000)
                .is_none()
        );
        // flagged form is rejected by the fr-server recognizer (argc 3 only).
    }

    #[test]
    fn plain_getset_borrowed_into_matches_generic() {
        let cases: &[(&[u8], &[u8], bool)] = &[
            (b"s", &[b'x'; 4096], false),
            (b"n", b"4321", false),
            (b"missing", b"", false),
            (b"l", b"", true),
        ];

        for (ts, (key, value, list_key)) in (2..).zip(cases.iter().copied()) {
            let mut direct = Runtime::default_strict();
            let mut generic = Runtime::default_strict();
            for rt in [&mut direct, &mut generic] {
                if list_key {
                    rt.execute_frame(command(&[b"RPUSH", key, b"a"]), 1);
                } else if !value.is_empty() {
                    rt.execute_frame(command(&[b"SET", key, value]), 1);
                }
            }

            let mut got = Vec::new();
            direct
                .execute_plain_getset_borrowed_into(key, b"new", ts, false, &mut got)
                .expect("getset _into fast path should engage");
            let mut want = Vec::new();
            generic
                .execute_frame(command(&[b"GETSET", key, b"new"]), ts)
                .encode_into(&mut want);
            assert_eq!(got, want, "encoded GETSET reply for key={key:?}");
            assert_eq!(
                direct.execute_frame(command(&[b"GET", key]), ts),
                generic.execute_frame(command(&[b"GET", key]), ts),
                "post-state for key={key:?}"
            );
            assert_eq!(direct.server.store.dirty, generic.server.store.dirty);
            assert_eq!(
                direct.server.store.stat_keyspace_hits,
                generic.server.store.stat_keyspace_hits
            );
            assert_eq!(
                direct.server.store.stat_keyspace_misses,
                generic.server.store.stat_keyspace_misses
            );
            assert_eq!(
                direct.server.store.stat_total_error_replies,
                generic.server.store.stat_total_error_replies
            );
        }
    }

    #[test]
    fn plain_rpoplpush_borrowed_into_matches_generic() {
        for (case, resp3) in [
            ("distinct", false),
            ("rotate", false),
            ("missing", true),
            ("wrongtype", false),
        ] {
            let mut direct = Runtime::default_strict();
            let mut generic = Runtime::default_strict();
            for runtime in [&mut direct, &mut generic] {
                let large = vec![b'x'; 4096];
                runtime.execute_frame(
                    command_owned(vec![
                        b"RPUSH".to_vec(),
                        b"src".to_vec(),
                        b"a".to_vec(),
                        large,
                    ]),
                    1,
                );
                runtime.execute_frame(command(&[b"RPUSH", b"dst", b"z"]), 1);
                runtime.execute_frame(command(&[b"SET", b"str", b"value"]), 1);
            }

            let (src, dst) = match case {
                "distinct" => (b"src".as_slice(), b"dst".as_slice()),
                "rotate" => (b"src".as_slice(), b"src".as_slice()),
                "missing" => (b"absent".as_slice(), b"dst".as_slice()),
                "wrongtype" => (b"src".as_slice(), b"str".as_slice()),
                _ => unreachable!(),
            };
            let ts = 2;
            let mut got = Vec::new();
            direct
                .execute_plain_rpoplpush_borrowed_into(src, dst, ts, resp3, &mut got)
                .expect("rpoplpush _into fast path should engage");
            let reply = generic.execute_frame(command(&[b"RPOPLPUSH", src, dst]), ts);
            let mut want = Vec::new();
            if resp3 {
                reply.encode_into_resp3(&mut want);
            } else {
                reply.encode_into(&mut want);
            }
            assert_eq!(got, want, "encoded RPOPLPUSH reply for {case}");

            for key in [b"src".as_slice(), b"dst".as_slice(), b"str".as_slice()] {
                assert_eq!(
                    direct.execute_frame(command(&[b"LRANGE", key, b"0", b"-1"]), ts),
                    generic.execute_frame(command(&[b"LRANGE", key, b"0", b"-1"]), ts),
                    "post-state for {case}, key={key:?}"
                );
            }
            assert_eq!(direct.server.store.dirty, generic.server.store.dirty);
            assert_eq!(
                direct.server.store.stat_total_error_replies,
                generic.server.store.stat_total_error_replies
            );
        }
    }

    #[test]
    fn plain_lmove_borrowed_into_matches_generic() {
        for (case, wherefrom, whereto, resp3) in [
            ("distinct_ll", b"LEFT".as_slice(), b"LEFT".as_slice(), false),
            ("distinct_lr", b"LEFT".as_slice(), b"RIGHT".as_slice(), false),
            ("rotate_rl", b"RIGHT".as_slice(), b"LEFT".as_slice(), false),
            ("rotate_rr", b"RIGHT".as_slice(), b"RIGHT".as_slice(), false),
            ("missing", b"RIGHT".as_slice(), b"LEFT".as_slice(), true),
            ("wrongtype", b"RIGHT".as_slice(), b"LEFT".as_slice(), false),
        ] {
            let mut direct = Runtime::default_strict();
            let mut generic = Runtime::default_strict();
            for runtime in [&mut direct, &mut generic] {
                let large = vec![b'x'; 4096];
                runtime.execute_frame(
                    command_owned(vec![
                        b"RPUSH".to_vec(),
                        b"src".to_vec(),
                        b"a".to_vec(),
                        large,
                    ]),
                    1,
                );
                runtime.execute_frame(command(&[b"RPUSH", b"dst", b"z"]), 1);
                runtime.execute_frame(command(&[b"SET", b"str", b"value"]), 1);
            }

            let src = if case == "missing" {
                b"absent".as_slice()
            } else {
                b"src".as_slice()
            };
            let dst = if case.starts_with("rotate") {
                b"src".as_slice()
            } else if case == "wrongtype" {
                b"str".as_slice()
            } else {
                b"dst".as_slice()
            };
            let ts = 2;
            let mut got = Vec::new();
            direct
                .execute_plain_lmove_borrowed_into(
                    src,
                    dst,
                    wherefrom,
                    whereto,
                    ts,
                    resp3,
                    &mut got,
                )
                .expect("LMOVE _into fast path should engage");
            let reply = generic.execute_frame(
                command(&[b"LMOVE", src, dst, wherefrom, whereto]),
                ts,
            );
            let mut want = Vec::new();
            if resp3 {
                reply.encode_into_resp3(&mut want);
            } else {
                reply.encode_into(&mut want);
            }
            assert_eq!(got, want, "encoded LMOVE reply for {case}");

            for key in [b"src".as_slice(), b"dst".as_slice(), b"str".as_slice()] {
                assert_eq!(
                    direct.execute_frame(command(&[b"LRANGE", key, b"0", b"-1"]), ts),
                    generic.execute_frame(command(&[b"LRANGE", key, b"0", b"-1"]), ts),
                    "post-state for {case}, key={key:?}"
                );
            }
            assert_eq!(direct.server.store.dirty, generic.server.store.dirty);
            assert_eq!(
                direct.server.store.stat_total_error_replies,
                generic.server.store.stat_total_error_replies
            );
        }

        let mut runtime = Runtime::default_strict();
        let mut out = Vec::new();
        assert!(
            runtime
                .execute_plain_lmove_borrowed_into(
                    b"src", b"dst", b"MIDDLE", b"LEFT", 1, false, &mut out,
                )
                .is_none()
        );
        assert!(out.is_empty());
    }

