    #[test]
    fn plain_echo_borrowed_into_matches_generic_bytes() {
        // (cold-cmd audit) ECHO message _into must write exactly the bytes generic
        // dispatch produces (a bulk string, protocol-invariant), for normal,
        // empty, and binary messages; RESP2 == RESP3.
        let mut direct = Runtime::default_strict();
        let mut generic = Runtime::default_strict();
        for msg in [b"hello".as_slice(), b"", b"\x00\xff\r\nx"] {
            for resp3 in [false, true] {
                let mut out = Vec::new();
                assert_eq!(
                    direct.execute_plain_echo_borrowed_into(msg, 2, resp3, &mut out),
                    Some(()),
                    "echo fast path should engage (resp3={resp3})"
                );
                let g = generic
                    .execute_frame(command(&[b"ECHO", msg]), 2)
                    .to_bytes();
                assert_eq!(out, g, "msg={msg:?} resp3={resp3}");
            }
        }
        assert_eq!(direct.session.last_command_name, "echo");
        assert_eq!(
            direct.server.store.stat_total_commands_processed,
            generic.server.store.stat_total_commands_processed
        );
    }

