    #[test]
    fn plain_incrby_borrowed_fast_path_matches_generic_and_defers_bad_int() {
        // (frankenredis-q0qym) INCRBY borrowed fast path == generic dispatch:
        // increments by N (incl negative), creates at delta, surfaces the same
        // errors, and DEFERS (None) on a non-integer delta so the generic path
        // emits the not-an-integer error.
        let mut fast = Runtime::default_strict();
        let mut generic = Runtime::default_strict();
        for rt in [&mut fast, &mut generic] {
            rt.execute_frame(command(&[b"SET", b"n", b"10"]), 1);
            rt.execute_frame(command(&[b"SET", b"big", b"9223372036854775807"]), 1);
            rt.execute_frame(command(&[b"SET", b"nan", b"abc"]), 1);
            rt.execute_frame(command(&[b"RPUSH", b"l", b"x"]), 1);
        }

        for (k, d) in [
            (b"n".as_slice(), b"5".as_slice()),
            (b"n", b"-3"),
            (b"fresh", b"7"),
            (b"fresh", b"-2"),
        ] {
            let f = fast
                .execute_plain_incrby_borrowed(k, d, 2)
                .expect("well-formed INCRBY should take fast path");
            let g = generic.execute_frame(command(&[b"INCRBY", k, d]), 2);
            assert_eq!(f, g, "k={k:?} d={d:?}");
        }

        // overflow / wrong-type / not-an-integer value -> same errors
        let ov = fast.execute_plain_incrby_borrowed(b"big", b"1", 3).unwrap();
        assert_eq!(
            ov,
            generic.execute_frame(command(&[b"INCRBY", b"big", b"1"]), 3)
        );
        assert!(matches!(ov, RespFrame::Error(_)));
        let wt = fast.execute_plain_incrby_borrowed(b"l", b"1", 4).unwrap();
        assert_eq!(
            wt,
            generic.execute_frame(command(&[b"INCRBY", b"l", b"1"]), 4)
        );
        assert!(matches!(wt, RespFrame::Error(_)));
        let nanv = fast.execute_plain_incrby_borrowed(b"nan", b"1", 5).unwrap();
        assert_eq!(
            nanv,
            generic.execute_frame(command(&[b"INCRBY", b"nan", b"1"]), 5)
        );
        assert!(matches!(nanv, RespFrame::Error(_)));

        // non-integer DELTA -> fast path defers (None), generic emits the error
        assert!(fast.execute_plain_incrby_borrowed(b"n", b"x", 6).is_none());

        assert_eq!(
            fast.execute_frame(command(&[b"GET", b"n"]), 7),
            generic.execute_frame(command(&[b"GET", b"n"]), 7)
        );
        assert_eq!(
            fast.server.store.stat_total_commands_processed,
            generic.server.store.stat_total_commands_processed
        );
        assert_eq!(
            fast.server.store.stat_total_writes_processed,
            generic.server.store.stat_total_writes_processed
        );
        assert_eq!(
            fast.server.store.stat_total_error_replies,
            generic.server.store.stat_total_error_replies
        );
    }

