    #[test]
    fn plain_getrange_borrowed_into_matches_generic_bytes() {
        // (frankenredis-5gisf) The borrow-encode GETRANGE _into path must write
        // EXACTLY the bytes generic dispatch produces, across every range case
        // (in-range / full / negative / inverted-empty / out-of-range), for a
        // missing key (empty bulk, not nil), and for a wrong-type key (WRONGTYPE
        // error). Bulk strings are protocol-invariant, so RESP2 and RESP3 must
        // also be byte-identical.
        let mut fast = Runtime::default_strict();
        let mut generic = Runtime::default_strict();
        for rt in [&mut fast, &mut generic] {
            rt.execute_frame(command(&[b"SET", b"s", b"Hello World"]), 1);
            rt.execute_frame(command(&[b"LPUSH", b"l", b"x"]), 1);
        }

        let cases: [(&[u8], &[u8]); 7] = [
            (b"0", b"4"),
            (b"0", b"-1"),
            (b"-5", b"-1"),
            (b"-1", b"-5"),    // inverted -> empty bulk
            (b"-100", b"-90"), // fully-negative clamp -> [0..=0]
            (b"100", b"200"),  // out of range -> empty bulk
            (b"6", b"6"),
        ];
        for (start, end) in cases {
            for resp3 in [false, true] {
                let mut out = Vec::new();
                assert_eq!(
                    fast.execute_plain_getrange_borrowed_into(b"s", start, end, 2, resp3, &mut out),
                    Some(()),
                    "well-formed GETRANGE should take _into fast path (start={start:?} end={end:?})"
                );
                let generic_bytes = generic
                    .execute_frame(command(&[b"GETRANGE", b"s", start, end]), 2)
                    .to_bytes();
                assert_eq!(
                    out, generic_bytes,
                    "start={start:?} end={end:?} resp3={resp3}"
                );
            }
        }

        // missing key -> empty bulk string (NOT nil)
        let mut miss = Vec::new();
        assert_eq!(
            fast.execute_plain_getrange_borrowed_into(b"nope", b"0", b"-1", 2, false, &mut miss),
            Some(())
        );
        assert_eq!(
            miss,
            generic
                .execute_frame(command(&[b"GETRANGE", b"nope", b"0", b"-1"]), 2)
                .to_bytes()
        );
        assert_eq!(miss, b"$0\r\n\r\n");

        // wrong-type key -> WRONGTYPE error written into out
        let mut wt = Vec::new();
        assert_eq!(
            fast.execute_plain_getrange_borrowed_into(b"l", b"0", b"-1", 3, false, &mut wt),
            Some(())
        );
        assert_eq!(
            wt,
            generic
                .execute_frame(command(&[b"GETRANGE", b"l", b"0", b"-1"]), 3)
                .to_bytes()
        );

        // non-integer arg -> defers to generic (None)
        let mut bad = Vec::new();
        assert!(
            fast.execute_plain_getrange_borrowed_into(b"s", b"x", b"4", 4, false, &mut bad)
                .is_none()
        );
        assert!(bad.is_empty());

        assert_eq!(
            fast.server.store.stat_total_commands_processed,
            generic.server.store.stat_total_commands_processed
        );
        assert_eq!(
            fast.server.store.stat_keyspace_hits,
            generic.server.store.stat_keyspace_hits
        );
        assert_eq!(
            fast.server.store.stat_total_error_replies,
            generic.server.store.stat_total_error_replies
        );
    }

    #[test]
    fn plain_hmget_borrowed_fast_path_matches_generic_mixed_and_wrongtype() {
        // (frankenredis-jbhwq) HMGET borrowed fast path == generic dispatch:
        // array of present/missing fields, nil array on a missing key, and a
        // WRONGTYPE error on a non-hash key.
        let mut fast = Runtime::default_strict();
        let mut generic = Runtime::default_strict();
        for rt in [&mut fast, &mut generic] {
            rt.execute_frame(command(&[b"HSET", b"h", b"f1", b"v1", b"f2", b"v2"]), 1);
            rt.execute_frame(command(&[b"SET", b"s", b"x"]), 1); // wrong type for HMGET
        }

        let f = fast
            .execute_plain_hmget_borrowed(b"h", &[b"f1", b"nope", b"f2"], 2)
            .expect("default HMGET should take borrowed fast path");
        let g = generic.execute_frame(command(&[b"HMGET", b"h", b"f1", b"nope", b"f2"]), 2);
        assert_eq!(f, g);
        assert_eq!(
            f,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"v1".to_vec())),
                RespFrame::BulkString(None),
                RespFrame::BulkString(Some(b"v2".to_vec())),
            ]))
        );

        let miss_key = fast
            .execute_plain_hmget_borrowed(b"nokey", &[b"f1", b"f2"], 3)
            .expect("missing-key HMGET should take borrowed fast path");
        assert_eq!(
            miss_key,
            generic.execute_frame(command(&[b"HMGET", b"nokey", b"f1", b"f2"]), 3)
        );
        assert_eq!(
            miss_key,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(None),
                RespFrame::BulkString(None),
            ]))
        );

        let wt = fast
            .execute_plain_hmget_borrowed(b"s", &[b"f1"], 4)
            .expect("wrong-type HMGET should take borrowed fast path");
        assert_eq!(
            wt,
            generic.execute_frame(command(&[b"HMGET", b"s", b"f1"]), 4)
        );
        assert!(matches!(wt, RespFrame::Error(_)));

        assert_eq!(
            fast.server.store.stat_total_commands_processed,
            generic.server.store.stat_total_commands_processed
        );
        assert_eq!(
            fast.server.store.stat_total_reads_processed,
            generic.server.store.stat_total_reads_processed
        );
        assert_eq!(
            fast.server.store.stat_keyspace_hits,
            generic.server.store.stat_keyspace_hits
        );
        assert_eq!(
            fast.server.store.stat_keyspace_misses,
            generic.server.store.stat_keyspace_misses
        );
        assert_eq!(
            fast.server.store.stat_total_error_replies,
            generic.server.store.stat_total_error_replies
        );
        assert_eq!(
            fast.server.store.stat_unexpected_error_replies,
            generic.server.store.stat_unexpected_error_replies
        );
        assert_eq!(
            fast.server.store.errorstats_per_type,
            generic.server.store.errorstats_per_type
        );
        assert_eq!(
            fast.session.last_command_name,
            generic.session.last_command_name
        );
        assert_eq!(
            fast.session.last_argv_len_sum,
            generic.session.last_argv_len_sum
        );
    }

