    #[test]
    fn plain_sintercard_borrowed_matches_generic_and_defers() {
        // (cold-cmd audit) SINTERCARD exact no-LIMIT and non-negative LIMIT forms
        // borrow == generic; invalid LIMIT / numkeys mismatch / bad numkeys defer.
        let mut direct = Runtime::default_strict();
        let mut generic = Runtime::default_strict();
        for rt in [&mut direct, &mut generic] {
            rt.execute_frame(command(&[b"SADD", b"a", b"1", b"2", b"3", b"4"]), 1);
            rt.execute_frame(command(&[b"SADD", b"b", b"2", b"3", b"5"]), 1);
            rt.execute_frame(command(&[b"SET", b"s", b"v"]), 1);
        }
        let mut ts = 2;
        // exact forms (tail = [numkeys, keys..., optional LIMIT count])
        let ok_tails: [&[&[u8]]; 7] = [
            &[b"2", b"a", b"b"],
            &[b"1", b"a"],
            &[b"2", b"a", b"missing"],
            &[b"1", b"s"], // wrong type
            &[b"2", b"a", b"b", b"LIMIT", b"1"],
            &[b"2", b"a", b"b", b"limit", b"0"],
            &[b"1", b"s", b"LIMIT", b"1"], // wrong type
        ];
        for tail in ok_tails {
            let f = direct
                .execute_plain_sintercard_borrowed(tail, ts)
                .expect("sintercard fast path");
            let g_argv: Vec<&[u8]> = std::iter::once(b"SINTERCARD".as_slice())
                .chain(tail.iter().copied())
                .collect();
            let g = generic.execute_frame(command(&g_argv), ts);
            assert_eq!(f, g, "tail={tail:?}");
            ts += 1;
        }
        // defer cases: malformed/negative LIMIT, numkeys mismatch, bad numkeys
        assert!(
            direct
                .execute_plain_sintercard_borrowed(&[b"2", b"a", b"b", b"LIMIT", b"-1"], ts)
                .is_none()
        );
        assert!(
            direct
                .execute_plain_sintercard_borrowed(&[b"2", b"a", b"b", b"LIMIT", b"x"], ts)
                .is_none()
        );
        assert!(
            direct
                .execute_plain_sintercard_borrowed(
                    &[b"2", b"a", b"b", b"LIMIT", b"1", b"LIMIT", b"2"],
                    ts,
                )
                .is_none()
        );
        assert!(
            direct
                .execute_plain_sintercard_borrowed(&[b"3", b"a", b"b"], ts)
                .is_none()
        );
        assert!(
            direct
                .execute_plain_sintercard_borrowed(&[b"0", b"a"], ts)
                .is_none()
        );
        assert_eq!(
            direct.server.store.stat_keyspace_hits,
            generic.server.store.stat_keyspace_hits
        );
        assert_eq!(
            direct.server.store.stat_keyspace_misses,
            generic.server.store.stat_keyspace_misses
        );
    }

    #[test]
    fn plain_zmscore_borrowed_matches_generic() {
        // (cold-cmd audit) ZMSCORE key m.. borrow == generic: per-member score /
        // nil array (RESP2 bulk + RESP3 double), missing key, wrong-type, stats.
        for resp3 in [false, true] {
            let mut direct = Runtime::default_strict();
            let mut generic = Runtime::default_strict();
            for rt in [&mut direct, &mut generic] {
                if resp3 {
                    rt.execute_frame(command(&[b"HELLO", b"3"]), 1);
                }
                rt.execute_frame(command(&[b"ZADD", b"z", b"1.5", b"a", b"2", b"b"]), 1);
                rt.execute_frame(command(&[b"SET", b"s", b"v"]), 1);
            }
            let cases: [(&[u8], &[&[u8]]); 4] = [
                (b"z", &[b"a", b"x", b"b"]),
                (b"z", &[b"a"]),
                (b"missing", &[b"a", b"b"]),
                (b"s", &[b"a"]),
            ];
            for (ts, (key, members)) in (2..).zip(cases) {
                let f = direct
                    .execute_plain_zmscore_borrowed(key, members, ts)
                    .expect("zmscore fast path");
                let g_argv: Vec<&[u8]> = std::iter::once(b"ZMSCORE".as_slice())
                    .chain(std::iter::once(key))
                    .chain(members.iter().copied())
                    .collect();
                let g = generic.execute_frame(command(&g_argv), ts);
                assert_eq!(f, g, "resp3={resp3} key={key:?} members={members:?}");
            }
            assert_eq!(
                direct.server.store.stat_keyspace_hits,
                generic.server.store.stat_keyspace_hits
            );
            assert_eq!(
                direct.server.store.stat_keyspace_misses,
                generic.server.store.stat_keyspace_misses
            );
        }
    }

