    #[test]
    fn plain_bitfield_ro_get_borrowed_matches_generic_and_keeps_command_identity() {
        let mut fast = Runtime::default_strict();
        let mut generic = Runtime::default_strict();
        let value = [0xA5_u8; 32];
        for rt in [&mut fast, &mut generic] {
            rt.execute_frame(command(&[b"SET", b"bf", &value]), 1);
        }

        let fast_reply = fast.execute_plain_bitfield_get_borrowed(
            PlainBitfieldGetCmd::BitfieldRo,
            b"bf",
            b"GET",
            b"u8",
            b"0",
            2,
        );
        assert!(
            fast_reply.is_some(),
            "BITFIELD_RO GET should take the borrowed fast path"
        );
        let Some(fast_reply) = fast_reply else {
            return;
        };
        let generic_reply =
            generic.execute_frame(command(&[b"BITFIELD_RO", b"bf", b"GET", b"u8", b"0"]), 2);

        assert_eq!(fast_reply, generic_reply);
        assert_eq!(fast.session.last_command_name, "bitfield_ro");
        assert_eq!(
            fast.session.last_command_name,
            generic.session.last_command_name
        );
        assert_eq!(
            fast.session.last_argv_len_sum,
            generic.session.last_argv_len_sum
        );
    }

    #[test]
    fn plain_bitfield_set_borrowed_matches_generic_for_unsigned_in_range() {
        let mut fast = Runtime::default_strict();
        let mut generic = Runtime::default_strict();
        let value = [0xA5_u8; 32];
        for rt in [&mut fast, &mut generic] {
            rt.execute_frame(command(&[b"SET", b"bf", &value]), 1);
        }

        let fast_reply =
            fast.execute_plain_bitfield_set_borrowed(b"bf", b"SET", b"u8", b"0", b"1", 2);
        assert!(
            fast_reply.is_some(),
            "BITFIELD SET should take the borrowed fast path"
        );
        let Some(fast_reply) = fast_reply else {
            return;
        };
        let generic_reply =
            generic.execute_frame(command(&[b"BITFIELD", b"bf", b"SET", b"u8", b"0", b"1"]), 2);
        assert_eq!(fast_reply, generic_reply);
        assert_eq!(fast.session.last_command_name, "bitfield");
        assert_eq!(
            fast.execute_frame(command(&[b"BITFIELD", b"bf", b"GET", b"u8", b"0"]), 3),
            generic.execute_frame(command(&[b"BITFIELD", b"bf", b"GET", b"u8", b"0"]), 3)
        );
        assert_eq!(fast.server.store.dirty, generic.server.store.dirty);
        assert_eq!(
            fast.server.store.stat_keyspace_hits,
            generic.server.store.stat_keyspace_hits
        );
        assert_eq!(
            fast.server.store.stat_keyspace_misses,
            generic.server.store.stat_keyspace_misses
        );

        assert!(
            fast.execute_plain_bitfield_set_borrowed(b"bf", b"SET", b"i8", b"0", b"1", 4)
                .is_none(),
            "signed SET stays on generic overflow/sign-extension logic"
        );
        assert!(
            fast.execute_plain_bitfield_set_borrowed(b"bf", b"SET", b"u8", b"0", b"-1", 4)
                .is_none(),
            "overflow/wrap SET stays on generic overflow logic"
        );
    }

    #[test]
    fn last_command_name_buffer_reuse_matches_reference_and_reports_ab_ratio() {
        use super::write_client_info_command_name;
        // Reference = the prior allocating implementation. (frankenredis-hackk)
        fn old_ref(argv: &[Vec<u8>]) -> String {
            let Some(command) = argv.first() else {
                return "NULL".to_string();
            };
            let command = String::from_utf8_lossy(command).to_ascii_lowercase();
            let Some(sub) = argv.get(1) else {
                return command;
            };
            let uses_subcommand = matches!(
                command.as_str(),
                "acl"
                    | "client"
                    | "cluster"
                    | "command"
                    | "config"
                    | "debug"
                    | "function"
                    | "latency"
                    | "memory"
                    | "module"
                    | "object"
                    | "pubsub"
                    | "script"
                    | "sentinel"
                    | "slowlog"
                    | "xgroup"
                    | "xinfo"
            );
            if !uses_subcommand {
                return command;
            }
            let sub = String::from_utf8_lossy(sub).to_ascii_lowercase();
            format!("{command}|{sub}")
        }
        let cases: Vec<Vec<Vec<u8>>> = vec![
            vec![],
            vec![b"GET".to_vec()],
            vec![b"set".to_vec(), b"k".to_vec()],
            vec![b"CONFIG".to_vec(), b"GET".to_vec()],
            vec![b"config".to_vec(), b"SET".to_vec(), b"x".to_vec()],
            vec![b"Client".to_vec(), b"SetName".to_vec()],
            vec![b"OBJECT".to_vec(), b"ENCODING".to_vec()],
            vec![b"XINFO".to_vec(), b"STREAM".to_vec()],
            vec![b"GET".to_vec(), b"k".to_vec()], // GET with arg: not a container
            vec![vec![0xff, 0xfe, b'A']],         // invalid UTF-8 fallback
            vec![b"acl".to_vec()],                // container without sub
            vec![b"MEMORY".to_vec(), vec![0xff, b'B']], // sub invalid UTF-8
        ];
        let mut buf = String::new();
        for argv in &cases {
            write_client_info_command_name(&mut buf, argv);
            assert_eq!(buf, old_ref(argv), "argv={argv:?}");
        }
        // Reuse keeps producing correct results across calls on the same buffer.
        for argv in &cases {
            write_client_info_command_name(&mut buf, argv);
            assert_eq!(buf, old_ref(argv));
        }

        // A/B: per-command name materialization — buffer reuse vs fresh String.
        let argv = vec![b"CONFIG".to_vec(), b"GET".to_vec()];
        let reps = 3_000_000usize;
        let t0 = std::time::Instant::now();
        let mut sink = 0usize;
        for _ in 0..reps {
            let s = old_ref(std::hint::black_box(&argv));
            sink = sink.wrapping_add(s.len());
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(sink);
        let mut b = String::new();
        let t1 = std::time::Instant::now();
        let mut sink2 = 0usize;
        for _ in 0..reps {
            write_client_info_command_name(&mut b, std::hint::black_box(&argv));
            sink2 = sink2.wrapping_add(b.len());
        }
        let new_ns = t1.elapsed().as_nanos().max(1);
        std::hint::black_box(sink2);
        let ratio = old_ns as f64 / new_ns as f64;
        println!(
            "last_command_name A/B (x{reps}): old(alloc)={old_ns}ns new(reuse)={new_ns}ns ratio={ratio:.2}x"
        );
    }

