    #[test]
    fn config_resetstat_clears_info_latencystats_histograms() {
        let mut rt = Runtime::default_strict();

        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"latency-tracking", b"yes"]),
                0,
            ),
            RespFrame::SimpleString("OK".to_string())
        );

        assert_eq!(
            rt.execute_frame(command(&[b"GET", b"missing"]), 1),
            RespFrame::BulkString(None)
        );

        let before_reset = rt.execute_frame(command(&[b"INFO", b"latencystats"]), 2);
        let RespFrame::BulkString(Some(before_reset_bytes)) = before_reset else {
            panic!("expected bulk info response");
        };
        let before_reset = String::from_utf8(before_reset_bytes).expect("utf8 info");
        // (frankenredis-6n2qm) Histogram keys are canonicalised to
        // lowercase at the recording site (mirroring upstream's
        // `cmd->fullname`), so Latencystats emits `_get:` not `_GET:`.
        assert!(
            before_reset.contains("latency_percentiles_usec_get:"),
            "before_reset:\n{before_reset}"
        );

        assert_eq!(
            rt.execute_frame(command(&[b"CONFIG", b"RESETSTAT"]), 3),
            RespFrame::SimpleString("OK".to_string())
        );

        let after_reset = rt.execute_frame(command(&[b"INFO", b"latencystats"]), 4);
        let RespFrame::BulkString(Some(after_reset_bytes)) = after_reset else {
            panic!("expected bulk info response");
        };
        let after_reset = String::from_utf8(after_reset_bytes).expect("utf8 info");
        assert!(
            !after_reset.contains("latency_percentiles_usec_get:"),
            "{after_reset}"
        );
    }

    #[test]
    fn info_commandstats_emits_per_command_call_counts() {
        // Pin upstream INFO commandstats parity (server.c::genRedisInfoStringCommandStats:5329-5353).
        // (frankenredis-ot3y) updated by frankenredis-infosections to use real
        // counters: calls / total_usec / usec_per_call / rejected_calls /
        // failed_calls all come from CommandHistogram now.
        let mut rt = Runtime::default_strict();

        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"latency-tracking", b"yes"]),
                0,
            ),
            RespFrame::SimpleString("OK".to_string())
        );

        for _ in 0..3 {
            rt.execute_frame(command(&[b"GET", b"missing"]), 1);
        }
        rt.execute_frame(command(&[b"SET", b"k", b"v"]), 1);

        let info = rt.execute_frame(command(&[b"INFO", b"commandstats"]), 2);
        let RespFrame::BulkString(Some(bytes)) = info else {
            panic!("expected bulk info response");
        };
        let body = String::from_utf8(bytes).expect("utf8 info");

        assert!(body.starts_with("# Commandstats\r\n"), "{body}");
        // Match the field shape — usec/usec_per_call are wall-clock
        // dependent, so check the discrete counters (calls/rejected/
        // failed) exactly and the variable middle via prefix+suffix.
        for line in body.lines() {
            if let Some(rest) = line.strip_prefix("cmdstat_get:") {
                assert!(rest.starts_with("calls=3,usec="), "{line}");
                assert!(rest.ends_with(",rejected_calls=0,failed_calls=0"), "{line}");
                assert!(rest.contains(",usec_per_call="), "{line}");
            }
            if let Some(rest) = line.strip_prefix("cmdstat_set:") {
                assert!(rest.starts_with("calls=1,usec="), "{line}");
                assert!(rest.ends_with(",rejected_calls=0,failed_calls=0"), "{line}");
                assert!(rest.contains(",usec_per_call="), "{line}");
            }
        }
        assert!(body.contains("cmdstat_get:"), "{body}");
        assert!(body.contains("cmdstat_set:"), "{body}");

        // Section omitted from default INFO; only present when requested or via all/everything.
        let default_info = rt.execute_frame(command(&[b"INFO"]), 3);
        let RespFrame::BulkString(Some(bytes)) = default_info else {
            panic!("expected bulk info response");
        };
        let default_body = String::from_utf8(bytes).expect("utf8 info");
        assert!(
            !default_body.contains("# Commandstats"),
            "default INFO should not include commandstats: {default_body}"
        );

        let all_info = rt.execute_frame(command(&[b"INFO", b"all"]), 4);
        let RespFrame::BulkString(Some(bytes)) = all_info else {
            panic!("expected bulk info response");
        };
        let all_body = String::from_utf8(bytes).expect("utf8 info");
        assert!(all_body.contains("# Commandstats"), "{all_body}");
    }

    #[test]
    fn info_under_resp3_includes_all_command_owned_sections() {
        // Regression (frankenredis-ffqgl follow-up): the INFO aggregator
        // delegates server/clients/memory/stats/cpu/modules/errorstats/
        // cluster to per-section INFO sub-calls. Under HELLO 3 those
        // sub-calls return a RESP3 Verbatim string, not a BulkString, so
        // an extract that only matched BulkString silently dropped every
        // fr-command-owned section — leaving RESP3 clients with just the
        // runtime-owned persistence/replication/keyspace trio.
        let mut rt = Runtime::default_strict();
        rt.execute_frame(command(&[b"HELLO", b"3"]), 0);

        let info = rt.execute_frame(command(&[b"INFO"]), 1);
        let body = match info {
            // RESP3 INFO is a Verbatim string.
            RespFrame::Verbatim(text) => text,
            other => panic!("expected verbatim info response under RESP3, got {other:?}"),
        };

        // Every default section, in upstream order, must be present.
        for section in [
            "# Server",
            "# Clients",
            "# Memory",
            "# Persistence",
            "# Stats",
            "# Replication",
            "# CPU",
            "# Modules",
            "# Errorstats",
            "# Cluster",
            "# Keyspace",
        ] {
            assert!(
                body.contains(section),
                "RESP3 default INFO missing {section}:\n{body}"
            );
        }
    }

    /// (frankenredis-rot3d) Mirror upstream server.c::processCommand —
    /// unknown commands are rejected via commandCheckExistence before
    /// call() runs, so they never bump SLOWLOG, INFO commandstats, or
    /// the latency histogram. Only errorstats / total_error_replies are
    /// incremented via the rejection path.
    #[test]
    fn unknown_commands_do_not_populate_slowlog_or_commandstats_rot3d() {
        let mut rt = Runtime::default_strict();

        // Enable latency tracking and SLOWLOG with a low threshold so any
        // command duration would normally land in slowlog.
        rt.execute_frame(
            command(&[b"CONFIG", b"SET", b"latency-tracking", b"yes"]),
            0,
        );
        rt.execute_frame(
            command(&[b"CONFIG", b"SET", b"slowlog-log-slower-than", b"0"]),
            0,
        );
        rt.execute_frame(command(&[b"SLOWLOG", b"RESET"]), 1);

        // Dispatch a genuinely unknown command.
        let reply = rt.execute_frame(command(&[b"DEFINITELY_NOT_A_COMMAND", b"arg1", b"arg2"]), 2);
        assert!(
            matches!(reply, RespFrame::Error(ref s) if s.starts_with("ERR unknown command")),
            "expected unknown-command error, got {reply:?}",
        );

        // INFO commandstats must NOT contain a row for the bogus name.
        let info = rt.execute_frame(command(&[b"INFO", b"commandstats"]), 3);
        let RespFrame::BulkString(Some(bytes)) = info else {
            panic!("expected bulk info");
        };
        let body = String::from_utf8(bytes).unwrap();
        assert!(
            !body.contains("cmdstat_definitely_not_a_command"),
            "unknown command leaked into commandstats:\n{body}",
        );

        // SLOWLOG must NOT list the bogus command. The most recent entry
        // should still be the prior SLOWLOG RESET (or empty if RESET
        // doesn't self-record).
        let slowlog = rt.execute_frame(command(&[b"SLOWLOG", b"GET", b"10"]), 4);
        let RespFrame::Array(Some(rows)) = slowlog else {
            panic!("expected slowlog array");
        };
        for row in &rows {
            let RespFrame::Array(Some(fields)) = row else {
                continue;
            };
            let argv_slot = &fields[3];
            let RespFrame::Array(Some(argv_fields)) = argv_slot else {
                continue;
            };
            for arg in argv_fields {
                let RespFrame::BulkString(Some(bytes)) = arg else {
                    continue;
                };
                let s = String::from_utf8_lossy(bytes);
                assert!(
                    !s.eq_ignore_ascii_case("definitely_not_a_command"),
                    "unknown command leaked into SLOWLOG: {s}",
                );
            }
        }

        // INFO errorstats must still bump errorstat_ERR for the rejection.
        let errs = rt.execute_frame(command(&[b"INFO", b"errorstats"]), 5);
        let RespFrame::BulkString(Some(bytes)) = errs else {
            panic!("expected bulk errorstats");
        };
        let body = String::from_utf8(bytes).unwrap();
        assert!(
            body.lines().any(|l| l.starts_with("errorstat_ERR:")),
            "errorstat_ERR should still be tracked for unknown commands:\n{body}"
        );
    }

    /// (frankenredis-infosections) Mirror upstream server.c::call —
    /// commands that return RespFrame::Error increment `failed_calls`
    /// while still bumping `calls`/`total_usec`. Probe both a wrong-type
    /// failure (handler ran, returned WRONGTYPE) and a successful call,
    /// then confirm the cmdstat_<cmd> row reports the exact counts.
    #[test]
    fn info_commandstats_failed_calls_increments_on_error_replies() {
        let mut rt = Runtime::default_strict();

        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"latency-tracking", b"yes"]),
                0,
            ),
            RespFrame::SimpleString("OK".to_string())
        );

        // Seed a list under "lk", then probe wrong-type + successful
        // GETs against it. The wrong-type probe is a real failed call;
        // the successful GET against "lk-string" is a successful call.
        rt.execute_frame(command(&[b"RPUSH", b"lk", b"a"]), 1);
        rt.execute_frame(command(&[b"SET", b"lk-string", b"hello"]), 1);
        // Two failures: GET on a list key.
        for _ in 0..2 {
            assert!(matches!(
                rt.execute_frame(command(&[b"GET", b"lk"]), 1),
                RespFrame::Error(_)
            ));
        }
        // One success: GET on a string key.
        assert_eq!(
            rt.execute_frame(command(&[b"GET", b"lk-string"]), 1),
            RespFrame::BulkString(Some(b"hello".to_vec()))
        );

        let info = rt.execute_frame(command(&[b"INFO", b"commandstats"]), 2);
        let RespFrame::BulkString(Some(bytes)) = info else {
            panic!("expected bulk info response");
        };
        let body = String::from_utf8(bytes).expect("utf8 info");

        let row = body
            .lines()
            .find(|l| l.starts_with("cmdstat_get:"))
            .unwrap_or_else(|| panic!("expected cmdstat_get row in:\n{body}"));
        // 3 total calls (2 failed + 1 success), 2 failed.
        assert!(row.starts_with("cmdstat_get:calls=3,usec="), "{row}");
        assert!(row.ends_with(",rejected_calls=0,failed_calls=2"), "{row}");
    }

    /// (frankenredis-infosections) `rejected_calls` increments for the
    /// admission-gate paths (NOAUTH, NOPERM, etc.) but does NOT contribute
    /// to `calls` or `usec`. Probe via a requirepass instance: pre-AUTH
    /// GET reaches the NOAUTH gate and is rejected.
    #[test]
    fn info_commandstats_rejected_calls_increments_on_admission_gate_rejection() {
        let mut rt = Runtime::default_strict();
        rt.set_requirepass(Some(b"secret".to_vec()));

        // Pre-AUTH GETs are rejected at the admission gate.
        for _ in 0..3 {
            assert!(matches!(
                rt.execute_frame(command(&[b"GET", b"k"]), 0),
                RespFrame::Error(_)
            ));
        }

        // Authenticate, then run a successful GET.
        assert!(matches!(
            rt.execute_frame(command(&[b"AUTH", b"secret"]), 1),
            RespFrame::SimpleString(_)
        ));
        assert_eq!(
            rt.execute_frame(command(&[b"GET", b"k"]), 1),
            RespFrame::BulkString(None)
        );

        let info = rt.execute_frame(command(&[b"INFO", b"commandstats"]), 2);
        let RespFrame::BulkString(Some(bytes)) = info else {
            panic!("expected bulk info response");
        };
        let body = String::from_utf8(bytes).expect("utf8 info");

        let row = body
            .lines()
            .find(|l| l.starts_with("cmdstat_get:"))
            .unwrap_or_else(|| panic!("expected cmdstat_get row in:\n{body}"));
        // 1 successful call, 3 rejected. Rejected do NOT contribute to
        // calls or usec — only to rejected_calls.
        assert!(row.starts_with("cmdstat_get:calls=1,usec="), "{row}");
        assert!(row.ends_with(",rejected_calls=3,failed_calls=0"), "{row}");
    }

    /// (frankenredis-arityreject) Upstream rejects a wrong-arity command in
    /// processCommand BEFORE call() (rejectCommandArity): it increments
    /// `rejected_calls` only — never `calls`/`usec`/`failed_calls`. An
    /// EXECUTED command that returns an error reply (e.g. WRONGTYPE) instead
    /// counts as `calls`+`failed_calls`. Verified vs redis 7.2.4.
    #[test]
    fn info_commandstats_wrong_arity_counts_rejected_not_failed() {
        let mut rt = Runtime::default_strict();
        // 2 wrong-arity GETs (too few / too many) → rejected, not calls.
        assert!(matches!(
            rt.execute_frame(command(&[b"GET"]), 0),
            RespFrame::Error(_)
        ));
        assert!(matches!(
            rt.execute_frame(command(&[b"GET", b"a", b"b"]), 0),
            RespFrame::Error(_)
        ));
        // 1 successful GET.
        rt.execute_frame(command(&[b"SET", b"k", b"v"]), 0);
        assert_eq!(
            rt.execute_frame(command(&[b"GET", b"k"]), 0),
            RespFrame::BulkString(Some(b"v".to_vec()))
        );
        // 1 EXECUTED failure: WRONGTYPE (LPUSH on a string) → calls+failed.
        assert!(matches!(
            rt.execute_frame(command(&[b"LPUSH", b"k", b"x"]), 0),
            RespFrame::Error(_)
        ));

        let info = rt.execute_frame(command(&[b"INFO", b"commandstats"]), 0);
        let RespFrame::BulkString(Some(bytes)) = info else {
            panic!("expected bulk info response");
        };
        let body = String::from_utf8(bytes).expect("utf8 info");
        let get_row = body
            .lines()
            .find(|l| l.starts_with("cmdstat_get:"))
            .unwrap_or_else(|| panic!("expected cmdstat_get row in:\n{body}"));
        // GET: 1 call (the success), 2 rejected (arity), 0 failed.
        assert!(
            get_row.starts_with("cmdstat_get:calls=1,usec="),
            "{get_row}"
        );
        assert!(
            get_row.ends_with(",rejected_calls=2,failed_calls=0"),
            "{get_row}"
        );
        let lpush_row = body
            .lines()
            .find(|l| l.starts_with("cmdstat_lpush:"))
            .unwrap_or_else(|| panic!("expected cmdstat_lpush row in:\n{body}"));
        // LPUSH: the WRONGTYPE reply is an executed failure → calls=1, failed=1.
        assert!(
            lpush_row.starts_with("cmdstat_lpush:calls=1,usec="),
            "{lpush_row}"
        );
        assert!(
            lpush_row.ends_with(",rejected_calls=0,failed_calls=1"),
            "{lpush_row}"
        );
    }

    /// (frankenredis-aaziu) Special/runtime-dispatched commands (SUBSCRIBE,
    /// CONFIG, EXEC, ...) must also count wrong-arity as rejected_calls, never
    /// calls/failed_calls — even EXEC, whose reply wording is EXECABORT but is
    /// still a pre-call arity rejection (verified vs redis 7.2.4). The reply
    /// itself is unchanged; only the stat classification is asserted here.
    #[test]
    fn info_commandstats_special_command_wrong_arity_counts_rejected() {
        let mut rt = Runtime::default_strict();
        // Wrong-arity special commands → rejected.
        let arity_cases: [&[&[u8]]; 4] = [
            &[b"SUBSCRIBE"],
            &[b"CONFIG"],
            &[b"WAIT", b"1"],
            &[b"EXEC", b"extra"],
        ];
        for cmd in arity_cases {
            assert!(matches!(
                rt.execute_frame(command(cmd), 0),
                RespFrame::Error(_)
            ));
        }
        let info = rt.execute_frame(command(&[b"INFO", b"commandstats"]), 0);
        let RespFrame::BulkString(Some(bytes)) = info else {
            panic!("expected bulk info response");
        };
        let body = String::from_utf8(bytes).expect("utf8 info");
        for cmd in ["subscribe", "config", "wait", "exec"] {
            let row = body
                .lines()
                .find(|l| l.starts_with(&format!("cmdstat_{cmd}:")))
                .unwrap_or_else(|| panic!("expected cmdstat_{cmd} row in:\n{body}"));
            assert!(
                row.starts_with(&format!("cmdstat_{cmd}:calls=0,usec=0,"))
                    && row.ends_with(",rejected_calls=1,failed_calls=0"),
                "{cmd} should be a rejection (0 calls, 1 rejected): {row}"
            );
        }
    }

    /// (frankenredis-8who6) Upstream
    /// server.c::genRedisInfoStringCommandStats keys cmdstat_<key> on
    /// `cmd->fullname`, which for any container subcommand is
    /// `parent|sub`. fr was bucketing every container call into the
    /// parent (`cmdstat_memory`, `cmdstat_object`, ...), so monitoring
    /// tools that grep specific subcommands saw 0-count entries even
    /// after thousands of calls.
    #[test]
    fn info_commandstats_namespaces_container_subcommands_per_upstream() {
        let mut rt = Runtime::default_strict();

        // Container subcommands: histogram key must be `parent|sub`.
        rt.execute_frame(command(&[b"SET", b"k", b"v"]), 0);
        rt.execute_frame(command(&[b"OBJECT", b"ENCODING", b"k"]), 1);
        rt.execute_frame(command(&[b"OBJECT", b"REFCOUNT", b"k"]), 2);
        rt.execute_frame(command(&[b"MEMORY", b"USAGE", b"k"]), 3);
        rt.execute_frame(command(&[b"CLIENT", b"INFO"]), 4);
        rt.execute_frame(command(&[b"COMMAND", b"INFO", b"GET"]), 5);

        let info = rt.execute_frame(command(&[b"INFO", b"commandstats"]), 6);
        let RespFrame::BulkString(Some(bytes)) = info else {
            panic!("expected bulk info response");
        };
        let body = String::from_utf8(bytes).expect("utf8 info");

        for expected in [
            "cmdstat_object|encoding:",
            "cmdstat_object|refcount:",
            "cmdstat_memory|usage:",
            "cmdstat_client|info:",
            "cmdstat_command|info:",
        ] {
            assert!(
                body.lines().any(|l| l.starts_with(expected)),
                "expected `{expected}` row in INFO commandstats, got:\n{body}"
            );
        }
        // Bare parent rows for container commands MUST NOT appear:
        // upstream never emits `cmdstat_object:` etc. as a standalone
        // bucket — that wire shape is reserved for top-level commands.
        for forbidden in [
            "cmdstat_object:",
            "cmdstat_memory:",
            "cmdstat_client:",
            "cmdstat_command:",
        ] {
            assert!(
                !body.lines().any(|l| l.starts_with(forbidden)),
                "container parent `{forbidden}` must not appear as a standalone bucket; got:\n{body}"
            );
        }
        // Top-level commands still bucket bare.
        assert!(
            body.lines().any(|l| l.starts_with("cmdstat_set:")),
            "expected bare `cmdstat_set:` row for top-level SET, got:\n{body}"
        );
    }

    #[test]
    fn time_uses_microsecond_precision_when_runtime_supplies_it() {
        let mut rt = Runtime::default_strict();

        assert_eq!(
            rt.execute_frame_with_unix_time_us(
                &command(&[b"TIME"]),
                1_778_390_164_120,
                1_778_390_164_118_366,
            ),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"1778390164".to_vec())),
                RespFrame::BulkString(Some(b"118366".to_vec())),
            ]))
        );

        assert_eq!(
            rt.execute_frame(command(&[b"TIME"]), 12_345),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"12".to_vec())),
                RespFrame::BulkString(Some(b"345000".to_vec())),
            ]))
        );
    }

    #[test]
    fn info_per_section_reply_omits_trailing_inter_section_separator_per_upstream() {
        // (frankenredis-b83fj) Upstream INFO emits the "\r\n" blank-line
        // separator BETWEEN sections only — the last section's content
        // line is the final byte before the bulk-string terminator.
        // fr-command::info_command_str appends the separator after every
        // section unconditionally; handle_info_command must trim the
        // trailing pair so the wire shape matches vendored.
        let mut rt = Runtime::default_strict();
        for section in [b"server".as_slice(), b"clients", b"cpu", b"errorstats"] {
            let reply = rt.execute_frame(command(&[b"INFO".as_slice(), section]), 0);
            let RespFrame::BulkString(Some(bytes)) = reply else {
                panic!("expected bulk INFO {section:?} reply");
            };
            assert!(
                bytes.ends_with(b"\r\n"),
                "INFO {section:?} should end with a single \\r\\n",
            );
            assert!(
                !bytes.ends_with(b"\r\n\r\n"),
                "INFO {section:?} should NOT have a trailing inter-section separator after the last content line; got tail {:?}",
                String::from_utf8_lossy(&bytes[bytes.len().saturating_sub(40)..]),
            );
        }
    }

    #[test]
    fn info_errorstats_emits_per_error_code_counts() {
        // Pin upstream INFO Errorstats parity (server.c::genRedisInfoString:
        // 6178-6191). Each emitted error reply should bump
        // server.store.errorstats_per_type[<CODE>], where <CODE> is the
        // leading whitespace-delimited token of the reply (no '-' prefix
        // since that lives at the protocol layer). (frankenredis-errorstatslines)
        let mut rt = Runtime::default_strict();
        rt.set_requirepass(Some(b"secret".to_vec()));

        // NOAUTH-coded reply (auth required, no AUTH yet).
        assert!(matches!(
            rt.execute_frame(command(&[b"GET", b"k"]), 0),
            RespFrame::Error(_)
        ));
        assert_eq!(
            rt.execute_frame(command(&[b"AUTH", b"secret"]), 1),
            RespFrame::SimpleString("OK".to_string())
        );

        // WRONGTYPE-coded reply.
        rt.execute_frame(command(&[b"SET", b"k", b"v"]), 2);
        assert!(matches!(
            rt.execute_frame(command(&[b"LPUSH", b"k", b"x"]), 3),
            RespFrame::Error(_)
        ));

        // Generic ERR-coded reply (wrong-arity).
        assert!(matches!(
            rt.execute_frame(command(&[b"SET"]), 4),
            RespFrame::Error(_)
        ));

        let info = rt.execute_frame(command(&[b"INFO", b"errorstats"]), 5);
        let RespFrame::BulkString(Some(bytes)) = info else {
            panic!("expected bulk info response");
        };
        let body = String::from_utf8(bytes).expect("utf8 info");

        assert!(body.starts_with("# Errorstats\r\n"), "{body}");
        assert!(
            body.contains("errorstat_NOAUTH:count=1\r\n"),
            "expected NOAUTH counter: {body}",
        );
        assert!(
            body.contains("errorstat_WRONGTYPE:count=1\r\n"),
            "expected WRONGTYPE counter: {body}",
        );
        assert!(
            body.contains("errorstat_ERR:count=1\r\n"),
            "expected ERR counter for wrong-arity: {body}",
        );

        // Codes emitted in lex-sorted order — ERR < NOAUTH < WRONGTYPE.
        let err_pos = body.find("errorstat_ERR:").expect("ERR present");
        let noauth_pos = body.find("errorstat_NOAUTH:").expect("NOAUTH present");
        let wrongtype_pos = body
            .find("errorstat_WRONGTYPE:")
            .expect("WRONGTYPE present");
        assert!(err_pos < noauth_pos && noauth_pos < wrongtype_pos, "{body}");

        // CONFIG RESETSTAT should clear the counters along with the rest.
        rt.execute_frame(command(&[b"CONFIG", b"RESETSTAT"]), 6);
        let after = rt.execute_frame(command(&[b"INFO", b"errorstats"]), 7);
        let RespFrame::BulkString(Some(bytes)) = after else {
            panic!("expected bulk info response");
        };
        let after_body = String::from_utf8(bytes).expect("utf8 info");
        // (frankenredis-b83fj) Trailing inter-section separator is
        // trimmed from single-section INFO replies — matches upstream
        // which emits the separator BETWEEN sections only.
        assert_eq!(
            after_body, "# Errorstats\r\n",
            "RESETSTAT should empty errorstats: {after_body}",
        );
    }

