    #[test]
    fn client_tracking_bcast_registry_drops_off_reset_and_disconnect() {
        let mut rt = Runtime::default_strict();

        assert_eq!(
            rt.execute_frame(command(&[b"CLIENT", b"TRACKING", b"ON", b"BCAST"]), 0),
            RespFrame::SimpleString("OK".to_string())
        );
        assert!(
            rt.server
                .client_tracking_bcast_clients
                .contains(&rt.client_id())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"CLIENT", b"TRACKING", b"OFF"]), 1),
            RespFrame::SimpleString("OK".to_string())
        );
        assert!(
            !rt.server
                .client_tracking_bcast_clients
                .contains(&rt.client_id())
        );

        assert_eq!(
            rt.execute_frame(command(&[b"CLIENT", b"TRACKING", b"ON", b"BCAST"]), 2),
            RespFrame::SimpleString("OK".to_string())
        );
        assert!(
            rt.server
                .client_tracking_bcast_clients
                .contains(&rt.client_id())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"RESET"]), 3),
            RespFrame::SimpleString("RESET".to_string())
        );
        assert!(
            !rt.server
                .client_tracking_bcast_clients
                .contains(&rt.client_id())
        );

        let tracker = rt.new_session();
        let writer = rt.new_session();
        let previous = rt.swap_session(tracker);
        assert_eq!(
            rt.execute_frame(command(&[b"CLIENT", b"TRACKING", b"ON", b"BCAST"]), 4),
            RespFrame::SimpleString("OK".to_string())
        );
        let tracker = rt.swap_session(writer);
        rt.record_client_session(&tracker);
        assert!(
            rt.server
                .client_tracking_bcast_clients
                .contains(&tracker.client_id)
        );
        rt.remove_client_session(tracker.client_id);
        assert!(
            !rt.server
                .client_tracking_bcast_clients
                .contains(&tracker.client_id)
        );

        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"foo", b"v"]), 5),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(rt.drain_pubsub_for_client(tracker.client_id), Vec::new());

        let _writer = rt.swap_session(previous);
    }

    #[test]
    fn non_bcast_tracking_emits_one_invalidate_push_per_key() {
        // frankenredis-8ypwc: when a single command modifies multiple tracked
        // keys, a non-BCAST (default/OPTIN/OPTOUT) client must receive one
        // invalidate push PER key — upstream trackingInvalidateKey fires per key
        // as each is modified — NOT one batched multi-key push. Verified against
        // vendored redis 7.2.4 (MSET of two tracked keys → two pushes).
        let mut rt = Runtime::default_strict();
        let tracker = rt.new_session();
        let writer = rt.new_session();

        let previous = rt.swap_session(tracker);
        assert!(matches!(
            rt.execute_frame(command(&[b"HELLO", b"3"]), 0),
            RespFrame::Map(Some(_))
        ));
        assert_eq!(
            rt.execute_frame(command(&[b"CLIENT", b"TRACKING", b"ON"]), 1),
            RespFrame::SimpleString("OK".to_string())
        );
        // Register caching interest in both keys via reads.
        rt.execute_frame(command(&[b"GET", b"m1"]), 2);
        rt.execute_frame(command(&[b"GET", b"m2"]), 3);
        let tracker_session = rt.swap_session(writer);
        rt.record_client_session(&tracker_session);

        // One command modifies both tracked keys, in arg order m1 then m2.
        assert_eq!(
            rt.execute_frame(command(&[b"MSET", b"m1", b"1", b"m2", b"2"]), 4),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.drain_pubsub_for_client(tracker_session.client_id),
            vec![
                fr_store::PubSubMessage::Invalidate {
                    keys: vec![b"m1".to_vec()],
                },
                fr_store::PubSubMessage::Invalidate {
                    keys: vec![b"m2".to_vec()],
                },
            ],
            "non-BCAST tracking must emit one single-key invalidate push per modified key, in key order"
        );

        let _writer = rt.swap_session(previous);
    }

    // (frankenredis-prz8f) A read that accessed a key but returned WRONGTYPE must
    // still register the key for client-tracking — upstream trackingRememberKeys
    // runs in afterCommand regardless of the error reply — so a later write
    // invalidates the client. Validation errors (wrong arity) access no key and
    // must NOT register.
    #[test]
    fn wrongtype_read_registers_client_tracking_key() {
        let mut rt = Runtime::default_strict();
        let tracker = rt.new_session();
        let writer = rt.new_session();

        let previous = rt.swap_session(tracker);
        assert!(matches!(
            rt.execute_frame(command(&[b"HELLO", b"3"]), 0),
            RespFrame::Map(Some(_))
        ));
        assert_eq!(
            rt.execute_frame(command(&[b"CLIENT", b"TRACKING", b"ON"]), 1),
            RespFrame::SimpleString("OK".to_string())
        );
        // The hash key `h` is read by GET, which returns WRONGTYPE; the key was
        // still accessed and must be tracked.
        rt.execute_frame(command(&[b"HSET", b"h", b"f", b"1"]), 2);
        assert!(matches!(
            rt.execute_frame(command(&[b"GET", b"h"]), 3),
            RespFrame::Error(_)
        ));
        // A wrong-arity GET accesses no key and must NOT register `unused`.
        assert!(matches!(
            rt.execute_frame(command(&[b"GET"]), 4),
            RespFrame::Error(_)
        ));
        let tracker_session = rt.swap_session(writer);
        rt.record_client_session(&tracker_session);

        // Writing the tracked (WRONGTYPE-read) key invalidates the client.
        rt.execute_frame(command(&[b"HSET", b"h", b"f", b"2"]), 5);
        assert_eq!(
            rt.drain_pubsub_for_client(tracker_session.client_id),
            vec![fr_store::PubSubMessage::Invalidate {
                keys: vec![b"h".to_vec()],
            }],
            "a WRONGTYPE read must register the key so a later write invalidates it"
        );

        let _writer = rt.swap_session(previous);
    }

    // (frankenredis) A tracked key that EXPIRES must push an invalidate to its
    // tracking clients, exactly like an explicit delete — upstream db.c
    // expireIfNeeded / activeExpireCycle reach trackingInvalidateKey. fr
    // previously only invalidated on command writes, so expiry silently left a
    // stale client-side cache. Covers both lazy (on-access) and active-cycle
    // expiry.
    #[test]
    fn expiry_invalidates_client_tracking() {
        for active in [false, true] {
            let mut rt = Runtime::default_strict();
            let tracker = rt.new_session();
            let writer = rt.new_session();

            let previous = rt.swap_session(tracker);
            rt.execute_frame(command(&[b"HELLO", b"3"]), 0);
            assert_eq!(
                rt.execute_frame(command(&[b"CLIENT", b"TRACKING", b"ON"]), 1),
                RespFrame::SimpleString("OK".to_string())
            );
            // Tracked key with a short TTL.
            rt.execute_frame(command(&[b"SET", b"ek", b"1", b"PX", b"100"]), 2);
            rt.execute_frame(command(&[b"GET", b"ek"]), 3);
            let tracker_session = rt.swap_session(writer);
            rt.record_client_session(&tracker_session);

            // Drive expiry past the deadline.
            if active {
                let _ = rt.run_active_expire_cycle(1_000, ActiveExpireCycleKind::Slow);
            } else {
                // A read by the writer lazily reaps the expired key.
                rt.execute_frame(command(&[b"GET", b"ek"]), 1_000);
            }

            assert_eq!(
                rt.drain_pubsub_for_client(tracker_session.client_id),
                vec![fr_store::PubSubMessage::Invalidate {
                    keys: vec![b"ek".to_vec()],
                }],
                "{} expiry of a tracked key must push exactly one invalidate",
                if active { "active-cycle" } else { "lazy" }
            );

            let _ = rt.swap_session(previous);
        }
    }

    #[test]
    fn bcast_tracking_batches_multiple_keys_into_one_push() {
        // frankenredis-8ypwc companion: a BCAST client still batches every
        // matching key modified by one command into a SINGLE invalidate push
        // (one flush per command) — the per-key split above must not regress it.
        let mut rt = Runtime::default_strict();
        assert_eq!(
            rt.execute_frame(
                command(&[b"CLIENT", b"TRACKING", b"ON", b"BCAST", b"PREFIX", b"foo"]),
                0,
            ),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"MSET", b"foo1", b"1", b"foo2", b"2"]), 1),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.drain_pending_pubsub(),
            vec![fr_store::PubSubMessage::Invalidate {
                keys: vec![b"foo1".to_vec(), b"foo2".to_vec()],
            }]
        );
    }

    #[test]
    fn live_pubsub_introspection_uses_runtime_subscription_state() {
        let mut rt = Runtime::default_strict();
        let first_client = rt.new_session();
        let second_client = rt.new_session();
        let observer = rt.new_session();

        let previous = rt.swap_session(first_client);
        assert_eq!(
            rt.execute_frame(command(&[b"SUBSCRIBE", b"alpha", b"beta"]), 0),
            RespFrame::Sequence(vec![
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"subscribe".to_vec())),
                    RespFrame::BulkString(Some(b"alpha".to_vec())),
                    RespFrame::Integer(1),
                ])),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"subscribe".to_vec())),
                    RespFrame::BulkString(Some(b"beta".to_vec())),
                    RespFrame::Integer(2),
                ])),
            ])
        );
        assert_eq!(
            rt.execute_frame(command(&[b"PSUBSCRIBE", b"a*"]), 1),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"psubscribe".to_vec())),
                RespFrame::BulkString(Some(b"a*".to_vec())),
                RespFrame::Integer(3),
            ]))
        );

        let _first_client = rt.swap_session(second_client);
        assert_eq!(
            rt.execute_frame(command(&[b"SUBSCRIBE", b"alpha"]), 2),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"subscribe".to_vec())),
                RespFrame::BulkString(Some(b"alpha".to_vec())),
                RespFrame::Integer(1),
            ]))
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SSUBSCRIBE", b"shard-1"]), 3),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"ssubscribe".to_vec())),
                RespFrame::BulkString(Some(b"shard-1".to_vec())),
                RespFrame::Integer(1),
            ]))
        );

        let second_client = rt.swap_session(observer);
        assert_eq!(
            rt.execute_frame(command(&[b"PUBSUB", b"CHANNELS"]), 4),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"alpha".to_vec())),
                RespFrame::BulkString(Some(b"beta".to_vec())),
            ]))
        );
        assert_eq!(
            rt.execute_frame(command(&[b"PUBSUB", b"CHANNELS", b"a*"]), 5),
            RespFrame::Array(Some(vec![RespFrame::BulkString(Some(b"alpha".to_vec()))]))
        );
        assert_eq!(
            rt.execute_frame(command(&[b"PUBSUB", b"NUMSUB", b"alpha", b"beta"]), 6),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"alpha".to_vec())),
                RespFrame::Integer(2),
                RespFrame::BulkString(Some(b"beta".to_vec())),
                RespFrame::Integer(1),
            ]))
        );
        assert_eq!(
            rt.execute_frame(command(&[b"PUBSUB", b"NUMPAT"]), 7),
            RespFrame::Integer(1)
        );
        assert_eq!(
            rt.execute_frame(command(&[b"PUBSUB", b"SHARDCHANNELS"]), 8),
            RespFrame::Array(Some(vec![RespFrame::BulkString(Some(b"shard-1".to_vec()))]))
        );
        assert_eq!(
            rt.execute_frame(
                command(&[b"PUBSUB", b"SHARDNUMSUB", b"shard-1", b"shard-2"]),
                9
            ),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"shard-1".to_vec())),
                RespFrame::Integer(1),
                RespFrame::BulkString(Some(b"shard-2".to_vec())),
                RespFrame::Integer(0),
            ]))
        );

        let observer = rt.swap_session(second_client);
        let _ = rt.swap_session(observer);
        let _ = rt.swap_session(previous);
    }

    #[test]
    fn live_pubsub_help_and_arity_follow_redis_syntax() {
        let mut rt = Runtime::default_strict();
        let help = rt.execute_frame(command(&[b"PUBSUB", b"HELP"]), 0);
        let RespFrame::Array(Some(lines)) = help else {
            unreachable!("expected pubsub help array");
        };
        assert!(lines.len() >= 6);

        // Upstream commands.def declares pubsub|help with arity = 2
        // (exact), so extra args trigger the WrongSubcommandArity
        // wording, matching NUMPAT below. (frankenredis-godyg)
        assert_eq!(
            rt.execute_frame(command(&[b"PUBSUB", b"HELP", b"extra"]), 1),
            RespFrame::Error("ERR wrong number of arguments for 'pubsub|help' command".to_string())
        );
        // (br-frankenredis-pubsubary) — upstream emits the
        // subcommand-specific arity error rather than syntax error.
        assert_eq!(
            rt.execute_frame(command(&[b"PUBSUB", b"CHANNELS", b"a*", b"extra"]), 2),
            RespFrame::Error("ERR unknown subcommand or wrong number of arguments for 'CHANNELS'. Try PUBSUB HELP.".to_string())
        );
        // Upstream commands.def declares PUBSUB NUMPAT with arity =
        // 2 (exact), so extra args trigger the table-level
        // WrongArity wording. (br-frankenredis-pubsubarity)
        assert_eq!(
            rt.execute_frame(command(&[b"PUBSUB", b"NUMPAT", b"extra"]), 3),
            RespFrame::Error(
                "ERR wrong number of arguments for 'pubsub|numpat' command".to_string()
            )
        );
        assert_eq!(
            rt.execute_frame(command(&[b"PUBSUB", b"BOGUS"]), 4),
            RespFrame::Error("ERR unknown subcommand 'BOGUS'. Try PUBSUB HELP.".to_string())
        );
    }

    #[test]
    fn reset_only_clears_callers_pubsub_state() {
        let mut rt = Runtime::default_strict();
        let first_client = rt.new_session();
        let second_client = rt.new_session();

        let previous = rt.swap_session(first_client);
        assert_eq!(
            rt.execute_frame(command(&[b"SUBSCRIBE", b"alpha"]), 0),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"subscribe".to_vec())),
                RespFrame::BulkString(Some(b"alpha".to_vec())),
                RespFrame::Integer(1),
            ]))
        );

        let first_client = rt.swap_session(second_client);
        assert_eq!(
            rt.execute_frame(command(&[b"SUBSCRIBE", b"beta"]), 1),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"subscribe".to_vec())),
                RespFrame::BulkString(Some(b"beta".to_vec())),
                RespFrame::Integer(1),
            ]))
        );
        assert!(
            rt.server
                .store
                .subscribed_channels
                .contains(b"alpha".as_slice())
        );
        assert!(
            rt.server
                .store
                .subscribed_channels
                .contains(b"beta".as_slice())
        );

        let second_client = rt.swap_session(first_client);
        assert_eq!(
            rt.execute_frame(command(&[b"RESET"]), 2),
            RespFrame::SimpleString("RESET".to_string())
        );
        assert!(
            !rt.server
                .store
                .subscribed_channels
                .contains(b"alpha".as_slice())
        );
        assert!(
            rt.server
                .store
                .subscribed_channels
                .contains(b"beta".as_slice())
        );

        let _first_client = rt.swap_session(second_client);
        assert!(rt.is_in_subscription_mode());
        assert_eq!(
            rt.execute_frame(command(&[b"UNSUBSCRIBE"]), 3),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"unsubscribe".to_vec())),
                RespFrame::BulkString(Some(b"beta".to_vec())),
                RespFrame::Integer(0),
            ]))
        );

        let _ = rt.swap_session(previous);
    }

    #[test]
    fn subscribe_inside_multi_exec_registers_and_enters_subscriber_mode() {
        // (frankenredis-execpubsub) A SUBSCRIBE queued in a transaction must
        // ACTUALLY register (not just build a reply): after EXEC the client is
        // in subscriber mode, the channel is in the pubsub registry, and a
        // non-allowed command is rejected with the subscriber-context error —
        // matching upstream execCommand call()ing the queued subscribeCommand.
        let mut rt = Runtime::default_strict();
        let c = rt.new_session();
        let previous = rt.swap_session(c);
        rt.execute_frame(command(&[b"MULTI"]), 0);
        rt.execute_frame(command(&[b"SUBSCRIBE", b"chan"]), 1);
        let _exec = rt.execute_frame(command(&[b"EXEC"]), 2);
        assert!(
            rt.is_in_subscription_mode(),
            "client must be in subscriber mode after EXEC[SUBSCRIBE]"
        );
        assert!(
            rt.server
                .store
                .subscribed_channels
                .contains(b"chan".as_slice()),
            "EXEC[SUBSCRIBE] must register the channel in the pubsub store"
        );
        match rt.execute_frame(command(&[b"GET", b"k"]), 3) {
            RespFrame::Error(e) => assert!(
                e.contains("only (P|S)SUBSCRIBE"),
                "GET after EXEC[SUBSCRIBE] must be subscriber-context-blocked, got {e:?}"
            ),
            other => panic!("expected subscriber-context error, got {other:?}"),
        }
        let _ = rt.swap_session(previous);

        // (frankenredis-execpubsub) A fresh (never-subscribed) client doing
        // MULTI; UNSUBSCRIBE; EXEC must reply a NIL channel with count 0, not a
        // stale channel name from prior server-wide pubsub state.
        let c2 = rt.new_session();
        let prev2 = rt.swap_session(c2);
        rt.execute_frame(command(&[b"MULTI"]), 4);
        rt.execute_frame(command(&[b"UNSUBSCRIBE"]), 5);
        let exec2 = rt.execute_frame(command(&[b"EXEC"]), 6);
        let RespFrame::Array(Some(outer)) = exec2 else {
            panic!("EXEC reply must be an array, got {exec2:?}");
        };
        let RespFrame::Array(Some(inner)) = &outer[0] else {
            panic!(
                "queued UNSUBSCRIBE reply must be an array, got {:?}",
                outer[0]
            );
        };
        assert_eq!(
            inner[0],
            RespFrame::BulkString(Some(b"unsubscribe".to_vec()))
        );
        assert_eq!(inner[1], RespFrame::BulkString(None), "channel must be nil");
        assert_eq!(inner[2], RespFrame::Integer(0));
        let _ = rt.swap_session(prev2);
    }

    #[test]
    fn ssubscribe_deny_blocking_and_ping_subscriber_form_inside_exec() {
        // (frankenredis-execpubsub) SSUBSCRIBE has no CLIENT_MULTI exemption
        // (unlike SUBSCRIBE/PSUBSCRIBE), so a queued SSUBSCRIBE aborts with the
        // DENY_BLOCKING error instead of subscribing.
        let mut rt = Runtime::default_strict();
        let c = rt.new_session();
        let prev = rt.swap_session(c);
        rt.execute_frame(command(&[b"MULTI"]), 0);
        rt.execute_frame(command(&[b"SSUBSCRIBE", b"sc"]), 1);
        let exec = rt.execute_frame(command(&[b"EXEC"]), 2);
        let RespFrame::Array(Some(outer)) = exec else {
            panic!("EXEC reply must be an array, got {exec:?}");
        };
        match &outer[0] {
            RespFrame::Error(e) => assert!(
                e.contains("SSUBSCRIBE isn't allowed for a DENY BLOCKING client"),
                "queued SSUBSCRIBE must deny-block, got {e:?}"
            ),
            other => panic!("queued SSUBSCRIBE must be a DENY_BLOCKING error, got {other:?}"),
        }
        let _ = rt.swap_session(prev);

        // PING after a queued SUBSCRIBE must use the RESP2 subscriber-mode form
        // ["pong", ""], not a bare +PONG.
        let c2 = rt.new_session();
        let prev2 = rt.swap_session(c2);
        rt.execute_frame(command(&[b"MULTI"]), 3);
        rt.execute_frame(command(&[b"SUBSCRIBE", b"ch"]), 4);
        rt.execute_frame(command(&[b"PING"]), 5);
        let exec2 = rt.execute_frame(command(&[b"EXEC"]), 6);
        let RespFrame::Array(Some(o2)) = exec2 else {
            panic!("EXEC reply must be an array, got {exec2:?}");
        };
        assert_eq!(
            o2[1],
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"pong".to_vec())),
                RespFrame::BulkString(Some(Vec::new())),
            ])),
            "PING after EXEC[SUBSCRIBE] must use the subscriber-mode 2-element form"
        );
        let _ = rt.swap_session(prev2);
    }

    #[test]
    fn unsubscribe_all_reports_total_count_with_remaining_other_subscriptions() {
        // (frankenredis-unsubcount) UNSUBSCRIBE with no channel args, on a client
        // that holds ONLY pattern subscriptions, replies with a nil channel and
        // the TOTAL remaining subscription count (channels + patterns) — upstream
        // pubsubUnsubscribeAllChannels returns clientTotalPubSubSubscriptionCount,
        // not a hardcoded 0. Symmetric for PUNSUBSCRIBE with channel-only state.
        let mut rt = Runtime::default_strict();
        let c = rt.new_session();
        let prev = rt.swap_session(c);
        rt.execute_frame(command(&[b"PSUBSCRIBE", b"p.*"]), 0);
        let r = rt.execute_frame(command(&[b"UNSUBSCRIBE"]), 1);
        assert_eq!(
            r,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"unsubscribe".to_vec())),
                RespFrame::BulkString(None),
                RespFrame::Integer(1),
            ])),
            "UNSUBSCRIBE (no channels) with 1 pattern held must report count 1, not 0"
        );
        let _ = rt.swap_session(prev);

        let c2 = rt.new_session();
        let prev2 = rt.swap_session(c2);
        rt.execute_frame(command(&[b"SUBSCRIBE", b"ch"]), 2);
        let r2 = rt.execute_frame(command(&[b"PUNSUBSCRIBE"]), 3);
        assert_eq!(
            r2,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"punsubscribe".to_vec())),
                RespFrame::BulkString(None),
                RespFrame::Integer(1),
            ])),
            "PUNSUBSCRIBE (no patterns) with 1 channel held must report count 1, not 0"
        );
        let _ = rt.swap_session(prev2);
    }

    #[test]
    fn multi_db_select_scopes_keyspace_commands() {
        let mut rt = Runtime::default_strict();

        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"shared", b"db0"]), 0),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SELECT", b"2"]), 1),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"shared", b"db2"]), 2),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"other", b"x"]), 3),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"DBSIZE"]), 4),
            RespFrame::Integer(2)
        );
        assert_eq!(
            rt.execute_frame(command(&[b"KEYS", b"*"]), 5),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"other".to_vec())),
                RespFrame::BulkString(Some(b"shared".to_vec())),
            ]))
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SCAN", b"0"]), 6),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"0".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"other".to_vec())),
                    RespFrame::BulkString(Some(b"shared".to_vec())),
                ])),
            ]))
        );

        assert_eq!(
            rt.execute_frame(command(&[b"SELECT", b"0"]), 7),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"GET", b"shared"]), 8),
            RespFrame::BulkString(Some(b"db0".to_vec()))
        );
        assert_eq!(
            rt.execute_frame(command(&[b"DBSIZE"]), 9),
            RespFrame::Integer(1)
        );
    }

    #[test]
    fn xgroup_keyspace_notifications_use_subcommand_event_names() {
        fn assert_xgroup_event(parts: &[&[u8]], expected: &'static str) {
            let command = argv(parts);
            assert_eq!(Runtime::command_to_keyspace_event(&command), expected);
            assert_eq!(
                Runtime::command_to_notify_type(&command),
                fr_store::NOTIFY_STREAM
            );
        }

        assert_xgroup_event(
            &[b"XGROUP", b"CREATE", b"stream", b"group", b"0"],
            "xgroup-create",
        );
        assert_xgroup_event(
            &[b"XGROUP", b"SETID", b"stream", b"group", b"$"],
            "xgroup-setid",
        );
        assert_xgroup_event(
            &[b"XGROUP", b"DESTROY", b"stream", b"group"],
            "xgroup-destroy",
        );
        assert_xgroup_event(
            &[
                b"XGROUP",
                b"CREATECONSUMER",
                b"stream",
                b"group",
                b"consumer",
            ],
            "xgroup-createconsumer",
        );
        assert_xgroup_event(
            &[b"XGROUP", b"DELCONSUMER", b"stream", b"group", b"consumer"],
            "xgroup-delconsumer",
        );
    }

