    #[test]
    fn multi_db_persistence_tracks_selected_db_boundaries() {
        let mut rt = Runtime::default_strict();
        // (frankenredis-rl0qz) Latch propagation so aof records are captured.
        rt.server.replication_runtime_state.ensure_replica(42);

        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"zero", b"0"]), 0),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SELECT", b"4"]), 1),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"four", b"4"]), 2),
            RespFrame::SimpleString("OK".to_string())
        );

        assert_eq!(
            rt.aof_records(),
            [
                AofRecord {
                    argv: vec![b"SET".to_vec(), b"zero".to_vec(), b"0".to_vec()],
                },
                AofRecord {
                    argv: vec![b"SELECT".to_vec(), b"4".to_vec()],
                },
                AofRecord {
                    argv: vec![b"SET".to_vec(), b"four".to_vec(), b"4".to_vec()],
                },
            ]
            .as_slice()
        );

        let entries = store_to_rdb_entries(&mut rt.server.store, 3);
        assert!(entries.iter().any(|entry| {
            entry.db == 0 && entry.key == b"zero" && entry.value == RdbValue::String(b"0".to_vec())
        }));
        assert!(entries.iter().any(|entry| {
            entry.db == 4 && entry.key == b"four" && entry.value == RdbValue::String(b"4".to_vec())
        }));
    }

    #[test]
    fn rdb_snapshot_expire_prepass_preserves_order_ttls_and_side_effects() {
        let mut rt = Runtime::default_strict();
        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"persistent", b"p"]), 0),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"expired", b"x"]), 1),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"PEXPIREAT", b"expired", b"100"]), 2),
            RespFrame::Integer(1)
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SELECT", b"1"]), 3),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"middle", b"m"]), 4),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SELECT", b"2"]), 5),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"live", b"l"]), 6),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"PEXPIREAT", b"live", b"5000"]), 7),
            RespFrame::Integer(1)
        );

        let snapshot = rt.encoded_rdb_snapshot(1_000);
        let decoded = fr_persist::decode_rdb_prefix(&snapshot).expect("decode snapshot");
        let projected: Vec<_> = decoded
            .entries
            .iter()
            .map(|entry| {
                let RdbValue::String(value) = &entry.value else {
                    panic!("expected string entry, got {:?}", entry.value);
                };
                (entry.db, entry.key.clone(), entry.expire_ms, value.clone())
            })
            .collect();

        assert_eq!(
            projected,
            vec![
                (0, b"persistent".to_vec(), None, b"p".to_vec()),
                (1, b"middle".to_vec(), None, b"m".to_vec()),
                (2, b"live".to_vec(), Some(5_000), b"l".to_vec()),
            ]
        );
        assert_eq!(rt.server.store.stat_expired_keys, 1);
        assert_eq!(
            rt.server.store.take_lazy_expired_propagation(),
            vec![b"expired".to_vec()]
        );
    }

    #[test]
    fn encoded_rdb_snapshot_string_fast_path_matches_generic_encoder() {
        let mut rt = Runtime::default_strict();
        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"zero", b"0"]), 0),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"PEXPIREAT", b"zero", b"100000"]), 1),
            RespFrame::Integer(1)
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SELECT", b"2"]), 2),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"two", b"2"]), 3),
            RespFrame::SimpleString("OK".to_string())
        );

        let snapshot = rt.encoded_rdb_snapshot(50);
        let entries = store_to_rdb_entries(&mut rt.server.store, 50);
        let aux = [
            ("redis-ver", fr_store::REDIS_COMPAT_VERSION),
            ("frankenredis", "true"),
        ];
        let generic = fr_persist::encode_rdb_with_functions(&entries, &aux, &[]);

        assert_eq!(snapshot, generic);
    }

    #[test]
    fn rdb_roundtrip_preserves_hash_field_ttls_via_hashwithttls_variant() {
        // (br-frankenredis-th7q) Seed a hash with per-field TTLs, serialize
        // to an RDB byte stream, load into a fresh Runtime, and verify
        // every per-field deadline round-tripped through type 21.
        // Per ja8yu, the wire-level HEXPIRE family is removed for 7.2.4
        // parity, so this test seeds via the Store API directly and
        // verifies via the same.
        let mut rt = Runtime::default_strict();
        rt.execute_frame(
            command(&[
                b"HSET", b"h", b"alive", b"a", b"doomed", b"b", b"keep", b"c",
            ]),
            0,
        );
        rt.server.store.hash_field_set_abs_expiry(
            b"h",
            b"alive",
            1_700_000_500_500,
            fr_store::HashFieldTtlCondition::None,
            0,
        );
        rt.server.store.hash_field_set_abs_expiry(
            b"h",
            b"doomed",
            1_800_000_000_000,
            fr_store::HashFieldTtlCondition::None,
            0,
        );

        let entries = store_to_rdb_entries(&mut rt.server.store, 0);
        let hash_entry = entries.iter().find(|e| e.key == b"h").expect("hash entry");
        match &hash_entry.value {
            RdbValue::HashWithTtls(fields) => {
                let map: std::collections::BTreeMap<Vec<u8>, Option<u64>> =
                    fields.iter().map(|(f, _, ttl)| (f.clone(), *ttl)).collect();
                assert_eq!(map.get(b"alive".as_slice()), Some(&Some(1_700_000_500_500)));
                assert_eq!(
                    map.get(b"doomed".as_slice()),
                    Some(&Some(1_800_000_000_000))
                );
                assert_eq!(map.get(b"keep".as_slice()), Some(&None));
            }
            other => panic!("expected HashWithTtls, got {other:?}"),
        }

        let bytes = fr_persist::encode_rdb(&entries, &[]);
        let (decoded_entries, _aux) = fr_persist::decode_rdb(&bytes).expect("decode");

        let mut rt2 = Runtime::default_strict();
        super::apply_rdb_entries_to_store(&mut rt2.server.store, decoded_entries, 0)
            .expect("apply rdb");

        // Verify the hash + TTLs reconstruct via the Store API.
        let hlen = rt2.execute_frame(command(&[b"HLEN", b"h"]), 0);
        assert_eq!(hlen, RespFrame::Integer(3));
        let alive_abs = rt2.server.store.hash_field_ttl(
            b"h",
            b"alive",
            0,
            fr_store::HashFieldTtlUnit::Milliseconds,
            true,
        );
        assert_eq!(
            alive_abs,
            fr_store::HashFieldTtl::Remaining(1_700_000_500_500)
        );
        let doomed_abs = rt2.server.store.hash_field_ttl(
            b"h",
            b"doomed",
            0,
            fr_store::HashFieldTtlUnit::Milliseconds,
            true,
        );
        assert_eq!(
            doomed_abs,
            fr_store::HashFieldTtl::Remaining(1_800_000_000_000)
        );
        let keep_ttl = rt2.server.store.hash_field_ttl(
            b"h",
            b"keep",
            0,
            fr_store::HashFieldTtlUnit::Seconds,
            false,
        );
        assert_eq!(keep_ttl, fr_store::HashFieldTtl::NoTtl);
    }

    #[test]
    fn rdb_roundtrip_hash_without_ttls_keeps_plain_type_tag() {
        // Hashes without per-field TTLs must keep emitting the classic
        // RDB_TYPE_HASH (4) encoding, so older RDB readers continue
        // working. (br-frankenredis-th7q)
        let mut rt = Runtime::default_strict();
        rt.execute_frame(command(&[b"HSET", b"plain", b"f1", b"v1", b"f2", b"v2"]), 0);
        let entries = store_to_rdb_entries(&mut rt.server.store, 0);
        let entry = entries.iter().find(|e| e.key == b"plain").unwrap();
        assert!(
            matches!(entry.value, RdbValue::Hash(_)),
            "expected plain Hash, got {:?}",
            entry.value
        );
    }

    #[test]
    fn fr_p2c_004_u010_user_auth_requires_authentication_before_dispatch() {
        // (frankenredis-aclnopass) Set requirepass to force the auth
        // gate; in upstream, adding a non-default user with a password
        // alone doesn't change default's nopass, so simply adding alice
        // would NOT gate dispatch. To exercise the gate we need
        // requirepass (which deauths default).
        let mut rt = Runtime::default_strict();
        rt.set_requirepass(Some(b"masterpw".to_vec()));
        rt.add_user(b"alice".to_vec(), b"secret2".to_vec());

        let gated = rt.execute_frame(command(&[b"GET", b"k"]), 0);
        assert_eq!(
            gated,
            RespFrame::Error("NOAUTH Authentication required.".to_string())
        );

        let wrong = rt.execute_frame(command(&[b"AUTH", b"alice", b"bad"]), 1);
        assert_eq!(
            wrong,
            RespFrame::Error(
                "WRONGPASS invalid username-password pair or user is disabled.".to_string()
            )
        );

        let ok = rt.execute_frame(command(&[b"AUTH", b"alice", b"secret2"]), 2);
        assert_eq!(ok, RespFrame::SimpleString("OK".to_string()));

        let after_auth = rt.execute_frame(command(&[b"GET", b"k"]), 3);
        assert_eq!(after_auth, RespFrame::BulkString(None));
    }

    #[test]
    fn adding_password_user_does_not_deauth_default_nopass_connections() {
        // Pins frankenredis-aclnopass. Upstream
        // src/networking.c::createClient assigns DefaultUser to every
        // new client and sets c->authenticated = 1 only when DefaultUser
        // carries USER_FLAG_NOPASS. Adding a non-default
        // password-protected user (alice / bob / ...) does NOT change
        // default's auth-required status. fr previously was checking
        //   self.acl_users.values().any(|u| !u.passwords.is_empty())
        // which globally locked out fresh connections whenever any user
        // had a password — even though the default user remained nopass.
        let mut rt = Runtime::default_strict();

        // Fresh runtime: default is nopass, fresh sessions auto-auth.
        assert!(
            rt.is_authenticated(),
            "fresh default-nopass session should be authenticated"
        );
        let ping = rt.execute_frame(command(&[b"PING"]), 0);
        assert_eq!(ping, RespFrame::SimpleString("PONG".to_string()));

        // Add a password-protected user; the existing connection MUST
        // stay authenticated and ordinary commands must NOT gate.
        rt.add_user(b"alice".to_vec(), b"secret".to_vec());
        assert!(
            rt.is_authenticated(),
            "adding non-default user with password must not deauth default-nopass session"
        );
        let after_add = rt.execute_frame(command(&[b"PING"]), 1);
        assert_eq!(
            after_add,
            RespFrame::SimpleString("PONG".to_string()),
            "PING must still succeed after adding a password-protected user"
        );

        // Add another; same.
        rt.add_user(b"bob".to_vec(), b"secret2".to_vec());
        let after_add2 = rt.execute_frame(command(&[b"GET", b"k"]), 2);
        assert_eq!(after_add2, RespFrame::BulkString(None));

        // Setting requirepass DOES gate — sets default-nopass=false.
        rt.set_requirepass(Some(b"masterpw".to_vec()));
        // The session is rebuilt by set_requirepass; check via execute.
        let gated = rt.execute_frame(command(&[b"GET", b"k"]), 3);
        assert_eq!(
            gated,
            RespFrame::Error("NOAUTH Authentication required.".to_string())
        );

        // Clearing requirepass restores nopass on default.
        rt.set_requirepass(None);
        let restored = rt.execute_frame(command(&[b"PING"]), 4);
        assert_eq!(restored, RespFrame::SimpleString("PONG".to_string()));
    }

    #[test]
    fn quit_and_reset_bypass_auth_gate_when_unauthenticated() {
        // Upstream Redis 7.2 commands.def marks AUTH / HELLO / QUIT / RESET
        // with CMD_NO_AUTH; server.c::processCommand:3911 bypasses the
        // requires-auth check for them. fr-runtime previously bypassed only
        // AUTH and HELLO via early-return arms, so unauthenticated callers
        // saw "NOAUTH Authentication required." for QUIT and RESET despite
        // upstream allowing them. (frankenredis-mhxwl)

        // QUIT under requirepass with no AUTH succeeds.
        // (frankenredis-aclnopass) Use set_requirepass since adding a
        // non-default password-protected user doesn't deauth the
        // current connection (default stays nopass).
        let mut rt = Runtime::default_strict();
        rt.set_requirepass(Some(b"secret".to_vec()));
        let quit = rt.execute_frame(command(&[b"QUIT"]), 0);
        assert_eq!(quit, RespFrame::SimpleString("OK".to_string()));

        // RESET under requirepass with no AUTH succeeds with +RESET.
        let mut rt = Runtime::default_strict();
        rt.set_requirepass(Some(b"secret".to_vec()));
        let reset = rt.execute_frame(command(&[b"RESET"]), 0);
        assert_eq!(reset, RespFrame::SimpleString("RESET".to_string()));

        // After RESET the auth gate still applies to ordinary commands.
        let gated = rt.execute_frame(command(&[b"GET", b"k"]), 1);
        assert_eq!(
            gated,
            RespFrame::Error("NOAUTH Authentication required.".to_string())
        );
    }

    #[test]
    fn hello_without_auth_on_requirepass_server_returns_hello_specific_hint() {
        // Upstream networking.c::helloCommand:3586-3592 emits a HELLO-
        // specific NOAUTH hint pointing callers at the HELLO <proto>
        // AUTH <user> <pass> form, rather than the generic
        // "NOAUTH Authentication required." used by other commands.
        // (frankenredis-qvouv)
        // (frankenredis-aclnopass) Force the auth gate via
        // set_requirepass — adding a non-default password-protected
        // user alone doesn't change default's nopass status, and the
        // pre-fix behavior of treating "any user has password" as
        // "auth required" was the bug we fixed.
        let mut rt = Runtime::default_strict();
        rt.set_requirepass(Some(b"secret".to_vec()));

        // Bare HELLO 2 without AUTH must surface the hint.
        let bare = rt.execute_frame(command(&[b"HELLO", b"2"]), 0);
        assert_eq!(
            bare,
            RespFrame::Error(
                "NOAUTH HELLO must be called with the client already \
                 authenticated, otherwise the HELLO <proto> AUTH <user> <pass> \
                 option can be used to authenticate the client and \
                 select the RESP protocol version at the same time"
                    .to_string()
            ),
            "bare HELLO without AUTH on requirepass server must hint inline AUTH form"
        );

        // HELLO 3 same.
        let bare3 = rt.execute_frame(command(&[b"HELLO", b"3"]), 1);
        assert!(
            matches!(&bare3, RespFrame::Error(s) if s.starts_with("NOAUTH HELLO must")),
            "HELLO 3 without AUTH must hint, got: {bare3:?}"
        );

        // HELLO 2 AUTH <user> <pass> still authenticates and switches
        // protocol — confirms the fix didn't break the inline form.
        // requirepass binds to the default user, so use 'default secret'.
        let inline = rt.execute_frame(
            command(&[b"HELLO", b"2", b"AUTH", b"default", b"secret"]),
            2,
        );
        let RespFrame::Array(_) = &inline else {
            panic!("expected RESP2 Array from HELLO 2 AUTH, got {inline:?}");
        };
        assert!(rt.is_authenticated());
    }

    #[test]
    fn fr_p2c_004_u011_config_set_requirepass_bridge_preserves_authenticated_session() {
        let mut rt = Runtime::default_strict();
        let set = rt.execute_frame(command(&[b"CONFIG", b"SET", b"requirepass", b"secret"]), 0);
        assert_eq!(set, RespFrame::SimpleString("OK".to_string()));
        assert!(rt.is_authenticated());

        let get = rt.execute_frame(command(&[b"CONFIG", b"GET", b"requirepass"]), 1);
        assert_eq!(
            get,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"requirepass".to_vec())),
                RespFrame::BulkString(Some(b"secret".to_vec())),
            ]))
        );

        let clear = rt.execute_frame(command(&[b"CONFIG", b"SET", b"requirepass", b""]), 2);
        assert_eq!(clear, RespFrame::SimpleString("OK".to_string()));
        assert!(rt.is_authenticated());

        let cleared = rt.execute_frame(command(&[b"CONFIG", b"GET", b"requirepass"]), 3);
        assert_eq!(
            cleared,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"requirepass".to_vec())),
                RespFrame::BulkString(Some(Vec::new())),
            ]))
        );
    }

    #[test]
    fn fr_p2c_004_u012_config_acllog_max_len_round_trips() {
        let mut rt = Runtime::default_strict();
        let default_get = rt.execute_frame(command(&[b"CONFIG", b"GET", b"acllog-max-len"]), 0);
        assert_eq!(
            default_get,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"acllog-max-len".to_vec())),
                RespFrame::BulkString(Some(b"128".to_vec())),
            ]))
        );

        let set = rt.execute_frame(command(&[b"CONFIG", b"SET", b"acllog-max-len", b"256"]), 1);
        assert_eq!(set, RespFrame::SimpleString("OK".to_string()));

        let wildcard_get = rt.execute_frame(command(&[b"CONFIG", b"GET", b"acl*"]), 2);
        assert_eq!(
            wildcard_get,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"acllog-max-len".to_vec())),
                RespFrame::BulkString(Some(b"256".to_vec())),
                RespFrame::BulkString(Some(b"aclfile".to_vec())),
                RespFrame::BulkString(Some(Vec::new())),
                RespFrame::BulkString(Some(b"acl-pubsub-default".to_vec())),
                RespFrame::BulkString(Some(b"resetchannels".to_vec())),
            ]))
        );

        let invalid = rt.execute_frame(command(&[b"CONFIG", b"SET", b"acllog-max-len", b"-1"]), 3);
        assert_eq!(
            invalid,
            RespFrame::Error(
                "ERR CONFIG SET failed (possibly related to argument 'acllog-max-len') - argument must be between 0 and 9223372036854775807 inclusive"
                    .to_string()
            )
        );
    }

    #[test]
    fn fr_p2c_005_u001_runtime_captures_successful_dispatched_commands_for_aof() {
        let mut rt = Runtime::default_strict();
        // (frankenredis-rl0qz) Latch the any-replica-ever-connected flag
        // so writes propagate through the replication/AOF capture
        // pipeline. Vendored short-circuits the entire propagation when
        // master+no-replicas+no-backlog+no-aof — fr mirrors that gate.
        rt.server.replication_runtime_state.ensure_replica(42);

        let set = rt.execute_frame(command(&[b"SET", b"k", b"v"]), 0);
        assert_eq!(set, RespFrame::SimpleString("OK".to_string()));

        let del = rt.execute_frame(command(&[b"DEL", b"k"]), 1);
        assert_eq!(del, RespFrame::Integer(1));

        let unknown = rt.execute_frame(command(&[b"NOPE"]), 2);
        assert!(matches!(unknown, RespFrame::Error(_)));

        let records = rt.aof_records();
        assert_eq!(records.len(), 2);
        assert_eq!(
            records[0].argv,
            vec![b"SET".to_vec(), b"k".to_vec(), b"v".to_vec()]
        );
        assert_eq!(records[1].argv, vec![b"DEL".to_vec(), b"k".to_vec()]);
    }

    fn read_runtime_test_frame(
        stream: &mut std::net::TcpStream,
        read_buf: &mut Vec<u8>,
    ) -> RespFrame {
        let parser_config = fr_protocol::ParserConfig::default();
        loop {
            match fr_protocol::parse_frame_with_config(read_buf, &parser_config) {
                Ok(parsed) => {
                    read_buf.drain(..parsed.consumed);
                    return parsed.frame;
                }
                Err(fr_protocol::RespParseError::Incomplete) => {}
                Err(err) => unreachable!("failed to parse runtime test frame: {err:?}"),
            }

            let mut chunk = [0u8; 4096];
            let n = std::io::Read::read(stream, &mut chunk).expect("read runtime test frame");
            assert_ne!(
                n, 0,
                "connection closed before runtime test frame completed"
            );
            read_buf.extend_from_slice(&chunk[..n]);
        }
    }

    fn runtime_test_frame_to_argv(frame: RespFrame) -> Vec<Vec<u8>> {
        match frame {
            RespFrame::Array(Some(items)) => items
                .into_iter()
                .map(|item| match item {
                    RespFrame::BulkString(Some(bytes)) => bytes,
                    other => unreachable!("expected bulk string, got {other:?}"),
                })
                .collect(),
            other => unreachable!("expected array frame, got {other:?}"),
        }
    }

    #[test]
    fn relative_expire_rewritten_to_absolute_pexpireat_for_propagation() {
        // (frankenredis-mdrk8) The propagation form must be the absolute
        // PEXPIREAT so a replica's deadline matches the master's exactly.
        let now = 1_000_000_u64;
        let rw = |argv: &[&[u8]]| {
            fr_command::rewrite_relative_expire_for_propagation(
                &argv.iter().map(|a| a.to_vec()).collect::<Vec<_>>(),
                now,
            )
        };
        let pexpireat = |key: &[u8], ms: i64| {
            Some(vec![
                b"PEXPIREAT".to_vec(),
                key.to_vec(),
                ms.to_string().into_bytes(),
            ])
        };
        // EXPIRE sec -> now + sec*1000
        assert_eq!(rw(&[b"EXPIRE", b"k", b"100"]), pexpireat(b"k", 1_100_000));
        // PEXPIRE ms -> now + ms
        assert_eq!(rw(&[b"PEXPIRE", b"k", b"500"]), pexpireat(b"k", 1_000_500));
        // EXPIREAT sec -> sec*1000 (absolute, unit-converted)
        assert_eq!(rw(&[b"EXPIREAT", b"k", b"50"]), pexpireat(b"k", 50_000));
        // PEXPIREAT ms -> passthrough as PEXPIREAT
        assert_eq!(
            rw(&[b"PEXPIREAT", b"k", b"123456"]),
            pexpireat(b"k", 123_456)
        );
        // Conditional flags are dropped (success already happened).
        assert_eq!(
            rw(&[b"EXPIRE", b"k", b"100", b"GT"]),
            pexpireat(b"k", 1_100_000)
        );
        // A past deadline is preserved (deletes the key on the replica too).
        assert_eq!(rw(&[b"EXPIRE", b"k", b"-1"]), pexpireat(b"k", 999_000));
        // Non-expire commands and malformed values are propagated verbatim.
        assert_eq!(rw(&[b"EXPIRE", b"k", b"notanint"]), None);
        assert_eq!(rw(&[b"PERSIST", b"k"]), None);

        // (frankenredis-dt3v0) SET-with-expire family -> SET key val PXAT <ms>.
        let setpxat = |key: &[u8], val: &[u8], ms: i64| {
            Some(vec![
                b"SET".to_vec(),
                key.to_vec(),
                val.to_vec(),
                b"PXAT".to_vec(),
                ms.to_string().into_bytes(),
            ])
        };
        assert_eq!(
            rw(&[b"SETEX", b"k", b"100", b"v"]),
            setpxat(b"k", b"v", 1_100_000)
        );
        assert_eq!(
            rw(&[b"PSETEX", b"k", b"500", b"v"]),
            setpxat(b"k", b"v", 1_000_500)
        );
        assert_eq!(
            rw(&[b"SET", b"k", b"v", b"EX", b"100"]),
            setpxat(b"k", b"v", 1_100_000)
        );
        assert_eq!(
            rw(&[b"SET", b"k", b"v", b"PX", b"500"]),
            setpxat(b"k", b"v", 1_000_500)
        );
        assert_eq!(
            rw(&[b"SET", b"k", b"v", b"EXAT", b"50"]),
            setpxat(b"k", b"v", 50_000)
        );
        // Conditional/return options around the expire are dropped.
        assert_eq!(
            rw(&[b"SET", b"k", b"v", b"NX", b"EX", b"100", b"GET"]),
            setpxat(b"k", b"v", 1_100_000)
        );
        // Absolute PXAT, KEEPTTL, and plain SET carry no relative drift -> verbatim.
        assert_eq!(rw(&[b"SET", b"k", b"v", b"PXAT", b"123456"]), None);
        assert_eq!(rw(&[b"SET", b"k", b"v", b"KEEPTTL"]), None);
        assert_eq!(rw(&[b"SET", b"k", b"v"]), None);

        // (frankenredis-dt3v0) GETEX -> PEXPIREAT (future) / PERSIST / DEL (past).
        assert_eq!(
            rw(&[b"GETEX", b"k", b"EX", b"100"]),
            pexpireat(b"k", 1_100_000)
        );
        assert_eq!(
            rw(&[b"GETEX", b"k", b"PXAT", b"2000000"]),
            pexpireat(b"k", 2_000_000)
        );
        assert_eq!(
            rw(&[b"GETEX", b"k", b"PERSIST"]),
            Some(vec![b"PERSIST".to_vec(), b"k".to_vec()])
        );
        // GETEX with a past absolute deadline deletes the key.
        assert_eq!(
            rw(&[b"GETEX", b"k", b"EXAT", b"1"]),
            Some(vec![b"DEL".to_vec(), b"k".to_vec()])
        );
        assert_eq!(rw(&[b"GETEX", b"k"]), None);
    }

    #[test]
    fn xadd_autoid_aof_capture_and_replay_preserve_master_id() {
        // (frankenredis-f9byo) Exercise the full capture path, not just the
        // helper: the emitted AOF/replication argv must carry the master's
        // concrete id, so replaying later with a different clock keeps the same
        // stream entry id.
        let mut source = Runtime::default_strict();
        source.server.replication_runtime_state.ensure_replica(42);

        let reply = source.execute_frame(command(&[b"XADD", b"s", b"*", b"f", b"v"]), 1_000);
        assert!(
            matches!(reply, RespFrame::BulkString(Some(_))),
            "expected generated XADD id, got {reply:?}"
        );
        let RespFrame::BulkString(Some(generated_id)) = reply else {
            return;
        };
        assert_eq!(
            source.aof_records().last().expect("last aof record").argv,
            vec![
                b"XADD".to_vec(),
                b"s".to_vec(),
                generated_id.clone(),
                b"f".to_vec(),
                b"v".to_vec(),
            ]
        );

        let encoded = source.encoded_aof_stream();
        let decoded = decode_aof_stream(&encoded).expect("decode xadd aof stream");
        assert_eq!(decoded, source.aof_records());

        let mut target = Runtime::default_strict();
        target.server.replication_runtime_state.ensure_replica(43);
        assert_eq!(
            target.replay_aof_records(&decoded, 9_999),
            vec![RespFrame::BulkString(Some(generated_id.clone()))]
        );
        assert_eq!(
            target.execute_frame(command(&[b"XRANGE", b"s", b"-", b"+"]), 10_000),
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(generated_id)),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"f".to_vec())),
                    RespFrame::BulkString(Some(b"v".to_vec())),
                ])),
            ]))])),
        );
    }

    #[test]
    fn active_expire_cycle_propagates_del_for_reaped_keys() {
        // (frankenredis-wqrb6) The active-expire cycle must propagate a DEL per
        // key it reaps so replicas / AOF replay delete the same keys (upstream
        // activeExpireCycle does this; without it the stream lacks the expiry
        // delete and an fr master + redis replica diverge).
        let mut rt = Runtime::default_strict();
        rt.server.replication_runtime_state.ensure_replica(42);
        // Key set at t=900 with a 100ms TTL -> expires at t=1000.
        rt.execute_frame(command(&[b"SET", b"ek", b"v", b"PX", b"100"]), 900);
        let before = rt.aof_records().len();

        // Run the cycle well past the deadline; it reaps `ek`.
        let _ = rt.run_active_expire_cycle(5_000, ActiveExpireCycleKind::Fast);

        let new_argvs: Vec<Vec<Vec<u8>>> = rt.aof_records()[before..]
            .iter()
            .map(|r| r.argv.clone())
            .collect();
        assert!(
            new_argvs.iter().any(|argv| argv
                .first()
                .is_some_and(|c| c.eq_ignore_ascii_case(b"DEL"))
                && argv.get(1).is_some_and(|k| k.as_slice() == b"ek")),
            "active-expire cycle must propagate `DEL ek`, got {new_argvs:?}"
        );

        // A replica (not a master) must NOT synthesize its own expiry DELs.
        let mut replica = Runtime::default_strict();
        replica.server.replication_runtime_state.ensure_replica(7);
        replica.execute_frame(command(&[b"REPLICAOF", b"127.0.0.1", b"6379"]), 900);
        replica.execute_frame(command(&[b"SET", b"rk", b"v", b"PX", b"100"]), 900);
        let rbefore = replica.aof_records().len();
        let _ = replica.run_active_expire_cycle(5_000, ActiveExpireCycleKind::Fast);
        let rnew: Vec<Vec<Vec<u8>>> = replica.aof_records()[rbefore..]
            .iter()
            .map(|r| r.argv.clone())
            .collect();
        assert!(
            !rnew
                .iter()
                .any(|argv| argv.first().is_some_and(|c| c.eq_ignore_ascii_case(b"DEL"))),
            "a replica must not generate expiry DELs, got {rnew:?}"
        );
    }

    #[test]
    fn lazy_expiry_on_access_propagates_del_and_not_the_read() {
        // (frankenredis-1d2xf) A command that lazily expires a key on access must
        // propagate the DEL (so replicas/AOF delete it) but must NOT propagate the
        // triggering read itself; and a write that recreates the key must order
        // the DEL before its own record.
        let mut rt = Runtime::default_strict();
        rt.server.replication_runtime_state.ensure_replica(42);
        // Disable the active cycle so access triggers LAZY expiry (otherwise the
        // pre-dispatch active cycle reaps the key first).
        rt.server.store.active_expire_enabled = false;

        rt.execute_frame(command(&[b"SET", b"k", b"v", b"PX", b"100"]), 900); // expires t=1000
        let before = rt.aof_records().len();

        // GET at t=5000 lazily expires k -> nil; propagate DEL k, NOT the GET.
        assert_eq!(
            rt.execute_frame(command(&[b"GET", b"k"]), 5000),
            RespFrame::BulkString(None)
        );
        let argvs: Vec<Vec<Vec<u8>>> = rt.aof_records()[before..]
            .iter()
            .map(|r| r.argv.clone())
            .collect();
        assert!(
            argvs.iter().any(
                |a| a.first().is_some_and(|c| c.eq_ignore_ascii_case(b"DEL"))
                    && a.get(1).is_some_and(|k| k.as_slice() == b"k")
            ),
            "lazy expiry must propagate DEL k, got {argvs:?}"
        );
        assert!(
            !argvs
                .iter()
                .any(|a| a.first().is_some_and(|c| c.eq_ignore_ascii_case(b"GET"))),
            "the GET that lazy-expired must NOT propagate, got {argvs:?}"
        );

        // SET on an expired key recreates it: stream must be [DEL k2, SET k2 ..].
        rt.execute_frame(command(&[b"SET", b"k2", b"old", b"PX", b"100"]), 900);
        let before = rt.aof_records().len();
        rt.execute_frame(command(&[b"SET", b"k2", b"new"]), 5000);
        let argvs: Vec<Vec<Vec<u8>>> = rt.aof_records()[before..]
            .iter()
            .map(|r| r.argv.clone())
            .collect();
        let del_pos = argvs.iter().position(|a| {
            a.first().is_some_and(|c| c.eq_ignore_ascii_case(b"DEL"))
                && a.get(1).is_some_and(|k| k.as_slice() == b"k2")
        });
        let set_pos = argvs.iter().position(|a| {
            a.first().is_some_and(|c| c.eq_ignore_ascii_case(b"SET"))
                && a.get(1).is_some_and(|k| k.as_slice() == b"k2")
        });
        assert!(
            matches!((del_pos, set_pos), (Some(d), Some(s)) if d < s),
            "SET on expired key must propagate DEL k2 before SET k2, got {argvs:?}"
        );
    }

    #[test]
    fn lazy_expiry_inside_exec_propagates_del_before_recreate() {
        // (frankenredis-wzs7l) A queued command in MULTI/EXEC that lazily expires
        // a key must propagate the DEL INSIDE the transaction, before a later
        // queued command recreates the key.
        let mut rt = Runtime::default_strict();
        rt.server.replication_runtime_state.ensure_replica(42);
        rt.server.store.active_expire_enabled = false;

        rt.execute_frame(command(&[b"SET", b"k", b"old", b"PX", b"100"]), 900); // expires t=1000
        let before = rt.aof_records().len();

        // Transaction at t=5000: GET k (lazy-expires) then SET k new (recreates).
        rt.execute_frame(command(&[b"MULTI"]), 5000);
        rt.execute_frame(command(&[b"GET", b"k"]), 5000);
        rt.execute_frame(command(&[b"SET", b"k", b"new"]), 5000);
        rt.execute_frame(command(&[b"EXEC"]), 5000);

        let argvs: Vec<Vec<Vec<u8>>> = rt.aof_records()[before..]
            .iter()
            .map(|r| r.argv.clone())
            .collect();
        let pos = |name: &[u8], key: Option<&[u8]>| {
            argvs.iter().position(|a| {
                a.first().is_some_and(|c| c.eq_ignore_ascii_case(name))
                    && key.is_none_or(|k| a.get(1).is_some_and(|kk| kk.as_slice() == k))
            })
        };
        let multi = pos(b"MULTI", None);
        let del = pos(b"DEL", Some(b"k"));
        let set = pos(b"SET", Some(b"k"));
        let exec = pos(b"EXEC", None);
        // Order: MULTI < DEL k < SET k new < EXEC.
        assert!(
            matches!((multi, del, set, exec), (Some(m), Some(d), Some(s), Some(e)) if m < d && d < s && s < e),
            "expected [MULTI, DEL k, SET k, EXEC] in order, got {argvs:?}"
        );
        // The lazy-expiring GET must not be propagated.
        assert!(
            pos(b"GET", None).is_none(),
            "the GET that lazy-expired must NOT propagate, got {argvs:?}"
        );
    }

    // Upstream propagatePendingCommands wraps a transaction's effects in
    // MULTI/EXEC only when MORE THAN ONE command propagates. A single-effect
    // transaction must propagate bare (no spurious MULTI/EXEC frame); a
    // multi-effect one must be wrapped.
    #[test]
    fn exec_wraps_in_multi_only_when_more_than_one_effect_propagates() {
        let verbs = |rt: &Runtime, from: usize| -> Vec<Vec<u8>> {
            rt.aof_records()[from..]
                .iter()
                .map(|r| r.argv[0].to_ascii_uppercase())
                .collect()
        };
        let mut rt = Runtime::default_strict();
        rt.server.replication_runtime_state.ensure_replica(42);

        // Single-write transaction -> propagated bare (no MULTI/EXEC).
        let b0 = rt.aof_records().len();
        rt.execute_frame(command(&[b"MULTI"]), 1);
        rt.execute_frame(command(&[b"SET", b"x", b"1"]), 1);
        rt.execute_frame(command(&[b"EXEC"]), 1);
        let v = verbs(&rt, b0);
        assert_eq!(
            v,
            vec![b"SET".to_vec()],
            "a 1-write MULTI/EXEC must propagate bare, got {v:?}"
        );

        // Two-write transaction -> wrapped in MULTI ... EXEC.
        let b1 = rt.aof_records().len();
        rt.execute_frame(command(&[b"MULTI"]), 2);
        rt.execute_frame(command(&[b"SET", b"a", b"1"]), 2);
        rt.execute_frame(command(&[b"SET", b"b", b"2"]), 2);
        rt.execute_frame(command(&[b"EXEC"]), 2);
        let v = verbs(&rt, b1);
        assert_eq!(
            v,
            vec![
                b"MULTI".to_vec(),
                b"SET".to_vec(),
                b"SET".to_vec(),
                b"EXEC".to_vec()
            ],
            "a 2-write MULTI/EXEC must be wrapped, got {v:?}"
        );

        // Effect-free transaction -> nothing propagated.
        let b2 = rt.aof_records().len();
        rt.execute_frame(command(&[b"MULTI"]), 3);
        rt.execute_frame(command(&[b"GET", b"x"]), 3);
        rt.execute_frame(command(&[b"EXEC"]), 3);
        assert_eq!(
            rt.aof_records().len(),
            b2,
            "an effect-free MULTI/EXEC must propagate nothing"
        );
    }

    #[test]
    fn migrate_in_selected_db_propagates_as_del_not_migrate() {
        let listener =
            std::net::TcpListener::bind("127.0.0.1:0").expect("bind migrate runtime listener");
        let addr = listener.local_addr().expect("runtime listener addr");
        let seen = std::sync::Arc::new(std::sync::Mutex::new(Vec::<Vec<Vec<u8>>>::new()));
        let seen_clone = std::sync::Arc::clone(&seen);
        let server = std::thread::spawn(move || {
            let (mut stream, _) = listener.accept().expect("accept runtime migrate client");
            let mut read_buf = Vec::new();
            for _ in 0..2 {
                let argv =
                    runtime_test_frame_to_argv(read_runtime_test_frame(&mut stream, &mut read_buf));
                seen_clone.lock().expect("lock seen").push(argv);
                std::io::Write::write_all(
                    &mut stream,
                    &RespFrame::SimpleString("OK".to_string()).to_bytes(),
                )
                .expect("write runtime migrate reply");
            }
        });

        let mut rt = Runtime::default_strict();
        // (frankenredis-rl0qz) Latch propagation.
        rt.server.replication_runtime_state.ensure_replica(42);
        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"k", b"db0"]), 0),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SELECT", b"2"]), 1),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"k", b"db2"]), 2),
            RespFrame::SimpleString("OK".to_string())
        );

        let reply = rt.execute_frame(
            command(&[
                b"MIGRATE",
                addr.ip().to_string().as_bytes(),
                addr.port().to_string().as_bytes(),
                b"k",
                b"9",
                b"5000",
            ]),
            3,
        );
        assert_eq!(reply, RespFrame::SimpleString("OK".to_string()));

        assert_eq!(
            rt.execute_frame(command(&[b"GET", b"k"]), 4),
            RespFrame::BulkString(None)
        );
        assert_eq!(
            rt.execute_frame(command(&[b"SELECT", b"0"]), 5),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"GET", b"k"]), 6),
            RespFrame::BulkString(Some(b"db0".to_vec()))
        );

        let migrate_records: Vec<&AofRecord> = rt
            .aof_records()
            .iter()
            .filter(|record| {
                record
                    .argv
                    .first()
                    .is_some_and(|cmd| cmd.eq_ignore_ascii_case(b"MIGRATE"))
            })
            .collect();
        assert!(migrate_records.is_empty(), "MIGRATE must not enter the AOF");
        assert_eq!(
            rt.aof_records().last().expect("last aof record").argv,
            vec![b"DEL".to_vec(), b"k".to_vec()]
        );

        server.join().expect("join runtime fake target");
        let seen = seen.lock().expect("lock seen");
        assert_eq!(seen[0], vec![b"SELECT".to_vec(), b"9".to_vec()]);
        assert_eq!(seen[1][0], b"RESTORE".to_vec());
        assert_eq!(seen[1][1], b"k".to_vec());
    }

    #[test]
    fn fr_p2c_005_u002_runtime_aof_stream_export_round_trips() {
        let mut rt = Runtime::default_strict();
        // (frankenredis-rl0qz) See note in u001 — latch propagation.
        rt.server.replication_runtime_state.ensure_replica(42);
        let _ = rt.execute_frame(command(&[b"SET", b"k", b"v"]), 0);
        let _ = rt.execute_frame(command(&[b"DEL", b"k"]), 1);

        let encoded = rt.encoded_aof_stream();
        let decoded = decode_aof_stream(&encoded).expect("decode aof stream");
        assert_eq!(decoded.len(), 2);
        assert_eq!(
            decoded[0].argv,
            vec![b"SET".to_vec(), b"k".to_vec(), b"v".to_vec()]
        );
        assert_eq!(decoded[1].argv, vec![b"DEL".to_vec(), b"k".to_vec()]);
    }

    #[test]
    fn eval_set_repl_runtime_consumes_script_propagation_records() {
        let mut rt = Runtime::default_strict();
        // (frankenredis-rl0qz) Latch propagation.
        rt.server.replication_runtime_state.ensure_replica(42);
        let reply = rt.execute_frame(
            command(&[
                b"EVAL",
                b"redis.call('SET','a','1')\nredis.set_repl(redis.REPL_NONE)\nredis.call('SET','b','2')\nredis.set_repl(redis.REPL_AOF)\nredis.call('SET','c','3')\nredis.set_repl(redis.REPL_REPLICA)\nredis.call('SET','d','4')\nredis.set_repl(redis.REPL_ALL)\nredis.call('SET','e','5')\nreturn redis.call('GET','e')",
                b"0",
            ]),
            0,
        );
        assert_eq!(reply, RespFrame::BulkString(Some(b"5".to_vec())));

        // Four effects propagate (b is REPL_NONE, filtered out). Upstream wraps a
        // script's >1 propagated effects in MULTI/EXEC so they replay atomically,
        // so the captured stream is MULTI .. EXEC around the four SETs.
        assert_eq!(
            rt.aof_records(),
            [
                AofRecord {
                    argv: vec![b"MULTI".to_vec()],
                },
                AofRecord {
                    argv: vec![b"SET".to_vec(), b"a".to_vec(), b"1".to_vec()],
                },
                AofRecord {
                    argv: vec![b"SET".to_vec(), b"c".to_vec(), b"3".to_vec()],
                },
                AofRecord {
                    argv: vec![b"SET".to_vec(), b"d".to_vec(), b"4".to_vec()],
                },
                AofRecord {
                    argv: vec![b"SET".to_vec(), b"e".to_vec(), b"5".to_vec()],
                },
                AofRecord {
                    argv: vec![b"EXEC".to_vec()],
                },
            ]
        );

        let decoded =
            decode_aof_stream(&rt.encoded_aof_stream_from_offset(0)).expect("decode backlog");
        assert_eq!(decoded, rt.aof_records());
    }

    // A script that propagates exactly one effect must NOT be MULTI/EXEC-wrapped
    // (upstream wraps only when MORE THAN ONE command propagates); a multi-effect
    // script must be wrapped. Mirrors the MULTI/EXEC transaction threshold.
    #[test]
    fn eval_wraps_in_multi_only_when_more_than_one_effect_propagates() {
        let verbs = |rt: &Runtime, from: usize| -> Vec<Vec<u8>> {
            rt.aof_records()[from..]
                .iter()
                .map(|r| r.argv[0].to_ascii_uppercase())
                .collect()
        };
        let mut rt = Runtime::default_strict();
        rt.server.replication_runtime_state.ensure_replica(42);

        // Single redis.call write -> propagated bare.
        let b0 = rt.aof_records().len();
        rt.execute_frame(
            command(&[b"EVAL", b"redis.call('set','a','1'); return 1", b"0"]),
            1,
        );
        assert_eq!(
            verbs(&rt, b0),
            vec![b"SET".to_vec()],
            "a single-effect script must propagate bare"
        );

        // Two redis.call writes -> wrapped in MULTI .. EXEC.
        let b1 = rt.aof_records().len();
        rt.execute_frame(
            command(&[
                b"EVAL",
                b"redis.call('set','b','1'); redis.call('set','c','2'); return 1",
                b"0",
            ]),
            2,
        );
        assert_eq!(
            verbs(&rt, b1),
            vec![
                b"MULTI".to_vec(),
                b"SET".to_vec(),
                b"SET".to_vec(),
                b"EXEC".to_vec()
            ],
            "a multi-effect script must be wrapped in MULTI/EXEC"
        );
    }

    #[test]
    fn fr_p2c_005_u003_runtime_replay_aof_stream_applies_records() {
        let mut source = Runtime::default_strict();
        // (frankenredis-rl0qz) Latch propagation so source captures aof records.
        source.server.replication_runtime_state.ensure_replica(42);
        let _ = source.execute_frame(command(&[b"SET", b"k", b"v"]), 0);
        let _ = source.execute_frame(command(&[b"INCR", b"counter"]), 1);
        let encoded = source.encoded_aof_stream();
        let decoded = decode_aof_stream(&encoded).expect("decode source stream");

        let mut target = Runtime::default_strict();
        // (frankenredis-rl0qz) Latch target too — replay_aof_stream
        // goes through execute_frame → capture_aof_record which is now
        // gated on master+no-replicas+no-aof.
        target.server.replication_runtime_state.ensure_replica(43);
        let replies = target
            .replay_aof_stream(&encoded, 10)
            .expect("replay aof stream");
        assert_eq!(
            replies,
            vec![
                RespFrame::SimpleString("OK".to_string()),
                RespFrame::Integer(1)
            ]
        );
        assert_eq!(target.aof_records(), decoded.as_slice());

        let get = target.execute_frame(command(&[b"GET", b"k"]), 100);
        assert_eq!(get, RespFrame::BulkString(Some(b"v".to_vec())));
        let get_counter = target.execute_frame(command(&[b"GET", b"counter"]), 101);
        assert_eq!(get_counter, RespFrame::BulkString(Some(b"1".to_vec())));
    }

    #[test]
    fn fr_p2c_005_u003_runtime_aof_stream_preserves_select_boundaries() {
        let mut source = Runtime::default_strict();
        // (frankenredis-rl0qz) Latch propagation.
        source.server.replication_runtime_state.ensure_replica(42);
        assert_eq!(
            source.execute_frame(command(&[b"SET", b"db0:key", b"zero"]), 0),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            source.execute_frame(command(&[b"SELECT", b"2"]), 1),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            source.execute_frame(command(&[b"SET", b"db2:key", b"two"]), 2),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            source.execute_frame(command(&[b"INCR", b"db2:counter"]), 3),
            RespFrame::Integer(1)
        );
        assert_eq!(
            source.execute_frame(command(&[b"SELECT", b"0"]), 4),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            source.execute_frame(command(&[b"SET", b"db0:other", b"again"]), 5),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            source.execute_frame(command(&[b"SELECT", b"2"]), 6),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            source.execute_frame(command(&[b"SET", b"db2:other", b"twice"]), 7),
            RespFrame::SimpleString("OK".to_string())
        );

        let decoded = decode_aof_stream(&source.encoded_aof_stream()).expect("decode aof stream");
        let propagated: Vec<Vec<Vec<u8>>> =
            decoded.iter().map(|record| record.argv.clone()).collect();
        assert_eq!(
            propagated,
            vec![
                vec![b"SET".to_vec(), b"db0:key".to_vec(), b"zero".to_vec()],
                vec![b"SELECT".to_vec(), b"2".to_vec()],
                vec![b"SET".to_vec(), b"db2:key".to_vec(), b"two".to_vec()],
                vec![b"INCR".to_vec(), b"db2:counter".to_vec()],
                vec![b"SELECT".to_vec(), b"0".to_vec()],
                vec![b"SET".to_vec(), b"db0:other".to_vec(), b"again".to_vec()],
                vec![b"SELECT".to_vec(), b"2".to_vec()],
                vec![b"SET".to_vec(), b"db2:other".to_vec(), b"twice".to_vec()],
            ],
            "AOF propagation must preserve replay-visible SELECT boundaries without redundant same-DB SELECTs"
        );

        let mut target = Runtime::default_strict();
        let replies = target.replay_aof_records(&decoded, 100);
        assert_eq!(replies.len(), decoded.len());

        assert_eq!(
            target.execute_frame(command(&[b"SELECT", b"0"]), 199),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            target.execute_frame(command(&[b"GET", b"db0:key"]), 200),
            RespFrame::BulkString(Some(b"zero".to_vec()))
        );
        assert_eq!(
            target.execute_frame(command(&[b"GET", b"db0:other"]), 201),
            RespFrame::BulkString(Some(b"again".to_vec()))
        );
        assert_eq!(
            target.execute_frame(command(&[b"GET", b"db2:key"]), 202),
            RespFrame::BulkString(None)
        );
        assert_eq!(
            target.execute_frame(command(&[b"SELECT", b"2"]), 203),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            target.execute_frame(command(&[b"GET", b"db2:key"]), 204),
            RespFrame::BulkString(Some(b"two".to_vec()))
        );
        assert_eq!(
            target.execute_frame(command(&[b"GET", b"db2:counter"]), 205),
            RespFrame::BulkString(Some(b"1".to_vec()))
        );
        assert_eq!(
            target.execute_frame(command(&[b"GET", b"db2:other"]), 206),
            RespFrame::BulkString(Some(b"twice".to_vec()))
        );
    }

