    #[test]
    fn client_list_applies_single_client_type_and_id_filters() {
        let mut rt = Runtime::default_strict();
        // Get the actual client ID (varies based on test execution order)
        let id_frame = rt.execute_frame(command(&[b"CLIENT", b"ID"]), 0);
        let client_id = match id_frame {
            RespFrame::Integer(n) => n.to_string(),
            other => unreachable!("CLIENT ID should return integer, got {other:?}"),
        };
        let id_bytes = client_id.as_bytes().to_vec();

        let list_all = rt.execute_frame(command(&[b"CLIENT", b"LIST"]), 1);
        let list_normal = rt.execute_frame(command(&[b"CLIENT", b"LIST", b"TYPE", b"normal"]), 2);
        let list_replica = rt.execute_frame(command(&[b"CLIENT", b"LIST", b"TYPE", b"replica"]), 3);
        let list_id_match = rt.execute_frame(command(&[b"CLIENT", b"LIST", b"ID", &id_bytes]), 4);
        let list_id_miss = rt.execute_frame(command(&[b"CLIENT", b"LIST", b"ID", b"999999999"]), 5);

        // `argv-mem` legitimately differs between these CLIENT LIST variants
        // (different command argv → different argv_len_sum, like upstream), so
        // compare with that one field normalised; the client set is identical.
        // (frankenredis-clargvmem)
        let without_argv_mem = |f: &RespFrame| -> String {
            let RespFrame::BulkString(Some(b)) = f else {
                return format!("{f:?}");
            };
            String::from_utf8_lossy(b)
                .split(' ')
                .filter(|t| !t.starts_with("argv-mem="))
                .collect::<Vec<_>>()
                .join(" ")
        };
        assert_eq!(without_argv_mem(&list_normal), without_argv_mem(&list_all));
        assert_eq!(list_replica, RespFrame::BulkString(Some(Vec::new())));
        assert_eq!(
            without_argv_mem(&list_id_match),
            without_argv_mem(&list_all)
        );
        assert_eq!(list_id_miss, RespFrame::BulkString(Some(Vec::new())));
    }

    #[test]
    fn client_list_and_kill_type_accept_slave_alias_for_replica_h4grb() {
        // (frankenredis-h4grb) Upstream networking.c::getClientTypeByName
        // accepts the legacy `slave` alias as a synonym for `replica`
        // (CLIENT_TYPE_SLAVE). fr previously hardcoded the match to only
        // {normal,master,replica,pubsub}, so `CLIENT KILL TYPE slave`
        // and `CLIENT LIST TYPE slave` returned "Unknown client type".
        let mut rt = Runtime::default_strict();

        // CLIENT LIST TYPE slave — no replicas connected, empty list.
        assert_eq!(
            rt.execute_frame(command(&[b"CLIENT", b"LIST", b"TYPE", b"slave"]), 1),
            RespFrame::BulkString(Some(Vec::new())),
        );
        // CLIENT KILL TYPE slave — no replicas, kills 0.
        assert_eq!(
            rt.execute_frame(command(&[b"CLIENT", b"KILL", b"TYPE", b"slave"]), 2),
            RespFrame::Integer(0),
        );
        // `replica` continues to work identically.
        assert_eq!(
            rt.execute_frame(command(&[b"CLIENT", b"LIST", b"TYPE", b"replica"]), 3),
            RespFrame::BulkString(Some(Vec::new())),
        );
        assert_eq!(
            rt.execute_frame(command(&[b"CLIENT", b"KILL", b"TYPE", b"replica"]), 4),
            RespFrame::Integer(0),
        );
        // Bogus types still get the unknown-type error.
        assert_eq!(
            rt.execute_frame(command(&[b"CLIENT", b"LIST", b"TYPE", b"bogus"]), 5),
            RespFrame::Error("ERR Unknown client type 'bogus'".to_string()),
        );
        assert_eq!(
            rt.execute_frame(command(&[b"CLIENT", b"KILL", b"TYPE", b"bogus"]), 6),
            RespFrame::Error("ERR Unknown client type 'bogus'".to_string()),
        );
        // Case-insensitive: SLAVE, Slave, sLaVe all accepted.
        for variant in [b"SLAVE".as_slice(), b"Slave", b"sLaVe"] {
            assert_eq!(
                rt.execute_frame(command(&[b"CLIENT", b"KILL", b"TYPE", variant]), 7),
                RespFrame::Integer(0),
                "expected `{}` to alias replica",
                String::from_utf8_lossy(variant),
            );
        }
    }

