    // (frankenredis-rl0qz) Vendored Redis 7.2.4
    // replication.c::replicationFeedSlaves short-circuits primary_offset
    // advances when role=master AND no slaves AND no backlog AND no AOF.
    // Pin that fr now also short-circuits in that state.
    #[test]
    fn master_repl_offset_stays_put_with_no_replicas_no_aof_rl0qz() {
        let mut rt = Runtime::default_strict();
        let before = rt.replication_primary_offset().0;
        for i in 0u64..5 {
            rt.execute_frame(command(&[b"SET", format!("k{i}").as_bytes(), b"v"]), i);
        }
        let after = rt.replication_primary_offset().0;
        assert_eq!(
            after, before,
            "master_repl_offset should not advance pre-first-replica with AOF off (was {before}, now {after})"
        );

        // After the latch, the next write should advance the offset.
        rt.server.replication_runtime_state.ensure_replica(42);
        let latched_before = rt.replication_primary_offset().0;
        rt.execute_frame(command(&[b"SET", b"after", b"v"]), 10);
        let latched_after = rt.replication_primary_offset().0;
        assert!(
            latched_after > latched_before,
            "post-latch write should advance offset (was {latched_before}, now {latched_after})"
        );
    }

    // (frankenredis pubsub-repl) Vendored Redis propagates PUBLISH/SPUBLISH to
    // replicas (PROPAGATE_REPL) so a subscriber attached to a replica receives
    // messages published on the master, but NEVER to the AOF. Pin that fr now
    // advances the replication offset and captures the command into the buffer
    // that feeds replicas, while leaving it absent pre-first-replica.
    #[test]
    fn publish_propagates_to_replicas_only() {
        // Classification: PUBLISH/SPUBLISH are repl-only; ordinary writes and
        // subscription commands are not.
        assert!(crate::command_is_replication_only(&[b"PUBLISH".to_vec()]));
        assert!(crate::command_is_replication_only(&[b"publish".to_vec()]));
        assert!(crate::command_is_replication_only(&[b"SPUBLISH".to_vec()]));
        // (97shd) REPLCONF (GETACK injected by WAIT) is repl-only: rides the backlog
        // to replicas but never persisted to the AOF.
        assert!(crate::command_is_replication_only(&[b"REPLCONF".to_vec()]));
        assert!(crate::command_is_replication_only(&[b"replconf".to_vec()]));
        assert!(!crate::command_is_replication_only(&[b"SET".to_vec()]));
        assert!(!crate::command_is_replication_only(
            &[b"SUBSCRIBE".to_vec()]
        ));

        // Pre-first-replica with AOF off: PUBLISH must not advance the offset,
        // mirroring replicationFeedSlaves short-circuiting with no backlog.
        let mut rt = Runtime::default_strict();
        let before = rt.replication_primary_offset().0;
        rt.execute_frame(command(&[b"PUBLISH", b"ch", b"hello"]), 0);
        assert_eq!(
            rt.replication_primary_offset().0,
            before,
            "PUBLISH must not advance the offset pre-first-replica with AOF off"
        );

        // After a replica has connected, PUBLISH propagates: the offset advances
        // and the verbatim command lands in the replica-feed buffer.
        rt.server.replication_runtime_state.ensure_replica(7);
        let pre = rt.replication_primary_offset().0;
        let records_before = rt.aof_records().len();
        rt.execute_frame(command(&[b"PUBLISH", b"ch", b"world"]), 1);
        assert!(
            rt.replication_primary_offset().0 > pre,
            "PUBLISH must advance the replication offset once a replica exists"
        );
        let recs = rt.aof_records();
        assert_eq!(
            recs.len(),
            records_before + 1,
            "PUBLISH should append exactly one replication record"
        );
        assert!(
            crate::eq_ascii_token(&recs.last().unwrap().argv[0], b"PUBLISH"),
            "the captured replication record should be the PUBLISH itself"
        );
    }

    // (frankenredis-8luan) Single-key PFCOUNT is a may-replicate read: when it
    // recomputes the invalid HLL cardinality cache it bumps `dirty` and upstream
    // propagates the PFCOUNT verbatim (AOF + REPL) so replicas/AOF rebuild the
    // same cache and the HLL string stays byte-identical. A cache hit and
    // multi-key PFCOUNT do not dirty, so they must not propagate.
    #[test]
    fn pfcount_cache_recompute_propagates_but_cache_hit_does_not() {
        assert!(crate::command_is_may_replicate_read(&[b"PFCOUNT".to_vec()]));
        assert!(crate::command_is_may_replicate_read(&[b"pfcount".to_vec()]));
        assert!(!crate::command_is_may_replicate_read(&[b"SET".to_vec()]));
        assert!(!crate::command_is_may_replicate_read(&[b"GET".to_vec()]));
        // PFCOUNT must NOT be treated as a write by the offset/maxmemory gate.
        assert!(!Runtime::command_advances_replication_offset(&[
            b"PFCOUNT".to_vec()
        ]));

        let mut rt = Runtime::default_strict();
        rt.server.replication_runtime_state.ensure_replica(11);
        rt.execute_frame(command(&[b"PFADD", b"hll", b"a", b"b", b"c"]), 0);

        // First PFCOUNT recomputes the cache invalidated by PFADD: it dirties
        // and therefore propagates verbatim.
        let pre = rt.replication_primary_offset().0;
        let recs_before = rt.aof_records().len();
        rt.execute_frame(command(&[b"PFCOUNT", b"hll"]), 1);
        assert!(
            rt.replication_primary_offset().0 > pre,
            "PFCOUNT that recomputes the HLL cache must advance the offset"
        );
        let recs = rt.aof_records();
        assert_eq!(recs.len(), recs_before + 1, "exactly one PFCOUNT record");
        assert!(
            crate::eq_ascii_token(&recs.last().unwrap().argv[0], b"PFCOUNT"),
            "the captured record should be the PFCOUNT itself"
        );

        // Second PFCOUNT hits the now-valid cache: no dirty, no propagation.
        let pre2 = rt.replication_primary_offset().0;
        let recs2 = rt.aof_records().len();
        rt.execute_frame(command(&[b"PFCOUNT", b"hll"]), 2);
        assert_eq!(
            rt.replication_primary_offset().0,
            pre2,
            "a PFCOUNT cache hit must not advance the offset"
        );
        assert_eq!(
            rt.aof_records().len(),
            recs2,
            "a PFCOUNT cache hit must not capture a record"
        );
    }

    // (frankenredis) CLIENT PAUSE WRITE must defer not only plain writes but the
    // whole CMD_MAY_REPLICATE set (EVAL/EVALSHA/FCALL/PFCOUNT/PUBLISH/SPUBLISH),
    // mirroring upstream server.c is_may_replicate_command. PAUSE ALL defers
    // everything; pure reads pass through a WRITE pause.
    #[test]
    fn client_pause_write_defers_may_replicate_commands() {
        let mut rt = Runtime::default_strict();
        // WRITE-mode pause active well past now_ms=0.
        rt.server.client_pause_deadline_ms = 10_000;
        rt.server.client_pause_all = false;

        for cmd in [
            b"EVAL".as_ref(),
            b"EVALSHA",
            b"FCALL",
            b"PFCOUNT",
            b"PUBLISH",
            b"SPUBLISH",
            b"SET", // plain write
        ] {
            assert!(
                rt.is_command_paused(&[cmd.to_vec()], 0),
                "{} must be deferred under PAUSE WRITE",
                String::from_utf8_lossy(cmd)
            );
        }

        // Pure reads (and read-only script variants, which are CMD_READONLY, not
        // CMD_MAY_REPLICATE) are NOT deferred under a write-pause.
        for cmd in [b"GET".as_ref(), b"EVAL_RO", b"FCALL_RO", b"EXISTS"] {
            assert!(
                !rt.is_command_paused(&[cmd.to_vec()], 0),
                "{} must pass through PAUSE WRITE",
                String::from_utf8_lossy(cmd)
            );
        }

        // PAUSE ALL defers everything, including pure reads.
        rt.server.client_pause_all = true;
        assert!(rt.is_command_paused(&[b"GET".to_vec()], 0));
        assert!(rt.is_command_paused(&[b"PING".to_vec()], 0));

        // Once the pause window lapses, nothing is deferred.
        assert!(!rt.is_command_paused(&[b"SET".to_vec()], 20_000));
        assert!(!rt.is_command_paused(&[b"EVAL".to_vec()], 20_000));
    }

    // (frankenredis-f82ny) Vendored Redis 7.2.4 keeps repl_backlog ==
    // NULL until the first replica connects, so INFO replication reports
    // repl_backlog_first_byte_offset:0 and repl_backlog_histlen:0 even
    // after writes have advanced master_repl_offset. Pin that fr now
    // mirrors the same display contract pre-first-replica, then surfaces
    // the live counters once any replica has been registered.
    #[test]
    fn replication_info_backlog_offsets_zero_until_first_replica_f82ny() {
        let mut rt = Runtime::default_strict();
        for i in 0u64..5 {
            rt.execute_frame(command(&[b"SET", format!("k{i}").as_bytes(), b"v"]), i);
        }
        let info = rt.execute_frame(command(&[b"INFO", b"replication"]), 100);
        let RespFrame::BulkString(Some(info_bytes)) = info else {
            unreachable!("expected bulk INFO response");
        };
        let info = String::from_utf8(info_bytes).expect("utf8");
        assert!(info.contains("repl_backlog_active:0\r\n"), "{info}");
        assert!(
            info.contains("repl_backlog_first_byte_offset:0\r\n"),
            "expected 0 pre-first-replica, got: {info}"
        );
        assert!(
            info.contains("repl_backlog_histlen:0\r\n"),
            "expected 0 pre-first-replica, got: {info}"
        );

        // Latch the any-replica-ever-connected flag, then issue more
        // writes — pre-latch writes are gated by rl0qz so they don't
        // advance primary_offset.
        rt.server.replication_runtime_state.ensure_replica(42);
        for i in 5u64..10 {
            rt.execute_frame(command(&[b"SET", format!("k{i}").as_bytes(), b"v"]), i);
        }
        let info = rt.execute_frame(command(&[b"INFO", b"replication"]), 101);
        let RespFrame::BulkString(Some(info_bytes)) = info else {
            unreachable!("expected bulk INFO response");
        };
        let info = String::from_utf8(info_bytes).expect("utf8");
        assert!(
            !info.contains("repl_backlog_histlen:0\r\n"),
            "expected non-zero histlen post-latch+writes, got: {info}"
        );
        assert!(
            info.contains("repl_backlog_first_byte_offset:1\r\n"),
            "expected first_byte_offset:1 post-latch+writes, got: {info}"
        );
    }

    #[test]
    fn replication_info_reports_byte_offsets() {
        let mut rt = Runtime::default_strict();

        // (frankenredis-rl0qz) Latch BEFORE the write — pre-latch writes
        // are gated by the no-slaves+no-backlog+no-aof short-circuit and
        // wouldn't advance the offset. (frankenredis-f82ny) The latch
        // also flips the display layer over to live counters.
        rt.server.replication_runtime_state.ensure_replica(42);
        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"rep:key", b"value"]), 0),
            RespFrame::SimpleString("OK".to_string())
        );
        let expected_offset = rt.replication_primary_offset().0;

        let info = rt.execute_frame(command(&[b"INFO", b"replication"]), 1);
        let RespFrame::BulkString(Some(info_bytes)) = info else {
            unreachable!("expected bulk INFO response");
        };
        let info = String::from_utf8(info_bytes).expect("utf8 info");
        assert!(info.contains(&format!("master_repl_offset:{expected_offset}\r\n")));
        assert!(info.contains(&format!("repl_backlog_histlen:{expected_offset}\r\n")));
        assert!(info.contains("repl_backlog_first_byte_offset:1\r\n"));
    }

