    fn unique_temp_path(prefix: &str, extension: &str) -> std::path::PathBuf {
        let unique = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .expect("clock should be after unix epoch")
            .as_nanos();
        std::env::temp_dir().join(format!(
            "{prefix}_{}_{}.{}",
            std::process::id(),
            unique,
            extension
        ))
    }

