    #[test]
    fn config_rewrite_surfaces_filesystem_failures() {
        let mut rt = Runtime::default_strict();
        let unique_suffix = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .expect("unix epoch")
            .as_nanos();
        let missing_dir = std::env::temp_dir().join(format!(
            "fr_runtime_config_rewrite_missing_{}_{}",
            std::process::id(),
            unique_suffix
        ));
        rt.set_config_file_path(Some(missing_dir.join("redis.conf")));

        let RespFrame::Error(err) = rt.execute_frame(command(&[b"CONFIG", b"REWRITE"]), 0) else {
            panic!("expected CONFIG REWRITE filesystem error"); // ubs:ignore — test assertion
        };
        assert!(
            err.starts_with("ERR Rewriting config file: "),
            "unexpected rewrite error: {err}"
        );
    }

    #[test]
    fn config_rewrite_under_resp3_writes_non_empty_config_file() {
        // (frankenredis-5h86s) handle_config_get returns RespFrame::Map
        // under RESP3 (i40x2-family fix). The CONFIG REWRITE handler
        // previously matched only RespFrame::Array, so a REWRITE
        // issued from a HELLO 3 session silently truncated the
        // config file to a single blank '\n'. After the fix,
        // both Map and Array shapes are accepted.
        let mut rt = Runtime::default_strict();
        let unique_suffix = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .expect("unix epoch")
            .as_nanos();
        let dir = std::env::temp_dir().join(format!(
            "fr_runtime_config_rewrite_resp3_{}_{}",
            std::process::id(),
            unique_suffix
        ));
        std::fs::create_dir_all(&dir).expect("mkdir");
        let path = dir.join("redis.conf");
        rt.set_config_file_path(Some(path.clone()));

        // Promote the session to RESP3 so handle_config_get emits Map.
        let hello = rt.execute_frame(command(&[b"HELLO", b"3"]), 0);
        assert!(matches!(hello, RespFrame::Map(_)));

        let reply = rt.execute_frame(command(&[b"CONFIG", b"REWRITE"]), 1);
        assert_eq!(reply, RespFrame::SimpleString("OK".to_string()));

        let written = std::fs::read_to_string(&path).expect("read config file");
        assert!(
            written.lines().count() > 10,
            "config file should have many lines after REWRITE; got {} lines:\n{}",
            written.lines().count(),
            written
        );
        // Cleanup.
        let _ = std::fs::remove_dir_all(&dir);
    }

    #[test]
    fn config_set_hz_matches_redis_validation_and_clamping() {
        let mut rt = Runtime::default_strict();

        assert_eq!(
            rt.execute_frame(command(&[b"CONFIG", b"SET", b"hz", b"abc"]), 0),
            RespFrame::Error(
                "ERR CONFIG SET failed (possibly related to argument 'hz') - argument couldn't be parsed into an integer"
                    .to_string()
            )
        );
        assert_eq!(
            rt.execute_frame(command(&[b"CONFIG", b"SET", b"hz", b"-1"]), 0),
            RespFrame::Error(
                "ERR CONFIG SET failed (possibly related to argument 'hz') - argument must be between 0 and 2147483647 inclusive"
                    .to_string()
            )
        );
        assert_eq!(
            rt.execute_frame(command(&[b"CONFIG", b"SET", b"hz", b"0"]), 0),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"CONFIG", b"GET", b"hz"]), 0),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"hz".to_vec())),
                RespFrame::BulkString(Some(b"1".to_vec())),
            ]))
        );
        assert_eq!(
            rt.execute_frame(command(&[b"CONFIG", b"SET", b"hz", b"501"]), 0),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"CONFIG", b"GET", b"hz"]), 0),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"hz".to_vec())),
                RespFrame::BulkString(Some(b"500".to_vec())),
            ]))
        );
        assert_eq!(
            rt.execute_frame(command(&[b"CONFIG", b"SET", b"hz", b"2147483648"]), 0),
            RespFrame::Error(
                "ERR CONFIG SET failed (possibly related to argument 'hz') - argument must be between 0 and 2147483647 inclusive"
                    .to_string()
            )
        );
        assert_eq!(
            rt.execute_frame(command(&[b"CONFIG", b"GET", b"hz"]), 0),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"hz".to_vec())),
                RespFrame::BulkString(Some(b"500".to_vec())),
            ]))
        );
    }

    #[test]
    fn config_set_active_expire_effort_enforces_1_to_10_inclusive_per_upstream() {
        // (frankenredis-dnbcg) Vendored Redis declares
        // active-expire-effort as INTEGER_CONFIG with inclusive range
        // [1, 10] (config.c). Out-of-range values surface the
        // table-level wording 'argument must be between 1 and 10
        // inclusive'; unparseable values surface the integer-parse
        // wording. fr previously had no validation for this option.
        //
        // Differential probe vs vendored 16380:
        //   CONFIG SET active-expire-effort 0
        //     vendored: ERR ... argument must be between 1 and 10 inclusive
        //     fr (pre-fix): OK
        //   CONFIG SET active-expire-effort 11  same divergence.
        let mut rt = Runtime::default_strict();

        let bound_msg = "ERR CONFIG SET failed (possibly related to argument 'active-expire-effort') - argument must be between 1 and 10 inclusive";
        let parse_msg = "ERR CONFIG SET failed (possibly related to argument 'active-expire-effort') - argument couldn't be parsed into an integer";

        for bad in [b"0".as_slice(), b"-1", b"11", b"100"] {
            assert_eq!(
                rt.execute_frame(
                    command(&[b"CONFIG", b"SET", b"active-expire-effort", bad]),
                    0,
                ),
                RespFrame::Error(bound_msg.to_string()),
                "bad value {:?} should be rejected with bound message",
                String::from_utf8_lossy(bad),
            );
        }

        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"active-expire-effort", b"abc"]),
                0,
            ),
            RespFrame::Error(parse_msg.to_string())
        );

        // Bounds are inclusive: 1 and 10 must both be accepted.
        for good in [b"1".as_slice(), b"5", b"10"] {
            assert_eq!(
                rt.execute_frame(
                    command(&[b"CONFIG", b"SET", b"active-expire-effort", good]),
                    0,
                ),
                RespFrame::SimpleString("OK".to_string()),
                "good value {:?} should be accepted",
                String::from_utf8_lossy(good),
            );
            assert_eq!(
                rt.execute_frame(command(&[b"CONFIG", b"GET", b"active-expire-effort"]), 0,),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"active-expire-effort".to_vec())),
                    RespFrame::BulkString(Some(good.to_vec())),
                ])),
                "GET should reflect last accepted SET",
            );
        }
    }

    #[test]
    fn config_set_enum_validation_uses_upstream_table_level_wording() {
        // (frankenredis-xqgra) ENUM_CONFIG values in upstream Redis
        // surface via configEnumGetError as
        //   'argument(s) must be one of the following: <values>'
        // (matching the existing appendfsync handler in fr). Two enum
        // configs were previously bypassing this template:
        //   - acl-pubsub-default emitted 'Invalid argument <value>'
        //     (non-standard wording).
        //   - cluster-preferred-endpoint-type had no validation at all
        //     (silently accepted arbitrary values into config_overrides).
        //
        // Differential probe vs vendored 16380:
        //   CONFIG SET cluster-preferred-endpoint-type bogus
        //     vendored: ERR ... argument(s) must be one of the following: ip, hostname, unknown-endpoint
        //     fr (pre-fix): OK
        //   CONFIG SET acl-pubsub-default bogus
        //     vendored: ERR ... argument(s) must be one of the following: allchannels, resetchannels
        //     fr (pre-fix): ERR Invalid argument 'bogus' for CONFIG SET 'acl-pubsub-default'
        let mut rt = Runtime::default_strict();

        // acl-pubsub-default — bad value uses table-level wording.
        let acl_msg = "ERR CONFIG SET failed (possibly related to argument 'acl-pubsub-default') - argument(s) must be one of the following: allchannels, resetchannels";
        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"acl-pubsub-default", b"bogus"]),
                0,
            ),
            RespFrame::Error(acl_msg.to_string()),
        );
        // Valid values still accepted.
        for good in [b"allchannels".as_slice(), b"resetchannels", b"AllChannels"] {
            assert_eq!(
                rt.execute_frame(
                    command(&[b"CONFIG", b"SET", b"acl-pubsub-default", good]),
                    0,
                ),
                RespFrame::SimpleString("OK".to_string()),
                "acl-pubsub-default {:?} should be accepted (case-insensitive)",
                String::from_utf8_lossy(good),
            );
        }

        // cluster-preferred-endpoint-type — bad value rejected with
        // upstream wording; valid values accepted.
        let endpoint_msg = "ERR CONFIG SET failed (possibly related to argument 'cluster-preferred-endpoint-type') - argument(s) must be one of the following: ip, hostname, unknown-endpoint";
        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"CONFIG",
                    b"SET",
                    b"cluster-preferred-endpoint-type",
                    b"bogus"
                ]),
                0,
            ),
            RespFrame::Error(endpoint_msg.to_string()),
        );
        for good in [
            b"ip".as_slice(),
            b"hostname",
            b"unknown-endpoint",
            b"IP",
            b"HostName",
        ] {
            assert_eq!(
                rt.execute_frame(
                    command(&[b"CONFIG", b"SET", b"cluster-preferred-endpoint-type", good]),
                    0,
                ),
                RespFrame::SimpleString("OK".to_string()),
                "cluster-preferred-endpoint-type {:?} should be accepted",
                String::from_utf8_lossy(good),
            );
        }
        // GET round-trips the canonical lowercase form.
        let get_reply = rt.execute_frame(
            command(&[b"CONFIG", b"GET", b"cluster-preferred-endpoint-type"]),
            0,
        );
        let RespFrame::Array(Some(items)) = get_reply else {
            panic!("expected Array");
        };
        assert_eq!(items.len(), 2);
        assert!(
            matches!(&items[0], RespFrame::BulkString(Some(b)) if b == b"cluster-preferred-endpoint-type")
        );
        // Last accepted value was 'HostName' → lowercased to 'hostname'.
        assert!(matches!(&items[1], RespFrame::BulkString(Some(b)) if b == b"hostname"));
    }

    #[test]
    fn config_set_min_replicas_slaves_family_validates_range_and_aliases() {
        // (frankenredis-pgl7g) min-replicas-to-write,
        // min-replicas-max-lag, and the legacy aliases
        // min-slaves-to-write / min-slaves-max-lag are all
        // INTEGER_CONFIG with inclusive range [0, INT_MAX] in upstream
        // config.c. Out-of-range values surface
        // 'argument must be between 0 and 2147483647 inclusive'.
        //
        // Two prior bugs:
        //   - the *replicas* handlers used the non-standard
        //     'Invalid argument' wording instead of the table-level
        //     bound message;
        //   - the *slaves* aliases had no handler at all and were
        //     silently accepted (returning OK for any value, including -1).
        //
        // Differential probe vs vendored 16380:
        //   SET min-slaves-max-lag -1
        //     vendored: ERR ... bound message
        //     fr (pre-fix): OK
        //   SET min-replicas-max-lag -1
        //     vendored: ERR ... bound message
        //     fr (pre-fix): ERR Invalid argument
        let mut rt = Runtime::default_strict();

        let bound_msg = |name: &str| {
            format!(
                "ERR CONFIG SET failed (possibly related to argument '{name}') - argument must be between 0 and 2147483647 inclusive"
            )
        };
        let parse_msg = |name: &str| {
            format!(
                "ERR CONFIG SET failed (possibly related to argument '{name}') - argument couldn't be parsed into an integer"
            )
        };

        for name in [
            "min-replicas-to-write",
            "min-replicas-max-lag",
            "min-slaves-to-write",
            "min-slaves-max-lag",
        ] {
            // Negative — bound message with the alias the user supplied.
            assert_eq!(
                rt.execute_frame(command(&[b"CONFIG", b"SET", name.as_bytes(), b"-1"]), 0,),
                RespFrame::Error(bound_msg(name)),
                "{name} -1 should be bound-rejected"
            );
            // Unparseable — parse message.
            assert_eq!(
                rt.execute_frame(command(&[b"CONFIG", b"SET", name.as_bytes(), b"abc"]), 0,),
                RespFrame::Error(parse_msg(name)),
                "{name} 'abc' should be parse-rejected"
            );
            // Valid (0 and a small positive both accepted).
            assert_eq!(
                rt.execute_frame(command(&[b"CONFIG", b"SET", name.as_bytes(), b"0"]), 0,),
                RespFrame::SimpleString("OK".to_string()),
                "{name} 0 should be accepted"
            );
            assert_eq!(
                rt.execute_frame(command(&[b"CONFIG", b"SET", name.as_bytes(), b"42"]), 0,),
                RespFrame::SimpleString("OK".to_string()),
                "{name} 42 should be accepted"
            );
        }
    }

    #[test]
    fn debug_reload_no_persistence_round_trips_in_memory_per_upstream() {
        // (frankenredis-8hzzv) Vendored Redis's debug.c::DEBUG RELOAD
        // does not require persistence to be configured — it always
        // round-trips through an RDB file (server.rdb_filename defaults
        // to 'dump.rdb'). fr previously short-circuited with
        // 'ERR DEBUG RELOAD requires configured appendonly or RDB
        // persistence' whenever neither --rdb nor --aof was supplied.
        //
        // The fix performs the round-trip entirely in memory via
        // encode_rdb → decode_rdb → apply_rdb_entries_to_store, which
        // validates the encoder/decoder pair (the actual semantic
        // intent of the upstream command) without touching disk.
        //
        // Differential probe vs vendored 16380:
        //   DEBUG RELOAD               → vendored OK,  fr OK (was ERR)
        //   DEBUG RELOAD NOSAVE        → vendored OK,  fr OK (was ERR)
        //   DEBUG RELOAD NOSAVE NOFLUSH MERGE → both OK
        let mut rt = Runtime::default_strict();
        rt.set_enable_debug_command("yes");

        // Seed with several different value types to exercise the
        // full RDB encoder.
        for cmd in [
            &[b"SET".as_slice(), b"k", b"v"][..],
            &[b"LPUSH", b"lst", b"a", b"b", b"c"],
            &[b"SADD", b"st", b"m1", b"m2"],
            &[b"HSET", b"h", b"f1", b"v1", b"f2", b"v2"],
            &[b"ZADD", b"z", b"1", b"a", b"2", b"b"],
        ] {
            let argv: Vec<Vec<u8>> = cmd.iter().map(|b| b.to_vec()).collect();
            let frame = RespFrame::Array(Some(
                argv.into_iter()
                    .map(|b| RespFrame::BulkString(Some(b)))
                    .collect(),
            ));
            rt.execute_frame(frame, 0);
        }

        // DEBUG RELOAD with no persistence configured — should now succeed.
        let reload = rt.execute_frame(command(&[b"DEBUG", b"RELOAD"]), 1);
        assert_eq!(
            reload,
            RespFrame::SimpleString("OK".to_string()),
            "DEBUG RELOAD must succeed in-memory; got {reload:?}"
        );

        // Each value type round-tripped — sanity check the survivors.
        for (cmd, expected) in [
            (
                &[b"GET".as_slice(), b"k"][..],
                RespFrame::BulkString(Some(b"v".to_vec())),
            ),
            (
                &[b"LRANGE", b"lst", b"0", b"-1"],
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"c".to_vec())),
                    RespFrame::BulkString(Some(b"b".to_vec())),
                    RespFrame::BulkString(Some(b"a".to_vec())),
                ])),
            ),
            (
                &[b"HGET", b"h", b"f1"],
                RespFrame::BulkString(Some(b"v1".to_vec())),
            ),
            (
                &[b"ZSCORE", b"z", b"a"],
                RespFrame::BulkString(Some(b"1".to_vec())),
            ),
        ] {
            let argv: Vec<Vec<u8>> = cmd.iter().map(|b| b.to_vec()).collect();
            let frame = RespFrame::Array(Some(
                argv.into_iter()
                    .map(|b| RespFrame::BulkString(Some(b)))
                    .collect(),
            ));
            let out = rt.execute_frame(frame, 2);
            assert_eq!(out, expected, "post-reload value for {cmd:?}");
        }

        // NOSAVE / NOFLUSH / MERGE keywords still accepted alongside.
        for argv in [
            &[b"DEBUG".as_slice(), b"RELOAD", b"NOSAVE"][..],
            &[b"DEBUG", b"RELOAD", b"NOSAVE", b"NOFLUSH", b"MERGE"],
        ] {
            let argv: Vec<Vec<u8>> = argv.iter().map(|b| b.to_vec()).collect();
            let frame = RespFrame::Array(Some(
                argv.into_iter()
                    .map(|b| RespFrame::BulkString(Some(b)))
                    .collect(),
            ));
            let out = rt.execute_frame(frame, 3);
            assert_eq!(out, RespFrame::SimpleString("OK".to_string()));
        }
    }

    // (frankenredis-hpfey) DEBUG RELOAD / RDB load must preserve runtime CONFIG SET
    // state — the encoding thresholds + eviction policy live in the Store, which
    // the reload swaps for a fresh one. Upstream never resets config on reload; a
    // full-synced replica or DEBUG RELOAD must keep its configured thresholds (else
    // large collections silently re-encode under the compiled-default config).
    #[test]
    fn debug_reload_preserves_store_runtime_config_hpfey() {
        let mut rt = Runtime::default_strict();
        rt.set_enable_debug_command("yes");

        for (name, val) in [
            ("list-max-listpack-size", "64"),
            ("hash-max-listpack-entries", "200"),
            ("hash-max-listpack-value", "99"),
            ("set-max-listpack-entries", "99"),
            ("set-max-intset-entries", "999"),
            ("zset-max-listpack-entries", "99"),
            ("zset-max-listpack-value", "99"),
            ("set-max-listpack-value", "77"),
            ("hll-sparse-max-bytes", "1234"),
            ("maxmemory-policy", "allkeys-lru"),
        ] {
            assert_eq!(
                rt.execute_frame(
                    command(&[b"CONFIG", b"SET", name.as_bytes(), val.as_bytes()]),
                    0
                ),
                RespFrame::SimpleString("OK".to_string()),
                "CONFIG SET {name} failed"
            );
        }

        assert_eq!(
            rt.execute_frame(command(&[b"DEBUG", b"RELOAD"]), 1),
            RespFrame::SimpleString("OK".to_string())
        );

        // Every configured store-level threshold survives the reload.
        assert_eq!(rt.server.store.list_max_listpack_size, 64);
        assert_eq!(rt.server.store.hash_max_listpack_entries, 200);
        assert_eq!(rt.server.store.hash_max_listpack_value, 99);
        assert_eq!(rt.server.store.set_max_listpack_entries, 99);
        assert_eq!(rt.server.store.set_max_intset_entries, 999);
        assert_eq!(rt.server.store.zset_max_listpack_entries, 99);
        assert_eq!(rt.server.store.zset_max_listpack_value, 99);
        assert_eq!(rt.server.store.set_max_listpack_value, 77);
        assert_eq!(rt.server.store.hll_sparse_max_bytes, 1234);
        assert!(matches!(
            rt.server.store.maxmemory_policy,
            fr_store::MaxmemoryPolicy::AllkeysLru
        ));
    }

