    #[test]
    fn config_set_shutdown_on_sig_rejects_save_nosave_combination_per_upstream() {
        // (frankenredis-9a33k) Upstream config.c:2378-2385
        // (validateShutdownOnSigFlags) rejects the SAVE + NOSAVE combo
        // with the dedicated wording 'shutdown options SAVE and NOSAVE
        // can't be used simultaneously'. The two flags are mutually
        // exclusive (one preserves the RDB on shutdown, the other
        // discards). fr previously accepted any token combination from
        // {default, save, nosave, now, force} without checking the
        // pair conflict.
        //
        // Differential probe vs vendored 16380:
        //   CONFIG SET shutdown-on-sigterm 'save now nosave'
        //     vendored: ERR ... SAVE and NOSAVE can't be used simultaneously
        //     fr (pre-fix): OK
        let mut rt = Runtime::default_strict();
        let conflict = |name: &str| {
            format!(
                "ERR CONFIG SET failed (possibly related to argument '{name}') - shutdown options SAVE and NOSAVE can't be used simultaneously"
            )
        };

        for name in ["shutdown-on-sigterm", "shutdown-on-sigint"] {
            // SAVE + NOSAVE in any order rejected.
            for combo in [
                b"save nosave".as_slice(),
                b"nosave save",
                b"save now nosave",
                b"nosave force save",
            ] {
                assert_eq!(
                    rt.execute_frame(command(&[b"CONFIG", b"SET", name.as_bytes(), combo]), 0,),
                    RespFrame::Error(conflict(name)),
                    "{name} {:?} should error",
                    String::from_utf8_lossy(combo),
                );
            }
            // Non-conflicting combos still accepted.
            for ok in [
                b"default".as_slice(),
                b"save",
                b"nosave",
                b"save now",
                b"nosave now force",
                b"save force",
                b"now force",
            ] {
                assert_eq!(
                    rt.execute_frame(command(&[b"CONFIG", b"SET", name.as_bytes(), ok]), 0,),
                    RespFrame::SimpleString("OK".to_string()),
                    "{name} {:?} should succeed",
                    String::from_utf8_lossy(ok),
                );
            }
        }
    }

    #[test]
    fn config_set_replica_priority_uses_table_level_wording_per_upstream() {
        // (frankenredis-ap2eo) Upstream config.c declares
        // replica-priority (and the slave-priority alias) as
        // INTEGER_CONFIG with [0, INT_MAX]. fr previously emitted the
        // non-standard 'Invalid argument' wording for out-of-range and
        // the generic 'value is not an integer or out of range' for
        // unparseable input. Both should route through config_set_failed
        // to match vendored.
        let mut rt = Runtime::default_strict();

        for name in ["replica-priority", "slave-priority"] {
            let bound = format!(
                "ERR CONFIG SET failed (possibly related to argument '{name}') - argument must be between 0 and 2147483647 inclusive"
            );
            let parse = format!(
                "ERR CONFIG SET failed (possibly related to argument '{name}') - argument couldn't be parsed into an integer"
            );
            for bad in [b"-1".as_slice(), b"-100", b"2147483648"] {
                assert_eq!(
                    rt.execute_frame(command(&[b"CONFIG", b"SET", name.as_bytes(), bad]), 0,),
                    RespFrame::Error(bound.clone()),
                    "{name} {:?} should be bound-rejected",
                    String::from_utf8_lossy(bad),
                );
            }
            assert_eq!(
                rt.execute_frame(command(&[b"CONFIG", b"SET", name.as_bytes(), b"abc"]), 0,),
                RespFrame::Error(parse.clone()),
            );
            for good in [b"0".as_slice(), b"100", b"2147483647"] {
                assert_eq!(
                    rt.execute_frame(command(&[b"CONFIG", b"SET", name.as_bytes(), good]), 0,),
                    RespFrame::SimpleString("OK".to_string()),
                    "{name} {:?} should succeed",
                    String::from_utf8_lossy(good),
                );
            }
        }
    }

    #[test]
    fn config_set_active_defrag_ignore_bytes_rejects_zero_per_upstream() {
        // (frankenredis-ap2eo) Upstream config.c declares
        // active-defrag-ignore-bytes as INTEGER_CONFIG with INCLUSIVE
        // range [1, INT64_MAX] — value 0 is not 'never trigger', it's
        // a separate disabled state. fr previously accepted 0.
        let mut rt = Runtime::default_strict();
        let msg = "ERR CONFIG SET failed (possibly related to argument 'active-defrag-ignore-bytes') - argument must be between 1 and 9223372036854775807 inclusive";
        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"active-defrag-ignore-bytes", b"0"]),
                0,
            ),
            RespFrame::Error(msg.to_string())
        );
        // Positive values still accepted.
        for ok in [b"1".as_slice(), b"104857600", b"100kb", b"1g"] {
            assert_eq!(
                rt.execute_frame(
                    command(&[b"CONFIG", b"SET", b"active-defrag-ignore-bytes", ok]),
                    0,
                ),
                RespFrame::SimpleString("OK".to_string()),
                "{:?} should succeed",
                String::from_utf8_lossy(ok),
            );
        }
    }

    #[test]
    fn config_set_maxmemory_clients_validates_memory_or_percent_per_upstream() {
        // (frankenredis-ap2eo) Upstream config.c declares
        // maxmemory-clients with a special validator that accepts
        // memory sizes (1g, 100mb) OR percentages (50%). Invalid forms
        // surface 'argument must be a memory or percent value'. fr
        // previously had no validator and silently stored garbage.
        let mut rt = Runtime::default_strict();
        let msg = "ERR CONFIG SET failed (possibly related to argument 'maxmemory-clients') - argument must be a memory or percent value";
        for bad in [b"-1".as_slice(), b"bogus", b"%", b"-50%", b"50pct"] {
            assert_eq!(
                rt.execute_frame(command(&[b"CONFIG", b"SET", b"maxmemory-clients", bad]), 0,),
                RespFrame::Error(msg.to_string()),
                "{:?} should be rejected",
                String::from_utf8_lossy(bad),
            );
        }
        for good in [b"0".as_slice(), b"100mb", b"1g", b"50%", b"100%"] {
            assert_eq!(
                rt.execute_frame(command(&[b"CONFIG", b"SET", b"maxmemory-clients", good]), 0,),
                RespFrame::SimpleString("OK".to_string()),
                "{:?} should succeed",
                String::from_utf8_lossy(good),
            );
        }
    }

    #[test]
    fn config_set_repl_and_cluster_params_use_table_level_wording_per_upstream() {
        // (frankenredis-cwonr) Pin the wording and bounds for the
        // CONFIG SET parameters that previously emitted ad-hoc
        // "ERR Invalid argument" or accepted out-of-range values.
        // Upstream config.c declares:
        //   - repl-backlog-size:           MEMORY_CONFIG, range [1, LLONG_MAX]
        //   - repl-backlog-ttl:            INTEGER_CONFIG, range [0, LLONG_MAX]
        //   - repl-ping-replica-period:    INTEGER_CONFIG, range [1, INT_MAX]
        //   - repl-ping-slave-period:      alias of above
        //   - repl-timeout:                INTEGER_CONFIG, range [1, INT_MAX]
        //   - cluster-link-sendbuf-limit:  MEMORY_CONFIG, range [0, SIZE_MAX]
        //   - cluster-node-timeout:        LONGLONG_CONFIG, range [0, LLONG_MAX]
        //   - list-max-listpack-size:      INTEGER_CONFIG, range [INT_MIN, INT_MAX]
        // Failures route through configSetFailed → table-level wording.
        let mut rt = Runtime::default_strict();

        let cases: &[(&[u8], &[u8], &str)] = &[
            (
                b"repl-backlog-size",
                b"0",
                "ERR CONFIG SET failed (possibly related to argument 'repl-backlog-size') - argument must be between 1 and 9223372036854775807 inclusive",
            ),
            (
                b"repl-backlog-size",
                b"bogus",
                "ERR CONFIG SET failed (possibly related to argument 'repl-backlog-size') - argument must be a memory value",
            ),
            (
                b"repl-backlog-ttl",
                b"-1",
                "ERR CONFIG SET failed (possibly related to argument 'repl-backlog-ttl') - argument must be between 0 and 9223372036854775807 inclusive",
            ),
            (
                b"repl-ping-replica-period",
                b"0",
                "ERR CONFIG SET failed (possibly related to argument 'repl-ping-replica-period') - argument must be between 1 and 2147483647 inclusive",
            ),
            (
                b"repl-ping-slave-period",
                b"-5",
                "ERR CONFIG SET failed (possibly related to argument 'repl-ping-slave-period') - argument must be between 1 and 2147483647 inclusive",
            ),
            (
                b"repl-timeout",
                b"0",
                "ERR CONFIG SET failed (possibly related to argument 'repl-timeout') - argument must be between 1 and 2147483647 inclusive",
            ),
            (
                b"cluster-link-sendbuf-limit",
                b"-1",
                "ERR CONFIG SET failed (possibly related to argument 'cluster-link-sendbuf-limit') - argument must be a memory value",
            ),
            (
                b"cluster-node-timeout",
                b"-1",
                "ERR CONFIG SET failed (possibly related to argument 'cluster-node-timeout') - argument must be between 0 and 9223372036854775807 inclusive",
            ),
            (
                b"cluster-node-timeout",
                b"bogus",
                "ERR CONFIG SET failed (possibly related to argument 'cluster-node-timeout') - argument couldn't be parsed into an integer",
            ),
        ];
        for (param, bad, expected) in cases {
            assert_eq!(
                rt.execute_frame(command(&[b"CONFIG", b"SET", param, bad]), 0,),
                RespFrame::Error(expected.to_string()),
                "param={:?} bad={:?}",
                String::from_utf8_lossy(param),
                String::from_utf8_lossy(bad),
            );
        }

        // Over-validation regression: list-max-listpack-size must accept
        // values down to INT_MIN (upstream allows full i32 range to encode
        // size-class indices and entry-count bounds).
        for good in [
            b"-100".as_slice(),
            b"-2147483648",
            b"2147483647",
            b"0",
            b"-2",
        ] {
            assert_eq!(
                rt.execute_frame(
                    command(&[b"CONFIG", b"SET", b"list-max-listpack-size", good]),
                    0,
                ),
                RespFrame::SimpleString("OK".to_string()),
                "list-max-listpack-size {:?} should be accepted",
                String::from_utf8_lossy(good),
            );
        }
        // Out-of-range still rejected with i32 bounds wording.
        for bad in [b"2147483648".as_slice(), b"-2147483649"] {
            assert_eq!(
                rt.execute_frame(
                    command(&[b"CONFIG", b"SET", b"list-max-listpack-size", bad]),
                    0,
                ),
                RespFrame::Error(
                    "ERR CONFIG SET failed (possibly related to argument 'list-max-listpack-size') - argument must be between -2147483648 and 2147483647 inclusive"
                        .to_string()
                ),
                "list-max-listpack-size {:?} should be rejected",
                String::from_utf8_lossy(bad),
            );
        }

        // Memory-suffix happy path for repl-backlog-size and cluster
        // sendbuf limit (proves these still parse memory suffixes).
        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"repl-backlog-size", b"4mb"]),
                0,
            ),
            RespFrame::SimpleString("OK".to_string()),
        );
        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"cluster-link-sendbuf-limit", b"1g"]),
                0,
            ),
            RespFrame::SimpleString("OK".to_string()),
        );
    }

    #[test]
    fn redis_7_4_hash_field_ttl_commands_return_unknown_command_per_7_2_4_parity() {
        // (frankenredis-ja8yu) The Redis 7.4 hash field TTL family
        // (HEXPIRE/HPEXPIRE/HEXPIREAT/HPEXPIREAT/HEXPIRETIME/
        // HPEXPIRETIME/HTTL/HPTTL/HPERSIST/HGETEX/HGETDEL) must surface
        // "ERR unknown command" on the wire to match vendored 7.2.4,
        // even though fr-store still implements the underlying
        // primitives so RDB type 21 round-trips can preserve per-field
        // TTL data. Same class as v0swv (DEBUG OBJECT hexpired_fields)
        // and c5746 (HSCAN NOVALUES).
        let mut rt = Runtime::default_strict();
        rt.execute_frame(command(&[b"HSET", b"h", b"f1", b"v1"]), 0);
        let cases: &[&[&[u8]]] = &[
            &[b"HEXPIRE", b"h", b"60", b"FIELDS", b"1", b"f1"],
            &[b"HPEXPIRE", b"h", b"60000", b"FIELDS", b"1", b"f1"],
            &[b"HEXPIREAT", b"h", b"9999999999", b"FIELDS", b"1", b"f1"],
            &[
                b"HPEXPIREAT",
                b"h",
                b"9999999999000",
                b"FIELDS",
                b"1",
                b"f1",
            ],
            &[b"HEXPIRETIME", b"h", b"FIELDS", b"1", b"f1"],
            &[b"HPEXPIRETIME", b"h", b"FIELDS", b"1", b"f1"],
            &[b"HTTL", b"h", b"FIELDS", b"1", b"f1"],
            &[b"HPTTL", b"h", b"FIELDS", b"1", b"f1"],
            &[b"HPERSIST", b"h", b"FIELDS", b"1", b"f1"],
            &[b"HGETEX", b"h", b"FIELDS", b"1", b"f1"],
            &[b"HGETDEL", b"h", b"FIELDS", b"1", b"f1"],
        ];
        for argv in cases {
            let frame = rt.execute_frame(command(argv), 0);
            let RespFrame::Error(msg) = &frame else {
                panic!("expected Error reply for {:?}, got {:?}", argv, frame);
            };
            assert!(
                msg.starts_with("ERR unknown command"),
                "expected 'ERR unknown command' prefix for {:?}, got: {msg}",
                argv,
            );
        }
    }

