    /// (frankenredis-maxclientsupper) Upstream config.c declares
    /// maxclients as INTEGER_CONFIG with the bounded range [1, UINT_MAX]
    /// so values above 4_294_967_295 must surface the documented bound,
    /// not silently widen to a 64-bit usize.
    #[test]
    fn config_set_maxclients_enforces_uint_max_upper_bound() {
        let mut rt = Runtime::default_strict();
        // Lower bound: 0 and -1 already covered elsewhere.
        // Upper bound: 4_294_967_295 must succeed; one over must fail.
        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"maxclients", b"4294967295"]),
                0
            ),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"maxclients", b"4294967296"]),
                0
            ),
            RespFrame::Error(
                "ERR CONFIG SET failed (possibly related to argument 'maxclients') - argument must be between 1 and 4294967295 inclusive"
                    .to_string()
            )
        );
        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"maxclients", b"99999999999"]),
                0
            ),
            RespFrame::Error(
                "ERR CONFIG SET failed (possibly related to argument 'maxclients') - argument must be between 1 and 4294967295 inclusive"
                    .to_string()
            )
        );
    }

    #[test]
    fn config_set_is_atomic_across_runtime_store_and_static_overrides() {
        let mut rt = Runtime::default_strict();

        let set = rt.execute_frame(
            command(&[
                b"CONFIG",
                b"SET",
                b"list-max-listpack-size",
                b"-5",
                b"timeout",
                b"300",
                b"hz",
                b"100",
                b"maxmemory-policy",
                b"allkeys-lru",
                b"maxmemory",
                b"-1",
            ]),
            0,
        );
        assert_eq!(
            set,
            RespFrame::Error(
                "ERR CONFIG SET failed (possibly related to argument 'maxmemory') - argument must be a memory value"
                    .to_string()
            )
        );

        let timeout = rt.execute_frame(command(&[b"CONFIG", b"GET", b"timeout"]), 1);
        assert_eq!(
            timeout,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"timeout".to_vec())),
                RespFrame::BulkString(Some(b"0".to_vec())),
            ]))
        );

        let hz = rt.execute_frame(command(&[b"CONFIG", b"GET", b"hz"]), 1);
        assert_eq!(
            hz,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"hz".to_vec())),
                RespFrame::BulkString(Some(b"10".to_vec())),
            ]))
        );

        let maxmemory_policy =
            rt.execute_frame(command(&[b"CONFIG", b"GET", b"maxmemory-policy"]), 1);
        assert_eq!(
            maxmemory_policy,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"maxmemory-policy".to_vec())),
                RespFrame::BulkString(Some(b"noeviction".to_vec())),
            ]))
        );

        let list_max_listpack_size =
            rt.execute_frame(command(&[b"CONFIG", b"GET", b"list-max-listpack-size"]), 1);
        assert_eq!(
            list_max_listpack_size,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"list-max-listpack-size".to_vec())),
                RespFrame::BulkString(Some(b"-2".to_vec())),
            ]))
        );
    }

