    #[test]
    fn config_set_maxmemory_accepts_redis_memory_suffixes() {
        // (frankenredis-memtu) Empty input, bare suffixes ('b' / 'kb' /
        // 'mb' / 'gb' alone), and zero are all accepted by upstream
        // memtoull and yield 0 — strtoull on the empty digit run is a
        // clean parse, then the multiplier gets applied to 0. fr's
        // parser previously rejected empty / suffix-only / bare-'b'
        // inputs.
        let cases: &[(&[u8], &[u8])] = &[
            (b"100kb", b"102400"),
            (b"100mb", b"104857600"),
            (b"100gb", b"107374182400"),
            (b"100k", b"100000"),
            (b"100m", b"100000000"),
            (b"100g", b"100000000000"),
            (b"100b", b"100"),
            (b"100", b"100"),
            (b"1Gb", b"1073741824"),
            (b"", b"0"),
            (b"b", b"0"),
            (b"kb", b"0"),
            (b"GB", b"0"),
            (b"0", b"0"),
        ];

        let mut rt = Runtime::default_strict();
        for (input, expected_bytes) in cases {
            assert_eq!(
                rt.execute_frame(command(&[b"CONFIG", b"SET", b"maxmemory", input]), 0),
                RespFrame::SimpleString("OK".to_string()),
                "CONFIG SET maxmemory {}",
                String::from_utf8_lossy(input)
            );
            assert_eq!(
                rt.execute_frame(command(&[b"CONFIG", b"GET", b"maxmemory"]), 0),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"maxmemory".to_vec())),
                    RespFrame::BulkString(Some((*expected_bytes).to_vec())),
                ])),
                "CONFIG GET maxmemory after {}",
                String::from_utf8_lossy(input)
            );
            assert_eq!(
                rt.server.maxmemory_bytes.to_string().as_bytes(),
                *expected_bytes
            );
            assert_eq!(
                rt.server.store.maxmemory_bytes_live.to_string().as_bytes(),
                *expected_bytes
            );
        }
    }

    #[test]
    fn config_set_maxmemory_silently_saturates_on_strtoull_overflow() {
        // (frankenredis-cfgmemovf) Upstream util.c::memtoull calls
        // strtoull and only fails on EINVAL or trailing non-digit
        // chars — ERANGE is silently accepted, so an overflowing
        // digit run becomes ULLONG_MAX and the subsequent val*mul
        // wraps modulo 2^64. fr was rejecting overflow at the
        // digits.parse step and again at checked_mul, surfacing
        // 'argument must be a memory value' for inputs that
        // vendored 7.2.4 happily accepts. Match the wrap-around
        // value byte-for-byte.
        let mut rt = Runtime::default_strict();

        // Digit overflow + gb suffix: matches vendored output.
        // u64::MAX.wrapping_mul(1024^3) == 18446744072635809792.
        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"maxmemory", b"9999999999999999999999gb",]),
                0,
            ),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"CONFIG", b"GET", b"maxmemory"]), 0),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"maxmemory".to_vec())),
                RespFrame::BulkString(Some(b"18446744072635809792".to_vec())),
            ]))
        );

        // No-suffix overflow: digits saturate to u64::MAX, mul=1
        // leaves the value at u64::MAX = 18446744073709551615.
        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"maxmemory", b"99999999999999999999",]),
                0,
            ),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.execute_frame(command(&[b"CONFIG", b"GET", b"maxmemory"]), 0),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"maxmemory".to_vec())),
                RespFrame::BulkString(Some(b"18446744073709551615".to_vec())),
            ]))
        );

        // Negative still rejected (memtoull returns err on '-' prefix).
        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"maxmemory", b"-1"]),
                0,
            ),
            RespFrame::Error(
                "ERR CONFIG SET failed (possibly related to argument 'maxmemory') - argument must be a memory value"
                    .to_string()
            )
        );

        // Unknown suffix still rejected (memtoull's else branch).
        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"maxmemory", b"5xb"]),
                0,
            ),
            RespFrame::Error(
                "ERR CONFIG SET failed (possibly related to argument 'maxmemory') - argument must be a memory value"
                    .to_string()
            )
        );
    }

    #[test]
    fn config_set_rejects_duplicate_parameters_within_one_call() {
        // (frankenredis-cfgdup) Upstream config.c::configSetCommand
        // walks the pair list, tracks each resolved config, and fires
        // the dedicated 'duplicate parameter' error when the same
        // config appears twice. Detection is case-insensitive — the
        // CONFIG SET parameter lookup itself is case-insensitive, so
        // `MaxMemory` and `maxmemory` count as a duplicate. fr
        // previously let duplicates win silently (last value applied).
        let mut rt = Runtime::default_strict();
        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"CONFIG",
                    b"SET",
                    b"maxmemory",
                    b"100",
                    b"maxmemory",
                    b"200",
                ]),
                0,
            ),
            RespFrame::Error(
                "ERR CONFIG SET failed (possibly related to argument 'maxmemory') - duplicate parameter"
                    .to_string()
            )
        );
        // Case-insensitive duplicate.
        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"CONFIG",
                    b"SET",
                    b"MaxMemory",
                    b"100",
                    b"maxmemory",
                    b"200",
                ]),
                1,
            ),
            RespFrame::Error(
                "ERR CONFIG SET failed (possibly related to argument 'maxmemory') - duplicate parameter"
                    .to_string()
            )
        );
        // Non-duplicate two-pair call still succeeds.
        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"CONFIG",
                    b"SET",
                    b"maxmemory",
                    b"100",
                    b"tcp-keepalive",
                    b"30",
                ]),
                2,
            ),
            RespFrame::SimpleString("OK".to_string())
        );
        // First-occurrence value never lands when the call errors.
        // The earlier error path returned 'maxmemory 0' (untouched);
        // the success path above set it to 100. Verify final state.
        assert_eq!(
            rt.execute_frame(command(&[b"CONFIG", b"GET", b"maxmemory"]), 3),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"maxmemory".to_vec())),
                RespFrame::BulkString(Some(b"100".to_vec())),
            ]))
        );
    }

    #[test]
    fn config_set_proto_max_bulk_len_rejects_below_one_mib() {
        // Upstream config.c declares proto-max-bulk-len with a 1MB
        // lower bound, so values below 1048576 are rejected with
        // the table-level range error. (br-frankenredis-cfgmemvalue)
        let mut rt = Runtime::default_strict();
        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"proto-max-bulk-len", b"1"]),
                0
            ),
            RespFrame::Error(
                "ERR CONFIG SET failed (possibly related to argument 'proto-max-bulk-len') - argument must be between 1048576 and 9223372036854775807 inclusive"
                    .to_string()
            )
        );
    }

    #[test]
    fn config_set_client_output_buffer_limit_updates_live_runtime_state() {
        let mut rt = Runtime::default_strict();

        // Strict default is redis-exact: normal unlimited, slave/pubsub capped.
        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"GET", b"client-output-buffer-limit"]),
                0
            ),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"client-output-buffer-limit".to_vec())),
                RespFrame::BulkString(Some(
                    b"normal 0 0 0 slave 268435456 67108864 60 pubsub 33554432 8388608 60".to_vec()
                )),
            ]))
        );

        // Per-class SET (single call may update several classes), human sizes.
        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"CONFIG",
                    b"SET",
                    b"client-output-buffer-limit",
                    b"normal 1mb 512kb 10 pubsub 0 0 0",
                ]),
                1
            ),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            rt.server.client_output_buffer_limits.normal,
            OutputBufferClassLimit {
                hard: 1024 * 1024,
                soft: 512 * 1024,
                soft_seconds: 10
            }
        );
        assert_eq!(rt.server.client_output_buffer_limits.pubsub.hard, 0);
        // Unmentioned class (slave) is preserved.
        assert_eq!(
            rt.server.client_output_buffer_limits.slave.hard,
            256 * 1024 * 1024
        );

        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"GET", b"client-output-buffer-limit"]),
                2
            ),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"client-output-buffer-limit".to_vec())),
                RespFrame::BulkString(Some(
                    b"normal 1048576 524288 10 slave 268435456 67108864 60 pubsub 0 0 0".to_vec()
                )),
            ]))
        );

        // A bare number is a syntax error (wrong arg count), matching redis.
        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"client-output-buffer-limit", b"1024"]),
                3
            ),
            config_set_failed(
                "client-output-buffer-limit",
                "Wrong number of arguments in buffer limit configuration."
            )
        );
        // An invalid class is rejected.
        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"CONFIG",
                    b"SET",
                    b"client-output-buffer-limit",
                    b"foo 1mb 1mb 1"
                ]),
                4
            ),
            config_set_failed(
                "client-output-buffer-limit",
                "Invalid client class specified in buffer limit configuration."
            )
        );
    }

    #[test]
    fn client_output_buffer_limit_mode_split_strict_redis_exact_hardened_caps_normal() {
        // (frankenredis-8sb0l) Compatibility Doctrine mode-split: strict mode is
        // redis-exact (normal class unlimited, hard 0); hardened mode reinstalls
        // fr's 256 MiB OOM guard for normal clients. slave/pubsub are identical
        // across modes (redis defaults).
        let strict = Runtime::default_strict();
        assert_eq!(strict.server.client_output_buffer_limits.normal.hard, 0);
        // An unknown/normal client_id is unlimited in strict → never disconnected.
        assert_eq!(strict.effective_output_hard_limit(99_999), usize::MAX);

        let hardened = Runtime::default_hardened();
        assert_eq!(
            hardened.server.client_output_buffer_limits.normal.hard,
            256 * 1024 * 1024
        );
        assert_eq!(
            hardened.effective_output_hard_limit(99_999),
            256 * 1024 * 1024
        );

        for rt in [&strict, &hardened] {
            assert_eq!(
                rt.server.client_output_buffer_limits.slave.hard,
                256 * 1024 * 1024
            );
            assert_eq!(
                rt.server.client_output_buffer_limits.pubsub.hard,
                32 * 1024 * 1024
            );
        }
    }

    #[test]
    fn config_set_latency_tracking_controls_info_latencystats() {
        let mut rt = Runtime::default_strict();

        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"CONFIG",
                    b"SET",
                    b"latency-tracking",
                    b"no",
                    b"latency-tracking-info-percentiles",
                    b"50 99.9",
                ]),
                0,
            ),
            RespFrame::SimpleString("OK".to_string())
        );
        assert!(!rt.server.latency_tracking);
        assert_eq!(rt.server.latency_percentiles, vec![50.0, 99.9]);

        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"CONFIG",
                    b"GET",
                    b"latency-tracking",
                    b"latency-tracking-info-percentiles",
                ]),
                1,
            ),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"latency-tracking".to_vec())),
                RespFrame::BulkString(Some(b"no".to_vec())),
                RespFrame::BulkString(Some(b"latency-tracking-info-percentiles".to_vec(),)),
                RespFrame::BulkString(Some(b"50 99.9".to_vec())),
            ]))
        );

        assert_eq!(
            rt.execute_frame(command(&[b"GET", b"missing"]), 2),
            RespFrame::BulkString(None)
        );

        let disabled_info = rt.execute_frame(command(&[b"INFO", b"latencystats"]), 3);
        let RespFrame::BulkString(Some(disabled_info_bytes)) = disabled_info else {
            unreachable!("expected bulk INFO response");
        };
        let disabled_info = String::from_utf8(disabled_info_bytes).expect("utf8 info");
        assert!(
            disabled_info.contains("# Latencystats\r\n"),
            "{disabled_info}"
        );
        // (frankenredis-6n2qm) Histogram keys are canonicalised to
        // lowercase at the recording site.
        assert!(
            !disabled_info.contains("latency_percentiles_usec_get:"),
            "{disabled_info}"
        );

        assert_eq!(
            rt.execute_frame(
                command(&[b"CONFIG", b"SET", b"latency-tracking", b"yes"]),
                4
            ),
            RespFrame::SimpleString("OK".to_string())
        );

        assert_eq!(
            rt.execute_frame(command(&[b"GET", b"missing"]), 5),
            RespFrame::BulkString(None)
        );

        let enabled_info = rt.execute_frame(command(&[b"INFO", b"latencystats"]), 6);
        let RespFrame::BulkString(Some(enabled_info_bytes)) = enabled_info else {
            unreachable!("expected bulk INFO response");
        };
        let enabled_info = String::from_utf8(enabled_info_bytes).expect("utf8 info");
        assert!(enabled_info.contains("latency_percentiles_usec_get:p50="));
        assert!(enabled_info.contains("p99.9="));
        // (frankenredis-7flec) Upstream server.c::
        // fillPercentileDistributionLatencies emits %.3f for the
        // percentile value. Pin the format width so we don't drift
        // back to %.2f. The exact bucket boundary depends on histogram
        // state, but every value must end in 3 fractional digits and
        // never 2 ('.NN,' would mean we regressed to %.2f).
        for line in enabled_info.lines() {
            if !line.starts_with("latency_percentiles_usec_") {
                continue;
            }
            for chunk in line.split(',') {
                if let Some(eq) = chunk.find('=') {
                    let val = &chunk[eq + 1..];
                    if let Some(dot) = val.find('.') {
                        let frac = &val[dot + 1..];
                        assert_eq!(
                            frac.len(),
                            3,
                            "latencystats value '{val}' must have 3 fractional digits to match upstream %.3f"
                        );
                    }
                }
            }
        }
    }

    // ── AOF persistence round-trip tests ────────────────────────────────

    #[test]
    fn save_and_load_aof_round_trip() {
        let dir = std::env::temp_dir().join("fr_runtime_aof_test");
        let _ = std::fs::create_dir_all(&dir);
        clean_aof_artifacts(&dir, "test_save.aof");
        let aof_path = dir.join("test_save.aof");

        // Populate a runtime with various data types
        let mut rt = Runtime::default_strict();
        rt.set_aof_path(aof_path.clone());

        rt.execute_frame(command(&[b"SET", b"str_key", b"hello"]), 100);
        rt.execute_frame(
            command(&[b"HSET", b"hash_key", b"f1", b"v1", b"f2", b"v2"]),
            100,
        );
        rt.execute_frame(command(&[b"RPUSH", b"list_key", b"a", b"b", b"c"]), 100);
        rt.execute_frame(command(&[b"SADD", b"set_key", b"x", b"y", b"z"]), 100);
        rt.execute_frame(
            command(&[b"ZADD", b"zset_key", b"1.5", b"alice", b"2.5", b"bob"]),
            100,
        );

        // SAVE to persist
        let save_result = rt.execute_frame(command(&[b"SAVE"]), 100);
        assert_eq!(save_result, RespFrame::SimpleString("OK".to_string()));

        // Verify the appendonlydir manifest was written. (frankenredis-oe6qt)
        assert!(dir.join("test_save.aof.manifest").exists());

        // Load into a fresh runtime
        let mut rt2 = Runtime::default_strict();
        rt2.set_aof_path(aof_path.clone());
        let loaded = rt2.load_aof(100).expect("load should succeed");
        assert!(loaded > 0, "should have loaded some records");

        // Verify data was restored
        let get = rt2.execute_frame(command(&[b"GET", b"str_key"]), 100);
        assert_eq!(get, RespFrame::BulkString(Some(b"hello".to_vec())));

        let hgetall = rt2.execute_frame(command(&[b"HGET", b"hash_key", b"f1"]), 100);
        assert_eq!(hgetall, RespFrame::BulkString(Some(b"v1".to_vec())));

        let lrange = rt2.execute_frame(command(&[b"LLEN", b"list_key"]), 100);
        assert_eq!(lrange, RespFrame::Integer(3));

        let scard = rt2.execute_frame(command(&[b"SCARD", b"set_key"]), 100);
        assert_eq!(scard, RespFrame::Integer(3));

        let zscore = rt2.execute_frame(command(&[b"ZSCORE", b"zset_key", b"alice"]), 100);
        assert_eq!(zscore, RespFrame::BulkString(Some(b"1.5".to_vec())));

        // Cleanup
        let _ = std::fs::remove_file(&aof_path);
    }

    #[test]
    fn save_and_load_aof_round_trip_with_streams_and_ttl() {
        let dir = std::env::temp_dir().join("fr_runtime_aof_stream_test");
        let _ = std::fs::create_dir_all(&dir);
        clean_aof_artifacts(&dir, "test_stream.aof");
        let aof_path = dir.join("test_stream.aof");

        let mut rt = Runtime::default_strict();
        rt.set_aof_path(aof_path.clone());

        // Add a stream
        rt.execute_frame(
            command(&[b"XADD", b"mystream", b"1-0", b"name", b"Alice"]),
            100,
        );
        rt.execute_frame(
            command(&[b"XADD", b"mystream", b"2-0", b"name", b"Bob"]),
            100,
        );

        // Add a key with TTL
        rt.execute_frame(
            command(&[b"SET", b"ttl_key", b"expiring", b"PX", b"60000"]),
            100,
        );

        // SAVE to persist
        let save_result = rt.execute_frame(command(&[b"SAVE"]), 100);
        assert_eq!(save_result, RespFrame::SimpleString("OK".to_string()));
        assert!(dir.join("test_stream.aof.manifest").exists());

        // Load into fresh runtime
        let mut rt2 = Runtime::default_strict();
        rt2.set_aof_path(aof_path.clone());
        let loaded = rt2.load_aof(100).expect("load should succeed");
        assert!(loaded > 0);

        // Verify stream was restored
        let xlen = rt2.execute_frame(command(&[b"XLEN", b"mystream"]), 100);
        assert_eq!(xlen, RespFrame::Integer(2));

        // Verify TTL key exists and has TTL
        let get_ttl = rt2.execute_frame(command(&[b"GET", b"ttl_key"]), 100);
        assert_eq!(get_ttl, RespFrame::BulkString(Some(b"expiring".to_vec())));
        let pttl = rt2.execute_frame(command(&[b"PTTL", b"ttl_key"]), 100);
        // TTL should be positive (key not expired)
        if let RespFrame::Integer(ms) = pttl {
            assert!(ms > 0, "TTL key should have positive PTTL, got {ms}");
        } else {
            unreachable!("Expected integer from PTTL, got: {pttl:?}");
        }

        let _ = std::fs::remove_file(&aof_path);
    }

    #[test]
    fn save_and_load_aof_round_trip_multi_db() {
        let dir = std::env::temp_dir().join("fr_runtime_aof_multidb_test");
        let _ = std::fs::create_dir_all(&dir);
        clean_aof_artifacts(&dir, "test_multidb.aof");
        let aof_path = dir.join("test_multidb.aof");

        let mut rt = Runtime::default_strict();
        rt.set_aof_path(aof_path.clone());

        // DB 0: string
        assert_eq!(
            rt.execute_frame(command(&[b"SET", b"db0:key", b"zero"]), 100),
            RespFrame::SimpleString("OK".to_string())
        );

        // DB 1: hash
        rt.execute_frame(command(&[b"SELECT", b"1"]), 100);
        assert_eq!(
            rt.execute_frame(
                command(&[b"HSET", b"db1:hash", b"f1", b"v1", b"f2", b"v2"]),
                100,
            ),
            RespFrame::Integer(2)
        );

        // DB 2: list
        rt.execute_frame(command(&[b"SELECT", b"2"]), 100);
        assert_eq!(
            rt.execute_frame(command(&[b"RPUSH", b"db2:list", b"a", b"b", b"c"]), 100),
            RespFrame::Integer(3)
        );

        // DB 3: set
        rt.execute_frame(command(&[b"SELECT", b"3"]), 100);
        assert_eq!(
            rt.execute_frame(command(&[b"SADD", b"db3:set", b"x", b"y", b"z"]), 100),
            RespFrame::Integer(3)
        );

        // DB 4: sorted set
        rt.execute_frame(command(&[b"SELECT", b"4"]), 100);
        assert_eq!(
            rt.execute_frame(
                command(&[b"ZADD", b"db4:zset", b"1", b"a", b"2", b"b"]),
                100
            ),
            RespFrame::Integer(2)
        );

        // SAVE
        rt.execute_frame(command(&[b"SELECT", b"0"]), 100);
        assert_eq!(
            rt.execute_frame(command(&[b"SAVE"]), 100),
            RespFrame::SimpleString("OK".to_string())
        );
        let manifest = dir.join("test_multidb.aof.manifest");
        let loaded_manifest =
            fr_persist::read_aof_manifest_dir(&manifest).expect("load manifest snapshot");
        assert!(
            loaded_manifest
                .base_rdb_entries
                .iter()
                .any(|entry| entry.db == 1
                    && entry.key == b"db1:hash"
                    && matches!(entry.value, RdbValue::Hash(_))),
            "SAVE manifest base RDB must include DB 1 hash, got {:?}",
            loaded_manifest.base_rdb_entries
        );
        assert!(
            loaded_manifest
                .base_rdb_entries
                .iter()
                .any(|entry| entry.db == 2
                    && entry.key == b"db2:list"
                    && matches!(entry.value, RdbValue::List(_))),
            "SAVE manifest base RDB must include DB 2 list, got {:?}",
            loaded_manifest.base_rdb_entries
        );
        assert!(
            loaded_manifest
                .base_rdb_entries
                .iter()
                .any(|entry| entry.db == 3
                    && entry.key == b"db3:set"
                    && matches!(entry.value, RdbValue::Set(_))),
            "SAVE manifest base RDB must include DB 3 set, got {:?}",
            loaded_manifest.base_rdb_entries
        );
        assert!(
            loaded_manifest
                .base_rdb_entries
                .iter()
                .any(|entry| entry.db == 4
                    && entry.key == b"db4:zset"
                    && matches!(entry.value, RdbValue::SortedSet(_))),
            "SAVE manifest base RDB must include DB 4 zset, got {:?}",
            loaded_manifest.base_rdb_entries
        );

        // Load into fresh runtime
        let mut rt2 = Runtime::default_strict();
        rt2.set_aof_path(aof_path.clone());
        let loaded = rt2.load_aof(100).expect("load should succeed");
        assert!(loaded > 0);

        // Verify DB 0
        assert_eq!(
            rt2.execute_frame(command(&[b"GET", b"db0:key"]), 100),
            RespFrame::BulkString(Some(b"zero".to_vec()))
        );

        // Verify DB 1
        rt2.execute_frame(command(&[b"SELECT", b"1"]), 100);
        assert_eq!(
            rt2.execute_frame(command(&[b"HGET", b"db1:hash", b"f1"]), 100),
            RespFrame::BulkString(Some(b"v1".to_vec()))
        );
        assert_eq!(
            rt2.execute_frame(command(&[b"HLEN", b"db1:hash"]), 100),
            RespFrame::Integer(2)
        );

        // Verify DB 2
        rt2.execute_frame(command(&[b"SELECT", b"2"]), 100);
        assert_eq!(
            rt2.execute_frame(command(&[b"LLEN", b"db2:list"]), 100),
            RespFrame::Integer(3)
        );

        // Verify DB 3
        rt2.execute_frame(command(&[b"SELECT", b"3"]), 100);
        assert_eq!(
            rt2.execute_frame(command(&[b"SCARD", b"db3:set"]), 100),
            RespFrame::Integer(3)
        );

        // Verify DB 4
        rt2.execute_frame(command(&[b"SELECT", b"4"]), 100);
        assert_eq!(
            rt2.execute_frame(command(&[b"ZCARD", b"db4:zset"]), 100),
            RespFrame::Integer(2)
        );
        assert_eq!(
            rt2.execute_frame(command(&[b"ZSCORE", b"db4:zset", b"b"]), 100),
            RespFrame::BulkString(Some(b"2".to_vec()))
        );

        let _ = std::fs::remove_file(&aof_path);
    }

