    #[test]
    fn acl_setuser_rejects_usernames_containing_whitespace_or_nul_mdg4o() {
        // (frankenredis-mdg4o) Pin upstream acl.c::aclCommand SETUSER
        // ACLStringHasSpaces check — reject names containing any
        // C-isspace byte (space, tab, newline, VT, FF, CR) or NUL. fr
        // previously accepted any byte sequence, so `ACL SETUSER "bad
        // name" ...` would silently create a user whose name breaks the
        // ACL-file serializer (which splits on whitespace on reload).
        let mut rt = Runtime::default_strict();
        let bad_names: &[&[u8]] = &[
            b"with space",
            b"tab\tname",
            b"newline\nname",
            b"vtab\x0bname",
            b"formfeed\x0cname",
            b"cr\rname",
            b"nul\x00name",
        ];
        for bad in bad_names {
            let reply = rt.execute_frame(command(&[b"ACL", b"SETUSER", bad, b"on", b">pw"]), 0);
            assert_eq!(
                reply,
                RespFrame::Error(
                    "ERR Usernames can't contain spaces or null characters".to_string()
                ),
                "expected SETUSER to reject {bad:?}",
            );
            // Bad-named user must not be created.
            assert!(
                !rt.server.auth_state.acl_users.contains_key(*bad),
                "user {bad:?} must not be inserted",
            );
        }

        // Sanity check: names with $ : @ - _ and other non-whitespace
        // symbols are still accepted, and empty name is also accepted
        // (matches upstream — ACLStringHasSpaces returns false for len 0).
        let ok_names: &[&[u8]] = &[
            b"alice",
            b"alice$bob",
            b"alice:bob",
            b"user-with-dashes",
            b"user_with_underscores",
            b"",
        ];
        for ok in ok_names {
            let reply = rt.execute_frame(command(&[b"ACL", b"SETUSER", ok, b"on", b">pw"]), 1);
            assert_eq!(
                reply,
                RespFrame::SimpleString("OK".to_string()),
                "expected SETUSER to accept {ok:?}",
            );
        }
    }

    #[test]
    fn acl_commands_string_preserves_explicit_cmds_after_allcommands_23o12() {
        // (frankenredis-23o12) `commands_string` previously short-
        // circuited as soon as `all_commands` was set, dropping any
        // explicit `+cmd`/`+@cat` modifiers layered on top of `+@all`.
        // Vendored re-emits them so the rule round-trips exactly:
        //   +@all +debug      -> "+@all +debug"  (was: "+@all")
        //   +@all -DEBUG +debug -> "+@all +debug" (was: "+@all")
        //   +@all              -> "+@all"        (unchanged)
        //   +@all -DEBUG       -> "+@all -debug" (unchanged)
        let mut rt = Runtime::default_strict();

        let cases = [
            // (rules, expected commands_string)
            (vec!["on", "+@all"], "+@all"),
            (vec!["on", "+@all", "+debug"], "+@all +debug"),
            (vec!["on", "+@all", "-DEBUG", "+debug"], "+@all +debug"),
            (vec!["on", "+@all", "-DEBUG"], "+@all -debug"),
            (vec!["on", "+@all", "+set"], "+@all +set"),
            (vec!["on", "+@all", "+@read"], "+@all +@read"),
        ];

        for (rules, expected) in cases {
            let user = format!("u_{}", expected.replace(['+', '@', '-', ' '], "_"));
            rt.execute_frame(command(&[b"ACL", b"DELUSER", user.as_bytes()]), 0);
            let mut argv: Vec<Vec<u8>> = vec![
                b"ACL".to_vec(),
                b"SETUSER".to_vec(),
                user.as_bytes().to_vec(),
            ];
            for r in &rules {
                argv.push(r.as_bytes().to_vec());
            }
            let argv_frame = RespFrame::Array(Some(
                argv.iter()
                    .map(|a| RespFrame::BulkString(Some(a.clone())))
                    .collect(),
            ));
            let reply = rt.execute_frame(argv_frame, 0);
            assert_eq!(
                reply,
                RespFrame::SimpleString("OK".to_string()),
                "SETUSER {user} with rules {rules:?} should succeed: got {reply:?}",
            );
            let acl_user = rt
                .server
                .auth_state
                .get_user(user.as_bytes())
                .unwrap_or_else(|| panic!("user {user} should exist after SETUSER"));
            let line = acl_user.acl_list_line(user.as_bytes());
            assert!(
                line.ends_with(expected) || line.contains(&format!(" {expected}")),
                "user {user} rules {rules:?}: expected line to contain trailing '{expected}', got line={line:?}",
            );
        }
    }

    #[test]
    fn acl_setuser_rejects_unknown_category_modifier() {
        // Pin upstream acl.c::ACLSetUser rejection of +@<unknown> /
        // -@<unknown> with "Unknown command or category name in ACL"
        // (frankenredis-acn5). +@all and known categories must still
        // succeed; only the bad-category contexts surface the error.
        let mut rt = Runtime::default_strict();

        let reply = rt.execute_frame(
            command(&[b"ACL", b"SETUSER", b"alice", b"on", b">pw", b"+@badcat"]),
            0,
        );
        assert_eq!(
            reply,
            RespFrame::Error(
                "ERR Error in ACL SETUSER modifier '+@badcat': Unknown command or category name in ACL".to_string()
            )
        );

        let reply = rt.execute_frame(
            command(&[b"ACL", b"SETUSER", b"alice", b"on", b">pw", b"-@bogus"]),
            1,
        );
        assert_eq!(
            reply,
            RespFrame::Error(
                "ERR Error in ACL SETUSER modifier '-@bogus': Unknown command or category name in ACL".to_string()
            )
        );

        // Sanity: real category +@read still succeeds.
        let reply = rt.execute_frame(
            command(&[b"ACL", b"SETUSER", b"alice", b"on", b">pw", b"+@read"]),
            2,
        );
        assert_eq!(reply, RespFrame::SimpleString("OK".to_string()));
    }

    #[test]
    fn acl_setuser_selector_errors_match_upstream_aclsel() {
        // (frankenredis-aclsel) Upstream acl.c selector parsing edge cases.
        let mut rt = Runtime::default_strict();
        let err = |rt: &mut Runtime, rule: &[u8]| -> String {
            match rt.execute_frame(command(&[b"ACL", b"SETUSER", b"u", b"reset", rule]), 0) {
                RespFrame::Error(e) => e,
                other => panic!(
                    "expected error for {:?}, got {other:?}",
                    String::from_utf8_lossy(rule)
                ),
            }
        };
        // Unmatched parenthesis reports the text from the '(' onward.
        assert_eq!(
            err(&mut rt, b"(+get"),
            "ERR Unmatched parenthesis in acl selector starting at '(+get'."
        );
        assert_eq!(
            err(&mut rt, b"("),
            "ERR Unmatched parenthesis in acl selector starting at '('."
        );
        // Identity rules inside a selector report the ORIGINAL arg, not the
        // inner token.
        assert_eq!(
            err(&mut rt, b"(on)"),
            "ERR Error in ACL SETUSER modifier '(on)': Syntax error"
        );
        assert_eq!(
            err(&mut rt, b"(>pass)"),
            "ERR Error in ACL SETUSER modifier '(>pass)': Syntax error"
        );
        // Nested selectors are rejected (no recursion).
        assert_eq!(
            err(&mut rt, b"((+get))"),
            "ERR Error in ACL SETUSER modifier '((+get))': Syntax error"
        );
        assert_eq!(
            err(&mut rt, b"(~k1 (+get))"),
            "ERR Error in ACL SETUSER modifier '(~k1 (+get))': Syntax error"
        );
        // Two parenthesised groups in one arg: the first inner token fails as an
        // unknown command, reported against the whole original arg.
        assert_eq!(
            err(&mut rt, b"(+get) (+set)"),
            "ERR Error in ACL SETUSER modifier '(+get) (+set)': Unknown command or category name in ACL"
        );
        // A valid selector still applies cleanly.
        assert_eq!(
            rt.execute_frame(
                command(&[b"ACL", b"SETUSER", b"u", b"reset", b"(+@read ~k*)"]),
                0
            ),
            RespFrame::SimpleString("OK".to_string())
        );
    }

    #[test]
    fn acl_per_subcommand_rejects_unknown_selector() {
        // (frankenredis-6lgmx) Upstream's `+parent|sub` rule
        // validates the sub against the parent's known subcommands
        // ONLY when the parent owns subcommands. ACL has
        // subcommands, so `+acl|nosuch` is rejected. GET has no
        // subcommands, so `+get|invalid` is accepted blindly.
        let mut rt = Runtime::default_strict();

        // Parent with subcommands + unknown sub → reject.
        let reply = rt.execute_frame(
            command(&[
                b"ACL",
                b"SETUSER",
                b"sub",
                b"on",
                b">pass",
                b"-@all",
                b"+acl|nosuch",
                b"allkeys",
            ]),
            0,
        );
        assert!(
            matches!(&reply, RespFrame::Error(err) if err.contains("Unknown command or category name in ACL")),
            "unknown ACL subcommand selector should be rejected, got {reply:?}"
        );

        // Parent without subcommands + any sub → accept blindly.
        let reply = rt.execute_frame(
            command(&[
                b"ACL",
                b"SETUSER",
                b"sub2",
                b"on",
                b">pass",
                b"-@all",
                b"+get|invalid",
                b"allkeys",
            ]),
            0,
        );
        assert_eq!(
            reply,
            RespFrame::SimpleString("OK".to_string()),
            "+get|invalid should be accepted because GET has no subcommands"
        );

        // Parent with subcommands + known sub → accept.
        let reply = rt.execute_frame(
            command(&[
                b"ACL",
                b"SETUSER",
                b"sub3",
                b"on",
                b">pass",
                b"-@all",
                b"+client|setname",
                b"allkeys",
            ]),
            0,
        );
        assert_eq!(
            reply,
            RespFrame::SimpleString("OK".to_string()),
            "+client|setname is a real subcommand"
        );

        // Unknown parent → reject.
        let reply = rt.execute_frame(
            command(&[
                b"ACL",
                b"SETUSER",
                b"sub4",
                b"on",
                b">pass",
                b"-@all",
                b"+nosuchcmd|whatever",
                b"allkeys",
            ]),
            0,
        );
        assert!(
            matches!(&reply, RespFrame::Error(err) if err.contains("Unknown command or category name in ACL")),
            "unknown parent should be rejected, got {reply:?}"
        );
    }

