    #[test]
    fn acl_per_command_override_category_deny() {
        let mut rt = Runtime::default_strict();
        // -@all +@read +set: deny all, allow reads, plus specifically allow SET
        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"ACL", b"SETUSER", b"mixed", b"on", b">pass", b"-@all", b"+@read", b"+set",
                    b"allkeys"
                ]),
                0
            ),
            RespFrame::SimpleString("OK".to_string())
        );

        // Dryrun: GET should be allowed (via +@read)
        assert_eq!(
            rt.execute_frame(command(&[b"ACL", b"DRYRUN", b"mixed", b"GET", b"k"]), 1),
            RespFrame::SimpleString("OK".to_string())
        );

        // Dryrun: SET should be allowed (via +set)
        assert_eq!(
            rt.execute_frame(
                command(&[b"ACL", b"DRYRUN", b"mixed", b"SET", b"k", b"v"]),
                2
            ),
            RespFrame::SimpleString("OK".to_string())
        );

        // Dryrun: DEL should be denied (not in +@read, not explicitly allowed)
        let reply = rt.execute_frame(command(&[b"ACL", b"DRYRUN", b"mixed", b"DEL", b"k"]), 3);
        assert!(
            matches!(&reply, RespFrame::BulkString(Some(b)) if std::str::from_utf8(b).map(|s| s.contains("no permissions")).unwrap_or(false)),
            "DEL should be denied, got: {reply:?}"
        );
    }

    #[test]
    fn acl_explicit_allow_overrides_category_deny() {
        // Upstream `+@all -@dangerous +flushdb`: every command in
        // @all is allowed except the @dangerous category, but the
        // explicit `+flushdb` re-grants FLUSHDB. Per-command rules
        // beat category rules. (br-frankenredis-r81v)
        let mut rt = Runtime::default_strict();
        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"ACL",
                    b"SETUSER",
                    b"flushdb_ok",
                    b"on",
                    b">pass",
                    b"+@all",
                    b"-@dangerous",
                    b"+flushdb",
                    b"allkeys",
                ]),
                0
            ),
            RespFrame::SimpleString("OK".to_string())
        );

        // FLUSHDB explicitly re-allowed via +flushdb
        assert_eq!(
            rt.execute_frame(command(&[b"ACL", b"DRYRUN", b"flushdb_ok", b"FLUSHDB"]), 1),
            RespFrame::SimpleString("OK".to_string())
        );

        // Other @dangerous commands remain denied
        let reply = rt.execute_frame(command(&[b"ACL", b"DRYRUN", b"flushdb_ok", b"FLUSHALL"]), 2);
        assert!(
            matches!(&reply, RespFrame::BulkString(Some(b)) if std::str::from_utf8(b).map(|s| s.contains("no permissions")).unwrap_or(false)),
            "FLUSHALL should remain denied via -@dangerous, got: {reply:?}"
        );

        // Read-side commands still allowed via +@all base
        assert_eq!(
            rt.execute_frame(
                command(&[b"ACL", b"DRYRUN", b"flushdb_ok", b"GET", b"k"]),
                3
            ),
            RespFrame::SimpleString("OK".to_string())
        );
    }

    #[test]
    fn command_to_keyspace_event_names_match_upstream() {
        // (frankenredis-ylu1p) Several commands fire a keyspace event whose
        // name differs from the command verb. Verified vs vendored 7.2.4.
        let ev = |parts: &[&[u8]]| {
            let argv: Vec<Vec<u8>> = parts.iter().map(|p| p.to_vec()).collect();
            Runtime::command_to_keyspace_event(&argv)
        };
        assert_eq!(ev(&[b"SETRANGE", b"k", b"0", b"x"]), "setrange");
        assert_eq!(ev(&[b"ZINCRBY", b"z", b"1", b"m"]), "zincr");
        // (frankenredis-irbta/msv0x/0gibs) GEOADD -> zadd; ZADD INCR -> zincr;
        // DECR/DECRBY -> incrby (all route through the upstream generic paths).
        assert_eq!(ev(&[b"GEOADD", b"g", b"13.0", b"38.0", b"m"]), "zadd");
        assert_eq!(ev(&[b"ZADD", b"z", b"INCR", b"1", b"m"]), "zincr");
        assert_eq!(
            ev(&[b"ZADD", b"z", b"GT", b"CH", b"INCR", b"1", b"m"]),
            "zincr"
        );
        assert_eq!(ev(&[b"ZADD", b"z", b"1", b"m"]), "zadd");
        assert_eq!(ev(&[b"ZADD", b"z", b"GT", b"1", b"m"]), "zadd");
        // Member literally named INCR (after the score) must stay "zadd".
        assert_eq!(ev(&[b"ZADD", b"z", b"1", b"INCR"]), "zadd");
        assert_eq!(ev(&[b"DECR", b"k"]), "incrby");
        assert_eq!(ev(&[b"DECRBY", b"k", b"3"]), "incrby");
        assert_eq!(ev(&[b"INCR", b"k"]), "incrby");
        assert_eq!(ev(&[b"GETDEL", b"k"]), "del");
        assert_eq!(ev(&[b"GETEX", b"k", b"EX", b"100"]), "expire");
        assert_eq!(ev(&[b"GETEX", b"k", b"PERSIST"]), "persist");
        assert_eq!(
            ev(&[b"ZREMRANGEBYRANK", b"z", b"0", b"1"]),
            "zremrangebyrank"
        );
        assert_eq!(
            ev(&[b"ZREMRANGEBYSCORE", b"z", b"0", b"1"]),
            "zremrangebyscore"
        );
        assert_eq!(ev(&[b"ZREMRANGEBYLEX", b"z", b"-", b"+"]), "zremrangebylex");
        // (frankenredis-5wz6g) *STORE commands each fire their OWN name.
        assert_eq!(ev(&[b"SINTERSTORE", b"d", b"s1", b"s2"]), "sinterstore");
        assert_eq!(ev(&[b"SUNIONSTORE", b"d", b"s1", b"s2"]), "sunionstore");
        assert_eq!(ev(&[b"SDIFFSTORE", b"d", b"s1", b"s2"]), "sdiffstore");
        assert_eq!(
            ev(&[b"ZINTERSTORE", b"d", b"2", b"z1", b"z2"]),
            "zinterstore"
        );
        assert_eq!(
            ev(&[b"ZUNIONSTORE", b"d", b"2", b"z1", b"z2"]),
            "zunionstore"
        );
        assert_eq!(ev(&[b"ZDIFFSTORE", b"d", b"2", b"z1", b"z2"]), "zdiffstore");
        assert_eq!(
            ev(&[b"ZRANGESTORE", b"d", b"z1", b"0", b"-1"]),
            "zrangestore"
        );
        assert_eq!(ev(&[b"SORT", b"l", b"STORE", b"d"]), "sortstore");
        assert_eq!(ev(&[b"GEOSEARCHSTORE", b"d", b"s"]), "geosearchstore");
        // Regression guard: the plain SET family stays "set".
        assert_eq!(ev(&[b"SET", b"k", b"v"]), "set");
        assert_eq!(ev(&[b"GETSET", b"k", b"v"]), "set");
        assert_eq!(ev(&[b"SETNX", b"k", b"v"]), "set");
    }

    #[test]
    fn borrowed_getex_persist_fast_path_matches_generic_edges() {
        let setup = |runtime: &mut Runtime| {
            assert_eq!(
                runtime.execute_frame(command(&[b"SET", b"k", b"val", b"EXAT", b"4102444800"]), 1),
                RespFrame::SimpleString("OK".to_string())
            );
            assert_eq!(
                runtime.execute_frame(command(&[b"SET", b"not", b"v"]), 2),
                RespFrame::SimpleString("OK".to_string())
            );
            assert_eq!(
                runtime.execute_frame(command(&[b"RPUSH", b"list", b"x"]), 3),
                RespFrame::Integer(1)
            );
        };

        let mut generic = Runtime::default_strict();
        let mut fast = Runtime::default_strict();
        setup(&mut generic);
        setup(&mut fast);

        let generic_reply = generic.execute_frame(command(&[b"GETEX", b"k", b"PERSIST"]), 4);
        let fast_reply = fast
            .execute_plain_getex_persist_borrowed(b"k", 4)
            .expect("exact GETEX PERSIST should use fast path");
        assert_eq!(fast_reply, generic_reply);
        assert_eq!(
            fast.execute_frame(command(&[b"TTL", b"k"]), 5),
            generic.execute_frame(command(&[b"TTL", b"k"]), 5)
        );

        assert_eq!(
            fast.execute_plain_getex_persist_borrowed(b"missing", 6),
            Some(generic.execute_frame(command(&[b"GETEX", b"missing", b"PERSIST"]), 6))
        );
        assert_eq!(
            fast.execute_plain_getex_persist_borrowed(b"not", 7),
            Some(generic.execute_frame(command(&[b"GETEX", b"not", b"PERSIST"]), 7))
        );
        let wrongtype = fast
            .execute_plain_getex_persist_borrowed(b"list", 8)
            .expect("wrong-type GETEX PERSIST should execute fast path");
        let generic_wrongtype = generic.execute_frame(command(&[b"GETEX", b"list", b"PERSIST"]), 8);
        assert_eq!(wrongtype, generic_wrongtype);
        assert!(matches!(wrongtype, RespFrame::Error(ref msg) if msg.contains("WRONGTYPE")));
    }

    #[test]
    fn borrowed_getex_absexpire_fast_path_matches_generic_edges() {
        let setup = |runtime: &mut Runtime| {
            assert_eq!(
                runtime.execute_frame(command(&[b"SET", b"k", b"val"]), 1),
                RespFrame::SimpleString("OK".to_string())
            );
            assert_eq!(
                runtime.execute_frame(command(&[b"SET", b"not", b"v"]), 2),
                RespFrame::SimpleString("OK".to_string())
            );
            assert_eq!(
                runtime.execute_frame(command(&[b"RPUSH", b"list", b"x"]), 3),
                RespFrame::Integer(1)
            );
        };

        for (is_seconds, unit, time_arg, deadline_cmd) in [
            (true, &b"EXAT"[..], &b"4102444801"[..], &b"EXPIRETIME"[..]),
            (
                false,
                &b"PXAT"[..],
                &b"4102444801000"[..],
                &b"PEXPIRETIME"[..],
            ),
        ] {
            let mut generic = Runtime::default_strict();
            let mut fast = Runtime::default_strict();
            setup(&mut generic);
            setup(&mut fast);

            let generic_reply =
                generic.execute_frame(command(&[b"GETEX", b"k", unit, time_arg]), 4);
            let fast_reply = fast
                .execute_plain_getex_absexpire_borrowed(is_seconds, b"k", time_arg, 4)
                .expect("exact GETEX EXAT/PXAT should use fast path");
            assert_eq!(fast_reply, generic_reply);
            assert_eq!(
                fast.execute_frame(command(&[deadline_cmd, b"k"]), 5),
                generic.execute_frame(command(&[deadline_cmd, b"k"]), 5)
            );

            assert_eq!(
                fast.execute_plain_getex_absexpire_borrowed(is_seconds, b"missing", time_arg, 6),
                Some(generic.execute_frame(command(&[b"GETEX", b"missing", unit, time_arg]), 6))
            );
            assert_eq!(
                fast.execute_plain_getex_absexpire_borrowed(is_seconds, b"not", time_arg, 7),
                Some(generic.execute_frame(command(&[b"GETEX", b"not", unit, time_arg]), 7))
            );
            let wrongtype = fast
                .execute_plain_getex_absexpire_borrowed(is_seconds, b"list", time_arg, 8)
                .expect("wrong-type GETEX EXAT/PXAT should execute fast path");
            let generic_wrongtype =
                generic.execute_frame(command(&[b"GETEX", b"list", unit, time_arg]), 8);
            assert_eq!(wrongtype, generic_wrongtype);
            assert!(matches!(wrongtype, RespFrame::Error(ref msg) if msg.contains("WRONGTYPE")));
        }

        let mut generic = Runtime::default_strict();
        let mut fast = Runtime::default_strict();
        setup(&mut generic);
        setup(&mut fast);
        assert_eq!(
            fast.execute_plain_getex_absexpire_borrowed(true, b"k", b"0", 9),
            None
        );
        assert_eq!(
            fast.execute_plain_getex_absexpire_borrowed(false, b"k", b"abc", 9),
            None
        );

        let generic_past = generic.execute_frame(command(&[b"GETEX", b"k", b"EXAT", b"1"]), 2_000);
        let fast_past = fast
            .execute_plain_getex_absexpire_borrowed(true, b"k", b"1", 2_000)
            .expect("past positive EXAT should use fast path");
        assert_eq!(fast_past, generic_past);
        assert_eq!(
            fast.execute_frame(command(&[b"EXISTS", b"k"]), 2_001),
            generic.execute_frame(command(&[b"EXISTS", b"k"]), 2_001)
        );
    }

    #[test]
    fn is_store_command_and_dest_position() {
        // (frankenredis-5wz6g) *STORE commands write a single destination key;
        // SORT/GEORADIUS put it LAST (after STORE), the set/zset/geosearch
        // stores put it FIRST.
        for c in [
            &b"SINTERSTORE"[..],
            b"SUNIONSTORE",
            b"SDIFFSTORE",
            b"ZINTERSTORE",
            b"ZUNIONSTORE",
            b"ZDIFFSTORE",
            b"ZRANGESTORE",
            b"GEOSEARCHSTORE",
            b"SORT",
            b"GEORADIUS",
            b"GEORADIUSBYMEMBER",
            b"BITOP",
            b"PFMERGE",
        ] {
            assert!(Runtime::is_store_command(c), "{c:?} is a *STORE command");
        }
        for c in [&b"SADD"[..], b"SET", b"SMOVE", b"COPY", b"SORT_RO"] {
            assert!(
                !Runtime::is_store_command(c),
                "{c:?} is NOT a *STORE command"
            );
        }
        assert!(Runtime::store_command_dest_is_last(b"SORT"));
        assert!(Runtime::store_command_dest_is_last(b"GEORADIUS"));
        assert!(Runtime::store_command_dest_is_last(b"GEORADIUSBYMEMBER"));
        assert!(!Runtime::store_command_dest_is_last(b"SINTERSTORE"));
        assert!(!Runtime::store_command_dest_is_last(b"ZRANGESTORE"));
    }

    #[test]
    fn command_sets_expire_as_side_effect_matches_upstream() {
        // (frankenredis-hm2as) SET with EX/PX/EXAT/PXAT and SETEX/PSETEX set
        // a TTL, so upstream fires a secondary "expire" event after "set".
        // Plain SET / KEEPTTL / MSET do not.
        let f = |parts: &[&[u8]]| {
            let argv: Vec<Vec<u8>> = parts.iter().map(|p| p.to_vec()).collect();
            Runtime::command_sets_expire_as_side_effect(&argv)
        };
        assert!(f(&[b"SET", b"k", b"v", b"EX", b"100"]));
        assert!(f(&[b"SET", b"k", b"v", b"PX", b"100"]));
        assert!(f(&[b"SET", b"k", b"v", b"EXAT", b"100"]));
        assert!(f(&[b"SET", b"k", b"v", b"PXAT", b"100"]));
        assert!(f(&[b"SET", b"k", b"v", b"NX", b"EX", b"100"]));
        assert!(f(&[b"SETEX", b"k", b"100", b"v"]));
        assert!(f(&[b"PSETEX", b"k", b"100", b"v"]));
        assert!(!f(&[b"SET", b"k", b"v"]));
        assert!(!f(&[b"SET", b"k", b"v", b"KEEPTTL"]));
        assert!(!f(&[b"MSET", b"a", b"1", b"b", b"2"]));
    }

    #[test]
    fn command_can_empty_collection_covers_element_removers() {
        // (frankenredis-g0crt) These commands remove elements and can leave a
        // key empty, triggering a secondary "del" event. Non-removal writes
        // and the delete-family (which fires "del" as its primary) are out.
        let yes: &[&[u8]] = &[
            b"LPOP", b"RPOP", b"LREM", b"LTRIM", b"LMPOP", b"SREM", b"SPOP", b"HDEL", b"ZREM",
            b"ZPOPMIN", b"ZPOPMAX", b"ZMPOP",
        ];
        for c in yes {
            assert!(
                Runtime::command_can_empty_collection(c),
                "{} should be a collection-emptier",
                String::from_utf8_lossy(c)
            );
        }
        // LMOVE/RPOPLPUSH (and blocking variants) fire their "del" via the
        // dedicated list-move branch (frankenredis-uw80w); SMOVE fires its
        // own srem/del/sadd from Store::smove (frankenredis-4ayjf). None of
        // them go through the generic trailing-del loop.
        let no: &[&[u8]] = &[
            b"SADD",
            b"LPUSH",
            b"HSET",
            b"ZADD",
            b"SET",
            b"DEL",
            b"GETDEL",
            b"LMOVE",
            b"RPOPLPUSH",
            b"BLMOVE",
            b"BRPOPLPUSH",
            b"SMOVE",
        ];
        for c in no {
            assert!(
                !Runtime::command_can_empty_collection(c),
                "{} should NOT be a collection-emptier",
                String::from_utf8_lossy(c)
            );
        }
    }

    #[test]
    fn list_move_events_map_directions() {
        // (frankenredis-uw80w) (pop_on_src, push_on_dst). RPOPLPUSH is fixed
        // rpop→lpush; LMOVE reads FROM (argv[3]) / TO (argv[4]). Verified vs
        // vendored 7.2.4.
        let ev = |parts: &[&[u8]]| {
            let argv: Vec<Vec<u8>> = parts.iter().map(|p| p.to_vec()).collect();
            Runtime::list_move_events(&argv)
        };
        assert_eq!(ev(&[b"RPOPLPUSH", b"a", b"b"]), ("rpop", "lpush"));
        assert_eq!(ev(&[b"BRPOPLPUSH", b"a", b"b", b"0"]), ("rpop", "lpush"));
        assert_eq!(
            ev(&[b"LMOVE", b"a", b"b", b"LEFT", b"RIGHT"]),
            ("lpop", "rpush")
        );
        assert_eq!(
            ev(&[b"LMOVE", b"a", b"b", b"RIGHT", b"LEFT"]),
            ("rpop", "lpush")
        );
        assert_eq!(
            ev(&[b"LMOVE", b"a", b"b", b"LEFT", b"LEFT"]),
            ("lpop", "lpush")
        );
        assert_eq!(
            ev(&[b"LMOVE", b"a", b"b", b"RIGHT", b"RIGHT"]),
            ("rpop", "rpush")
        );
        assert_eq!(
            ev(&[b"BLMOVE", b"a", b"b", b"LEFT", b"RIGHT", b"0"]),
            ("lpop", "rpush")
        );
    }

    #[test]
    fn acl_getuser_under_resp3_returns_map_shape() {
        // (frankenredis-e4njz) Upstream acl.c::aclCommand GETUSER calls
        // addReplyMapLen(c, 6), so the RESP3 wire shape is a Map of
        // 6 (key, value) pairs. fr was emitting Array regardless of
        // session.resp_protocol_version. Same shape pattern as
        // CLIENT TRACKINGINFO (i40x2).
        let mut rt = Runtime::default_strict();
        let hello = rt.execute_frame(command(&[b"HELLO", b"3"]), 1);
        assert!(
            matches!(hello, RespFrame::Map(_)),
            "HELLO 3 should reply with a Map, got {hello:?}"
        );

        let info = rt.execute_frame(command(&[b"ACL", b"GETUSER", b"default"]), 2);
        let RespFrame::Map(Some(entries)) = info else {
            panic!("RESP3 ACL GETUSER must be a Map, got {info:?}"); // ubs:ignore — AI triage
        };
        assert_eq!(entries.len(), 6, "Map should have exactly 6 entries");
        let keys: Vec<&RespFrame> = entries.iter().map(|(k, _)| k).collect();
        assert_eq!(keys[0], &RespFrame::BulkString(Some(b"flags".to_vec())));
        assert_eq!(keys[1], &RespFrame::BulkString(Some(b"passwords".to_vec())));
        assert_eq!(keys[2], &RespFrame::BulkString(Some(b"commands".to_vec())));
        assert_eq!(keys[3], &RespFrame::BulkString(Some(b"keys".to_vec())));
        assert_eq!(keys[4], &RespFrame::BulkString(Some(b"channels".to_vec())));
        assert_eq!(keys[5], &RespFrame::BulkString(Some(b"selectors".to_vec())));
        // (frankenredis-42abp) The `flags` value is emitted via addReplySetLen,
        // so under RESP3 it must be a Set (~), not an Array.
        assert!(
            matches!(entries[0].1, RespFrame::Set(_)),
            "RESP3 ACL GETUSER flags must be a Set, got {:?}",
            entries[0].1
        );
    }

    #[test]
    fn acl_getuser_under_resp2_stays_flat_array() {
        // (frankenredis-e4njz) RESP2 wire shape is a flat Array of 12
        // alternating k/v entries — companion pin to the RESP3 test.
        let mut rt = Runtime::default_strict();
        let info = rt.execute_frame(command(&[b"ACL", b"GETUSER", b"default"]), 1);
        let RespFrame::Array(Some(items)) = info else {
            panic!("RESP2 ACL GETUSER must be a flat Array, got {info:?}"); // ubs:ignore — AI triage
        };
        assert_eq!(items.len(), 12, "flat shape: 6 keys + 6 values");
        assert_eq!(items[0], RespFrame::BulkString(Some(b"flags".to_vec())));
        assert_eq!(items[2], RespFrame::BulkString(Some(b"passwords".to_vec())));
        assert_eq!(items[4], RespFrame::BulkString(Some(b"commands".to_vec())));
        assert_eq!(
            items[10],
            RespFrame::BulkString(Some(b"selectors".to_vec()))
        );
    }

    #[test]
    fn acl_getuser_reflects_per_command_permissions() {
        let mut rt = Runtime::default_strict();
        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"ACL", b"SETUSER", b"dave", b"on", b">pass", b"-@all", b"+get", b"+set"
                ]),
                0
            ),
            RespFrame::SimpleString("OK".to_string())
        );

        let reply = rt.execute_frame(command(&[b"ACL", b"GETUSER", b"dave"]), 1);
        // The commands field should reflect the per-command permissions
        if let RespFrame::Array(Some(fields)) = &reply {
            // Find the "commands" field value
            let mut found_commands = false;
            for (i, field) in fields.iter().enumerate() {
                if let RespFrame::BulkString(Some(name)) = field
                    && name == b"commands"
                    && i + 1 < fields.len()
                    && let RespFrame::BulkString(Some(val)) = &fields[i + 1]
                {
                    let val_str = std::str::from_utf8(val).unwrap();
                    assert!(
                        val_str.contains("+get"),
                        "commands string should contain +get, got: {val_str}"
                    );
                    assert!(
                        val_str.contains("+set"),
                        "commands string should contain +set, got: {val_str}"
                    );
                    found_commands = true;
                }
            }
            assert!(
                found_commands,
                "Should have found commands field in GETUSER reply"
            );
        } else {
            unreachable!("Expected array reply from GETUSER, got: {reply:?}");
        }
    }

    #[test]
    fn acl_subcommand_selectors_are_accepted_and_enforced() {
        let mut rt = Runtime::default_strict();
        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"ACL",
                    b"SETUSER",
                    b"inspector",
                    b"on",
                    b">pass",
                    b"-@all",
                    b"+client|info",
                    b"allkeys",
                ]),
                0,
            ),
            RespFrame::SimpleString("OK".to_string())
        );

        assert_eq!(
            rt.execute_frame(
                command(&[b"ACL", b"DRYRUN", b"inspector", b"CLIENT", b"INFO"]),
                1
            ),
            RespFrame::SimpleString("OK".to_string())
        );

        let denied = rt.execute_frame(
            command(&[
                b"ACL",
                b"DRYRUN",
                b"inspector",
                b"CLIENT",
                b"KILL",
                b"TYPE",
                b"normal",
            ]),
            2,
        );
        assert!(
            matches!(&denied, RespFrame::BulkString(Some(msg)) if std::str::from_utf8(msg).is_ok_and(|s| s.contains("no permissions"))),
            "CLIENT KILL should remain denied for +client|info-only user, got: {denied:?}"
        );

        let getuser = rt.execute_frame(command(&[b"ACL", b"GETUSER", b"inspector"]), 3);
        let RespFrame::Array(Some(fields)) = getuser else {
            unreachable!("expected ACL GETUSER array");
        };
        let commands = fields
            .windows(2)
            .find_map(|pair| match pair {
                [
                    RespFrame::BulkString(Some(name)),
                    RespFrame::BulkString(Some(value)),
                ] if name == b"commands" => Some(String::from_utf8_lossy(value).into_owned()),
                _ => None,
            })
            .expect("ACL GETUSER commands field");
        assert!(
            commands.contains("+client|info"),
            "commands field should preserve +client|info, got: {commands}"
        );
    }

    #[test]
    fn acl_list_reflects_per_command_permissions() {
        let mut rt = Runtime::default_strict();
        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"ACL", b"SETUSER", b"eve", b"on", b">pass", b"+@all", b"-del"
                ]),
                0
            ),
            RespFrame::SimpleString("OK".to_string())
        );

        let reply = rt.execute_frame(command(&[b"ACL", b"LIST"]), 1);
        if let RespFrame::Array(Some(entries)) = &reply {
            let eve_entry = entries.iter().find(|e| {
                if let RespFrame::BulkString(Some(s)) = e {
                    String::from_utf8_lossy(s).contains("eve")
                } else {
                    false
                }
            });
            assert!(eve_entry.is_some(), "Should find eve in ACL LIST");
            if let Some(RespFrame::BulkString(Some(s))) = eve_entry {
                let entry_str = String::from_utf8_lossy(s);
                assert!(
                    entry_str.contains("-del"),
                    "ACL LIST for eve should contain -del, got: {entry_str}"
                );
            }
        } else {
            unreachable!("Expected array reply from ACL LIST, got: {reply:?}");
        }
    }

    #[test]
    fn acl_case_insensitive_command_matching() {
        let mut rt = Runtime::default_strict();
        // Create user allowing only +GET (uppercase)
        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"ACL", b"SETUSER", b"ci", b"on", b">pass", b"-@all", b"+GET", b"allkeys"
                ]),
                0
            ),
            RespFrame::SimpleString("OK".to_string())
        );

        // Dryrun with lowercase "get" should still be allowed
        assert_eq!(
            rt.execute_frame(command(&[b"ACL", b"DRYRUN", b"ci", b"get", b"k"]), 1),
            RespFrame::SimpleString("OK".to_string())
        );

        // Dryrun with mixed case "Get" should also be allowed
        assert_eq!(
            rt.execute_frame(command(&[b"ACL", b"DRYRUN", b"ci", b"Get", b"k"]), 2),
            RespFrame::SimpleString("OK".to_string())
        );
    }

    #[test]
    fn acl_allcommands_resets_granular_permissions() {
        let mut rt = Runtime::default_strict();
        // Start with -@all +get, then apply allcommands
        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"ACL",
                    b"SETUSER",
                    b"reset_test",
                    b"on",
                    b">pass",
                    b"-@all",
                    b"+get",
                    b"allkeys"
                ]),
                0
            ),
            RespFrame::SimpleString("OK".to_string())
        );

        // DEL denied before allcommands
        let reply = rt.execute_frame(
            command(&[b"ACL", b"DRYRUN", b"reset_test", b"DEL", b"k"]),
            1,
        );
        assert!(
            matches!(&reply, RespFrame::BulkString(Some(b)) if std::str::from_utf8(b).map(|s| s.contains("no permissions")).unwrap_or(false))
        );

        // Apply allcommands
        assert_eq!(
            rt.execute_frame(
                command(&[b"ACL", b"SETUSER", b"reset_test", b"allcommands"]),
                2
            ),
            RespFrame::SimpleString("OK".to_string())
        );

        // DEL now allowed
        assert_eq!(
            rt.execute_frame(
                command(&[b"ACL", b"DRYRUN", b"reset_test", b"DEL", b"k"]),
                3
            ),
            RespFrame::SimpleString("OK".to_string())
        );
    }

    #[test]
    fn acl_deny_command_wins_over_allow_all() {
        let mut rt = Runtime::default_strict();
        // +@all -del: explicit deny should override the +@all base
        assert_eq!(
            rt.execute_frame(
                command(&[
                    b"ACL",
                    b"SETUSER",
                    b"deny_test",
                    b"on",
                    b">pass",
                    b"+@all",
                    b"-del",
                    b"allkeys"
                ]),
                0
            ),
            RespFrame::SimpleString("OK".to_string())
        );

        // GET allowed
        assert_eq!(
            rt.execute_frame(command(&[b"ACL", b"DRYRUN", b"deny_test", b"GET", b"k"]), 1),
            RespFrame::SimpleString("OK".to_string())
        );

        // DEL denied
        let reply = rt.execute_frame(command(&[b"ACL", b"DRYRUN", b"deny_test", b"DEL", b"k"]), 2);
        assert!(
            matches!(&reply, RespFrame::BulkString(Some(b)) if std::str::from_utf8(b).map(|s| s.contains("no permissions")).unwrap_or(false)),
            "DEL should be denied despite +@all, got: {reply:?}"
        );
    }

    #[test]
    fn acl_log_under_resp3_returns_map_per_entry() {
        // (frankenredis-5d04d) Upstream acl.c::aclCommand 'log'
        // emits each entry via addReplyMapLen(c, 10) — the RESP3
        // wire shape is a Map of 10 (key, value) pairs per entry,
        // wrapped in an outer Array (one entry per ACL deny). fr
        // was emitting a flat 20-element Array per entry regardless
        // of session.resp_protocol_version. Same shape pattern as
        // CLIENT TRACKINGINFO (i40x2), ACL GETUSER (e4njz), MEMORY
        // STATS (udl3y), FUNCTION STATS (asvh1).
        let mut rt = Runtime::default_strict();
        rt.session.client_id = 4;
        rt.session.last_command_name = "auth".to_string();
        rt.record_acl_log_event("auth", "AUTH".to_string(), b"default".to_vec(), 1_000);

        let hello = rt.execute_frame(command(&[b"HELLO", b"3"]), 1);
        assert!(
            matches!(hello, RespFrame::Map(_)),
            "HELLO 3 should reply with a Map, got {hello:?}"
        );

        let reply = rt.execute_frame(command(&[b"ACL", b"LOG"]), 5_500);
        let RespFrame::Array(Some(entries)) = reply else {
            panic!("ACL LOG outer reply must be Array of entries"); // ubs:ignore — AI triage
        };
        assert!(!entries.is_empty(), "must have one ACL log entry");
        let RespFrame::Map(Some(pairs)) = &entries[0] else {
            panic!("entry must be Map under RESP3, got {:?}", entries[0]); // ubs:ignore — AI triage
        };
        assert_eq!(pairs.len(), 10, "Map should have exactly 10 entries");
        // Spot-check the canonical key order against upstream.
        assert_eq!(pairs[0].0, RespFrame::BulkString(Some(b"count".to_vec())));
        assert_eq!(pairs[1].0, RespFrame::BulkString(Some(b"reason".to_vec())));
        assert_eq!(
            pairs[4].0,
            RespFrame::BulkString(Some(b"username".to_vec()))
        );
        assert_eq!(
            pairs[9].0,
            RespFrame::BulkString(Some(b"timestamp-last-updated".to_vec()))
        );
    }

    #[test]
    fn acl_log_under_resp2_stays_flat_array_per_entry() {
        // (frankenredis-5d04d) Companion pin: under RESP2 each entry
        // is the existing 20-element flat Array of alternating k/v.
        let mut rt = Runtime::default_strict();
        rt.session.client_id = 4;
        rt.session.last_command_name = "auth".to_string();
        rt.record_acl_log_event("auth", "AUTH".to_string(), b"default".to_vec(), 1_000);

        let reply = rt.execute_frame(command(&[b"ACL", b"LOG"]), 5_500);
        let RespFrame::Array(Some(entries)) = reply else {
            panic!("ACL LOG outer reply must be Array of entries"); // ubs:ignore — AI triage
        };
        assert!(!entries.is_empty());
        let RespFrame::Array(Some(items)) = &entries[0] else {
            panic!("entry must be flat Array under RESP2, got {:?}", entries[0]); // ubs:ignore — AI triage
        };
        assert_eq!(items.len(), 20, "flat shape: 10 keys + 10 values");
        assert_eq!(items[0], RespFrame::BulkString(Some(b"count".to_vec())));
        assert_eq!(items[2], RespFrame::BulkString(Some(b"reason".to_vec())));
        assert_eq!(
            items[16],
            RespFrame::BulkString(Some(b"timestamp-created".to_vec()))
        );
        assert_eq!(
            items[18],
            RespFrame::BulkString(Some(b"timestamp-last-updated".to_vec()))
        );
    }

